fn topology_ownership_scope_slug(scope: TopologyOwnershipScopeKind) -> &'static str {
    match scope {
        TopologyOwnershipScopeKind::SiteOwned => "site_owned",
        TopologyOwnershipScopeKind::FootprintOwned => "footprint_owned",
        TopologyOwnershipScopeKind::FloorOwned => "floor_owned",
        TopologyOwnershipScopeKind::UnitOwned => "unit_owned",
        TopologyOwnershipScopeKind::RoomOwned => "room_owned",
        TopologyOwnershipScopeKind::RoofOwned => "roof_owned",
        TopologyOwnershipScopeKind::StackOwned => "stack_owned",
        TopologyOwnershipScopeKind::ServiceOwned => "service_owned",
        TopologyOwnershipScopeKind::ResidualOwned => "residual_owned",
    }
}

fn make_space_placement(
    category: impl Into<String>,
    space_name: impl Into<String>,
    qty: f64,
    rect: Rect2,
    polygon: Vec<Point2>,
    area_sf: f64,
) -> SpacePlacement {
    SpacePlacement {
        space_id: String::new(),
        category: category.into(),
        space_name: space_name.into(),
        qty,
        rect,
        polygon,
        area_sf,
        ownership_scope: TopologyOwnershipScopeKind::FloorOwned,
        ownership_chain_ids: Vec::new(),
        parent_topology_node_id: None,
        child_topology_node_ids: Vec::new(),
        sibling_constraints: Vec::new(),
        zone_owner_id: None,
        host_zone_id: None,
        concept_block_id: None,
        parent_space_id: None,
        stack_id: None,
        adjacency_ids: Vec::new(),
        ingress_relations: Vec::new(),
        egress_relations: Vec::new(),
        service_dependencies: Vec::new(),
        daylight_owner_ids: Vec::new(),
        frontage_owner_ids: Vec::new(),
        privacy_owner_ids: Vec::new(),
        support_program: None,
        support_profile: None,
        residual_source_id: None,
    }
}

fn is_service_space(space: &SpacePlacement) -> bool {
    let hay = format!(
        "{} {}",
        space.category.to_lowercase(),
        space.space_name.to_lowercase()
    );
    hay.contains("service")
        || hay.contains("support")
        || hay.contains("boh")
        || hay.contains("shaft")
        || hay.contains("stair")
        || hay.contains("elevator")
        || hay.contains("lobby")
        || hay.contains("core")
        || hay.contains("loading")
        || hay.contains("mechanical")
        || hay.contains("parking")
        || hay.contains("drive aisle")
        || hay.contains("ramp")
        || hay.contains("vehicle")
}

fn is_outdoor_or_roof_space(space: &SpacePlacement) -> bool {
    let hay = format!(
        "{} {}",
        space.category.to_lowercase(),
        space.space_name.to_lowercase()
    );
    hay.contains("outdoor")
        || hay.contains("roof")
        || hay.contains("terrace")
        || hay.contains("balcony")
        || hay.contains("landscape")
        || hay.contains("deck")
        || hay.contains("courtyard")
}

fn space_center(space: &SpacePlacement) -> Point2 {
    if space.polygon.len() >= 3 {
        poly_centroid(&space.polygon)
    } else {
        space.rect.center()
    }
}

fn space_touches_floor_boundary(space: &SpacePlacement, floor_bbox: Rect2) -> bool {
    let bb = space_bbox(space);
    (bb.min_x - floor_bbox.min_x).abs() <= 1.0
        || (bb.max_x - floor_bbox.max_x).abs() <= 1.0
        || (bb.min_y - floor_bbox.min_y).abs() <= 1.0
        || (bb.max_y - floor_bbox.max_y).abs() <= 1.0
}

fn default_space_scope(
    space: &SpacePlacement,
    level_index: u32,
    top_level_index: u32,
) -> TopologyOwnershipScopeKind {
    if is_dwelling_space(space) {
        TopologyOwnershipScopeKind::UnitOwned
    } else if is_service_space(space) {
        TopologyOwnershipScopeKind::ServiceOwned
    } else if is_outdoor_or_roof_space(space) && level_index == top_level_index {
        TopologyOwnershipScopeKind::RoofOwned
    } else if is_outdoor_or_roof_space(space) {
        TopologyOwnershipScopeKind::SiteOwned
    } else if space.category.to_lowercase().contains("circulation") {
        TopologyOwnershipScopeKind::FloorOwned
    } else {
        TopologyOwnershipScopeKind::FloorOwned
    }
}

fn zone_owner_id_for_space(space: &SpacePlacement, level_index: u32) -> String {
    let category_slug = space
        .category
        .chars()
        .map(|c| {
            if c.is_ascii_alphanumeric() {
                c.to_ascii_lowercase()
            } else {
                '_'
            }
        })
        .collect::<String>();
    format!("owner_zone_L{:02}_{}", level_index, category_slug)
}

fn stack_id_for_space(
    space: &SpacePlacement,
    verticals: &VerticalState,
    family_id: &str,
) -> String {
    let center = space_center(space);
    if let Some((idx, group)) = verticals
        .groups
        .iter()
        .enumerate()
        .min_by(|(_, a), (_, b)| {
            center
                .distance_to(a.anchor)
                .partial_cmp(&center.distance_to(b.anchor))
                .unwrap_or(Ordering::Equal)
        })
    {
        if let Some(ownership) = verticals
            .topology_state
            .stack_ownerships
            .iter()
            .find(|ownership| ownership.owner_ref == group.name)
        {
            ownership.stack_id.clone()
        } else {
            format!(
                "stack_{}_{}",
                idx,
                group.name.replace(' ', "_").to_lowercase()
            )
        }
    } else {
        format!(
            "stack_family_{}",
            family_id.replace(' ', "_").to_lowercase()
        )
    }
}

fn root_parent_node_id_for_scope(
    scope: TopologyOwnershipScopeKind,
    level_index: u32,
    stack_id: Option<&str>,
) -> String {
    match scope {
        TopologyOwnershipScopeKind::SiteOwned => "topo_site_root".to_string(),
        TopologyOwnershipScopeKind::FootprintOwned => "topo_footprint_root".to_string(),
        TopologyOwnershipScopeKind::FloorOwned => format!("topo_floor_root_L{:02}", level_index),
        TopologyOwnershipScopeKind::UnitOwned => stack_id
            .map(|id| format!("topo_stack_root_{}", id))
            .unwrap_or_else(|| format!("topo_floor_root_L{:02}", level_index)),
        TopologyOwnershipScopeKind::RoomOwned => format!("topo_floor_root_L{:02}", level_index),
        TopologyOwnershipScopeKind::RoofOwned => format!("topo_roof_root_L{:02}", level_index),
        TopologyOwnershipScopeKind::StackOwned => stack_id
            .map(|id| format!("topo_stack_root_{}", id))
            .unwrap_or_else(|| format!("topo_floor_root_L{:02}", level_index)),
        TopologyOwnershipScopeKind::ServiceOwned => {
            format!("topo_service_root_L{:02}", level_index)
        }
        TopologyOwnershipScopeKind::ResidualOwned => {
            format!("topo_residual_root_L{:02}", level_index)
        }
    }
}

fn space_privacy_owner_ids(
    space_id: &str,
    scope: TopologyOwnershipScopeKind,
    level_index: u32,
) -> Vec<String> {
    match scope {
        TopologyOwnershipScopeKind::UnitOwned => vec![format!("privacy_unit_{}", space_id)],
        TopologyOwnershipScopeKind::RoomOwned => vec![format!("privacy_room_{}", space_id)],
        TopologyOwnershipScopeKind::ServiceOwned => {
            vec![format!("privacy_service_L{:02}", level_index)]
        }
        TopologyOwnershipScopeKind::ResidualOwned => {
            vec![format!("privacy_residual_L{:02}", level_index)]
        }
        TopologyOwnershipScopeKind::RoofOwned | TopologyOwnershipScopeKind::SiteOwned => {
            vec![format!("privacy_exterior_L{:02}", level_index)]
        }
        _ => vec![format!("privacy_common_L{:02}", level_index)],
    }
}

fn canonical_graph_add_owner_record(
    graph: &mut CanonicalTopologyGraph,
    record: TopologyOwnershipRecord,
) {
    if let Some(existing) = graph
        .ownership_hierarchy
        .iter_mut()
        .find(|x| x.owner_id == record.owner_id)
    {
        if existing.parent_owner_id.is_none() {
            existing.parent_owner_id = record.parent_owner_id.clone();
        }
        if existing.level_index.is_none() {
            existing.level_index = record.level_index;
        }
        if existing.family_id.is_none() {
            existing.family_id = record.family_id.clone();
        }
        if existing.zone_owner_id.is_none() {
            existing.zone_owner_id = record.zone_owner_id.clone();
        }
        if existing.stack_id.is_none() {
            existing.stack_id = record.stack_id.clone();
        }
        existing
            .owned_space_ids
            .extend(record.owned_space_ids.clone());
        existing
            .owned_node_ids
            .extend(record.owned_node_ids.clone());
        existing
            .child_owner_ids
            .extend(record.child_owner_ids.clone());
        existing.notes.extend(record.notes.clone());
        dedup_vec_strings(&mut existing.owned_space_ids);
        dedup_vec_strings(&mut existing.owned_node_ids);
        dedup_vec_strings(&mut existing.child_owner_ids);
        dedup_vec_strings(&mut existing.notes);
    } else {
        graph.ownership_hierarchy.push(record);
    }
}

