fn circulation_node_square(anchor: Point2, half_extent_ft: f64) -> Vec<Point2> {
    Rect2::new(
        anchor.x - half_extent_ft,
        anchor.y - half_extent_ft,
        anchor.x + half_extent_ft,
        anchor.y + half_extent_ft,
    )
    .to_polygon()
}

fn line_segment_rect(line: Line2, width_ft: f64) -> Vec<Point2> {
    let dir = line.dir();
    let perp = dir.perp().scale(width_ft.max(1.0) * 0.5);
    vec![
        line.a.add(perp),
        line.b.add(perp),
        line.b.sub(perp),
        line.a.sub(perp),
    ]
}

fn point_almost_eq(a: Point2, b: Point2, tol: f64) -> bool {
    a.distance_to(b) <= tol
}

fn line_point_at_param(line: Line2, t: f64) -> Point2 {
    Point2::new(
        line.a.x + (line.b.x - line.a.x) * t,
        line.a.y + (line.b.y - line.a.y) * t,
    )
}

fn line_param_and_projection(line: Line2, point: Point2) -> (f64, Point2, f64) {
    let d = line.b.sub(line.a);
    let len2 = d.dot(d).max(EPS);
    let t = clamp(point.sub(line.a).dot(d) / len2, 0.0, 1.0);
    let proj = line_point_at_param(line, t);
    (t, proj, proj.distance_to(point))
}

fn axis_aligned_line_intersection(a: Line2, b: Line2) -> Option<Point2> {
    let a_horizontal = (a.a.y - a.b.y).abs() <= EPS;
    let a_vertical = (a.a.x - a.b.x).abs() <= EPS;
    let b_horizontal = (b.a.y - b.b.y).abs() <= EPS;
    let b_vertical = (b.a.x - b.b.x).abs() <= EPS;

    match (a_horizontal, a_vertical, b_horizontal, b_vertical) {
        (true, false, false, true) => {
            let x = b.a.x;
            let y = a.a.y;
            let within_a = x >= a.a.x.min(a.b.x) - EPS && x <= a.a.x.max(a.b.x) + EPS;
            let within_b = y >= b.a.y.min(b.b.y) - EPS && y <= b.a.y.max(b.b.y) + EPS;
            if within_a && within_b {
                Some(Point2::new(x, y))
            } else {
                None
            }
        }
        (false, true, true, false) => axis_aligned_line_intersection(b, a),
        _ => None,
    }
}

fn dedup_sorted_scalars(values: &mut Vec<f64>, tol: f64) {
    values.sort_by(|a, b| a.partial_cmp(b).unwrap_or(Ordering::Equal));
    let mut out = Vec::<f64>::new();
    for value in values.iter().copied() {
        if out
            .last()
            .map(|last| (value - *last).abs() > tol)
            .unwrap_or(true)
        {
            out.push(value);
        }
    }
    *values = out;
}

fn corridor_half_width_estimate(floor: &FloorOutput, input: &RoomSynthesisLayoutInput) -> f64 {
    let corridor_rects = corridor_rects_for_floor(floor);
    let inferred = corridor_rects
        .iter()
        .map(|rect| rect.width().min(rect.height()) * 0.5)
        .filter(|value| *value > EPS)
        .fold(f64::INFINITY, |acc, value| acc.min(value));
    if inferred.is_finite() {
        inferred.max(input.corridor_graph_controls.min_corridor_clear_width_ft * 0.5)
    } else {
        input.corridor_graph_controls.min_corridor_clear_width_ft * 0.5
    }
}

fn corridor_centerlines_for_floor(floor: &FloorOutput) -> Vec<Line2> {
    if !floor.guide_lines.is_empty() {
        return floor.guide_lines.clone();
    }
    corridor_rects_for_floor(floor)
        .iter()
        .map(|rect| {
            if rect.width() >= rect.height() {
                let cy = (rect.min_y + rect.max_y) * 0.5;
                Line2::new(Point2::new(rect.min_x, cy), Point2::new(rect.max_x, cy))
            } else {
                let cx = (rect.min_x + rect.max_x) * 0.5;
                Line2::new(Point2::new(cx, rect.min_y), Point2::new(cx, rect.max_y))
            }
        })
        .collect()
}

fn room_privacy_class(room_kind: &str) -> &'static str {
    if room_kind.starts_with("bedroom")
        || room_kind.starts_with("bath")
        || room_kind == "private_hall"
        || room_kind.starts_with("closet")
    {
        "private"
    } else if room_kind.starts_with("laundry_niche")
        || room_kind.starts_with("mechanical_closet")
        || room_kind == "storage"
    {
        "service"
    } else {
        "public"
    }
}

fn undirected_component_count(node_ids: &[String], edges: &[CirculationEdge]) -> usize {
    let mut adjacency = BTreeMap::<String, Vec<String>>::new();
    for node_id in node_ids {
        adjacency.entry(node_id.clone()).or_default();
    }
    for edge in edges {
        adjacency
            .entry(edge.from_node_id.clone())
            .or_default()
            .push(edge.to_node_id.clone());
        adjacency
            .entry(edge.to_node_id.clone())
            .or_default()
            .push(edge.from_node_id.clone());
    }

    let mut seen = BTreeMap::<String, bool>::new();
    let mut components = 0usize;
    for node_id in node_ids {
        if seen.get(node_id).copied().unwrap_or(false) {
            continue;
        }
        components += 1;
        let mut stack = vec![node_id.clone()];
        while let Some(current) = stack.pop() {
            if seen.insert(current.clone(), true).unwrap_or(false) {
                continue;
            }
            if let Some(nexts) = adjacency.get(&current) {
                for next in nexts {
                    if !seen.get(next).copied().unwrap_or(false) {
                        stack.push(next.clone());
                    }
                }
            }
        }
    }
    components
}

