fn canonical_space_polygon(space: &SpacePlacement) -> Vec<Point2> {
    if space.polygon.len() >= 3 {
        space.polygon.clone()
    } else {
        space.rect.to_polygon()
    }
}

fn canonical_graph_node_bbox(node: &CanonicalTopologyNode) -> Option<Rect2> {
    if !node.polygon.is_empty() {
        Some(bounding_rect(&node.polygon))
    } else {
        node.guide_line.map(|line| bounding_rect(&[line.a, line.b]))
    }
}

fn canonical_graph_node_center(node: &CanonicalTopologyNode) -> Option<Point2> {
    canonical_graph_node_bbox(node).map(|bb| bb.center())
}

fn canonical_graph_touch_or_overlap(a: Rect2, b: Rect2, tolerance_ft: f64) -> bool {
    !(a.max_x < b.min_x - tolerance_ft
        || a.min_x > b.max_x + tolerance_ft
        || a.max_y < b.min_y - tolerance_ft
        || a.min_y > b.max_y + tolerance_ft)
}

fn canonical_graph_node_has_frontage(node: &CanonicalTopologyNode, floor_bbox: Rect2) -> bool {
    canonical_graph_node_bbox(node).map_or(false, |bb| {
        (bb.min_x - floor_bbox.min_x).abs() <= 1.0
            || (bb.max_x - floor_bbox.max_x).abs() <= 1.0
            || (bb.min_y - floor_bbox.min_y).abs() <= 1.0
            || (bb.max_y - floor_bbox.max_y).abs() <= 1.0
    })
}

fn canonical_graph_add_node(graph: &mut CanonicalTopologyGraph, node: CanonicalTopologyNode) {
    if !graph.nodes.iter().any(|x| x.node_id == node.node_id) {
        graph.nodes.push(node);
    }
}

fn canonical_graph_add_edge(graph: &mut CanonicalTopologyGraph, edge: CanonicalTopologyEdge) {
    if !graph.edges.iter().any(|x| x.edge_id == edge.edge_id) {
        graph.edges.push(edge);
    }
}

