    #[test]
    fn main_electrical_seed_matches_workbook_profile_without_typical_floor_drift() {
        let mut repo_input = sample_repo_integration_input();
        repo_input.levels.count = 10;
        repo_input.levels.podium_levels = 1;
        repo_input.targets.dwelling_units_cap = Some(140);
        repo_input.constraints.parking_mode = ParkingMode::Podium;
        repo_input.residential_features.in_unit_wd.mode = InUnitWdMode::None;

        let input = repo_input.to_core();
        let assumptions = AssumptionPack::default();
        let engine = LayoutEngine::default();
        let mut state = EngineState::new(input, assumptions);

        solve_input_normalization(&mut state);
        solve_massing_targets(&mut state);
        engine.solve_program_targets(&mut state);

        let normalized = state.normalized.as_ref().unwrap();
        let massing = state.massing.as_ref().unwrap();
        let program = state.program.as_ref().unwrap();
        let code = &state.code_pack;
        let (passenger_elevators, freight_elevators, stairs) =
            LayoutEngine::coarse_vertical_counts_for_program(
                normalized,
                massing,
                program.dwelling_units_total,
                program.net_residential_area_sf,
                code,
                &state.assumptions,
            );
        let unit_areas = [
            resolved_unit_area_sf(normalized, UnitType::Studio, &state.assumptions),
            resolved_unit_area_sf(normalized, UnitType::OneBedroom, &state.assumptions),
            resolved_unit_area_sf(normalized, UnitType::TwoBedroom, &state.assumptions),
            resolved_unit_area_sf(normalized, UnitType::ThreeBedroom, &state.assumptions),
        ];
        let unit_types = [
            UnitType::Studio,
            UnitType::OneBedroom,
            UnitType::TwoBedroom,
            UnitType::ThreeBedroom,
        ];
        let mut widths_ft = [0.0; 4];
        for (i, unit_type) in unit_types.iter().copied().enumerate() {
            let ratio = resolved_depth_over_width_ratio(unit_type, normalized.optimization.objective);
            let (width, _) =
                unit_width_depth_ft(unit_areas[i], ratio, normalized, &state.assumptions);
            widths_ft[i] = width;
        }
        let corridor_loading_factor = match normalized.constraints.corridor_type {
            CorridorType::SingleLoaded | CorridorType::Perimeter => 1.0,
            _ => 2.0,
        };
        let residential_frontage_ft = frontage_length_ft(program.unit_counts, widths_ft);
        let (_, _, corridor_area_sf) = corridor_length_area_v12(
            residential_frontage_ft,
            corridor_loading_factor,
            program.preliminary_area_budget.corridor_width_ft,
            massing
                .story_count
                .saturating_sub(
                    normalized.levels.below_grade_count + normalized.levels.podium_levels,
                )
                .max(1),
        );
        let shaft_stair_area_sf = stairs as f64
            * state
                .assumptions
                .boh
                .electrical_stair_shaft_area_sf_per_stair_per_floor
            * massing
                .story_count
                .saturating_sub(normalized.levels.below_grade_count)
                .max(1) as f64;
        let expected_kva = coarse_total_electrical_load_kva(
            program.dwelling_units_total,
            passenger_elevators,
            freight_elevators,
            program.net_residential_area_sf,
            corridor_area_sf,
            normalized.targets.retail_area_sf,
            shaft_stair_area_sf,
            entry_lobby_area_sf(
                massing.story_count,
                program.dwelling_units_total,
                &state.assumptions,
            ),
            0.0,
            &state.assumptions,
        );
        let main_electrical = program
            .support_rows
            .iter()
            .find(|row| row.space_name == "Main Electrical Room")
            .unwrap();
        let expected_area = main_electrical_room_project_area_sf(
            expected_kva,
            program.dwelling_units_total,
            &state.assumptions,
        );
        assert!((main_electrical.area_sf - expected_area).abs() <= 1.0e-6);
        assert!(program
            .support_topology
            .nodes
            .iter()
            .any(|node| node.program_kind == SupportProgramKind::MainElectricalRoom));

        let podium_family = FloorFamily {
            family_id: "podium".to_string(),
            level_indices: vec![0],
            is_typical: false,
            area_budget_sf: 0.0,
            uses_upper_footprint: false,
            family_role: "arrival".to_string(),
            bound_block_ids: Vec::new(),
            binding_notes: Vec::new(),
        };
        let arrival_rows = support_rows_for_level(normalized, program, &podium_family, 0);
        assert!(arrival_rows
            .iter()
            .any(|row| row.space_name == "Main Electrical Room"));

        let typical_family = FloorFamily {
            family_id: "typical_residential".to_string(),
            level_indices: vec![5],
            is_typical: true,
            area_budget_sf: 0.0,
            uses_upper_footprint: true,
            family_role: "residential".to_string(),
            bound_block_ids: Vec::new(),
            binding_notes: Vec::new(),
        };
        let typical_rows = support_rows_for_level(normalized, program, &typical_family, 5);
        assert!(!typical_rows
            .iter()
            .any(|row| row.space_name == "Main Electrical Room"));
    }

