    #[test]
    fn domestic_water_booster_room_seed_matches_workbook_profile_without_typical_floor_drift() {
        let mut repo_input = sample_repo_integration_input();
        repo_input.levels.count = 10;
        repo_input.levels.podium_levels = 1;
        repo_input.targets.dwelling_units_cap = Some(140);
        repo_input.constraints.parking_mode = ParkingMode::Podium;
        repo_input.residential_features.in_unit_wd.mode = InUnitWdMode::None;

        let input = repo_input.to_core();
        let assumptions = AssumptionPack::default();
        let engine = LayoutEngine::default();
        let mut state = EngineState::new(input, assumptions);

        solve_input_normalization(&mut state);
        solve_massing_targets(&mut state);
        engine.solve_program_targets(&mut state);

        let normalized = state.normalized.as_ref().unwrap();
        let massing = state.massing.as_ref().unwrap();
        let program = state.program.as_ref().unwrap();
        let booster_room = program
            .support_rows
            .iter()
            .find(|row| row.space_name == "Domestic Water Booster Pump Room")
            .unwrap();
        let operations_staff =
            support_staff_count(program.dwelling_units_total, &state.assumptions)
                .round()
                .max(0.0) as u32;
        let has_leasing_office = program
            .support_rows
            .iter()
            .any(|row| row.space_name == "Leasing Office");
        let (public_wc, public_urinal, public_lav) = domestic_public_plumbing_fixture_counts(
            normalized,
            program.indoor_amenity_target_sf,
            operations_staff,
            has_leasing_office,
            &state.assumptions,
        );
        let fixture_units = domestic_cold_water_fixture_units(
            program.unit_counts,
            public_wc,
            public_urinal,
            public_lav,
            &state.assumptions,
        );
        let peak_flow_gpm = domestic_peak_flow_gpm(fixture_units, &state.assumptions);
        let coarse_gba_sf = massing.gfa_goal_sf
            + program.preliminary_area_budget.support_staff_area_sf
            + program.preliminary_area_budget.fixed_common_area_sf
            + program.preliminary_area_budget.stair_vestibule_total_sf;
        let expected_area = domestic_water_booster_pump_room_area_sf(
            massing.story_count,
            coarse_gba_sf,
            peak_flow_gpm,
            &state.assumptions,
        );
        assert!((booster_room.area_sf - expected_area).abs() <= 1.0e-6);
        assert!(program.support_topology.nodes.iter().any(|node| {
            node.program_kind == SupportProgramKind::DomesticWaterBoosterRoom
        }));

        let podium_family = FloorFamily {
            family_id: "podium".to_string(),
            level_indices: vec![0],
            is_typical: false,
            area_budget_sf: 0.0,
            uses_upper_footprint: false,
            family_role: "arrival".to_string(),
            bound_block_ids: Vec::new(),
            binding_notes: Vec::new(),
        };
        let arrival_rows = support_rows_for_level(normalized, program, &podium_family, 0);
        assert!(arrival_rows
            .iter()
            .any(|row| row.space_name == "Domestic Water Booster Pump Room"));

        let typical_family = FloorFamily {
            family_id: "typical_residential".to_string(),
            level_indices: vec![5],
            is_typical: true,
            area_budget_sf: 0.0,
            uses_upper_footprint: true,
            family_role: "residential".to_string(),
            bound_block_ids: Vec::new(),
            binding_notes: Vec::new(),
        };
        let typical_rows = support_rows_for_level(normalized, program, &typical_family, 5);
        assert!(!typical_rows
            .iter()
            .any(|row| row.space_name == "Domestic Water Booster Pump Room"));
    }

