    #[test]
    fn solve_detail_from_concept_smoke() {
        let input = sample_repo_integration_input().to_core();
        let assumptions = AssumptionPack::default();
        let options = generate_concept_options(&input, &assumptions);
        let concept = select_default_concept(&options, &input);
        let engine = LayoutEngine::default();
        let mut state = EngineState::new(input, assumptions.clone());

        solve_input_normalization(&mut state);
        solve_massing_targets(&mut state);
        engine.solve_program_targets(&mut state);
        engine.solve_vertical_system(&mut state);

        let result = solve_detail_from_concept(
            state.normalized.as_ref().unwrap(),
            state.massing.as_ref().unwrap(),
            state.program.as_ref().unwrap(),
            state.verticals.as_ref().unwrap(),
            &assumptions,
            concept,
        );

        assert!(!result.selected_candidate.candidate_id.is_empty());
        assert!(!result.selected_candidate.floors.is_empty());
        assert!(!result.concept_applied.concept_blocks.is_empty());
        assert!(result
            .selected_candidate
            .floors
            .iter()
            .all(|floor| !floor.zones.is_empty()));
        assert!(result
            .selected_candidate
            .floors
            .iter()
            .any(|floor| !floor.circulation_topology.corridor_segment_graph.is_empty()));
        assert!(result
            .selected_candidate
            .floors
            .iter()
            .any(|floor| !floor.room_spaces.is_empty()));
        assert!(!result.selected_candidate.roof_spaces.is_empty());
        assert!(!result.selected_candidate.site_spaces.is_empty());
    }

    #[test]
    fn outdoor_cwh_pad_assumption_creates_site_space_without_indoor_support_drift() {
        let input = sample_repo_integration_input().to_core();
        let mut assumptions = AssumptionPack::default();
        assumptions.boh.central_water_heating_room_indoor_enabled = false;
        assumptions.boh.central_water_heating_pad_outdoor_enabled = true;
        let options = generate_concept_options(&input, &assumptions);
        let concept = select_default_concept(&options, &input);
        let engine = LayoutEngine::default();
        let mut state = EngineState::new(input, assumptions.clone());

        solve_input_normalization(&mut state);
        solve_massing_targets(&mut state);
        engine.solve_program_targets(&mut state);
        engine.solve_vertical_system(&mut state);

        let program = state.program.as_ref().unwrap();
        assert!(!program
            .support_rows
            .iter()
            .any(|row| row.space_name == "Central Water Heating Room (Indoor)"));

        let result = solve_detail_from_concept(
            state.normalized.as_ref().unwrap(),
            state.massing.as_ref().unwrap(),
            program,
            state.verticals.as_ref().unwrap(),
            &assumptions,
            concept,
        );

        let cwh_pad_site_space = result
            .selected_candidate
            .site_spaces
            .iter()
            .find(|space| space.space_name == "Central Water Heating Pad (Outdoor)")
            .expect("outdoor CWH pad should surface as a site space");
        assert_eq!(cwh_pad_site_space.category, "Site Support");
        assert!(cwh_pad_site_space.area_sf > 0.0);
        assert!(
            cwh_pad_site_space.area_sf
                <= central_water_heating_pad_outdoor_area_sf(&assumptions) + 1.0e-6
        );
        assert!(result
            .selected_candidate
            .outdoor_site_topology_graph
            .as_ref()
            .unwrap()
            .nodes
            .iter()
            .any(|node| node
                .notes
                .iter()
                .any(|note| note == "space_name=Central Water Heating Pad (Outdoor)")));
        assert!(result
            .selected_candidate
            .floors
            .iter()
            .flat_map(|floor| floor.spaces.iter())
            .all(|space| space.space_name != "Central Water Heating Pad (Outdoor)"));
    }

