/* ========================= v12 explicit formulas ========================== */

pub fn residential_area_from_gfa_formula(
    gfa_sf: f64,
    retail_area_sf: f64,
    wall_loss_ratio: f64,
    common_fixed_sf: f64,
    stair_total_sf: f64,
    corridor_term: f64,
    elevator_term: f64,
    stair_occ_term: f64,
    open_space_term: f64,
) -> f64 {
    let denominator = 1.0 + corridor_term + elevator_term + stair_occ_term + open_space_term;
    if denominator <= EPS {
        return 0.0;
    }
    (((1.0 - wall_loss_ratio) * (gfa_sf - retail_area_sf)) - (common_fixed_sf + stair_total_sf))
        / denominator
}

pub fn gfa_from_residential_area_formula(
    residential_area_sf: f64,
    retail_area_sf: f64,
    wall_loss_ratio: f64,
    common_fixed_sf: f64,
    stair_total_sf: f64,
    corridor_term: f64,
    elevator_term: f64,
    stair_occ_term: f64,
    open_space_term: f64,
) -> f64 {
    let denominator = 1.0 + corridor_term + elevator_term + stair_occ_term + open_space_term;
    retail_area_sf
        + (residential_area_sf * denominator + common_fixed_sf + stair_total_sf)
            / (1.0 - wall_loss_ratio).max(EPS)
}

pub fn frontage_length_ft(counts: [u32; 4], widths_ft: [f64; 4]) -> f64 {
    let mut out = 0.0;
    for i in 0..4 {
        out += counts[i] as f64 * widths_ft[i];
    }
    out
}

pub fn average_unit_to_corridor_distance_ft(
    counts: [u32; 4],
    widths_ft: [f64; 4],
    depths_ft: [f64; 4],
) -> f64 {
    let mut wsum = 0.0;
    let mut total = 0.0;
    for i in 0..4 {
        let c = counts[i] as f64;
        let d = 0.5 * depths_ft[i] + 0.25 * widths_ft[i];
        wsum += c * d;
        total += c;
    }
    if total <= EPS {
        0.0
    } else {
        wsum / total
    }
}

pub fn corridor_length_area_v12(
    frontage_ft: f64,
    loading_factor: f64,
    corridor_width_ft: f64,
    residential_stories: u32,
) -> (f64, f64, f64) {
    let total_length_ft = frontage_ft / loading_factor.max(1.0);
    let per_floor_ft = if residential_stories == 0 {
        0.0
    } else {
        total_length_ft / residential_stories as f64
    };
    let area_sf = total_length_ft * corridor_width_ft;
    (total_length_ft, per_floor_ft, area_sf)
}

pub fn rent_multiplier_from_market(
    avg_rent_psf: f64,
    low_x: f64,
    high_x: f64,
    low_mult: f64,
    high_mult: f64,
) -> f64 {
    if avg_rent_psf <= low_x {
        return low_mult;
    }
    if avg_rent_psf >= high_x {
        return high_mult;
    }
    low_mult + (avg_rent_psf - low_x) * (high_mult - low_mult) / (high_x - low_x).max(EPS)
}

pub fn size_multiplier_from_gba(
    gba_sf: f64,
    low_x: f64,
    high_x: f64,
    low_mult: f64,
    high_mult: f64,
) -> f64 {
    if gba_sf <= low_x {
        return low_mult;
    }
    if gba_sf >= high_x {
        return high_mult;
    }
    low_mult + (gba_sf - low_x) * (high_mult - low_mult) / (high_x - low_x).max(EPS)
}

pub fn elevator_lobby_geometry_v12(
    total_cars: u32,
    stories: u32,
    code: &JurisdictionCodePack,
    a: &AssumptionPack,
) -> (u32, f64, f64, f64) {
    let cars_per_bank = if total_cars <= 1 {
        1
    } else if stories > a.vertical.mid_rise_max_stories {
        4
    } else {
        2
    };
    let banks = ((total_cars as f64) / cars_per_bank as f64).ceil().max(1.0) as u32;
    let lobby_width_ft = if stories > a.vertical.mid_rise_max_stories {
        a.corridor_core
            .elevator_lobby_width_min_ft
            .max(8.0)
            .max(code.min_corridor_clear_width_ft)
    } else {
        a.corridor_core
            .elevator_lobby_width_min_ft
            .max(code.min_corridor_clear_width_ft)
    };
    let lobby_length_ft = ((cars_per_bank as f64) * lobby_width_ft * 0.5 + 1.0)
        .max(a.corridor_core.elevator_lobby_length_min_ft);
    let lobby_area_sf = banks as f64 * lobby_width_ft * lobby_length_ft;
    (banks, lobby_width_ft, lobby_length_ft, lobby_area_sf)
}

pub fn surface_parking_geometry_v12(
    area_remaining_sf: f64,
    required_stalls: u32,
    angle_deg: f64,
    stall_width_ft: f64,
    stall_length_ft: f64,
    aisle_width_ft: f64,
) -> (u32, f64, f64) {
    let theta = angle_deg.to_radians().max(1.0e-4);
    let sp = stall_length_ft * theta.sin();
    let s = stall_width_ft / theta.sin().max(1.0e-4);
    let s2 = stall_length_ft * theta.cos();
    let module_depth = 2.0 * sp + aisle_width_ft;
    let raw = 2.0 * (area_remaining_sf - module_depth * s2).max(0.0) / (module_depth * s).max(EPS);
    let stalls = raw.floor().max(0.0) as u32;
    let stalls = stalls.min(required_stalls);
    let area_used_sf = if stalls == 0 {
        0.0
    } else {
        module_depth * ((stalls as f64 / 2.0) * s + s2)
    };
    let efficiency_sf_per_stall = if stalls == 0 {
        0.0
    } else {
        area_used_sf / stalls as f64
    };
    (stalls, area_used_sf, efficiency_sf_per_stall)
}

pub fn amenity_knapsack_value(
    area_sf: f64,
    rent_effect_ratio: f64,
    weighted_rent_sf: f64,
    cost_sf: f64,
    years: f64,
) -> f64 {
    let revenue = area_sf * weighted_rent_sf * rent_effect_ratio * 12.0 * years.max(0.0);
    let cost = area_sf * cost_sf;
    revenue - cost
}

pub fn f_flat_v12(values: &[f64], counts: &[u32]) -> Vec<f64> {
    let mut out = Vec::<f64>::new();
    for (v, c) in values.iter().zip(counts.iter()) {
        for _ in 0..*c {
            out.push(*v);
        }
    }
    out
}

pub fn f_roomsize_v12(
    qty: &[u32],
    widths_ft: &[f64],
    depths_ft: &[f64],
    clr_front_ft: f64,
    clr_2side_ft: f64,
    clr_2equip_ft: f64,
) -> (f64, f64) {
    let total_stacks: u32 = qty.iter().sum();
    if total_stacks == 0 {
        return (0.0, 0.0);
    }

    let as_count = qty
        .iter()
        .zip(widths_ft.iter())
        .map(|(q, w)| *q as f64 * *w)
        .sum::<f64>()
        * 0.5;

    let widths = f_flat_v12(widths_ft, qty);
    let depths = f_flat_v12(depths_ft, qty);

    // Keep the v12 helper aligned with the workbook MATCH(..., 1) split rule.
    let mut split_idx = 1usize;
    for (i, w) in widths.iter().enumerate() {
        let running = widths.iter().take(i + 1).sum::<f64>();
        if running <= as_count + EPS {
            split_idx = i + 1;
        } else {
            break;
        }
    }

    let left_sum: f64 = widths.iter().take(split_idx).sum();
    let right_sum: f64 = widths.iter().skip(split_idx).sum();
    let total_equip_clear = clr_2equip_ft * split_idx.saturating_sub(1) as f64;
    let room_width_ft = left_sum.max(right_sum) + clr_2side_ft + total_equip_clear;

    let left_depth = depths
        .iter()
        .take(split_idx)
        .fold(0.0_f64, |acc, d| acc.max(*d));
    let right_depth = depths
        .iter()
        .skip(split_idx)
        .fold(0.0_f64, |acc, d| acc.max(*d));
    let room_depth_ft = left_depth + right_depth + clr_front_ft;

    (room_width_ft, room_depth_ft)
}

/* ============================ candidate solver ============================ */

fn polygon_signed_area(poly: &[Point2]) -> f64 {
    if poly.len() < 3 {
        return 0.0;
    }
    let mut s = 0.0;
    for i in 0..poly.len() {
        let a = poly[i];
        let b = poly[(i + 1) % poly.len()];
        s += a.x * b.y - b.x * a.y;
    }
    0.5 * s
}

fn point_key(p: Point2) -> (i64, i64) {
    ((p.x * 1000.0).round() as i64, (p.y * 1000.0).round() as i64)
}

fn point_from_key(key: (i64, i64)) -> Point2 {
    Point2::new(key.0 as f64 / 1000.0, key.1 as f64 / 1000.0)
}

fn compress_orthogonal_loop(poly: &[Point2]) -> Vec<Point2> {
    if poly.len() <= 3 {
        return poly.to_vec();
    }

    let mut out = poly.to_vec();
    if let (Some(first), Some(last)) = (out.first().copied(), out.last().copied()) {
        if first.distance_to(last) <= 1.0e-6 {
            out.pop();
        }
    }

    loop {
        let mut changed = false;
        if out.len() <= 3 {
            break;
        }
        let mut next = Vec::<Point2>::new();
        for idx in 0..out.len() {
            let prev = out[(idx + out.len() - 1) % out.len()];
            let curr = out[idx];
            let foll = out[(idx + 1) % out.len()];
            let collinear = ((prev.x - curr.x).abs() <= 1.0e-6
                && (curr.x - foll.x).abs() <= 1.0e-6)
                || ((prev.y - curr.y).abs() <= 1.0e-6 && (curr.y - foll.y).abs() <= 1.0e-6);
            if collinear {
                changed = true;
            } else {
                next.push(curr);
            }
        }
        if !changed {
            break;
        }
        out = next;
    }
    out
}

fn rect_intersection(a: Rect2, b: Rect2) -> Option<Rect2> {
    let min_x = a.min_x.max(b.min_x);
    let min_y = a.min_y.max(b.min_y);
    let max_x = a.max_x.min(b.max_x);
    let max_y = a.max_y.min(b.max_y);
    if max_x - min_x <= EPS || max_y - min_y <= EPS {
        None
    } else {
        Some(Rect2::new(min_x, min_y, max_x, max_y))
    }
}

fn subtract_rect(host: Rect2, cut: Rect2) -> Vec<Rect2> {
    let inter = match rect_intersection(host, cut) {
        Some(inter) => inter,
        None => return vec![host],
    };

    let mut out = Vec::<Rect2>::new();
    if inter.min_y - host.min_y > EPS {
        out.push(Rect2::new(host.min_x, host.min_y, host.max_x, inter.min_y));
    }
    if host.max_y - inter.max_y > EPS {
        out.push(Rect2::new(host.min_x, inter.max_y, host.max_x, host.max_y));
    }
    if inter.min_x - host.min_x > EPS {
        out.push(Rect2::new(
            host.min_x,
            inter.min_y,
            inter.min_x,
            inter.max_y,
        ));
    }
    if host.max_x - inter.max_x > EPS {
        out.push(Rect2::new(
            inter.max_x,
            inter.min_y,
            host.max_x,
            inter.max_y,
        ));
    }
    out.into_iter().filter(|rect| rect.area() > EPS).collect()
}

fn subtract_rects(hosts: Vec<Rect2>, cuts: &[Rect2]) -> Vec<Rect2> {
    let mut current = hosts;
    for cut in cuts {
        let mut next = Vec::<Rect2>::new();
        for host in current {
            next.extend(subtract_rect(host, *cut));
        }
        current = next;
    }
    current
}

fn build_footprint_geometry_from_rects(
    rects: &[Rect2],
) -> (Vec<Point2>, Vec<Vec<Point2>>, Vec<Vec<Point2>>) {
    if rects.is_empty() {
        return (Vec::new(), Vec::new(), Vec::new());
    }
    if rects.len() == 1 {
        let poly = rects[0].to_polygon();
        return (poly.clone(), vec![poly], Vec::new());
    }

    let mut xs = rects
        .iter()
        .flat_map(|rect| [rect.min_x, rect.max_x])
        .collect::<Vec<_>>();
    let mut ys = rects
        .iter()
        .flat_map(|rect| [rect.min_y, rect.max_y])
        .collect::<Vec<_>>();
    xs.sort_by(|a, b| a.partial_cmp(b).unwrap_or(Ordering::Equal));
    ys.sort_by(|a, b| a.partial_cmp(b).unwrap_or(Ordering::Equal));
    xs.dedup_by(|a, b| (*a - *b).abs() <= EPS);
    ys.dedup_by(|a, b| (*a - *b).abs() <= EPS);

    let mut occupied = BTreeMap::<(usize, usize), bool>::new();
    for xi in 0..xs.len().saturating_sub(1) {
        for yi in 0..ys.len().saturating_sub(1) {
            let probe = Point2::new((xs[xi] + xs[xi + 1]) * 0.5, (ys[yi] + ys[yi + 1]) * 0.5);
            if rects.iter().any(|rect| rect.contains(probe)) {
                occupied.insert((xi, yi), true);
            }
        }
    }

    let mut edge_map = BTreeMap::<(i64, i64), Vec<(i64, i64)>>::new();
    let mut edge_list = Vec::<((i64, i64), (i64, i64))>::new();
    for (&(xi, yi), _) in &occupied {
        let p00 = point_key(Point2::new(xs[xi], ys[yi]));
        let p10 = point_key(Point2::new(xs[xi + 1], ys[yi]));
        let p11 = point_key(Point2::new(xs[xi + 1], ys[yi + 1]));
        let p01 = point_key(Point2::new(xs[xi], ys[yi + 1]));
        let neighbors = [
            (yi == 0 || !occupied.contains_key(&(xi, yi - 1)), (p00, p10)),
            (
                xi + 1 >= xs.len() - 1 || !occupied.contains_key(&(xi + 1, yi)),
                (p10, p11),
            ),
            (
                yi + 1 >= ys.len() - 1 || !occupied.contains_key(&(xi, yi + 1)),
                (p11, p01),
            ),
            (xi == 0 || !occupied.contains_key(&(xi - 1, yi)), (p01, p00)),
        ];
        for (emit, edge) in neighbors {
            if emit {
                edge_map.entry(edge.0).or_default().push(edge.1);
                edge_list.push(edge);
            }
        }
    }

    let mut unused = edge_list;
    let mut loops = Vec::<Vec<Point2>>::new();
    while let Some((start, end)) = unused.first().copied() {
        unused.remove(0);
        let mut loop_keys = vec![start, end];
        let mut cursor = end;
        while cursor != start {
            let next_idx = unused.iter().position(|(from, _)| *from == cursor);
            let (_, next_to) = match next_idx {
                Some(idx) => unused.remove(idx),
                None => break,
            };
            loop_keys.push(next_to);
            cursor = next_to;
        }
        if loop_keys.len() >= 4 && loop_keys.first() == loop_keys.last() {
            let mut poly = loop_keys
                .iter()
                .take(loop_keys.len() - 1)
                .map(|key| point_from_key(*key))
                .collect::<Vec<_>>();
            poly = compress_orthogonal_loop(&poly);
            if poly.len() >= 3 {
                loops.push(poly);
            }
        }
    }

    let mut components = loops
        .iter()
        .filter(|poly| polygon_signed_area(poly) > 0.0)
        .cloned()
        .collect::<Vec<_>>();
    let mut voids = loops
        .iter()
        .filter(|poly| polygon_signed_area(poly) < 0.0)
        .cloned()
        .collect::<Vec<_>>();
    components.sort_by(|a, b| {
        polygon_area_sf(b)
            .partial_cmp(&polygon_area_sf(a))
            .unwrap_or(Ordering::Equal)
    });
    voids.sort_by(|a, b| {
        polygon_area_sf(b)
            .partial_cmp(&polygon_area_sf(a))
            .unwrap_or(Ordering::Equal)
    });
    let footprint_polygon = components
        .first()
        .cloned()
        .unwrap_or_else(|| rects[0].to_polygon());
    (footprint_polygon, components, voids)
}

fn footprint_area_from_geometry(components: &[Vec<Point2>], voids: &[Vec<Point2>]) -> f64 {
    components
        .iter()
        .map(|poly| polygon_area_sf(poly))
        .sum::<f64>()
        - voids.iter().map(|poly| polygon_area_sf(poly)).sum::<f64>()
}

fn floor_zone_kind_slug(kind: FloorZoneKind) -> &'static str {
    match kind {
        FloorZoneKind::Dwelling => "dwelling",
        FloorZoneKind::Circulation => "circulation",
        FloorZoneKind::CoreService => "core_service",
        FloorZoneKind::Parking => "parking",
        FloorZoneKind::Support => "support",
        FloorZoneKind::OutdoorCapable => "outdoor_capable",
        FloorZoneKind::RoofAmenity => "roof_amenity",
        FloorZoneKind::Site => "site",
    }
}

fn floor_zone_labels(zones: &[FloorZone]) -> Vec<String> {
    zones
        .iter()
        .map(|zone| {
            let block = zone
                .concept_block_id
                .as_ref()
                .map(|id| format!(" block={}", id))
                .unwrap_or_default();
            format!(
                "{}:{} area={:.1}{}",
                zone.zone_id,
                floor_zone_kind_slug(zone.kind),
                zone.area_sf,
                block
            )
        })
        .collect()
}

pub fn build_footprint_polygon_from_rects(rects: &[Rect2]) -> Vec<Point2> {
    if rects.is_empty() {
        return Vec::new();
    }
    build_footprint_geometry_from_rects(rects).0
}

fn partition_rect_weighted(rect: Rect2, weights: &[f64], horizontal: bool) -> Vec<Rect2> {
    if weights.is_empty() || rect.area() <= EPS {
        return Vec::new();
    }
    let total = weights
        .iter()
        .copied()
        .map(|x| x.max(0.0))
        .sum::<f64>()
        .max(1.0);
    let mut out = Vec::<Rect2>::new();
    let mut cursor = if horizontal { rect.min_x } else { rect.min_y };
    let end = if horizontal { rect.max_x } else { rect.max_y };
    for (idx, weight) in weights.iter().enumerate() {
        let span = if idx + 1 == weights.len() {
            end - cursor
        } else if horizontal {
            rect.width() * weight.max(0.0) / total
        } else {
            rect.height() * weight.max(0.0) / total
        };
        let next = (cursor + span).min(end);
        out.push(if horizontal {
            Rect2::new(cursor, rect.min_y, next, rect.max_y)
        } else {
            Rect2::new(rect.min_x, cursor, rect.max_x, next)
        });
        cursor = next;
    }
    out
}

fn family_shape_rects(
    input: &NormalizedInput,
    family: &FloorFamily,
    a: &AssumptionPack,
) -> Vec<Rect2> {
    let target_area = family.area_budget_sf.max(1.0);
    seed_shape_rects(input.building_shape, target_area, &input.site_polygon, a)
}

fn concept_bindings_for_family(
    concept: &ConceptOption,
    family_id: &str,
) -> Vec<ConceptFamilyBlockBinding> {
    let mut out = concept
        .family_block_bindings
        .iter()
        .filter(|binding| {
            binding.family_id == family_id && binding.active && binding.area_sf > EPS
        })
        .cloned()
        .collect::<Vec<_>>();
    out.sort_by(|a, b| a.block_id.cmp(&b.block_id));
    out
}

fn make_floor_zone(
    zone_id: String,
    level_index: u32,
    family_id: String,
    kind: FloorZoneKind,
    rect: Rect2,
    concept_block_id: Option<String>,
    notes: Vec<String>,
) -> FloorZone {
    FloorZone {
        zone_id,
        level_index,
        family_id,
        kind,
        polygon: rect.to_polygon(),
        rect,
        area_sf: rect.area(),
        concept_block_id,
        notes,
    }
}

fn clamp_rect_to_host(rect: Rect2, host: Rect2) -> Rect2 {
    if host.area() <= EPS {
        return rect;
    }
    let width = rect.width().min(host.width()).max(4.0);
    let height = rect.height().min(host.height()).max(4.0);
    let cx = rect
        .center()
        .x
        .clamp(host.min_x + width * 0.5, host.max_x - width * 0.5);
    let cy = rect
        .center()
        .y
        .clamp(host.min_y + height * 0.5, host.max_y - height * 0.5);
    Rect2::new(
        cx - width * 0.5,
        cy - height * 0.5,
        cx + width * 0.5,
        cy + height * 0.5,
    )
}

fn raw_vertical_rect(group: &VerticalGroup) -> Rect2 {
    Rect2::new(
        group.anchor.x - group.width_ft * 0.5,
        group.anchor.y - group.depth_ft * 0.5,
        group.anchor.x + group.width_ft * 0.5,
        group.anchor.y + group.depth_ft * 0.5,
    )
}

fn best_host_binding_for_rect(
    rect: Rect2,
    bindings: &[ConceptFamilyBlockBinding],
) -> Option<ConceptFamilyBlockBinding> {
    bindings.iter().cloned().max_by(|a, b| {
        let inter_a = rect_intersection_area(rect, a.rect_seed);
        let inter_b = rect_intersection_area(rect, b.rect_seed);
        inter_a
            .partial_cmp(&inter_b)
            .unwrap_or(Ordering::Equal)
            .then_with(|| {
                rect.center()
                    .distance_to(a.rect_seed.center())
                    .partial_cmp(&rect.center().distance_to(b.rect_seed.center()))
                    .unwrap_or(Ordering::Equal)
                    .reverse()
            })
            .then_with(|| a.block_id.cmp(&b.block_id).reverse())
    })
}

fn vertical_space_label(group_name: &str) -> (String, String) {
    let hay = group_name.to_lowercase();
    if hay.contains("main_core") {
        ("Core".to_string(), "Main Core".to_string())
    } else if hay.contains("freight_elevator") {
        (
            "Vertical Transport".to_string(),
            group_name.replace('_', " "),
        )
    } else if hay.contains("passenger_elevator") {
        (
            "Vertical Transport".to_string(),
            group_name.replace('_', " "),
        )
    } else if hay.contains("stair") {
        ("Life Safety".to_string(), group_name.replace('_', " "))
    } else {
        ("Service".to_string(), group_name.replace('_', " "))
    }
}

fn place_vertical_spaces(
    level_index: u32,
    family_id: &str,
    bindings: &[ConceptFamilyBlockBinding],
    verticals: &VerticalState,
) -> Vec<SpacePlacement> {
    let mut out = Vec::<SpacePlacement>::new();
    for group in verticals.groups.iter().filter(|group| {
        level_index >= group.served_floor_min && level_index <= group.served_floor_max
    }) {
        let raw_rect = raw_vertical_rect(group);
        let host_binding = match best_host_binding_for_rect(raw_rect, bindings) {
            Some(binding) => binding,
            None => continue,
        };
        let placed_rect = clamp_rect_to_host(raw_rect, host_binding.rect_seed);
        let (category, label) = vertical_space_label(&group.name);
        let mut space = make_space_placement(
            category,
            format!("{} @ floor {}", label, level_index),
            1.0,
            placed_rect,
            placed_rect.to_polygon(),
            placed_rect.area(),
        );
        space.concept_block_id = Some(host_binding.block_id.clone());
        space.parent_space_id = None;
        out.push(space);
    }
    out
}

fn corridor_rect_for_block(
    rect: Rect2,
    corridor_type: CorridorType,
    corridor_width_ft: f64,
) -> Option<Rect2> {
    if rect.area() <= EPS {
        return None;
    }
    let width = corridor_width_ft
        .max(6.0)
        .min(rect.width().min(rect.height()) * 0.55);
    let long_horizontal = rect.width() >= rect.height();
    Some(if long_horizontal {
        match corridor_type {
            CorridorType::Perimeter => Rect2::new(
                rect.min_x,
                rect.min_y,
                rect.max_x,
                (rect.min_y + width).min(rect.max_y),
            ),
            CorridorType::SingleLoaded => {
                Rect2::new(rect.min_x, rect.max_y - width, rect.max_x, rect.max_y)
            }
            _ => {
                let cy = (rect.min_y + rect.max_y) * 0.5;
                Rect2::new(rect.min_x, cy - width * 0.5, rect.max_x, cy + width * 0.5)
            }
        }
    } else {
        match corridor_type {
            CorridorType::Perimeter => Rect2::new(
                rect.min_x,
                rect.min_y,
                (rect.min_x + width).min(rect.max_x),
                rect.max_y,
            ),
            CorridorType::SingleLoaded => {
                Rect2::new(rect.max_x - width, rect.min_y, rect.max_x, rect.max_y)
            }
            _ => {
                let cx = (rect.min_x + rect.max_x) * 0.5;
                Rect2::new(cx - width * 0.5, rect.min_y, cx + width * 0.5, rect.max_y)
            }
        }
    })
}

fn support_band_rect_for_block(rect: Rect2) -> Rect2 {
    if rect.width() >= rect.height() {
        Rect2::new(
            rect.min_x,
            rect.min_y,
            rect.max_x,
            (rect.min_y + 18.0).min(rect.max_y),
        )
    } else {
        Rect2::new(
            rect.min_x,
            rect.min_y,
            (rect.min_x + 18.0).min(rect.max_x),
            rect.max_y,
        )
    }
}

fn build_floor_zones(
    input: &NormalizedInput,
    family: &FloorFamily,
    level_index: u32,
    candidate: &CandidateCase,
    bindings: &[ConceptFamilyBlockBinding],
    verticals: &VerticalState,
    vertical_spaces: &[SpacePlacement],
) -> Vec<FloorZone> {
    let mut zones = Vec::<FloorZone>::new();
    let top_podium_level = family
        .level_indices
        .iter()
        .max()
        .copied()
        .unwrap_or(level_index);
    let top_family_level = family
        .level_indices
        .iter()
        .max()
        .copied()
        .unwrap_or(level_index);
    let is_arrival_level = level_index == input.levels.below_grade_count;
    let is_top_podium = family.family_id == "podium" && level_index == top_podium_level;
    let is_first_residential_above_podium = family.family_id == "typical_residential"
        && input.levels.podium_levels > 0
        && level_index == input.levels.below_grade_count + input.levels.podium_levels;

    for binding in bindings {
        let keepouts = vertical_spaces
            .iter()
            .filter(|space| space.concept_block_id.as_deref() == Some(binding.block_id.as_str()))
            .map(|space| space.rect)
            .collect::<Vec<_>>();

        for (idx, keepout) in keepouts.iter().enumerate() {
            zones.push(make_floor_zone(
                format!("L{:02}_{}_core_{:02}", level_index, binding.block_id, idx),
                level_index,
                family.family_id.clone(),
                FloorZoneKind::CoreService,
                *keepout,
                Some(binding.block_id.clone()),
                vec!["reserved_from_vertical_keepout".to_string()],
            ));
        }

        let residuals = subtract_rects(vec![binding.rect_seed], &keepouts);
        if family.family_id == "typical_residential" {
            if let Some(corridor_rect) = corridor_rect_for_block(
                binding.rect_seed,
                candidate.corridor_type,
                verticals.corridor_width_ft,
            ) {
                for (idx, rect) in subtract_rects(vec![corridor_rect], &keepouts)
                    .into_iter()
                    .enumerate()
                {
                    zones.push(make_floor_zone(
                        format!(
                            "L{:02}_{}_circulation_{:02}",
                            level_index, binding.block_id, idx
                        ),
                        level_index,
                        family.family_id.clone(),
                        FloorZoneKind::Circulation,
                        rect,
                        Some(binding.block_id.clone()),
                        vec![format!("corridor={:?}", candidate.corridor_type)],
                    ));
                }
                for (idx, rect) in subtract_rects(residuals.clone(), &[corridor_rect])
                    .into_iter()
                    .enumerate()
                {
                    if rect.area() > 120.0 {
                        zones.push(make_floor_zone(
                            format!(
                                "L{:02}_{}_dwelling_{:02}",
                                level_index, binding.block_id, idx
                            ),
                            level_index,
                            family.family_id.clone(),
                            FloorZoneKind::Dwelling,
                            rect,
                            Some(binding.block_id.clone()),
                            vec!["residential_allocation_band".to_string()],
                        ));
                    }
                }
            }
            if is_arrival_level && input.levels.podium_levels == 0 {
                let support_band = support_band_rect_for_block(binding.rect_seed);
                for (idx, rect) in subtract_rects(vec![support_band], &keepouts)
                    .into_iter()
                    .enumerate()
                {
                    if rect.area() > 90.0 {
                        zones.push(make_floor_zone(
                            format!(
                                "L{:02}_{}_arrival_support_{:02}",
                                level_index, binding.block_id, idx
                            ),
                            level_index,
                            family.family_id.clone(),
                            FloorZoneKind::Support,
                            rect,
                            Some(binding.block_id.clone()),
                            vec![
                                "grade_level_support_band".to_string(),
                                "support_role=public".to_string(),
                            ],
                        ));
                    }
                }
            }
            if is_first_residential_above_podium {
                let transfer_band = support_band_rect_for_block(binding.rect_seed);
                for (idx, rect) in subtract_rects(vec![transfer_band], &keepouts)
                    .into_iter()
                    .enumerate()
                {
                    if rect.area() > 80.0 {
                        zones.push(make_floor_zone(
                            format!(
                                "L{:02}_{}_transfer_support_{:02}",
                                level_index, binding.block_id, idx
                            ),
                            level_index,
                            family.family_id.clone(),
                            FloorZoneKind::Support,
                            rect,
                            Some(binding.block_id.clone()),
                            vec![
                                "typical_floor_transfer_override".to_string(),
                                "support_role=semi_public".to_string(),
                            ],
                        ));
                    }
                }
            }
            if level_index == top_family_level && !matches!(candidate.shape_case, ShapeCase::Linear)
            {
                let terrace_rect = Rect2::new(
                    (binding.rect_seed.max_x - 24.0).max(binding.rect_seed.min_x),
                    (binding.rect_seed.max_y - 18.0).max(binding.rect_seed.min_y),
                    binding.rect_seed.max_x,
                    binding.rect_seed.max_y,
                );
                for (idx, rect) in subtract_rects(vec![terrace_rect], &keepouts)
                    .into_iter()
                    .enumerate()
                {
                    if rect.area() > 100.0 {
                        zones.push(make_floor_zone(
                            format!(
                                "L{:02}_{}_terrace_{:02}",
                                level_index, binding.block_id, idx
                            ),
                            level_index,
                            family.family_id.clone(),
                            FloorZoneKind::OutdoorCapable,
                            rect,
                            Some(binding.block_id.clone()),
                            vec!["typical_floor_terrace_override".to_string()],
                        ));
                    }
                }
            }
        } else {
            let public_band = support_band_rect_for_block(binding.rect_seed);
            let service_band = if binding.rect_seed.width() >= binding.rect_seed.height() {
                Rect2::new(
                    binding.rect_seed.min_x,
                    (binding.rect_seed.max_y - 18.0).max(binding.rect_seed.min_y),
                    binding.rect_seed.max_x,
                    binding.rect_seed.max_y,
                )
            } else {
                Rect2::new(
                    (binding.rect_seed.max_x - 18.0).max(binding.rect_seed.min_x),
                    binding.rect_seed.min_y,
                    binding.rect_seed.max_x,
                    binding.rect_seed.max_y,
                )
            };
            for (idx, rect) in subtract_rects(vec![public_band], &keepouts)
                .into_iter()
                .enumerate()
            {
                if rect.area() > 90.0 {
                    zones.push(make_floor_zone(
                        format!(
                            "L{:02}_{}_support_public_{:02}",
                            level_index, binding.block_id, idx
                        ),
                        level_index,
                        family.family_id.clone(),
                        FloorZoneKind::Support,
                        rect,
                        Some(binding.block_id.clone()),
                        vec![
                            format!("family={}", family.family_id),
                            "support_role=public".to_string(),
                        ],
                    ));
                }
            }
            for (idx, rect) in subtract_rects(vec![service_band], &keepouts)
                .into_iter()
                .enumerate()
            {
                if rect.area() > 90.0 {
                    zones.push(make_floor_zone(
                        format!(
                            "L{:02}_{}_support_service_{:02}",
                            level_index, binding.block_id, idx
                        ),
                        level_index,
                        family.family_id.clone(),
                        FloorZoneKind::Support,
                        rect,
                        Some(binding.block_id.clone()),
                        vec![
                            format!("family={}", family.family_id),
                            "support_role=service".to_string(),
                        ],
                    ));
                }
            }
            let protected_support = vec![public_band, service_band];
            for (idx, rect) in subtract_rects(residuals.clone(), &protected_support)
                .into_iter()
                .enumerate()
            {
                if rect.area() <= 120.0 {
                    continue;
                }
                let kind = if family.family_id == "below_grade" || family.family_id == "podium" {
                    FloorZoneKind::Parking
                } else {
                    FloorZoneKind::Support
                };
                zones.push(make_floor_zone(
                    format!(
                        "L{:02}_{}_{}_{}",
                        level_index,
                        binding.block_id,
                        floor_zone_kind_slug(kind),
                        idx
                    ),
                    level_index,
                    family.family_id.clone(),
                    kind,
                    rect,
                    Some(binding.block_id.clone()),
                    vec![
                        "non_dwelling_residual".to_string(),
                        if matches!(kind, FloorZoneKind::Parking) {
                            "support_role=semi_public".to_string()
                        } else {
                            "support_role=general".to_string()
                        },
                    ],
                ));
            }
            if let Some(corridor_rect) = corridor_rect_for_block(
                binding.rect_seed,
                candidate.corridor_type,
                verticals.corridor_width_ft,
            ) {
                for (idx, rect) in subtract_rects(vec![corridor_rect], &keepouts)
                    .into_iter()
                    .enumerate()
                {
                    if rect.area() > 80.0 {
                        zones.push(make_floor_zone(
                            format!(
                                "L{:02}_{}_circulation_{:02}",
                                level_index, binding.block_id, idx
                            ),
                            level_index,
                            family.family_id.clone(),
                            FloorZoneKind::Circulation,
                            rect,
                            Some(binding.block_id.clone()),
                            vec!["service_or_parking_access".to_string()],
                        ));
                    }
                }
            }
            if is_top_podium {
                let deck_rect = Rect2::new(
                    (binding.rect_seed.max_x - 26.0).max(binding.rect_seed.min_x),
                    (binding.rect_seed.max_y - 20.0).max(binding.rect_seed.min_y),
                    binding.rect_seed.max_x,
                    binding.rect_seed.max_y,
                );
                if deck_rect.area() > 120.0 {
                    zones.push(make_floor_zone(
                        format!("L{:02}_{}_outdoor_capable", level_index, binding.block_id),
                        level_index,
                        family.family_id.clone(),
                        FloorZoneKind::OutdoorCapable,
                        deck_rect,
                        Some(binding.block_id.clone()),
                        vec!["top_podium_outdoor_capable".to_string()],
                    ));
                }
            }
        }
    }

    zones.sort_by(|a, b| a.zone_id.cmp(&b.zone_id));
    zones
}

fn pack_units_in_zone(
    zone: &FloorZone,
    input: &NormalizedInput,
    a: &AssumptionPack,
    available_seq: &mut Vec<UnitType>,
    floor_index: u32,
) -> Vec<SpacePlacement> {
    let mut out = Vec::<SpacePlacement>::new();
    if available_seq.is_empty() || zone.rect.area() <= EPS {
        return out;
    }

    let wing = zone.rect;
    let long_horizontal = wing.width() >= wing.height();
    let mut cursor = if long_horizontal {
        wing.min_x
    } else {
        wing.min_y
    };
    let limit = if long_horizontal {
        wing.max_x
    } else {
        wing.max_y
    };
    while !available_seq.is_empty() && cursor < limit - 4.0 {
        let unit_type = available_seq[0];
        let area = resolved_unit_area_sf(input, unit_type, a);
        let ratio = resolved_depth_over_width_ratio(unit_type, input.optimization.objective);
        let (u_w, u_d) = unit_width_depth_ft(area, ratio, input, a);
        let slot_len = u_w;
        let band_depth = u_d.min(if long_horizontal {
            wing.height()
        } else {
            wing.width()
        });
        if cursor + slot_len > limit + EPS {
            break;
        }
        let rect = if long_horizontal {
            Rect2::new(
                cursor,
                wing.min_y,
                cursor + slot_len,
                wing.min_y + band_depth,
            )
        } else {
            Rect2::new(
                wing.min_x,
                cursor,
                wing.min_x + band_depth,
                cursor + slot_len,
            )
        };
        let mut space = make_space_placement(
            "Dwelling Units",
            format!("{} @ floor {}", unit_type.as_key(), floor_index),
            1.0,
            rect,
            rect.to_polygon(),
            rect.area(),
        );
        space.host_zone_id = Some(zone.zone_id.clone());
        space.concept_block_id = zone.concept_block_id.clone();
        out.push(space);
        available_seq.remove(0);
        cursor += slot_len;
    }
    out
}

#[derive(Debug, Clone, Copy)]
enum UnitEntrySide {
    Left,
    Right,
    Bottom,
    Top,
}

fn unit_entry_side_for_space(
    unit: &SpacePlacement,
    floor_spaces: &[SpacePlacement],
) -> UnitEntrySide {
    let unit_center = unit.rect.center();
    let corridor = floor_spaces
        .iter()
        .filter(|space| space.category.to_lowercase().contains("circulation"))
        .min_by(|a, b| {
            unit_center
                .distance_to(a.rect.center())
                .partial_cmp(&unit_center.distance_to(b.rect.center()))
                .unwrap_or(Ordering::Equal)
        });
    if let Some(corridor) = corridor {
        let delta = corridor.rect.center().sub(unit_center);
        if delta.x.abs() > delta.y.abs() {
            if delta.x < 0.0 {
                UnitEntrySide::Left
            } else {
                UnitEntrySide::Right
            }
        } else if delta.y < 0.0 {
            UnitEntrySide::Bottom
        } else {
            UnitEntrySide::Top
        }
    } else {
        UnitEntrySide::Bottom
    }
}

fn band_on_side(rect: Rect2, side: UnitEntrySide, depth: f64) -> Rect2 {
    match side {
        UnitEntrySide::Left => Rect2::new(
            rect.min_x,
            rect.min_y,
            (rect.min_x + depth).min(rect.max_x),
            rect.max_y,
        ),
        UnitEntrySide::Right => Rect2::new(
            (rect.max_x - depth).max(rect.min_x),
            rect.min_y,
            rect.max_x,
            rect.max_y,
        ),
        UnitEntrySide::Bottom => Rect2::new(
            rect.min_x,
            rect.min_y,
            rect.max_x,
            (rect.min_y + depth).min(rect.max_y),
        ),
        UnitEntrySide::Top => Rect2::new(
            rect.min_x,
            (rect.max_y - depth).max(rect.min_y),
            rect.max_x,
            rect.max_y,
        ),
    }
}

fn room_space_from_rect(
    unit: &SpacePlacement,
    level_index: u32,
    room_kind: &str,
    semantic_kind: &str,
    rect: Rect2,
) -> SpacePlacement {
    let mut room = make_space_placement(
        "Room",
        format!("{} @ floor {}", room_kind, level_index),
        1.0,
        rect,
        rect.to_polygon(),
        rect.area(),
    );
    room.parent_space_id = Some(unit.space_id.clone());
    room.host_zone_id = unit.host_zone_id.clone();
    room.concept_block_id = unit.concept_block_id.clone();
    room
}

fn subdivide_unit_into_rooms(
    unit: &SpacePlacement,
    floor_spaces: &[SpacePlacement],
    level_index: u32,
) -> Vec<SpacePlacement> {
    let unit_type = infer_unit_type(unit);
    let entry_side = unit_entry_side_for_space(unit, floor_spaces);
    let short_side = unit.rect.width().min(unit.rect.height());
    let foyer_depth = short_side.min(7.0).max(5.0);
    let bath_depth = short_side.min(7.5).max(5.5);
    let foyer_rect = band_on_side(unit.rect, entry_side, foyer_depth);
    let mut remainder = subtract_rects(vec![unit.rect], &[foyer_rect]);
    let host_rect = remainder
        .iter()
        .max_by(|a, b| a.area().partial_cmp(&b.area()).unwrap_or(Ordering::Equal))
        .copied()
        .unwrap_or(unit.rect);
    let bath_rect = band_on_side(host_rect, entry_side, bath_depth.min(short_side * 0.42));
    remainder = subtract_rects(vec![host_rect], &[bath_rect]);
    let main_rect = remainder
        .iter()
        .max_by(|a, b| a.area().partial_cmp(&b.area()).unwrap_or(Ordering::Equal))
        .copied()
        .unwrap_or(host_rect);

    let split_horizontal = main_rect.width() >= main_rect.height();
    let room_slices = match unit_type.as_str() {
        "studio" => partition_rect_weighted(main_rect, &[0.35, 0.65], split_horizontal),
        "one_bedroom" => partition_rect_weighted(main_rect, &[0.46, 0.54], split_horizontal),
        "two_bedroom" => partition_rect_weighted(main_rect, &[0.30, 0.35, 0.35], split_horizontal),
        _ => partition_rect_weighted(main_rect, &[0.25, 0.25, 0.25, 0.25], split_horizontal),
    };

    let mut rooms = Vec::<SpacePlacement>::new();
    rooms.push(room_space_from_rect(
        unit,
        level_index,
        "foyer",
        "foyer",
        foyer_rect,
    ));
    rooms.push(room_space_from_rect(
        unit,
        level_index,
        "bath",
        "bath",
        bath_rect,
    ));

    match unit_type.as_str() {
        "studio" => {
            if let Some(kitchen_rect) = room_slices.get(0).copied() {
                rooms.push(room_space_from_rect(
                    unit,
                    level_index,
                    "kitchen",
                    "kitchen",
                    kitchen_rect,
                ));
            }
            if let Some(living_rect) = room_slices.get(1).copied() {
                rooms.push(room_space_from_rect(
                    unit,
                    level_index,
                    "living_sleep",
                    "living",
                    living_rect,
                ));
            }
        }
        "one_bedroom" => {
            if let Some(kitchen_rect) = room_slices.get(0).copied() {
                rooms.push(room_space_from_rect(
                    unit,
                    level_index,
                    "kitchen_dining",
                    "kitchen",
                    kitchen_rect,
                ));
            }
            if let Some(living_rect) = room_slices.get(1).copied() {
                let split = partition_rect_weighted(living_rect, &[0.52, 0.48], !split_horizontal);
                if let Some(a) = split.get(0).copied() {
                    rooms.push(room_space_from_rect(
                        unit,
                        level_index,
                        "living",
                        "living",
                        a,
                    ));
                }
                if let Some(b) = split.get(1).copied() {
                    rooms.push(room_space_from_rect(
                        unit,
                        level_index,
                        "bedroom_1",
                        "bedroom",
                        b,
                    ));
                }
            }
        }
        "two_bedroom" => {
            let names = [
                ("living", "living"),
                ("bedroom_1", "bedroom"),
                ("bedroom_2", "bedroom"),
            ];
            for (idx, rect) in room_slices.iter().copied().enumerate().take(names.len()) {
                rooms.push(room_space_from_rect(
                    unit,
                    level_index,
                    names[idx].0,
                    names[idx].1,
                    rect,
                ));
            }
            if let Some(first_room) = room_slices.first().copied() {
                let kitchen_strip =
                    band_on_side(first_room, entry_side, short_side.min(6.0).max(4.5));
                rooms.push(room_space_from_rect(
                    unit,
                    level_index,
                    "kitchen",
                    "kitchen",
                    kitchen_strip,
                ));
            }
        }
        _ => {
            let names = [
                ("living", "living"),
                ("bedroom_1", "bedroom"),
                ("bedroom_2", "bedroom"),
                ("bedroom_3", "bedroom"),
            ];
            for (idx, rect) in room_slices.iter().copied().enumerate().take(names.len()) {
                rooms.push(room_space_from_rect(
                    unit,
                    level_index,
                    names[idx].0,
                    names[idx].1,
                    rect,
                ));
            }
            if let Some(first_room) = room_slices.first().copied() {
                let kitchen_strip =
                    band_on_side(first_room, entry_side, short_side.min(6.0).max(4.5));
                rooms.push(room_space_from_rect(
                    unit,
                    level_index,
                    "kitchen",
                    "kitchen",
                    kitchen_strip,
                ));
            }
        }
    }

    for idx in 0..rooms.len() {
        rooms[idx].adjacency_ids = rooms
            .iter()
            .enumerate()
            .filter(|(peer_idx, peer)| {
                *peer_idx != idx
                    && canonical_graph_touch_or_overlap(rooms[idx].rect, peer.rect, 1.0)
            })
            .map(|(_, peer)| peer.space_name.clone())
            .collect();
    }
    rooms
}

fn clone_spaces_for_level(spaces: &[SpacePlacement], level_index: u32) -> Vec<SpacePlacement> {
    spaces
        .iter()
        .enumerate()
        .map(|(idx, space)| {
            let mut cloned = space.clone();
            cloned.space_name = format!("{} @ floor {}", cloned.space_name, level_index);
            cloned.space_id = format!("L{:02}_seed_{:03}", level_index, idx);
            cloned
        })
        .collect::<Vec<_>>()
}

fn remap_level_token(value: &str, from_level_index: u32, to_level_index: u32) -> String {
    value.replace(
        format!("L{:02}", from_level_index).as_str(),
        format!("L{:02}", to_level_index).as_str(),
    )
}

fn clone_floor_artifacts_for_level(
    floor: &FloorOutput,
    level_index: u32,
) -> (Vec<SpacePlacement>, Vec<SpacePlacement>) {
    let mut id_map = BTreeMap::<String, String>::new();
    let mut spaces = floor
        .spaces
        .iter()
        .enumerate()
        .map(|(idx, space)| {
            let mut cloned = space.clone();
            let new_id = format!("L{:02}_CLONE_SP{:03}", level_index, idx);
            id_map.insert(space.space_id.clone(), new_id.clone());
            cloned.space_id = new_id;
            cloned.space_name = format!("{} @ floor {}", space.space_name, level_index);
            cloned.host_zone_id = cloned
                .host_zone_id
                .as_ref()
                .map(|value| remap_level_token(value, floor.level_index, level_index));
            cloned.zone_owner_id = cloned
                .zone_owner_id
                .as_ref()
                .map(|value| remap_level_token(value, floor.level_index, level_index));
            cloned.adjacency_ids = space
                .adjacency_ids
                .iter()
                .map(|value| {
                    id_map
                        .get(value)
                        .cloned()
                        .unwrap_or_else(|| remap_level_token(value, floor.level_index, level_index))
                })
                .collect();
            cloned
        })
        .collect::<Vec<_>>();
    for space in &mut spaces {
        if let Some(parent_space_id) = &space.parent_space_id {
            space.parent_space_id = id_map.get(parent_space_id).cloned();
        }
        if let Some(stack_id) = &space.stack_id {
            space.stack_id = Some(remap_level_token(stack_id, floor.level_index, level_index));
        }
        for relation in &mut space.ingress_relations {
            relation.target_id = id_map.get(&relation.target_id).cloned().unwrap_or_else(|| {
                remap_level_token(&relation.target_id, floor.level_index, level_index)
            });
        }
        for relation in &mut space.egress_relations {
            relation.target_id = id_map.get(&relation.target_id).cloned().unwrap_or_else(|| {
                remap_level_token(&relation.target_id, floor.level_index, level_index)
            });
        }
        for dependency in &mut space.service_dependencies {
            dependency.target_id =
                id_map
                    .get(&dependency.target_id)
                    .cloned()
                    .unwrap_or_else(|| {
                        remap_level_token(&dependency.target_id, floor.level_index, level_index)
                    });
        }
    }

    let rooms = floor
        .room_spaces
        .iter()
        .enumerate()
        .map(|(idx, room)| {
            let mut cloned = room.clone();
            cloned.space_id = format!("L{:02}_CLONE_RM{:03}", level_index, idx);
            cloned.space_name = format!("{} @ floor {}", room.space_name, level_index);
            cloned.parent_space_id = room
                .parent_space_id
                .as_ref()
                .and_then(|parent_space_id| id_map.get(parent_space_id).cloned());
            cloned.host_zone_id = cloned
                .host_zone_id
                .as_ref()
                .map(|value| remap_level_token(value, floor.level_index, level_index));
            cloned
        })
        .collect::<Vec<_>>();
    (spaces, rooms)
}

fn support_row_name_matches(space_name: &str, needle: &str) -> bool {
    let hay = space_name.to_lowercase();
    let needle = needle.to_lowercase();
    if hay.contains(&needle) {
        return true;
    }
    match needle.as_str() {
        "general storage" | "storage room - general / maintenance" => {
            hay.contains("general storage") || hay.contains("storage room - general / maintenance")
        }
        "janitor closet" | "storage room - janitor's closet" => {
            hay.contains("janitor closet") || hay.contains("storage room - janitor's closet")
        }
        "parcel storage" | "storage room - parcels" => {
            hay.contains("parcel storage") || hay.contains("storage room - parcels")
        }
        "cold storage delivery" | "storage room - cold storage delivery room" => {
            hay.contains("cold storage delivery")
                || hay.contains("storage room - cold storage delivery room")
        }
        "manager office" | "manager's office" => {
            hay.contains("manager office") || hay.contains("manager's office")
        }
        "cctv room" | "cctv / it / security equipment rooms" => {
            hay.contains("cctv room") || hay.contains("cctv / it / security equipment rooms")
        }
        _ => false,
    }
}

fn support_row_by_name<'a>(program: &'a ProgramState, needle: &str) -> Option<&'a SpaceDemandRow> {
    program
        .support_rows
        .iter()
        .find(|row| support_row_name_matches(&row.space_name, needle))
}

fn should_place_parking_on_level(
    input: &NormalizedInput,
    family_id: &str,
    level_index: u32,
) -> bool {
    match input.constraints.parking_mode {
        ParkingMode::None | ParkingMode::Surface => false,
        ParkingMode::Underground => family_id == "below_grade",
        ParkingMode::Podium => family_id == "podium",
        ParkingMode::Structured => family_id == "podium" || family_id == "below_grade",
        ParkingMode::Mixed | ParkingMode::Auto => {
            family_id == "below_grade" || family_id == "podium" || level_index == 0
        }
    }
}

fn distributed_parking_stalls_for_level(
    input: &NormalizedInput,
    program: &ProgramState,
    families: &[FloorFamily],
    family_id: &str,
    level_index: u32,
) -> usize {
    let total = support_row_by_name(program, "parking")
        .map(|row| row.qty.round().max(0.0) as usize)
        .unwrap_or(0);
    if total == 0 || !should_place_parking_on_level(input, family_id, level_index) {
        return 0;
    }
    let weighted_levels = families
        .iter()
        .flat_map(|family| {
            family.level_indices.iter().map(move |level| {
                let base_weight = if family.family_id == "below_grade" {
                    1.25
                } else if family.family_id == "podium" {
                    0.95
                } else {
                    0.55
                };
                let grade_bias = if *level == input.levels.below_grade_count {
                    0.90
                } else {
                    1.0
                };
                let area_bias = (family.area_budget_sf / 6_000.0).clamp(0.45, 1.65);
                (
                    family.family_id.as_str(),
                    *level,
                    base_weight * grade_bias * area_bias,
                )
            })
        })
        .filter(|(family_id, level, _)| should_place_parking_on_level(input, family_id, *level))
        .collect::<Vec<_>>();
    let total_weight = weighted_levels
        .iter()
        .map(|(_, _, weight)| *weight)
        .sum::<f64>()
        .max(1.0);
    let this_weight = weighted_levels
        .iter()
        .find(|(current_family_id, current_level_index, _)| {
            *current_family_id == family_id && *current_level_index == level_index
        })
        .map(|(_, _, weight)| *weight)
        .unwrap_or(1.0);
    ((total as f64) * this_weight / total_weight).ceil() as usize
}

fn make_named_space(category: &str, name: &str, rect: Rect2) -> SpacePlacement {
    make_space_placement(
        category.to_string(),
        name.to_string(),
        1.0,
        rect,
        rect.to_polygon(),
        rect.area(),
    )
}

fn build_support_strip_spaces(
    level_index: u32,
    host_rect: Rect2,
    rows: &[SpaceDemandRow],
    horizontal: bool,
) -> Vec<SpacePlacement> {
    if rows.is_empty() || host_rect.area() <= EPS {
        return Vec::new();
    }
    let weights = rows
        .iter()
        .map(|row| row.area_sf.max(1.0))
        .collect::<Vec<_>>();
    let slices = partition_rect_weighted(host_rect, &weights, horizontal);
    rows.iter()
        .zip(slices.into_iter())
        .map(|(row, rect)| {
            let mut space = make_named_space(
                &row.category,
                &format!("{} @ floor {}", row.space_name, level_index),
                rect,
            );
            space.qty = row.qty.max(1.0);
            space
        })
        .collect::<Vec<_>>()
}

fn build_structured_parking_spaces(
    level_index: u32,
    rects: &[Rect2],
    target_stalls: usize,
    include_ramp: bool,
    include_loading: bool,
    vertical_targets: &[SpacePlacement],
) -> Vec<SpacePlacement> {
    let mut spaces = Vec::<SpacePlacement>::new();
    if rects.is_empty() || target_stalls == 0 {
        return spaces;
    }
    let accessible_target = ((target_stalls as f64) * 0.08).ceil().max(1.0) as usize;
    let mut remaining_stalls = target_stalls;
    let mut remaining_accessible = accessible_target;
    for (rect_idx, rect) in rects.iter().copied().enumerate() {
        if rect.area() <= EPS {
            continue;
        }
        let long_horizontal = rect.width() >= rect.height();
        let aisle_width = 24.0f64
            .min(if long_horizontal {
                rect.height() * 0.5
            } else {
                rect.width() * 0.5
            })
            .max(12.0);
        let stall_depth = 18.0f64.min(if long_horizontal {
            ((rect.height() - aisle_width) * 0.5).max(16.0)
        } else {
            ((rect.width() - aisle_width) * 0.5).max(16.0)
        });
        let accessible_width = 12.0;
        let typical_width = 9.0;
        let usable_span = if long_horizontal {
            rect.width()
        } else {
            rect.height()
        };
        let max_stalls_this_rect = ((usable_span / typical_width).floor() as usize).max(1)
            * if stall_depth * 2.0 + aisle_width + 2.0
                <= if long_horizontal {
                    rect.height()
                } else {
                    rect.width()
                }
            {
                2
            } else {
                1
            };
        let stall_count = remaining_stalls.min(max_stalls_this_rect).max(1);
        let per_side = if stall_depth * 2.0 + aisle_width + 2.0
            <= if long_horizontal {
                rect.height()
            } else {
                rect.width()
            } {
            ((stall_count as f64) * 0.5).ceil() as usize
        } else {
            stall_count
        };

        let aisle_rect = if long_horizontal {
            let cy = (rect.min_y + rect.max_y) * 0.5;
            Rect2::new(
                rect.min_x,
                cy - aisle_width * 0.5,
                rect.max_x,
                cy + aisle_width * 0.5,
            )
        } else {
            let cx = (rect.min_x + rect.max_x) * 0.5;
            Rect2::new(
                cx - aisle_width * 0.5,
                rect.min_y,
                cx + aisle_width * 0.5,
                rect.max_y,
            )
        };
        spaces.push(make_named_space(
            "Parking",
            &format!("Drive Aisle {} @ floor {}", rect_idx + 1, level_index),
            aisle_rect,
        ));

        let top_or_right = if long_horizontal {
            Rect2::new(rect.min_x, aisle_rect.max_y, rect.max_x, rect.max_y)
        } else {
            Rect2::new(aisle_rect.max_x, rect.min_y, rect.max_x, rect.max_y)
        };
        let bottom_or_left = if long_horizontal {
            Rect2::new(rect.min_x, rect.min_y, rect.max_x, aisle_rect.min_y)
        } else {
            Rect2::new(rect.min_x, rect.min_y, aisle_rect.min_x, rect.max_y)
        };
        let sides = if top_or_right.area() > EPS && bottom_or_left.area() > EPS {
            vec![top_or_right, bottom_or_left]
        } else {
            vec![rect]
        };

        for (side_idx, side) in sides.into_iter().enumerate() {
            let local_count = per_side.min(remaining_stalls).max(1);
            let mut widths = Vec::<f64>::new();
            let mut stall_flags = Vec::<bool>::new();
            for _ in 0..local_count {
                if remaining_accessible > 0 {
                    widths.push(accessible_width);
                    stall_flags.push(true);
                    remaining_accessible = remaining_accessible.saturating_sub(1);
                } else {
                    widths.push(typical_width);
                    stall_flags.push(false);
                }
            }
            let stall_rects = partition_rect_weighted(side, &widths, long_horizontal);
            for (stall_idx, stall_rect) in stall_rects.into_iter().enumerate() {
                let accessible = stall_flags.get(stall_idx).copied().unwrap_or(false);
                spaces.push(make_named_space(
                    "Parking",
                    &format!(
                        "{} Parking Stall {}-{} @ floor {}",
                        if accessible { "Accessible" } else { "Standard" },
                        rect_idx + 1,
                        side_idx * 100 + stall_idx + 1,
                        level_index
                    ),
                    stall_rect,
                ));
                remaining_stalls = remaining_stalls.saturating_sub(1);
                if remaining_stalls == 0 {
                    break;
                }
            }
            if remaining_stalls == 0 {
                break;
            }
        }

        if include_ramp && rect_idx == 0 {
            let ramp_rect = if long_horizontal {
                Rect2::new(
                    rect.min_x,
                    rect.min_y,
                    (rect.min_x + 22.0).min(rect.max_x),
                    rect.max_y,
                )
            } else {
                Rect2::new(
                    rect.min_x,
                    rect.min_y,
                    rect.max_x,
                    (rect.min_y + 22.0).min(rect.max_y),
                )
            };
            if ramp_rect.area() > EPS {
                spaces.push(make_named_space(
                    "Vehicle",
                    &format!("Structured Parking Ramp @ floor {}", level_index),
                    ramp_rect,
                ));
            }
        }
        if include_loading && rect_idx + 1 == rects.len() {
            let loading_rect = if long_horizontal {
                Rect2::new(
                    (rect.max_x - 28.0).max(rect.min_x),
                    rect.min_y,
                    rect.max_x,
                    (rect.min_y + 18.0).min(rect.max_y),
                )
            } else {
                Rect2::new(
                    rect.min_x,
                    (rect.max_y - 28.0).max(rect.min_y),
                    (rect.min_x + 18.0).min(rect.max_x),
                    rect.max_y,
                )
            };
            if loading_rect.area() > EPS {
                spaces.push(make_named_space(
                    "Loading",
                    &format!("Loading Zone @ floor {}", level_index),
                    loading_rect,
                ));
            }
        }
        if rect_idx == 0 {
            if let Some(core_target) = vertical_targets.iter().min_by(|a, b| {
                rect.center()
                    .distance_to(a.rect.center())
                    .partial_cmp(&rect.center().distance_to(b.rect.center()))
                    .unwrap_or(Ordering::Equal)
            }) {
                let walk_rect = if long_horizontal {
                    let walk_y = (rect.min_y + rect.max_y) * 0.5;
                    let min_x = rect.center().x.min(core_target.rect.center().x);
                    let max_x = rect.center().x.max(core_target.rect.center().x);
                    Rect2::new(min_x, walk_y - 4.0, max_x, walk_y + 4.0)
                } else {
                    let walk_x = (rect.min_x + rect.max_x) * 0.5;
                    let min_y = rect.center().y.min(core_target.rect.center().y);
                    let max_y = rect.center().y.max(core_target.rect.center().y);
                    Rect2::new(walk_x - 4.0, min_y, walk_x + 4.0, max_y)
                };
                if walk_rect.area() > EPS {
                    spaces.push(make_named_space(
                        "Circulation",
                        &format!("Parking Walk Route @ floor {}", level_index),
                        walk_rect,
                    ));
                }
            }
        }
        if remaining_stalls == 0 {
            break;
        }
    }
    spaces
}

fn build_typical_floor_spaces(
    input: &NormalizedInput,
    a: &AssumptionPack,
    rects: &[Rect2],
    level_index: u32,
    units_per_floor: usize,
    unit_seq: &mut Vec<UnitType>,
) -> Vec<SpacePlacement> {
    let mut spaces = Vec::<SpacePlacement>::new();
    let mut seq_local = unit_seq
        .iter()
        .take(units_per_floor)
        .copied()
        .collect::<Vec<_>>();
    for rect in rects {
        let mut packed = pack_units_in_rect(
            *rect,
            input.constraints.corridor_type,
            input,
            a,
            &mut seq_local,
            level_index,
        );
        spaces.append(&mut packed);
    }
    merge_adjacent_rects_for_composites(&spaces)
}

fn build_non_dwelling_floor_spaces(
    input: &NormalizedInput,
    program: &ProgramState,
    families: &[FloorFamily],
    family: &FloorFamily,
    level_index: u32,
    rects: &[Rect2],
) -> Vec<SpacePlacement> {
    let mut spaces = Vec::<SpacePlacement>::new();
    if rects.is_empty() {
        return spaces;
    }

    let bbox = rects.iter().fold(rects[0], |acc, rect| {
        Rect2::new(
            acc.min_x.min(rect.min_x),
            acc.min_y.min(rect.min_y),
            acc.max_x.max(rect.max_x),
            acc.max_y.max(rect.max_y),
        )
    });
    let long_horizontal = bbox.width() >= bbox.height();
    let edge_band = if long_horizontal {
        Rect2::new(
            bbox.min_x,
            bbox.min_y,
            bbox.max_x,
            (bbox.min_y + 18.0).min(bbox.max_y),
        )
    } else {
        Rect2::new(
            bbox.min_x,
            bbox.min_y,
            (bbox.min_x + 18.0).min(bbox.max_x),
            bbox.max_y,
        )
    };

    let mut support_rows = Vec::<SpaceDemandRow>::new();
    if family.family_id == "podium" {
        for needle in [
            "Entry Lobby",
            "Mail",
            "Bicycle",
            "Indoor Amenity",
            "Restroom for Residents",
            "Common Laundry",
        ] {
            if let Some(row) = support_row_by_name(program, needle) {
                support_rows.push(row.clone());
            }
        }
        if level_index == input.levels.below_grade_count {
            for needle in [
                "Entry Wind Lobby",
                "Main Electrical Room",
                "Generator Room",
                "Automatic Transfer Switch (ATS) Room (Emergency equipment)",
                "Emergency Lighting Inverter Room",
                "Solar Battery Room / UPS Room",
                "Fan Room / Air Handling Unit (AHU) Room",
                "Electrical Utility - Customer Station (indoor)",
                "Gas Utility - Indoor Meter Room",
                "Gas Meter Space/Alcove",
                "Domestic Water Booster Pump Room",
                "Cistern Water Storage/Tank Room",
                "Backflow Preventer Room/Alcove/Space",
                "Central Water Heating Room (Indoor)",
                "Graywater System Room",
                "Water PRV Closet",
                "Fire Pump Room",
                "Water Filtration/Conditioning Room",
                "Grease Interceptor Room",
                "Fire Control Room",
                "Sprinkler Riser Closets",
                "Loading Dock",
                "Temp Loading Zone / Ride-share",
                "MPOE Room",
            ] {
                if let Some(row) = support_row_by_name(program, needle) {
                    support_rows.push(row.clone());
                }
            }
        }
    } else {
        for needle in [
            "Main Electrical Room",
            "Generator Room",
            "Automatic Transfer Switch (ATS) Room (Emergency equipment)",
            "Emergency Lighting Inverter Room",
            "Solar Battery Room / UPS Room",
            "Fan Room / Air Handling Unit (AHU) Room",
            "Mechanical Shaft / Vertical Riser Space - Commercial Kitchen",
            "Mechanical Shaft / Vertical Riser Space - Ventilation & Ref. Lines",
            "Shaft - Plumbing Risers",
            "Electrical Utility - Customer Station (indoor)",
            "Gas Utility - Indoor Meter Room",
            "Domestic Water Booster Pump Room",
            "Cistern Water Storage/Tank Room",
            "Backflow Preventer Room/Alcove/Space",
            "Central Water Heating Room (Indoor)",
            "Graywater System Room",
            "Water PRV Closet",
            "Fire Pump Room",
            "Water Filtration/Conditioning Room",
            "Grease Interceptor Room",
            "Fire Control Room",
            "Sprinkler Riser Closets",
            "Rain Water Harvesting Room",
            "DAS (ERRCS) Room",
            "IDF",
            "Sub Electrical",
        ] {
            if let Some(row) = support_row_by_name(program, needle) {
                support_rows.push(row.clone());
            }
        }
    }
    if family.family_id != "below_grade" && level_index + 1 == input.levels.count {
        if let Some(row) = support_row_by_name(program, "Elevator Machine Room (Interior)") {
            support_rows.push(row.clone());
        }
    }
    spaces.extend(build_support_strip_spaces(
        level_index,
        edge_band,
        &support_rows,
        long_horizontal,
    ));

    let stall_count = distributed_parking_stalls_for_level(
        input,
        program,
        families,
        &family.family_id,
        level_index,
    );
    if stall_count > 0 {
        spaces.extend(build_structured_parking_spaces(
            level_index,
            rects,
            stall_count,
            true,
            family.family_id == "podium" && level_index == input.levels.below_grade_count,
            &[],
        ));
    }

    if family.family_id == "podium"
        && level_index + 1 == input.levels.below_grade_count + input.levels.podium_levels
    {
        let deck_rect = if long_horizontal {
            Rect2::new(
                (bbox.max_x - 32.0).max(bbox.min_x),
                (bbox.max_y - 22.0).max(bbox.min_y),
                bbox.max_x,
                bbox.max_y,
            )
        } else {
            Rect2::new(
                (bbox.max_x - 22.0).max(bbox.min_x),
                (bbox.max_y - 32.0).max(bbox.min_y),
                bbox.max_x,
                bbox.max_y,
            )
        };
        if deck_rect.area() > 0.0 {
            spaces.push(make_named_space(
                "Outdoor Amenity",
                &format!("Podium Deck Amenity @ floor {}", level_index),
                deck_rect,
            ));
        }
    }

    spaces
}

fn floor_zones_for_level(
    family: &FloorFamily,
    level_index: u32,
    candidate: &CandidateCase,
    verticals: &VerticalState,
) -> Vec<String> {
    let primary_program = if family.family_id == "below_grade" {
        "parking_service"
    } else if family.family_id == "podium" {
        "arrival_support_transfer"
    } else {
        "dwelling"
    };
    vec![
        format!("family={}", family.family_id),
        format!("primary_program={}", primary_program),
        format!("corridor={:?}", candidate.corridor_type),
        format!("core={:?}", candidate.core_strategy),
        format!("vertical_groups={}", verticals.groups.len()),
        format!("level_index={}", level_index),
    ]
}

