fn assign_zone_metadata_to_space(space: &mut SpacePlacement, zone: &FloorZone) {
    space.host_zone_id = Some(zone.zone_id.clone());
    space.concept_block_id = zone.concept_block_id.clone();
}

fn build_floor_room_spaces(
    level_index: u32,
    floor_spaces: &[SpacePlacement],
) -> Vec<SpacePlacement> {
    let mut room_spaces = Vec::<SpacePlacement>::new();
    for dwelling in floor_spaces.iter().filter(|space| is_dwelling_space(space)) {
        room_spaces.extend(subdivide_unit_into_rooms(
            dwelling,
            floor_spaces,
            level_index,
        ));
    }
    room_spaces
}

fn zone_note_value<'a>(zone: &'a FloorZone, key: &str) -> Option<&'a str> {
    let prefix = format!("{}=", key);
    zone.notes
        .iter()
        .find_map(|note| note.strip_prefix(prefix.as_str()))
}

fn support_zone_role(zone: &FloorZone) -> String {
    zone_note_value(zone, "support_role")
        .unwrap_or("general")
        .to_string()
}

fn support_row_role(row: &SpaceDemandRow) -> &'static str {
    let hay = row.space_name.to_lowercase();
    if hay.contains("lobby")
        || hay.contains("mail")
        || hay.contains("bicycle")
        || hay.contains("wheelchair")
        || hay.contains("leasing office")
        || hay.contains("manager office")
        || hay.contains("manager's office")
    {
        "public"
    } else if hay.contains("amenity")
        || hay.contains("laundry")
        || hay.contains("parcel")
        || hay.contains("restroom for residents")
    {
        "semi_public"
    } else if hay.contains("loading")
        || hay.contains("filtration")
        || hay.contains("fire control")
        || hay.contains("rainwater")
        || hay.contains("rain water")
        || hay.contains("machine room")
        || hay.contains("elevator machine")
        || hay.contains("generator")
        || hay.contains("transfer switch")
        || hay.contains("inverter")
        || hay.contains("ups")
        || hay.contains("mechanical")
        || hay.contains("shaft")
        || hay.contains("riser")
        || hay.contains("booster")
        || hay.contains("cistern")
        || hay.contains("backflow")
        || hay.contains("heating")
        || hay.contains("graywater")
        || hay.contains("prv")
        || hay.contains("fire pump")
        || hay.contains("grease")
        || hay.contains("interceptor")
        || hay.contains("das")
        || hay.contains("mpoe")
        || hay.contains("idf")
        || hay.contains("electrical")
        || hay.contains("gas utility")
        || hay.contains("gas meter")
        || hay.contains("staff")
        || hay.contains("cctv")
        || hay.contains("storage")
        || hay.contains("janitor")
        || hay.contains("trash")
        || hay.contains("recycling")
        || hay.contains("parking control")
    {
        "service"
    } else {
        "general"
    }
}

fn build_support_spaces_for_zones(
    level_index: u32,
    support_zones: &[FloorZone],
    support_rows: &[SpaceDemandRow],
) -> Vec<SpacePlacement> {
    if support_zones.is_empty() || support_rows.is_empty() {
        return Vec::new();
    }

    let mut allocated = Vec::<SpacePlacement>::new();
    let mut remaining_rows = support_rows.to_vec();
    let zone_roles = ["public", "semi_public", "service"];
    for role in zone_roles {
        let matching_rows = remaining_rows
            .iter()
            .filter(|row| support_row_role(row) == role)
            .cloned()
            .collect::<Vec<_>>();
        if matching_rows.is_empty() {
            continue;
        }
        if let Some(zone) = support_zones
            .iter()
            .find(|zone| support_zone_role(zone) == role)
        {
            let mut spaces = build_support_strip_spaces(
                level_index,
                zone.rect,
                &matching_rows,
                zone.rect.width() >= zone.rect.height(),
            );
            for space in &mut spaces {
                assign_zone_metadata_to_space(space, zone);
            }
            allocated.extend(spaces);
            remaining_rows.retain(|row| support_row_role(row) != role);
        }
    }

    for (idx, zone) in support_zones.iter().enumerate() {
        let remaining_for_zone = if idx + 1 == support_zones.len() {
            remaining_rows.clone()
        } else {
            remaining_rows
                .iter()
                .take((remaining_rows.len() / (support_zones.len() - idx)).max(1))
                .cloned()
                .collect::<Vec<_>>()
        };
        if remaining_for_zone.is_empty() {
            continue;
        }
        let mut spaces = build_support_strip_spaces(
            level_index,
            zone.rect,
            &remaining_for_zone,
            zone.rect.width() >= zone.rect.height(),
        );
        for space in &mut spaces {
            assign_zone_metadata_to_space(space, zone);
        }
        allocated.extend(spaces);
        let consumed = remaining_for_zone.len().min(remaining_rows.len());
        remaining_rows.drain(0..consumed);
    }

    allocated
}

fn nearest_corridor_for_space<'a>(
    space: &SpacePlacement,
    floor_spaces: &'a [SpacePlacement],
) -> Option<&'a SpacePlacement> {
    floor_spaces
        .iter()
        .filter(|peer| peer.category.to_lowercase().contains("circulation"))
        .min_by(|a, b| {
            space
                .rect
                .center()
                .distance_to(a.rect.center())
                .partial_cmp(&space.rect.center().distance_to(b.rect.center()))
                .unwrap_or(Ordering::Equal)
        })
}

fn nearest_vertical_for_space<'a>(
    space: &SpacePlacement,
    floor_spaces: &'a [SpacePlacement],
) -> Option<&'a SpacePlacement> {
    floor_spaces
        .iter()
        .filter(|peer| is_service_space(peer))
        .min_by(|a, b| {
            space
                .rect
                .center()
                .distance_to(a.rect.center())
                .partial_cmp(&space.rect.center().distance_to(b.rect.center()))
                .unwrap_or(Ordering::Equal)
        })
}

fn commit_circulation_contract(spaces: &mut [SpacePlacement], level_index: u32) {
    let snapshot = spaces.to_vec();
    for space in spaces.iter_mut().filter(|space| {
        is_dwelling_space(space) || space.category.to_lowercase().contains("support")
    }) {
        if let Some(corridor) = nearest_corridor_for_space(space, &snapshot) {
            space.ingress_relations.push(SpaceFlowRelation {
                relation_id: format!("entry:{}:{}", space.space_id, corridor.space_id),
                relation_kind: "committed_entry".to_string(),
                target_id: corridor.space_id.clone(),
                required: true,
                notes: vec![format!("level={}", level_index)],
            });
            space.egress_relations.push(SpaceFlowRelation {
                relation_id: format!("egress:{}:{}", space.space_id, corridor.space_id),
                relation_kind: "committed_corridor_access".to_string(),
                target_id: corridor.space_id.clone(),
                required: true,
                notes: vec![format!("level={}", level_index)],
            });
            if canonical_graph_touch_or_overlap(space.rect, corridor.rect, 2.0) {
                space.adjacency_ids.push(corridor.space_id.clone());
            }
        }
        if let Some(vertical) = nearest_vertical_for_space(space, &snapshot) {
            space.service_dependencies.push(SpaceServiceDependency {
                dependency_id: format!("dep:{}:vertical_link", space.space_id),
                dependency_kind: "vertical_transfer".to_string(),
                target_id: vertical.space_id.clone(),
                required: true,
                notes: vec![format!("level={}", level_index)],
            });
        }
    }
}

fn build_residual_spaces_for_level(
    family: &FloorFamily,
    level_index: u32,
    zones: &[FloorZone],
    spaces: &[SpacePlacement],
) -> Vec<SpacePlacement> {
    let mut residual_spaces = Vec::<SpacePlacement>::new();
    for zone in zones {
        if matches!(
            zone.kind,
            FloorZoneKind::CoreService | FloorZoneKind::OutdoorCapable
        ) {
            continue;
        }
        let cuts = spaces
            .iter()
            .filter(|space| rect_intersection_area(zone.rect, space.rect) > 1.0)
            .map(|space| space.rect)
            .collect::<Vec<_>>();
        for (idx, rect) in subtract_rects(vec![zone.rect], &cuts)
            .into_iter()
            .enumerate()
        {
            if rect.area() <= 40.0 {
                continue;
            }
            let (category, name) =
                if family.family_id == "typical_residential" && rect.area() >= 95.0 {
                    ("Support Areas", "Resident Storage")
                } else if family.family_id == "podium" && rect.area() >= 120.0 {
                    ("Amenity Support", "Pocket Amenity")
                } else if family.family_id == "below_grade" && rect.area() >= 85.0 {
                    ("Parking", "Parking Support Pocket")
                } else {
                    ("Residual", "Residual Pocket")
                };
            let mut space = make_named_space(
                category,
                &format!("{} {} @ floor {}", name, idx + 1, level_index),
                rect,
            );
            assign_zone_metadata_to_space(&mut space, zone);
            space.residual_source_id = Some(zone.zone_id.clone());
            residual_spaces.push(space);
        }
    }
    residual_spaces
}

fn build_spaces_from_floor_zones(
    input: &NormalizedInput,
    program: &ProgramState,
    family: &FloorFamily,
    families: &[FloorFamily],
    level_index: u32,
    zones: &[FloorZone],
    mut vertical_spaces: Vec<SpacePlacement>,
    unit_seq: &mut Vec<UnitType>,
    units_per_floor: usize,
    a: &AssumptionPack,
) -> (Vec<SpacePlacement>, Vec<SpacePlacement>) {
    let mut spaces = Vec::<SpacePlacement>::new();

    for vertical in &mut vertical_spaces {
        if let Some(zone) = zones.iter().find(|zone| {
            zone.kind == FloorZoneKind::CoreService
                && zone.concept_block_id == vertical.concept_block_id
                && rect_intersection_area(zone.rect, vertical.rect) > 1.0
        }) {
            assign_zone_metadata_to_space(vertical, zone);
        }
    }
    spaces.extend(vertical_spaces.into_iter());

    for zone in zones
        .iter()
        .filter(|zone| zone.kind == FloorZoneKind::Circulation)
    {
        let mut space = make_named_space(
            "Circulation",
            &format!("Mainline Corridor @ floor {}", level_index),
            zone.rect,
        );
        assign_zone_metadata_to_space(&mut space, zone);
        spaces.push(space);
    }

    let support_zones = zones
        .iter()
        .filter(|zone| zone.kind == FloorZoneKind::Support)
        .cloned()
        .collect::<Vec<_>>();
    let support_rows = support_rows_for_level(input, program, family, level_index);
    spaces.extend(build_support_spaces_for_zones(
        level_index,
        &support_zones,
        &support_rows,
    ));

    let parking_zones = zones
        .iter()
        .filter(|zone| zone.kind == FloorZoneKind::Parking)
        .cloned()
        .collect::<Vec<_>>();
    if !parking_zones.is_empty() {
        let stall_count = distributed_parking_stalls_for_level(
            input,
            program,
            families,
            &family.family_id,
            level_index,
        );
        let mut parking_spaces = build_structured_parking_spaces(
            level_index,
            &parking_zones
                .iter()
                .map(|zone| zone.rect)
                .collect::<Vec<_>>(),
            stall_count,
            true,
            level_index == input.levels.below_grade_count,
            &spaces,
        );
        for space in &mut parking_spaces {
            if let Some(zone) = parking_zones
                .iter()
                .find(|zone| rect_intersection_area(zone.rect, space.rect) > 1.0)
            {
                assign_zone_metadata_to_space(space, zone);
            }
        }
        spaces.extend(parking_spaces);
    }

    for zone in zones
        .iter()
        .filter(|zone| zone.kind == FloorZoneKind::OutdoorCapable)
    {
        let mut outdoor = make_named_space(
            "Outdoor Amenity",
            &format!("Podium Deck Amenity @ floor {}", level_index),
            zone.rect,
        );
        assign_zone_metadata_to_space(&mut outdoor, zone);
        spaces.push(outdoor);
    }

    let dwelling_zones = zones
        .iter()
        .filter(|zone| zone.kind == FloorZoneKind::Dwelling)
        .cloned()
        .collect::<Vec<_>>();
    let total_dwelling_area = dwelling_zones
        .iter()
        .map(|zone| zone.area_sf)
        .sum::<f64>()
        .max(1.0);
    let mut units_remaining = units_per_floor;
    for (zone_idx, zone) in dwelling_zones.iter().enumerate() {
        if unit_seq.is_empty() {
            break;
        }
        let target_here = if zone_idx + 1 == dwelling_zones.len() {
            units_remaining.max(1)
        } else {
            ((units_per_floor as f64) * zone.area_sf / total_dwelling_area)
                .round()
                .max(1.0) as usize
        };
        let before = unit_seq.len();
        let mut packed = pack_units_in_zone(zone, input, a, unit_seq, level_index);
        if packed.len() > target_here {
            let extra = packed.split_off(target_here);
            for space in extra.into_iter().rev() {
                let unit_type = match infer_unit_type(&space).as_str() {
                    "studio" => UnitType::Studio,
                    "one_bedroom" => UnitType::OneBedroom,
                    "two_bedroom" => UnitType::TwoBedroom,
                    _ => UnitType::ThreeBedroom,
                };
                unit_seq.insert(0, unit_type);
            }
        }
        for space in &mut packed {
            assign_zone_metadata_to_space(space, zone);
        }
        units_remaining = units_remaining.saturating_sub(packed.len());
        spaces.extend(packed);
        if unit_seq.len() == before {
            break;
        }
    }

    if spaces.is_empty() {
        if let Some(zone) = zones.first() {
            let mut fallback = make_named_space(
                "Support Areas",
                &format!("Service Reserve @ floor {}", level_index),
                zone.rect,
            );
            assign_zone_metadata_to_space(&mut fallback, zone);
            spaces.push(fallback);
        }
    }

    for (idx, space) in spaces.iter_mut().enumerate() {
        if space.space_id.is_empty() {
            space.space_id = format!("L{:02}_SEED_SP{:03}", level_index, idx);
        }
    }
    let mut room_spaces = build_floor_room_spaces(level_index, &spaces);
    for (idx, room) in room_spaces.iter_mut().enumerate() {
        if room.space_id.is_empty() {
            room.space_id = format!("L{:02}_SEED_RM{:03}", level_index, idx);
        }
    }
    spaces.extend(build_residual_spaces_for_level(
        family,
        level_index,
        zones,
        &spaces,
    ));
    commit_circulation_contract(&mut spaces, level_index);
    (spaces, room_spaces)
}

fn build_mainline_floor_circulation_topology(floor: &FloorOutput) -> FloorCirculationTopology {
    let mut topo = FloorCirculationTopology::empty(floor.level_index, floor.family_id.clone());
    topo.routing_mode = "mainline_geometry".to_string();

    let mut corridor_nodes = Vec::<CirculationNode>::new();
    for (idx, space) in floor
        .spaces
        .iter()
        .filter(|space| space.category.to_lowercase().contains("circulation"))
        .enumerate()
    {
        corridor_nodes.push(CirculationNode {
            node_id: format!("circ_L{:02}_seg_{:02}", floor.level_index, idx),
            level_index: floor.level_index,
            family_id: floor.family_id.clone(),
            node_kind: CirculationNodeKind::CorridorSegment,
            polygon: space.polygon.clone(),
            anchor: space.rect.center(),
            linked_topology_node_ids: space.parent_topology_node_id.clone().into_iter().collect(),
            linked_space_ids: vec![space.space_id.clone()],
            branch_label: Some("mainline".to_string()),
            notes: vec![format!(
                "host_zone={}",
                space.host_zone_id.clone().unwrap_or_default()
            )],
        });
    }
    topo.corridor_segment_graph = corridor_nodes;

    for (idx, space) in floor
        .spaces
        .iter()
        .filter(|space| {
            is_service_space(space) && !space.category.to_lowercase().contains("circulation")
        })
        .enumerate()
    {
        topo.junction_graph.push(CirculationNode {
            node_id: format!("circ_L{:02}_core_{:02}", floor.level_index, idx),
            level_index: floor.level_index,
            family_id: floor.family_id.clone(),
            node_kind: CirculationNodeKind::CoreAnchor,
            polygon: space.polygon.clone(),
            anchor: space.rect.center(),
            linked_topology_node_ids: space.parent_topology_node_id.clone().into_iter().collect(),
            linked_space_ids: vec![space.space_id.clone()],
            branch_label: Some("service_anchor".to_string()),
            notes: vec![],
        });
    }

    for (idx, space) in floor
        .spaces
        .iter()
        .filter(|space| {
            is_dwelling_space(space) || space.category.to_lowercase().contains("support")
        })
        .enumerate()
    {
        let committed_corridor = space
            .ingress_relations
            .iter()
            .find(|relation| relation.relation_kind.contains("committed"))
            .and_then(|relation| {
                topo.corridor_segment_graph.iter().find(|corridor| {
                    corridor
                        .linked_space_ids
                        .iter()
                        .any(|space_id| space_id == &relation.target_id)
                })
            })
            .cloned();
        let nearest_corridor = committed_corridor.or_else(|| {
            topo.corridor_segment_graph
                .iter()
                .min_by(|a, b| {
                    space
                        .rect
                        .center()
                        .distance_to(a.anchor)
                        .partial_cmp(&space.rect.center().distance_to(b.anchor))
                        .unwrap_or(Ordering::Equal)
                })
                .cloned()
        });
        let decision_id = format!("circ_L{:02}_decision_{:02}", floor.level_index, idx);
        topo.decision_node_graph.push(CirculationNode {
            node_id: decision_id.clone(),
            level_index: floor.level_index,
            family_id: floor.family_id.clone(),
            node_kind: if is_dwelling_space(space) {
                CirculationNodeKind::Door
            } else {
                CirculationNodeKind::Decision
            },
            polygon: space.polygon.clone(),
            anchor: space.rect.center(),
            linked_topology_node_ids: space.parent_topology_node_id.clone().into_iter().collect(),
            linked_space_ids: vec![space.space_id.clone()],
            branch_label: Some(if is_dwelling_space(space) {
                "unit_access".to_string()
            } else {
                "support_access".to_string()
            }),
            notes: vec![],
        });
        if let Some(corridor) = nearest_corridor {
            let edge_id = format!("circ_edge_{}_{}", decision_id, corridor.node_id);
            topo.edges.push(CirculationEdge {
                edge_id: edge_id.clone(),
                from_node_id: decision_id.clone(),
                to_node_id: corridor.node_id.clone(),
                edge_kind: CirculationEdgeKind::DoorConnection,
                directed: false,
                length_ft: corridor.anchor.distance_to(space.rect.center()),
                linked_owner_id: space.zone_owner_id.clone(),
                notes: vec![if space.ingress_relations.iter().any(|relation| {
                    relation.target_id
                        == corridor
                            .linked_space_ids
                            .first()
                            .cloned()
                            .unwrap_or_default()
                        && relation.relation_kind.contains("committed")
                }) {
                    "committed_entry_edge".to_string()
                } else {
                    "proxy_entry_edge".to_string()
                }],
            });
            topo.door_to_corridor_connections
                .push(DoorToCorridorConnection {
                    connection_id: format!("door_conn_{}", space.space_id),
                    unit_id: space.space_id.clone(),
                    door_opening_id: format!("door_proxy_{}", space.space_id),
                    door_node_id: decision_id.clone(),
                    corridor_segment_node_id: corridor.node_id.clone(),
                    decision_node_id: Some(decision_id.clone()),
                    distance_ft: corridor.anchor.distance_to(space.rect.center()),
                    notes: vec![if space.ingress_relations.iter().any(|relation| {
                        relation.target_id
                            == corridor
                                .linked_space_ids
                                .first()
                                .cloned()
                                .unwrap_or_default()
                            && relation.relation_kind.contains("committed")
                    }) {
                        "committed_entry_connection".to_string()
                    } else {
                        "mainline_proxy_connection".to_string()
                    }],
                });
            topo.entry_sequence_graphs.push(EntrySequenceGraph {
                sequence_id: format!("entry_seq_{}", space.space_id),
                unit_id: space.space_id.clone(),
                step_node_ids: vec![decision_id.clone(), corridor.node_id.clone()],
                edge_ids: vec![edge_id.clone()],
                public_node_ids: vec![corridor.node_id.clone()],
                private_node_ids: vec![decision_id.clone()],
                notes: vec![],
            });
            topo.public_private_transition_graphs
                .push(PublicPrivateTransition {
                    transition_id: format!("ppt_{}", space.space_id),
                    unit_id: space.space_id.clone(),
                    from_node_id: corridor.node_id.clone(),
                    to_node_id: decision_id.clone(),
                    privacy_owner_id: space.privacy_owner_ids.first().cloned(),
                    notes: vec![],
                });
        }
    }

    for i in 0..topo.corridor_segment_graph.len() {
        for j in (i + 1)..topo.corridor_segment_graph.len() {
            let a = &topo.corridor_segment_graph[i];
            let b = &topo.corridor_segment_graph[j];
            if canonical_graph_touch_or_overlap(
                bounding_rect(&a.polygon),
                bounding_rect(&b.polygon),
                2.0,
            ) {
                topo.edges.push(CirculationEdge {
                    edge_id: format!("circ_link_{}_{}", a.node_id, b.node_id),
                    from_node_id: a.node_id.clone(),
                    to_node_id: b.node_id.clone(),
                    edge_kind: CirculationEdgeKind::SegmentConnection,
                    directed: false,
                    length_ft: a.anchor.distance_to(b.anchor),
                    linked_owner_id: None,
                    notes: vec![],
                });
            }
        }
    }

    for corridor in &topo.corridor_segment_graph {
        let degree = topo
            .edges
            .iter()
            .filter(|edge| {
                edge.from_node_id == corridor.node_id || edge.to_node_id == corridor.node_id
            })
            .count();
        if degree <= 1 {
            topo.dead_end_ownerships.push(DeadEndOwnership {
                ownership_id: format!("dead_end_{}", corridor.node_id),
                corridor_leaf_node_id: corridor.node_id.clone(),
                corridor_segment_node_id: corridor.node_id.clone(),
                owner_scope_id: format!("owner_floor_L{:02}", floor.level_index),
                owner_space_id: corridor.linked_space_ids.first().cloned(),
                owner_topology_node_id: corridor.linked_topology_node_ids.first().cloned(),
                length_ft: bounding_rect(&corridor.polygon)
                    .width()
                    .max(bounding_rect(&corridor.polygon).height()),
                notes: vec![],
            });
        }
    }

    topo.routing_classes = vec![
        "dwelling_access".to_string(),
        "service_access".to_string(),
        "egress_proxy".to_string(),
    ];
    topo
}

fn site_zone_note_value<'a>(zone: &'a SiteZone, key: &str) -> Option<&'a str> {
    let prefix = format!("{}=", key);
    zone.notes
        .iter()
        .find_map(|note| note.strip_prefix(prefix.as_str()))
}

fn primary_service_yard_zone<'a>(bundle: &'a MassingSitePlanBundle) -> Option<&'a SiteZone> {
    bundle
        .site_zones
        .iter()
        .filter(|zone| {
            zone.zone_kind == SitePlanProgramKind::ServiceYard
                && !zone.polygon.is_empty()
                && site_zone_note_value(zone, "space_name").is_none()
        })
        .max_by(|a, b| a.area_sf.partial_cmp(&b.area_sf).unwrap_or(Ordering::Equal))
}

fn build_electrical_utility_infrastructure_exterior_site_space(
    candidate: &CandidateSolution,
    program: &ProgramState,
    assumptions: &AssumptionPack,
    site_space_index: usize,
) -> Option<SpacePlacement> {
    let bundle = candidate.site_plan_bundle.as_ref()?;
    let host_zone = primary_service_yard_zone(bundle)?;
    let area_sf = electrical_utility_infrastructure_exterior_area_sf(
        program.coarse_total_electrical_load_kva,
        assumptions,
    );
    if area_sf <= EPS {
        return None;
    }
    let host_rect = bounding_rect(&host_zone.polygon);
    if host_rect.area() <= EPS {
        return None;
    }
    let rect = centered_rect_in_bbox(area_sf.min(host_rect.area()), host_rect, 1.0);
    if rect.area() <= EPS {
        return None;
    }
    let mut space = make_space_placement(
        "Site Support",
        "Electrical Utilty Infrastructure - Exterior",
        1.0,
        rect,
        rect.to_polygon(),
        rect.area(),
    );
    space.space_id = format!("site_SP{:02}", site_space_index);
    space.host_zone_id = Some(host_zone.zone_id.clone());
    space.ownership_scope = TopologyOwnershipScopeKind::SiteOwned;
    Some(space)
}

fn build_site_spaces_and_topology(
    _input: &NormalizedInput,
    candidate: &CandidateSolution,
) -> (Vec<SpacePlacement>, OutdoorSiteTopologyGraph) {
    let bundle = match candidate.site_plan_bundle.as_ref() {
        Some(bundle) => bundle,
        None => {
            return (
                Vec::new(),
                OutdoorSiteTopologyGraph {
                    graph_id: "missing_site_plan_bundle".to_string(),
                    nodes: Vec::new(),
                    edges: Vec::new(),
                    notes: vec![
                        "layout_space_consumer_missing_massing_site_plan_bundle".to_string()
                    ],
                },
            )
        }
    };

    let mut spaces = Vec::<SpacePlacement>::new();
    for zone in &bundle.site_zones {
        if matches!(
            zone.zone_kind,
            SitePlanProgramKind::BuildingFootprint
                | SitePlanProgramKind::PodiumEnvelope
                | SitePlanProgramKind::BelowGradeParkingEnvelope
        ) {
            continue;
        }
        let polygon = if zone.polygon.is_empty() {
            continue;
        } else {
            zone.polygon.clone()
        };
        let rect = bounding_rect(&polygon);
        let category = site_zone_note_value(zone, "space_category").unwrap_or("Site");
        let space_name = site_zone_note_value(zone, "space_name")
            .map(|value| value.to_string())
            .unwrap_or_else(|| format!("{:?}", zone.zone_kind));
        let mut space = make_space_placement(
            category,
            space_name,
            1.0,
            rect,
            polygon,
            zone.area_sf.max(rect.area()),
        );
        space.space_id = format!("site_SP{:02}", spaces.len());
        spaces.push(space);
    }

    (spaces, bundle.outdoor_topology_graph.clone())
}

fn build_roof_spaces_and_topologies(
    input: &NormalizedInput,
    candidate: &CandidateSolution,
    program: &ProgramState,
    verticals: &VerticalState,
    assumptions: &AssumptionPack,
) -> (Vec<SpacePlacement>, Vec<RoofTopologyGraph>) {
    let top_floor = match candidate
        .floors
        .iter()
        .max_by_key(|floor| floor.level_index)
    {
        Some(floor) => floor,
        None => return (Vec::new(), Vec::new()),
    };
    let roof_bbox = bounding_rect(&top_floor.footprint_polygon);
    let roof_area_sf = polygon_area_sf(&top_floor.footprint_polygon).max(EPS);
    let vertical_overruns = top_floor
        .spaces
        .iter()
        .filter(|space| is_service_space(space))
        .map(|space| space.rect)
        .collect::<Vec<_>>();
    let mut residuals = subtract_rects(vec![roof_bbox], &vertical_overruns);
    let above_grade_story_count = candidate
        .story_count
        .saturating_sub(input.levels.below_grade_count)
        .max(1);
    let mut mechanical_equipment_specs = Vec::<(String, Rect2)>::new();
    let mut reserve_mechanical_rect =
        |space_name: &str, footprint_ft: Option<(f64, f64)>| -> Option<Rect2> {
            let (width_ft, depth_ft) = footprint_ft?;
            let host_rect = residuals
                .iter()
                .max_by(|a, b| a.area().partial_cmp(&b.area()).unwrap_or(Ordering::Equal))
                .copied()
                .unwrap_or(roof_bbox);
            if host_rect.area() <= EPS {
                return None;
            }
            let clamped_width_ft = width_ft.min(host_rect.width()).max(0.0);
            let clamped_depth_ft = depth_ft.min(host_rect.height()).max(0.0);
            if clamped_width_ft <= EPS || clamped_depth_ft <= EPS {
                return None;
            }
            let rect = Rect2::new(
                host_rect.min_x,
                host_rect.min_y,
                host_rect.min_x + clamped_width_ft,
                host_rect.min_y + clamped_depth_ft,
            );
            residuals = subtract_rects(residuals.clone(), &[rect]);
            mechanical_equipment_specs.push((space_name.to_string(), rect));
            Some(rect)
        };
    reserve_mechanical_rect(
        "Elevator Machine Room (Roof)",
        elevator_machine_room_roof_footprint_ft(
            above_grade_story_count,
            verticals.passenger_elevators,
            verticals.freight_elevators,
            assumptions,
        ),
    );
    reserve_mechanical_rect(
        "Mechanical Pad for HVAC Equipment (Outdoor)",
        mechanical_pad_outdoor_footprint_ft(
            program.dwelling_units_total,
            program.net_residential_area_sf,
            roof_area_sf,
            assumptions,
        ),
    );
    let amenity_rect = residuals
        .iter()
        .max_by(|a, b| a.area().partial_cmp(&b.area()).unwrap_or(Ordering::Equal))
        .copied()
        .unwrap_or(roof_bbox);
    let drainage_rect = Rect2::new(
        roof_bbox.min_x,
        roof_bbox.min_y,
        roof_bbox.max_x,
        (roof_bbox.min_y + 6.0).min(roof_bbox.max_y),
    );
    let screening_rect = Rect2::new(
        roof_bbox.min_x,
        (roof_bbox.max_y - 6.0).max(roof_bbox.min_y),
        roof_bbox.max_x,
        roof_bbox.max_y,
    );
    let mut spaces = Vec::<SpacePlacement>::new();
    for rect in &vertical_overruns {
        let mut space = make_space_placement(
            "Roof",
            format!("Mechanical Overrun @ floor {}", top_floor.level_index),
            1.0,
            *rect,
            rect.to_polygon(),
            rect.area(),
        );
        space.space_id = format!("roof_SP{:02}", spaces.len());
        spaces.push(space);
    }
    for (space_name, rect) in &mechanical_equipment_specs {
        let mut space = make_space_placement(
            "Roof",
            space_name.clone(),
            1.0,
            *rect,
            rect.to_polygon(),
            rect.area(),
        );
        space.space_id = format!("roof_SP{:02}", spaces.len());
        spaces.push(space);
    }
    if amenity_rect.area() > EPS {
        let mut space = make_space_placement(
            "Roof",
            format!("Occupied Roof Amenity @ floor {}", top_floor.level_index),
            1.0,
            amenity_rect,
            amenity_rect.to_polygon(),
            amenity_rect.area(),
        );
        space.space_id = format!("roof_SP{:02}", spaces.len());
        spaces.push(space);
    }
    if drainage_rect.area() > EPS {
        let mut space = make_space_placement(
            "Roof",
            format!("Drainage Corridor @ floor {}", top_floor.level_index),
            1.0,
            drainage_rect,
            drainage_rect.to_polygon(),
            drainage_rect.area(),
        );
        space.space_id = format!("roof_SP{:02}", spaces.len());
        spaces.push(space);
    }
    if screening_rect.area() > EPS {
        let mut space = make_space_placement(
            "Roof",
            format!("Screening Buffer @ floor {}", top_floor.level_index),
            1.0,
            screening_rect,
            screening_rect.to_polygon(),
            screening_rect.area(),
        );
        space.space_id = format!("roof_SP{:02}", spaces.len());
        spaces.push(space);
    }

    let mechanical_equipment_area = mechanical_equipment_specs
        .iter()
        .map(|(_, rect)| rect.area())
        .sum::<f64>();
    let mechanical_exclusion_area =
        vertical_overruns.iter().map(|rect| rect.area()).sum::<f64>() + mechanical_equipment_area;
    let mut nodes = vec![
        RoofTopologyNode {
            node_id: format!("roof_L{:02}_occupied", top_floor.level_index),
            level_index: top_floor.level_index,
            zone_kind: RoofZoneKind::OccupiedAmenity,
            area_sf: amenity_rect.area(),
            occupied: true,
            notes: vec![],
        },
        RoofTopologyNode {
            node_id: format!("roof_L{:02}_mechanical", top_floor.level_index),
            level_index: top_floor.level_index,
            zone_kind: RoofZoneKind::MechanicalExclusion,
            area_sf: mechanical_exclusion_area,
            occupied: false,
            notes: vec![],
        },
        RoofTopologyNode {
            node_id: format!("roof_L{:02}_drainage", top_floor.level_index),
            level_index: top_floor.level_index,
            zone_kind: RoofZoneKind::DrainageCorridor,
            area_sf: drainage_rect.area(),
            occupied: false,
            notes: vec![],
        },
        RoofTopologyNode {
            node_id: format!("roof_L{:02}_screening", top_floor.level_index),
            level_index: top_floor.level_index,
            zone_kind: RoofZoneKind::ScreeningBuffer,
            area_sf: screening_rect.area(),
            occupied: false,
            notes: vec![],
        },
        RoofTopologyNode {
            node_id: format!("roof_L{:02}_egress", top_floor.level_index),
            level_index: top_floor.level_index,
            zone_kind: RoofZoneKind::AccessibleEgressPath,
            area_sf: 120.0,
            occupied: false,
            notes: vec![],
        },
    ];
    for (idx, (space_name, rect)) in mechanical_equipment_specs.iter().enumerate() {
        nodes.push(RoofTopologyNode {
            node_id: format!("roof_L{:02}_mechanical_equipment_{:02}", top_floor.level_index, idx),
            level_index: top_floor.level_index,
            zone_kind: RoofZoneKind::MechanicalEquipment,
            area_sf: rect.area(),
            occupied: false,
            notes: vec![format!("space_name={}", space_name)],
        });
    }
    let mut edges = vec![
        RoofTopologyEdge {
            edge_id: format!("roof_L{:02}_egress_link", top_floor.level_index),
            from_node_id: format!("roof_L{:02}_egress", top_floor.level_index),
            to_node_id: format!("roof_L{:02}_occupied", top_floor.level_index),
            edge_kind: RoofTopologyEdgeKind::EgressConnectivity,
            required: true,
            notes: vec![],
        },
        RoofTopologyEdge {
            edge_id: format!("roof_L{:02}_service_sep", top_floor.level_index),
            from_node_id: format!("roof_L{:02}_occupied", top_floor.level_index),
            to_node_id: format!("roof_L{:02}_mechanical", top_floor.level_index),
            edge_kind: RoofTopologyEdgeKind::ServiceSeparation,
            required: true,
            notes: vec![],
        },
    ];
    for (idx, _) in mechanical_equipment_specs.iter().enumerate() {
        edges.push(RoofTopologyEdge {
            edge_id: format!("roof_L{:02}_mechanical_access_{:02}", top_floor.level_index, idx),
            from_node_id: format!(
                "roof_L{:02}_mechanical_equipment_{:02}",
                top_floor.level_index, idx
            ),
            to_node_id: format!("roof_L{:02}_egress", top_floor.level_index),
            edge_kind: RoofTopologyEdgeKind::MaintenanceAccess,
            required: true,
            notes: vec!["roof_mechanical_equipment_access".to_string()],
        });
    }
    let graph = RoofTopologyGraph {
        graph_id: format!("mainline_roof_L{:02}", top_floor.level_index),
        level_index: top_floor.level_index,
        nodes,
        edges,
        notes: vec!["mainline_roof_solve".to_string()],
    };
    (spaces, vec![graph])
}

fn validate_candidate_detail(candidate: &CandidateSolution) -> Vec<ValidationIssue> {
    let mut issues = Vec::<ValidationIssue>::new();
    for floor in &candidate.floors {
        let vertical_space_count = floor
            .spaces
            .iter()
            .filter(|space| is_service_space(space))
            .count();
        if vertical_space_count == 0 && !floor.family_id.contains("roof") {
            issues.push(ValidationIssue::warning(
                "vertical_carveout_missing",
                "Served floor is missing explicit core, stair, elevator, or shaft carve-out geometry.",
            ));
        }
        for i in 0..floor.spaces.len() {
            for j in (i + 1)..floor.spaces.len() {
                if rect_intersection_area(floor.spaces[i].rect, floor.spaces[j].rect) > 1.0 {
                    issues.push(ValidationIssue::warning(
                        "space_overlap_detected",
                        "Two floor-level spaces still overlap after zoning and keepout allocation.",
                    ));
                    break;
                }
            }
        }
        if floor.spaces.iter().any(is_dwelling_space)
            && floor.circulation_topology.corridor_segment_graph.is_empty()
        {
            issues.push(ValidationIssue::warning(
                "missing_mainline_circulation",
                "Dwelling floor is missing mainline circulation topology wiring.",
            ));
        }
        for dwelling in floor.spaces.iter().filter(|space| is_dwelling_space(space)) {
            if !dwelling
                .ingress_relations
                .iter()
                .any(|relation| relation.required && relation.relation_kind.contains("committed"))
            {
                issues.push(ValidationIssue::error(
                    "dwelling_entry_unresolved",
                    "At least one dwelling envelope does not have a committed corridor entry relation.",
                ));
                break;
            }
        }
        for space in floor
            .spaces
            .iter()
            .filter(|space| is_dwelling_space(space) || is_service_space(space))
        {
            if !space
                .service_dependencies
                .iter()
                .any(|dependency| dependency.required)
            {
                issues.push(ValidationIssue::warning(
                    "service_dependency_missing",
                    "A primary floor space is missing its required service or vertical dependency.",
                ));
                break;
            }
        }
        if floor.spaces.iter().any(is_dwelling_space) && floor.room_spaces.is_empty() {
            issues.push(ValidationIssue::warning(
                "missing_room_subdivision",
                "Dwelling envelopes were produced without room-level subdivision.",
            ));
        }
        for i in 0..floor.room_spaces.len() {
            for j in (i + 1)..floor.room_spaces.len() {
                if floor.room_spaces[i].parent_space_id == floor.room_spaces[j].parent_space_id
                    && rect_intersection_area(floor.room_spaces[i].rect, floor.room_spaces[j].rect)
                        > 0.5
                {
                    issues.push(ValidationIssue::warning(
                        "room_overlap_detected",
                        "At least one dwelling unit still has overlapping room geometry.",
                    ));
                    break;
                }
            }
        }
    }

    if let Some(site_graph) = &candidate.outdoor_site_topology_graph {
        let has_arrival = site_graph
            .nodes
            .iter()
            .any(|node| node.node_kind == OutdoorSiteNodeKind::ArrivalEntry);
        let has_loading = site_graph
            .nodes
            .iter()
            .any(|node| node.node_kind == OutdoorSiteNodeKind::LoadingZone);
        if !has_arrival || !has_loading {
            issues.push(ValidationIssue::warning(
                "site_program_incomplete",
                "Mainline site solve is missing either arrival or loading geometry.",
            ));
        }
    }
    for graph in &candidate.roof_topology_graphs {
        let has_occupied = graph
            .nodes
            .iter()
            .any(|node| node.zone_kind == RoofZoneKind::OccupiedAmenity);
        let has_egress = graph
            .nodes
            .iter()
            .any(|node| node.zone_kind == RoofZoneKind::AccessibleEgressPath);
        if has_occupied && !has_egress {
            issues.push(ValidationIssue::error(
                "roof_egress_missing",
                "Occupied roof geometry exists without an explicit roof egress path.",
            ));
        }
    }
    issues
}

fn apply_candidate_detail_penalties(candidate: &mut CandidateSolution) {
    let warning_count = candidate.diagnostics.validation_warning_count as f64;
    let error_count = candidate.diagnostics.validation_error_count as f64;
    let drift_overages = candidate
        .drift_metrics
        .iter()
        .filter(|metric| !metric.within_budget)
        .count() as f64;
    let access_penalty = candidate.diagnostics.unresolved_entry_count as f64 * 0.06
        + candidate.diagnostics.daylight_miss_count as f64 * 0.02;
    let service_penalty = candidate.diagnostics.unresolved_service_count as f64 * 0.05;
    let parking_penalty = if candidate.diagnostics.parking_required_stalls == 0 {
        0.0
    } else {
        (candidate.diagnostics.parking_shortfall.max(0) as f64
            / candidate.diagnostics.parking_required_stalls.max(1) as f64)
            * 0.25
    };
    let residual_penalty = clamp(
        candidate.diagnostics.residual_area_sf / candidate.gross_floor_area_sf.max(1.0),
        0.0,
        0.18,
    );
    let validation_penalty = 0.04 * warning_count + 0.18 * error_count;
    let drift_penalty = 0.06 * drift_overages;
    candidate.feasibility = evaluate_candidate_feasibility(candidate);
    candidate.score_breakdown.access_penalty = access_penalty;
    candidate.score_breakdown.service_penalty = service_penalty;
    candidate.score_breakdown.parking_penalty = parking_penalty;
    candidate.score_breakdown.residual_penalty = residual_penalty;
    candidate.score_breakdown.validation_penalty = validation_penalty;
    candidate.score_breakdown.drift_penalty = drift_penalty;
    candidate.score_breakdown.total_score = candidate.score_total
        - access_penalty
        - service_penalty
        - parking_penalty
        - residual_penalty
        - validation_penalty
        - drift_penalty
        - candidate.feasibility.penalty_total
        + 0.05 * candidate.concept_score;
    candidate.score_total = candidate.score_breakdown.total_score;
}

fn rebalance_unit_sequence(
    program: &ProgramState,
    realized_mix: [u32; 4],
    allow_unit_size_rebalance: bool,
) -> Vec<UnitType> {
    let mut ordering = vec![
        (
            UnitType::Studio,
            program.unit_counts[0].saturating_sub(realized_mix[0]) as i32,
            0u8,
        ),
        (
            UnitType::OneBedroom,
            program.unit_counts[1].saturating_sub(realized_mix[1]) as i32,
            1u8,
        ),
        (
            UnitType::TwoBedroom,
            program.unit_counts[2].saturating_sub(realized_mix[2]) as i32,
            2u8,
        ),
        (
            UnitType::ThreeBedroom,
            program.unit_counts[3].saturating_sub(realized_mix[3]) as i32,
            3u8,
        ),
    ];
    ordering.sort_by(|a, b| {
        b.1.cmp(&a.1).then_with(|| {
            if allow_unit_size_rebalance {
                a.2.cmp(&b.2)
            } else {
                Ordering::Equal
            }
        })
    });

    let mut seq = Vec::<UnitType>::new();
    for (unit_type, _, _) in ordering {
        let count = match unit_type {
            UnitType::Studio => program.unit_counts[0],
            UnitType::OneBedroom => program.unit_counts[1],
            UnitType::TwoBedroom => program.unit_counts[2],
            UnitType::ThreeBedroom => program.unit_counts[3],
        };
        for _ in 0..count {
            seq.push(unit_type);
        }
    }
    seq
}

fn solve_candidate_case_once(
    input: &NormalizedInput,
    massing: &MassingState,
    program: &ProgramState,
    verticals: &VerticalState,
    families: &[FloorFamily],
    concept: &ConceptOption,
    a: &AssumptionPack,
    candidate: CandidateCase,
    unit_seq_seed: &[UnitType],
    solve_attempt: usize,
) -> CandidateSolution {
    let mut all_floors = Vec::<FloorOutput>::new();
    let mut unit_seq = unit_seq_seed.to_vec();

    let residential_floors = candidate
        .story_count
        .saturating_sub(input.levels.below_grade_count + candidate.podium_levels)
        .max(1);
    let units_per_floor =
        (program.dwelling_units_total as f64 / residential_floors as f64).ceil() as usize;

    for family in families {
        let bindings = concept_bindings_for_family(concept, &family.family_id);
        let rects = bindings
            .iter()
            .map(|binding| binding.rect_seed)
            .collect::<Vec<_>>();
        let (footprint_polygon, footprint_components, footprint_voids) =
            build_footprint_geometry_from_rects(&rects);
        let level_guide_lines = rects_to_guide_lines(&rects, candidate.corridor_type);
        let concept_block_ids = bindings
            .iter()
            .map(|binding| binding.block_id.clone())
            .collect::<Vec<_>>();
        let mut master_floor: Option<FloorOutput> = None;
        let mut master_signature = Vec::<String>::new();
        for &level_index in &family.level_indices {
            let vertical_spaces =
                place_vertical_spaces(level_index, &family.family_id, &bindings, verticals);
            let zones = build_floor_zones(
                input,
                family,
                level_index,
                &candidate,
                &bindings,
                verticals,
                &vertical_spaces,
            );
            let zone_signature = floor_variant_signature(&zones);
            let (spaces, room_spaces, inherited_from_level_index, variant_kind, override_notes) =
                if family.is_typical {
                    if let Some(master) = &master_floor {
                        if zone_signature == master_signature {
                            let (cloned_spaces, cloned_rooms) =
                                clone_floor_artifacts_for_level(master, level_index);
                            (
                                cloned_spaces,
                                cloned_rooms,
                                Some(master.level_index),
                                "exact_repeat".to_string(),
                                vec!["cloned_from_typical_master".to_string()],
                            )
                        } else {
                            let (spaces, room_spaces) = build_spaces_from_floor_zones(
                                input,
                                program,
                                family,
                                families,
                                level_index,
                                &zones,
                                vertical_spaces,
                                &mut unit_seq,
                                units_per_floor,
                                a,
                            );
                            (
                                spaces,
                                room_spaces,
                                Some(master.level_index),
                                "derived_variant".to_string(),
                                vec![
                                    "level_specific_zone_override".to_string(),
                                    format!(
                                        "master_zone_count={} local_zone_count={}",
                                        master_signature.len(),
                                        zone_signature.len()
                                    ),
                                ],
                            )
                        }
                    } else {
                        let (spaces, room_spaces) = build_spaces_from_floor_zones(
                            input,
                            program,
                            family,
                            families,
                            level_index,
                            &zones,
                            vertical_spaces,
                            &mut unit_seq,
                            units_per_floor,
                            a,
                        );
                        (
                            spaces,
                            room_spaces,
                            None,
                            "typical_master".to_string(),
                            vec!["master_typical_solve".to_string()],
                        )
                    }
                } else {
                    let (spaces, room_spaces) = build_spaces_from_floor_zones(
                        input,
                        program,
                        family,
                        families,
                        level_index,
                        &zones,
                        vertical_spaces,
                        &mut unit_seq,
                        units_per_floor,
                        a,
                    );
                    (
                        spaces,
                        room_spaces,
                        None,
                        "unique".to_string(),
                        vec!["non_typical_family".to_string()],
                    )
                };

            let floor_output = FloorOutput {
                level_index,
                family_id: family.family_id.clone(),
                inherited_from_level_index,
                variant_kind,
                override_notes,
                footprint_polygon: footprint_polygon.clone(),
                footprint_components: footprint_components.clone(),
                footprint_voids: footprint_voids.clone(),
                concept_block_ids: concept_block_ids.clone(),
                zones,
                guide_lines: level_guide_lines.clone(),
                spaces,
                room_spaces,
                canonical_topology_graph: CanonicalTopologyGraph::empty(
                    format!("floor_L{:02}_canonical", level_index),
                    "floor",
                    "uninitialized",
                ),
                circulation_topology: FloorCirculationTopology::empty(
                    level_index,
                    family.family_id.clone(),
                ),
            };
            if family.is_typical && master_floor.is_none() {
                master_signature = zone_signature;
                master_floor = Some(floor_output.clone());
            }
            all_floors.push(floor_output);
        }
    }

    let gross_floor_area = all_floors
        .iter()
        .map(|floor| {
            footprint_area_from_geometry(&floor.footprint_components, &floor.footprint_voids)
                .max(polygon_area_sf(&floor.footprint_polygon))
        })
        .sum::<f64>();
    let (footprint_polygon, footprint_area) = all_floors
        .iter()
        .map(|floor| {
            let area =
                footprint_area_from_geometry(&floor.footprint_components, &floor.footprint_voids)
                    .max(polygon_area_sf(&floor.footprint_polygon));
            (floor.footprint_polygon.clone(), area)
        })
        .max_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal))
        .unwrap_or_else(|| (Vec::new(), 0.0));

    let candidate_id = candidate.candidate_id.clone();
    let mut candidate_solution = CandidateSolution {
        candidate_id: candidate_id.clone(),
        building_shape: candidate.building_shape,
        story_count: candidate.story_count,
        corridor_type: candidate.corridor_type,
        core_strategy: candidate.core_strategy,
        concept_score: concept.concept_score,
        score_total: 0.0,
        score_far: 0.0,
        score_dwelling_units: 0.0,
        score_yield: 0.0,
        score_amenity: 0.0,
        score_repeatability: 0.0,
        score_breakdown: CandidateScoreBreakdown::default(),
        diagnostics: CandidateDiagnostics::default(),
        feasibility: CandidateFeasibility::default(),
        footprint_polygon,
        floors: all_floors,
        canonical_topology_graph: CanonicalTopologyGraph::empty(
            format!("candidate_{}_canonical", candidate_id),
            "candidate",
            "uninitialized",
        ),
        repeatability_score: 0.0,
        footprint_area_sf: footprint_area,
        gross_floor_area_sf: gross_floor_area,
        validation_issues: Vec::new(),
        drift_metrics: Vec::new(),
        site_plan_bundle: Some(candidate.site_plan_bundle.clone()),
        site_spaces: Vec::new(),
        roof_spaces: Vec::new(),
        outdoor_site_topology_graph: None,
        roof_topology_graphs: Vec::new(),
        notes: vec![
            format!("solve_attempt={}", solve_attempt + 1),
            format!("shape={:?}", candidate.building_shape),
            format!("corridor={:?}", candidate.corridor_type),
            format!("core={:?}", candidate.core_strategy),
        ],
    };
    populate_space_topology_for_candidate(&mut candidate_solution, verticals);
    seed_candidate_topology_graphs(&mut candidate_solution);
    for floor in &mut candidate_solution.floors {
        floor.circulation_topology = build_mainline_floor_circulation_topology(floor);
    }
    let (mut site_spaces, mut outdoor_site_topology_graph) =
        build_site_spaces_and_topology(input, &candidate_solution);
    if let Some(space) = build_electrical_utility_infrastructure_exterior_site_space(
        &candidate_solution,
        program,
        a,
        site_spaces.len(),
    ) {
        outdoor_site_topology_graph.notes.push(
            "generated_site_support=Electrical Utilty Infrastructure - Exterior".to_string(),
        );
        site_spaces.push(space);
    }
    candidate_solution.site_spaces = site_spaces;
    candidate_solution.outdoor_site_topology_graph = Some(outdoor_site_topology_graph);
    let (roof_spaces, roof_topology_graphs) =
        build_roof_spaces_and_topologies(input, &candidate_solution, program, verticals, a);
    candidate_solution.roof_spaces = roof_spaces;
    candidate_solution.roof_topology_graphs = roof_topology_graphs;
    candidate_solution.validation_issues = validate_candidate_detail(&candidate_solution);
    candidate_solution.diagnostics =
        collect_candidate_diagnostics(input, massing, program, &candidate_solution);

    let score_far = clamp(
        candidate_solution.gross_floor_area_sf / massing.gfa_goal_sf.max(1.0),
        0.0,
        1.0,
    );
    let dwelling_cap = input
        .targets
        .dwelling_units_cap
        .unwrap_or(program.dwelling_units_total)
        .max(1);
    let score_du = clamp(
        candidate_solution.diagnostics.realized_dwelling_units as f64 / dwelling_cap as f64,
        0.0,
        1.0,
    );
    let target_mix = program.unit_counts;
    let mix_delta = [
        (target_mix[0] as i32 - candidate_solution.diagnostics.realized_dwelling_mix[0] as i32)
            .abs() as f64,
        (target_mix[1] as i32 - candidate_solution.diagnostics.realized_dwelling_mix[1] as i32)
            .abs() as f64,
        (target_mix[2] as i32 - candidate_solution.diagnostics.realized_dwelling_mix[2] as i32)
            .abs() as f64,
        (target_mix[3] as i32 - candidate_solution.diagnostics.realized_dwelling_mix[3] as i32)
            .abs() as f64,
    ]
    .iter()
    .sum::<f64>();
    let mix_alignment = clamp(
        1.0 - mix_delta / (2.0 * program.dwelling_units_total.max(1) as f64),
        0.0,
        1.0,
    );
    let area_alignment = clamp(
        1.0 - (candidate_solution.diagnostics.realized_avg_unit_area_sf
            - program.avg_unit_area_sf)
            .abs()
            / program.avg_unit_area_sf.max(1.0),
        0.0,
        1.0,
    );
    let score_yield = clamp(0.55 * mix_alignment + 0.45 * area_alignment, 0.0, 1.0);
    let realized_amenity = amenity_area_from_floors(&candidate_solution.floors)
        + candidate_solution
            .site_spaces
            .iter()
            .filter(|space| is_outdoor_or_roof_space(space))
            .map(|space| space.area_sf)
            .sum::<f64>()
        + candidate_solution
            .roof_spaces
            .iter()
            .filter(|space| is_outdoor_or_roof_space(space))
            .map(|space| space.area_sf)
            .sum::<f64>();
    let target_amenity = indoor_amenity_target_sf(input, program.dwelling_units_total, a)
        + outdoor_amenity_target_sf(input, program.dwelling_units_total, a);
    let score_amenity = clamp(realized_amenity / target_amenity.max(1.0), 0.0, 1.0);
    let exact_repeat_count = candidate_solution
        .floors
        .iter()
        .filter(|floor| floor.variant_kind == "exact_repeat")
        .count();
    let derived_variant_count = candidate_solution
        .floors
        .iter()
        .filter(|floor| floor.variant_kind == "derived_variant")
        .count();
    let repeatability = if families.iter().any(|f| f.is_typical) {
        clamp(
            0.92 + 0.02 * exact_repeat_count as f64
                - 0.10 * derived_variant_count as f64
                    / candidate_solution.floors.len().max(1) as f64,
            0.0,
            1.0,
        )
    } else {
        0.62
    };
    let w = &input.optimization.weights;
    let base_total = w.far * score_far
        + w.dwelling_units * score_du
        + w.yield_ * score_yield
        + w.amenity * score_amenity
        + w.repeatability * repeatability;

    candidate_solution.score_far = score_far;
    candidate_solution.score_dwelling_units = score_du;
    candidate_solution.score_yield = score_yield;
    candidate_solution.score_amenity = score_amenity;
    candidate_solution.score_repeatability = repeatability;
    candidate_solution.repeatability_score = repeatability;
    candidate_solution.score_total = base_total;
    candidate_solution.score_breakdown = CandidateScoreBreakdown {
        concept_pre_score: concept.concept_score,
        solved_far_score: score_far,
        solved_dwelling_units_score: score_du,
        solved_yield_score: score_yield,
        solved_amenity_score: score_amenity,
        solved_repeatability_score: repeatability,
        total_score: base_total,
        ..CandidateScoreBreakdown::default()
    };
    candidate_solution.notes.extend([
        format!(
            "parcel_fit_ratio={:.3}",
            massing.shape_diagnostics.parcel_fit_ratio
        ),
        format!(
            "realized_units={}/{}",
            candidate_solution.diagnostics.realized_dwelling_units, program.dwelling_units_total
        ),
        format!("repeatability={:.3}", repeatability),
    ]);
    candidate_solution
}

pub fn solve_candidate_case(
    input: &NormalizedInput,
    massing: &MassingState,
    program: &ProgramState,
    verticals: &VerticalState,
    families: &[FloorFamily],
    concept: &ConceptOption,
    a: &AssumptionPack,
    candidate: CandidateCase,
) -> CandidateSolution {
    let mut unit_seq = split_unit_sequence(program.unit_counts);
    sort_unit_sequence_for_packing(&mut unit_seq);
    let attempt_cap = if input.optimization.allow_unit_mix_rebalance
        || input.optimization.allow_unit_size_rebalance
    {
        2
    } else {
        1
    };
    let mut best_solution: Option<CandidateSolution> = None;

    for attempt in 0..attempt_cap {
        let solved = solve_candidate_case_once(
            input,
            massing,
            program,
            verticals,
            families,
            concept,
            a,
            candidate.clone(),
            &unit_seq,
            attempt,
        );
        let should_replace = best_solution
            .as_ref()
            .map(|best| solved.score_total > best.score_total)
            .unwrap_or(true);
        if should_replace {
            best_solution = Some(solved.clone());
        }
        if attempt + 1 >= attempt_cap
            || solved.diagnostics.realized_dwelling_units >= program.dwelling_units_total
        {
            break;
        }
        unit_seq = rebalance_unit_sequence(
            program,
            solved.diagnostics.realized_dwelling_mix,
            input.optimization.allow_unit_size_rebalance,
        );
    }

    let mut candidate_solution =
        best_solution.expect("solve_candidate_case should produce a candidate");
    candidate_solution.diagnostics =
        collect_candidate_diagnostics(input, massing, program, &candidate_solution);
    apply_candidate_detail_penalties(&mut candidate_solution);
    candidate_solution
}

