/* ========================= Repo Integration Layer ========================= */

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RepoIntegrationMode {
    OfflineBatch,
    RepoCaseGeneration,
    RepoRuntimePreview,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SpaceNameMode {
    SemanticCategoryIndex,
    SemanticOnly,
    Existing,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PreferredViewMode {
    Plan,
    SitePlan,
    ThreeD,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FeasibilityStatus {
    FullyFeasible,
    ConditionallyFeasible,
    DeferredZonesPresent,
    NotRepoContractSafe,
}

#[derive(Debug, Clone)]
pub struct RepoExportInput {
    pub enabled: bool,
    pub integration_mode: RepoIntegrationMode,
    pub target_format: String,
    pub space_name_mode: SpaceNameMode,
    pub include_engine_metadata: bool,
    pub include_site_plan: bool,
    pub case_group: String,
    pub preferred_view: PreferredViewMode,
}

#[derive(Debug, Clone)]
pub struct FeasibilityControlsInput {
    pub strict_repo_contract: bool,
    pub mark_unclear_before_deep_solve: bool,
    pub allow_deferred_zones: bool,
    pub max_unclear_zones: usize,
}

#[derive(Debug, Clone)]
pub struct RepoIntegrationLayoutInput {
    pub jurisdiction_profile: JurisdictionProfile,
    pub building_shape: BuildingShape,
    pub building_construction_type: BuildingConstructionType,
    pub site_polygon: Vec<Point2>,
    pub levels: LevelsInput,
    pub unit_mix: UnitMix,
    pub constraints: ConstraintsInput,
    pub residential_features: ResidentialFeaturesInput,
    pub vertical_rules: VerticalRulesInput,
    pub amenities: AmenitiesInput,
    pub targets: TargetsInput,
    pub optimization: OptimizationInput,
    pub code_profile_overrides: Option<CodeProfileOverridesInput>,
    pub shape_parameters: Option<ShapeParametersInput>,
    pub solver_controls: Option<SolverControlsInput>,
    pub user_overrides: Vec<UserOverride>,
    pub repo_export: RepoExportInput,
    pub feasibility_controls: FeasibilityControlsInput,
}

impl RepoIntegrationLayoutInput {
    pub fn validate(&self) -> Vec<ValidationIssue> {
        let mut issues = self.to_core().validate();

        if self.feasibility_controls.max_unclear_zones == 0 {
            issues.push(ValidationIssue::warning(
                "max_unclear_zones_zero",
                "feasibility_controls.max_unclear_zones = 0 means any unresolved zone should be treated as a hard stop by downstream orchestration",
            ));
        }

        if self.feasibility_controls.strict_repo_contract
            && matches!(
                self.repo_export.integration_mode,
                RepoIntegrationMode::RepoRuntimePreview
            )
        {
            issues.push(ValidationIssue::warning(
                "repo_runtime_preview_contract_conflict",
                "RepoRuntimePreview conflicts with the current GLOQSpaceAllocation ownership contract unless an explicit architecture exception is granted",
            ));
        }

        issues
    }

    pub fn to_core(&self) -> LayoutInput {
        LayoutInput {
            jurisdiction_profile: self.jurisdiction_profile.clone(),
            building_shape: self.building_shape,
            building_construction_type: self.building_construction_type,
            site_polygon: self.site_polygon.clone(),
            site_planning: SitePlanningInput {
                california_mode: matches!(
                    self.jurisdiction_profile.state_amendment_profile,
                    StateAmendmentProfile::Ca2022Title24 | StateAmendmentProfile::Ca2025Title24
                ),
                overlay: SiteOverlayReferenceInput {
                    binding_mode: if self.jurisdiction_profile.local_overlay_id.is_some() {
                        SiteOverlayBindingMode::Assumed
                    } else {
                        SiteOverlayBindingMode::Missing
                    },
                    overlay_id: self.jurisdiction_profile.local_overlay_id.clone(),
                    source_tag: Some("jurisdiction_profile.local_overlay_id".to_string()),
                },
                ..SitePlanningInput::default()
            },
            levels: self.levels.clone(),
            unit_mix: self.unit_mix.clone(),
            constraints: self.constraints.clone(),
            residential_features: self.residential_features.clone(),
            vertical_rules: self.vertical_rules.clone(),
            amenities: self.amenities.clone(),
            targets: self.targets.clone(),
            optimization: self.optimization.clone(),
            code_profile_overrides: self.code_profile_overrides.clone(),
            shape_parameters: self.shape_parameters.clone(),
            solver_controls: self.solver_controls.clone(),
            user_overrides: self.user_overrides.clone(),
        }
    }
}

