#[derive(Debug, Clone)]
pub struct RepoIntegrationLayoutOutput {
    pub engine_layer: LayoutEngineLayer,
    pub feasibility_status: FeasibilityStatus,
    pub repo_contract_evaluation: RepoContractEvaluation,
    pub preflight_unclear_zones: Vec<UnclearZone>,
    pub postsolve_unclear_zones: Vec<UnclearZone>,
    pub project_doc_export: ProjectDocExport,
    pub core_output: LayoutOutput,
}

#[derive(Debug, Clone, Default)]
pub struct RepoIntegrationLayoutEngine {
    pub inner: LayoutEngine,
}

impl RepoIntegrationLayoutEngine {
    pub fn run(&self, input: RepoIntegrationLayoutInput) -> RepoIntegrationLayoutOutput {
        let preflight_unclear_zones = identify_preflight_unclear_zones(&input);
        let core_output = self.inner.run(input.to_core());
        let postsolve_unclear_zones = identify_postsolve_unclear_zones(&input, &core_output);
        let merged_unclear =
            merge_unclear_zones(&preflight_unclear_zones, &postsolve_unclear_zones);
        let repo_contract_evaluation =
            evaluate_repo_contract_from_unclear_zones(&input, &merged_unclear);
        let feasibility_status = classify_feasibility_status(
            &input,
            &core_output,
            &repo_contract_evaluation,
            &merged_unclear,
        );
        let project_doc_export = build_project_doc_export_base(&input, &core_output);

        RepoIntegrationLayoutOutput {
            engine_layer: LayoutEngineLayer::RepoIntegration,
            feasibility_status,
            repo_contract_evaluation,
            preflight_unclear_zones,
            postsolve_unclear_zones,
            project_doc_export,
            core_output,
        }
    }
}

pub fn identify_preflight_unclear_zones(input: &RepoIntegrationLayoutInput) -> Vec<UnclearZone> {
    let mut zones = Vec::<UnclearZone>::new();

    if input.jurisdiction_profile.local_overlay_id.is_none() {
        zones.push(UnclearZone::new(
            "local_overlay_missing",
            ValidationSeverity::Warning,
            SolvePhase::InputNormalization,
            "code-profile",
            "No local_overlay_id was provided. The base IBC/state profile may be insufficient for egress, parking, and local zoning numerics.",
            "Conditional feasibility only; local amendments and zoning numerics remain unresolved.",
            LayoutEngineLayer::OverlayAware,
            false,
        ));
    }

    if matches!(
        input.building_shape,
        BuildingShape::FreeForm | BuildingShape::Cluster | BuildingShape::XShape
    ) {
        zones.push(UnclearZone::new(
            "complex_shape_template_uncertain",
            ValidationSeverity::Warning,
            SolvePhase::FloorZoning,
            "geometry-template",
            "The selected building_shape uses a high-variance template family. repo-integration still treats this as a guided heuristic rather than a fully deterministic topology solver.",
            "Template quality may vary substantially with irregular parcels.",
            LayoutEngineLayer::SpatialGeometry,
            false,
        ));
    }

    if input.constraints.parking_mode != ParkingMode::None
        && input.jurisdiction_profile.local_overlay_id.is_none()
    {
        zones.push(UnclearZone::new(
            "parking_ordinance_not_bound",
            ValidationSeverity::Warning,
            SolvePhase::ProgramTargets,
            "zoning-parking",
            "Parking mode is active, but no local zoning overlay was supplied. Parking demand and geometry remain only partially grounded.",
            "Parking may be under- or over-sized relative to the actual jurisdiction.",
            LayoutEngineLayer::OverlayAware,
            false,
        ));
    }

    if input.levels.below_grade_count + input.levels.podium_levels >= input.levels.count {
        zones.push(UnclearZone::new(
            "floor_stack_partition_invalid",
            ValidationSeverity::Error,
            SolvePhase::MassingTargets,
            "floor-stack",
            "The floor stack does not leave an upper residential interval after below-grade and podium allocation.",
            "Typical-floor generation becomes undefined.",
            LayoutEngineLayer::RepoIntegration,
            true,
        ));
    }

    if input.repo_export.enabled {
        zones.push(UnclearZone::new(
            "project_doc_semantic_loss",
            ValidationSeverity::Info,
            SolvePhase::OutputAssembly,
            "repo-export",
            "GLOQSpaceAllocation ProjectDoc stores only id/name/levelId/footprint for spaces. Rich space category metadata must remain in the engine sidecar output.",
            "Direct ProjectDoc export loses some semantics unless sidecar JSON is preserved.",
            LayoutEngineLayer::OverlayAware,
            false,
        ));
    }

    if input.feasibility_controls.strict_repo_contract
        && matches!(
            input.repo_export.integration_mode,
            RepoIntegrationMode::RepoRuntimePreview
        )
    {
        zones.push(UnclearZone::new(
            "repo_runtime_preview_not_contract_safe",
            ValidationSeverity::Error,
            SolvePhase::InputNormalization,
            "repo-contract",
            "Rust runtime preview mode conflicts with the current GLOQSpaceAllocation contract where TypeScript owns ProjectDoc and geometry logic.",
            "Runtime integration is not contract-safe without an explicit architecture exception.",
            LayoutEngineLayer::OverlayAware,
            true,
        ));
    }

    zones
}

pub fn identify_postsolve_unclear_zones(
    input: &RepoIntegrationLayoutInput,
    output: &LayoutOutput,
) -> Vec<UnclearZone> {
    let mut zones = Vec::<UnclearZone>::new();

    if output.selected_candidate.floors.is_empty() {
        zones.push(UnclearZone::new(
            "selected_candidate_has_no_floors",
            ValidationSeverity::Error,
            SolvePhase::SpaceLayout,
            "solver-result",
            "The selected candidate contains no floor outputs.",
            "ProjectDoc export and downstream review are not meaningful.",
            LayoutEngineLayer::RepoIntegration,
            true,
        ));
    }

    if input.vertical_rules.repeat_typical_floors
        && output.selected_candidate.repeatability_score < 0.75
    {
        zones.push(UnclearZone::new(
            "typical_floor_similarity_low",
            ValidationSeverity::Warning,
            SolvePhase::SpaceLayout,
            "repeatability",
            "Typical-floor repetition was requested, but the solved repeatability score remains below the preferred threshold.",
            "Sibling floors may diverge more than expected.",
            LayoutEngineLayer::OverlayAware,
            false,
        ));
    }

    if input.constraints.min_daylight {
        zones.push(UnclearZone::new(
            "daylight_is_facade_proxy",
            ValidationSeverity::Info,
            SolvePhase::SpaceLayout,
            "daylight",
            "repo-integration checks daylight by facade-contact and max-depth proxies. It does not yet solve room-by-room daylight legality.",
            "Manual review is still required for final unit planning.",
            LayoutEngineLayer::SpatialGeometry,
            false,
        ));
    }

    zones
}

pub fn merge_unclear_zones(a: &[UnclearZone], b: &[UnclearZone]) -> Vec<UnclearZone> {
    let mut by_id = BTreeMap::<String, UnclearZone>::new();
    for zone in a.iter().chain(b.iter()) {
        by_id.entry(zone.id.clone()).or_insert_with(|| zone.clone());
    }
    by_id.into_values().collect()
}

pub fn evaluate_repo_contract_from_unclear_zones(
    input: &RepoIntegrationLayoutInput,
    merged_unclear: &[UnclearZone],
) -> RepoContractEvaluation {
    let requested_mode = input.repo_export.integration_mode;
    let mut resolved_mode = requested_mode;
    let mut contract_safe = true;
    let mut notes = Vec::<String>::new();

    match requested_mode {
        RepoIntegrationMode::OfflineBatch => {
            notes
                .push("OfflineBatch keeps Rust outside the live GLOQ editor contract.".to_string());
        }
        RepoIntegrationMode::RepoCaseGeneration => {
            notes.push("RepoCaseGeneration is contract-safe if the engine emits ProjectDoc snapshots plus sidecar engine JSON.".to_string());
        }
        RepoIntegrationMode::RepoRuntimePreview => {
            if input.feasibility_controls.strict_repo_contract {
                resolved_mode = RepoIntegrationMode::RepoCaseGeneration;
                contract_safe = false;
                notes.push("Requested RepoRuntimePreview was downgraded to RepoCaseGeneration because strict_repo_contract=true.".to_string());
            } else {
                notes.push("RepoRuntimePreview remains conditionally allowed only as a non-canonical suggestion path.".to_string());
            }
        }
    }

    if merged_unclear.iter().any(|zone| zone.blocks_repo_runtime) {
        contract_safe =
            contract_safe && !matches!(requested_mode, RepoIntegrationMode::RepoRuntimePreview);
    }

    if input.repo_export.enabled {
        notes.push("ProjectDoc should stay canonical in TypeScript; engine output should be treated as a proposal and exported snapshot.".to_string());
    }

    RepoContractEvaluation {
        requested_mode,
        resolved_mode,
        contract_safe,
        notes,
    }
}

pub fn classify_feasibility_status(
    input: &RepoIntegrationLayoutInput,
    core: &LayoutOutput,
    repo: &RepoContractEvaluation,
    unclear: &[UnclearZone],
) -> FeasibilityStatus {
    if input.feasibility_controls.strict_repo_contract && !repo.contract_safe {
        return FeasibilityStatus::NotRepoContractSafe;
    }

    if matches!(core.solution_status, SolutionStatus::Infeasible)
        || unclear
            .iter()
            .any(|z| matches!(z.severity, ValidationSeverity::Error))
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }

    if !unclear.is_empty() {
        return FeasibilityStatus::ConditionallyFeasible;
    }

    FeasibilityStatus::FullyFeasible
}

pub fn project_doc_default_story_height_ft(input: &RepoIntegrationLayoutInput) -> f64 {
    if input.levels.count <= 4 {
        10.0
    } else if input.levels.count <= 9 {
        11.0
    } else {
        12.0
    }
}

pub fn level_stack_specs(input: &RepoIntegrationLayoutInput) -> Vec<GloqLevel> {
    let mut levels = Vec::<GloqLevel>::new();
    let total = input.levels.count;
    let below = input.levels.below_grade_count;
    let default_h = project_doc_default_story_height_ft(input);

    for i in 0..below {
        let ordinal = below - i;
        levels.push(GloqLevel {
            id: format!("level-b{}", ordinal),
            name: format!("Basement {}", ordinal),
            elevationFt: -(ordinal as f64) * default_h,
            heightFt: default_h,
        });
    }

    let above = total.saturating_sub(below);
    for j in 0..above {
        levels.push(GloqLevel {
            id: format!("level-{}", j + 1),
            name: format!("Level {}", j + 1),
            elevationFt: j as f64 * default_h,
            heightFt: default_h,
        });
    }

    levels
}

pub fn level_id_for_export_levels(levels: &[GloqLevel], idx: u32) -> String {
    levels
        .get(idx as usize)
        .map(|x| x.id.clone())
        .unwrap_or_else(|| format!("level-unknown-{}", idx))
}

pub fn space_name_from_mode(mode: SpaceNameMode, placement: &SpacePlacement, seq: usize) -> String {
    match mode {
        SpaceNameMode::SemanticCategoryIndex => format!(
            "{} / {:03} / {}",
            placement.category, seq, placement.space_name
        ),
        SpaceNameMode::SemanticOnly => placement.category.clone(),
        SpaceNameMode::Existing => {
            if placement.space_name.trim().is_empty() {
                placement.category.clone()
            } else {
                placement.space_name.clone()
            }
        }
    }
}

pub fn to_gloq_points(points: &[Point2]) -> Vec<GloqPoint2Ft> {
    points
        .iter()
        .map(|p| GloqPoint2Ft {
            xFt: snap_ft(p.x, 0.01),
            yFt: snap_ft(p.y, 0.01),
        })
        .collect()
}

pub fn build_project_doc_export_base(
    input: &RepoIntegrationLayoutInput,
    core: &LayoutOutput,
) -> ProjectDocExport {
    if !input.repo_export.enabled {
        return ProjectDocExport {
            enabled: false,
            target_format: input.repo_export.target_format.clone(),
            preferred_view: preferred_view_string(input.repo_export.preferred_view),
            doc: None,
            notes: vec!["repo_export.enabled = false".to_string()],
        };
    }

    let levels = level_stack_specs(input);
    let default_story_height_ft = project_doc_default_story_height_ft(input);
    let mut spaces = Vec::<GloqSpace>::new();

    let mut seq = 1usize;
    for floor in &core.selected_candidate.floors {
        let level_id = level_id_for_export_levels(&levels, floor.level_index);
        for placement in &floor.spaces {
            let polygon = if !placement.polygon.is_empty() {
                placement.polygon.clone()
            } else {
                placement.rect.to_polygon()
            };
            spaces.push(GloqSpace {
                id: format!("space-auto-{:03}", seq),
                levelId: level_id.clone(),
                name: space_name_from_mode(input.repo_export.space_name_mode, placement, seq),
                footprint: to_gloq_points(&polygon),
            });
            seq += 1;
        }
    }

    let site_plan = if input.repo_export.include_site_plan {
        let host_level = levels
            .iter()
            .find(|level| level.elevationFt >= -EPS)
            .map(|level| level.id.clone())
            .unwrap_or_else(|| {
                levels
                    .first()
                    .map(|x| x.id.clone())
                    .unwrap_or_else(|| "level-1".to_string())
            });
        Some(GloqSitePlan {
            levelId: host_level,
            boundary: to_gloq_points(&input.site_polygon),
            edgeSetbacksFt: vec![5.0; input.site_polygon.len()],
        })
    } else {
        None
    };

    let mut notes = Vec::<String>::new();
    notes.push("edgeSetbacksFt defaults to 5.0 ft because the repo-integration apartment engine input does not yet carry per-edge site setbacks.".to_string());
    notes.push(
        "Space category semantics remain richer in engine sidecar output than in ProjectDoc."
            .to_string(),
    );
    if input.repo_export.include_engine_metadata {
        notes.push(
            "Preserve engine output JSON alongside ProjectDoc to avoid semantic loss.".to_string(),
        );
    }

    let doc = GloqProjectDoc {
        id: format!("autolayout-{}", input.repo_export.case_group),
        name: format!("Autolayout {}", input.repo_export.case_group),
        defaultStoryHeightFt: default_story_height_ft,
        levels,
        spaces,
        sitePlan: site_plan,
    };

    ProjectDocExport {
        enabled: true,
        target_format: input.repo_export.target_format.clone(),
        preferred_view: preferred_view_string(input.repo_export.preferred_view),
        doc: Some(doc),
        notes,
    }
}

pub fn preferred_view_string(view: PreferredViewMode) -> String {
    match view {
        PreferredViewMode::Plan => "plan".to_string(),
        PreferredViewMode::SitePlan => "site-plan".to_string(),
        PreferredViewMode::ThreeD => "3d".to_string(),
    }
}

