#[derive(Debug, Clone, Default)]
pub struct OverlayAwareLayoutEngine {
    pub inner: LayoutEngine,
}

impl OverlayAwareLayoutInput {
    pub fn validate(&self) -> Vec<ValidationIssue> {
        let mut issues = self.to_core().validate();

        if self.site_polygon.len() != self.site_controls.edge_setbacks_ft.len() {
            issues.push(ValidationIssue::error(
                "edge_setback_count_mismatch",
                "site_controls.edge_setbacks_ft length must equal the number of site polygon edges",
            ));
        }

        if self.site_controls.min_buildable_area_sf <= 0.0 {
            issues.push(ValidationIssue::error(
                "min_buildable_area_nonpositive",
                "site_controls.min_buildable_area_sf must be > 0",
            ));
        }

        if self.repeatability_controls.fail_threshold > self.repeatability_controls.warn_threshold {
            issues.push(ValidationIssue::error(
                "repeatability_threshold_order_invalid",
                "repeatability_controls.fail_threshold must be <= warn_threshold",
            ));
        }

        if self
            .feasibility_controls
            .require_bound_local_overlay_for_parking
            && self.constraints.parking_mode != ParkingMode::None
            && !matches!(
                self.local_overlay_pack.binding_mode,
                OverlayBindingMode::Bound
            )
        {
            issues.push(ValidationIssue::warning(
                "parking_requires_bound_overlay",
                "Parking is active and the feasibility policy requires a bound local overlay pack.",
            ));
        }

        if self.repo_export.enabled
            && self
                .feasibility_controls
                .require_projection_bundle_for_repo_export
            && matches!(
                self.repo_export.projection_bundle_mode,
                ProjectionBundleMode::None
            )
        {
            issues.push(ValidationIssue::error(
                "projection_bundle_required",
                "Projection bundle export is required when repo_export.enabled = true by the overlay-aware feasibility policy.",
            ));
        }

        issues
    }

    pub fn to_core(&self) -> LayoutInput {
        LayoutInput {
            jurisdiction_profile: self.jurisdiction_profile.clone(),
            building_shape: self.building_shape,
            building_construction_type: self.building_construction_type,
            site_polygon: self.site_polygon.clone(),
            site_planning: SitePlanningInput {
                california_mode: matches!(
                    self.jurisdiction_profile.state_amendment_profile,
                    StateAmendmentProfile::Ca2022Title24 | StateAmendmentProfile::Ca2025Title24
                ),
                frontage: SiteFrontageControlsInput {
                    frontage_edge_indices: self
                        .site_controls
                        .frontage_edge_indices
                        .iter()
                        .map(|idx| *idx as usize)
                        .collect(),
                    entry_edge_indices: self
                        .site_controls
                        .entry_edge_indices
                        .iter()
                        .map(|idx| *idx as usize)
                        .collect(),
                    fire_access_edge_indices: self
                        .site_controls
                        .fire_access_edge_indices
                        .iter()
                        .map(|idx| *idx as usize)
                        .collect(),
                    service_access_edge_indices: self
                        .site_controls
                        .service_access_edge_indices
                        .iter()
                        .map(|idx| *idx as usize)
                        .collect(),
                    privacy_edge_indices: Vec::new(),
                    allow_service_on_public_front: false,
                    prioritize_multiple_fronts: self.site_controls.frontage_edge_indices.len() > 1,
                },
                buildable: SiteBuildableEnvelopeInput {
                    edge_setbacks_ft: self.site_controls.edge_setbacks_ft.clone(),
                    min_buildable_area_sf: self.site_controls.min_buildable_area_sf,
                    setback_snap_ft: self.site_controls.setback_snap_ft,
                    ..SiteBuildableEnvelopeInput::default()
                },
                fire_access: SiteFireAccessControlsInput {
                    required: !self.site_controls.fire_access_edge_indices.is_empty(),
                    preferred_clear_width_ft: Some(20.0),
                    apparatus_reach_depth_ft: Some(24.0),
                },
                clearance: SiteClearanceReserveInput {
                    public_walk_width_ft: Some(
                        self.local_overlay_pack
                            .egress
                            .min_corridor_clear_width_ft
                            .unwrap_or(10.0)
                            .max(10.0),
                    ),
                    accessible_walk_width_ft: Some(
                        self.local_overlay_pack
                            .egress
                            .min_corridor_clear_width_ft
                            .unwrap_or(8.0)
                            .max(8.0),
                    ),
                    service_path_width_ft: Some(14.0),
                    fire_lane_width_ft: Some(20.0),
                    parking_walk_width_ft: Some(7.0),
                    drive_aisle_width_ft: Some(24.0),
                    turning_radius_ft: Some(28.0),
                },
                parking: SiteParkingControlsInput {
                    guest_stalls_per_du: None,
                    tdm_reduction_ratio: self.parking_program.tdm_reduction_ratio,
                    accessible_stall_ratio: None,
                    provided_stalls_cap: self.parking_program.provided_stalls_cap,
                    allow_shared_retail_parking: self.parking_program.allow_shared_retail_parking,
                },
                overlay: SiteOverlayReferenceInput {
                    binding_mode: match self.local_overlay_pack.binding_mode {
                        OverlayBindingMode::Bound => SiteOverlayBindingMode::Bound,
                        OverlayBindingMode::Assumed => SiteOverlayBindingMode::Assumed,
                        OverlayBindingMode::Missing => SiteOverlayBindingMode::Missing,
                    },
                    overlay_id: Some(self.local_overlay_pack.overlay_id.clone()),
                    source_tag: Some(self.local_overlay_pack.source_tag.clone()),
                },
                ..SitePlanningInput::default()
            },
            levels: self.levels.clone(),
            unit_mix: self.unit_mix.clone(),
            constraints: self.constraints.clone(),
            residential_features: self.residential_features.clone(),
            vertical_rules: self.vertical_rules.clone(),
            amenities: AmenitiesInput {
                strategy: self.amenities.strategy,
                indoor_target_sf: self.amenities.indoor_target_sf,
                outdoor_target_sf: self.amenities.outdoor_target_sf,
                include: self.amenities.include.clone(),
                exclude: self.amenities.exclude.clone(),
            },
            targets: self.targets.clone(),
            optimization: self.optimization.clone(),
            code_profile_overrides: self.code_profile_overrides.clone(),
            shape_parameters: self
                .shape_parameters
                .as_ref()
                .map(|x| ShapeParametersInput {
                    target_wing_depth_ft: x.target_wing_depth_ft,
                    target_courtyard_width_ft: x.target_courtyard_width_ft,
                    tower_core_area_ratio: x.tower_core_area_ratio,
                    perimeter_bar_width_ft: x.perimeter_bar_width_ft,
                }),
            solver_controls: self.solver_controls.as_ref().map(|x| SolverControlsInput {
                max_threads: x.max_threads,
                candidate_count: x.max_candidates,
                floor_family_parallel: x.enable_floor_family_parallel,
                candidate_parallel: x.enable_candidate_parallel,
                shape_search_enabled: None,
                shape_search_limit: None,
                prune_incompatible_candidates: None,
            }),
            user_overrides: self.user_overrides.clone(),
        }
    }

    pub fn to_repo_integration_input(&self) -> RepoIntegrationLayoutInput {
        RepoIntegrationLayoutInput {
            jurisdiction_profile: self.jurisdiction_profile.clone(),
            building_shape: self.building_shape,
            building_construction_type: self.building_construction_type,
            site_polygon: self.site_polygon.clone(),
            levels: self.levels.clone(),
            unit_mix: self.unit_mix.clone(),
            constraints: self.constraints.clone(),
            residential_features: self.residential_features.clone(),
            vertical_rules: self.vertical_rules.clone(),
            amenities: AmenitiesInput {
                strategy: self.amenities.strategy,
                indoor_target_sf: self.amenities.indoor_target_sf,
                outdoor_target_sf: self.amenities.outdoor_target_sf,
                include: self.amenities.include.clone(),
                exclude: self.amenities.exclude.clone(),
            },
            targets: self.targets.clone(),
            optimization: self.optimization.clone(),
            code_profile_overrides: self.code_profile_overrides.clone(),
            shape_parameters: self
                .shape_parameters
                .as_ref()
                .map(|x| ShapeParametersInput {
                    target_wing_depth_ft: x.target_wing_depth_ft,
                    target_courtyard_width_ft: x.target_courtyard_width_ft,
                    tower_core_area_ratio: x.tower_core_area_ratio,
                    perimeter_bar_width_ft: x.perimeter_bar_width_ft,
                }),
            solver_controls: self.solver_controls.as_ref().map(|x| SolverControlsInput {
                max_threads: x.max_threads,
                candidate_count: x.max_candidates,
                floor_family_parallel: x.enable_floor_family_parallel,
                candidate_parallel: x.enable_candidate_parallel,
                shape_search_enabled: None,
                shape_search_limit: None,
                prune_incompatible_candidates: None,
            }),
            user_overrides: self.user_overrides.clone(),
            repo_export: RepoExportInput {
                enabled: self.repo_export.enabled,
                integration_mode: self.repo_export.integration_mode,
                target_format: self.repo_export.target_format.clone(),
                space_name_mode: self.repo_export.space_name_mode,
                include_engine_metadata: self.repo_export.include_engine_metadata,
                include_site_plan: self.repo_export.include_site_plan,
                case_group: self.repo_export.case_group.clone(),
                preferred_view: self.repo_export.preferred_view,
            },
            feasibility_controls: FeasibilityControlsInput {
                strict_repo_contract: self.feasibility_controls.strict_repo_contract,
                mark_unclear_before_deep_solve: self
                    .feasibility_controls
                    .mark_unclear_before_deep_solve,
                allow_deferred_zones: self.feasibility_controls.allow_deferred_zones,
                max_unclear_zones: self.feasibility_controls.max_unclear_zones,
            },
        }
    }
}

impl OverlayAwareLayoutEngine {
    pub fn run(&self, input: OverlayAwareLayoutInput) -> OverlayAwareLayoutOutput {
        let preflight_unclear_zones = identify_preflight_unclear_zones_with_local_overlay(&input);
        let core_output = self.inner.run(input.to_core());
        let postsolve_unclear_zones =
            identify_postsolve_unclear_zones_with_local_overlay(&input, &core_output);
        let local_overlay_evaluation = evaluate_local_overlay(&input);
        let parking_binding_evaluation = evaluate_parking_binding(&input, &core_output);
        let repeatability_evaluation = evaluate_repeatability(&input, &core_output);
        let projection_bundle = build_projection_bundle(&input, &core_output);
        let repo_contract_evaluation = evaluate_repo_contract_with_runtime_guard(&input);
        let project_doc_export = build_project_doc_export_with_projection_bundle(
            &input,
            &core_output,
            &projection_bundle,
        );

        let feasibility_status = classify_feasibility_status_with_local_overlay(
            &input,
            &core_output,
            &repo_contract_evaluation,
            &preflight_unclear_zones,
            &postsolve_unclear_zones,
            &repeatability_evaluation,
            &local_overlay_evaluation,
            &projection_bundle,
        );

        OverlayAwareLayoutOutput {
            engine_layer: LayoutEngineLayer::OverlayAware,
            feasibility_status,
            repo_contract_evaluation,
            local_overlay_evaluation,
            parking_binding_evaluation,
            repeatability_evaluation,
            preflight_unclear_zones,
            postsolve_unclear_zones,
            project_doc_export,
            projection_bundle,
            core_output,
        }
    }
}

pub fn identify_preflight_unclear_zones_with_local_overlay(
    input: &OverlayAwareLayoutInput,
) -> Vec<UnclearZone> {
    let mut zones = Vec::<UnclearZone>::new();

    if input.site_polygon.len() != input.site_controls.edge_setbacks_ft.len() {
        zones.push(UnclearZone::new(
            "edge_setback_count_mismatch",
            ValidationSeverity::Error,
            SolvePhase::InputNormalization,
            "site-controls",
            "edge_setbacks_ft length does not match the site polygon edge count.",
            "Buildable polygon offset cannot be evaluated reliably.",
            LayoutEngineLayer::OverlayAware,
            true,
        ));
    }

    if !matches!(
        input.local_overlay_pack.binding_mode,
        OverlayBindingMode::Bound
    ) {
        zones.push(UnclearZone::new(
            "local_overlay_missing_or_assumed",
            ValidationSeverity::Warning,
            SolvePhase::InputNormalization,
            "code-profile",
            "The local overlay pack is not fully bound. Some jurisdiction-specific numerics remain assumed.",
            "Feasibility can be conditional only unless the downstream policy explicitly accepts assumed overlays.",
            LayoutEngineLayer::SpatialGeometry,
            false,
        ));
    }

    if input.constraints.parking_mode != ParkingMode::None
        && input
            .feasibility_controls
            .require_bound_local_overlay_for_parking
        && !matches!(
            input.local_overlay_pack.binding_mode,
            OverlayBindingMode::Bound
        )
    {
        zones.push(UnclearZone::new(
            "parking_binding_heuristic_only",
            ValidationSeverity::Warning,
            SolvePhase::ProgramTargets,
            "zoning-parking",
            "Parking is active but the local overlay pack is not fully bound.",
            "Parking demand may still be only partially grounded.",
            LayoutEngineLayer::OverlayAware,
            false,
        ));
    }

    if input.repo_export.enabled
        && input
            .feasibility_controls
            .require_projection_bundle_for_repo_export
        && matches!(
            input.repo_export.projection_bundle_mode,
            ProjectionBundleMode::None
        )
    {
        zones.push(UnclearZone::new(
            "projection_bundle_missing",
            ValidationSeverity::Error,
            SolvePhase::OutputAssembly,
            "repo-export",
            "Repo export is enabled but projection bundle export is disabled.",
            "Semantic loss becomes too high for overlay-aware contract expectations.",
            LayoutEngineLayer::OverlayAware,
            true,
        ));
    }

    if matches!(
        input.repo_export.integration_mode,
        RepoIntegrationMode::RepoRuntimePreview
    ) && matches!(
        input.repo_export.runtime_preview_guard,
        RuntimePreviewGuard::Disabled
    ) {
        zones.push(UnclearZone::new(
            "repo_runtime_preview_guard_disabled",
            ValidationSeverity::Error,
            SolvePhase::InputNormalization,
            "repo-contract",
            "repo_runtime_preview requires a non-disabled preview guard in overlay-aware.",
            "Runtime preview would violate the ownership boundary if treated as canonical.",
            LayoutEngineLayer::SpatialGeometry,
            true,
        ));
    }

    zones
}

pub fn identify_postsolve_unclear_zones_with_local_overlay(
    input: &OverlayAwareLayoutInput,
    output: &LayoutOutput,
) -> Vec<UnclearZone> {
    let mut zones = Vec::<UnclearZone>::new();

    let repeatability = evaluate_repeatability(input, output);
    if repeatability.status != "pass" {
        zones.push(UnclearZone::new(
            "typical_floor_similarity_low",
            if repeatability.status == "fail" { ValidationSeverity::Error } else { ValidationSeverity::Warning },
            SolvePhase::SpaceLayout,
            "repeatability",
            "Typical-floor repeatability did not remain fully inside the preferred overlay-aware budget.",
            "Transfer floors or sibling repair may diverge more than expected.",
            LayoutEngineLayer::SpatialGeometry,
            repeatability.status == "fail",
        ));
    }

    if input.constraints.min_daylight {
        zones.push(UnclearZone::new(
            "daylight_is_facade_proxy",
            ValidationSeverity::Info,
            SolvePhase::SpaceLayout,
            "daylight",
            "overlay-aware still evaluates daylight primarily via facade access and depth caps.",
            "Manual architectural review is still required for room-level legality.",
            LayoutEngineLayer::SpatialGeometry,
            false,
        ));
    }

    if matches!(
        input.building_shape,
        BuildingShape::FreeForm | BuildingShape::Cluster | BuildingShape::XShape
    ) {
        zones.push(UnclearZone::new(
            "complex_shape_template_uncertain",
            ValidationSeverity::Warning,
            SolvePhase::FloorZoning,
            "geometry-template",
            "Complex shape families still rely on guided template heuristics in overlay-aware.",
            "Topology quality can vary on highly irregular parcels.",
            LayoutEngineLayer::SpatialGeometry,
            false,
        ));
    }

    zones
}

pub fn evaluate_local_overlay(input: &OverlayAwareLayoutInput) -> OverlayEvaluation {
    let mut notes = Vec::<String>::new();
    if matches!(
        input.local_overlay_pack.binding_mode,
        OverlayBindingMode::Bound
    ) {
        notes.push("Local overlay numerics are bound and can participate directly in overlay-aware feasibility decisions.".to_string());
    } else {
        notes.push(
            "Local overlay numerics remain partially assumed; downstream review is still required."
                .to_string(),
        );
    }

    OverlayEvaluation {
        overlay_id: input.local_overlay_pack.overlay_id.clone(),
        binding_mode: input.local_overlay_pack.binding_mode,
        parking_bound: matches!(
            input.local_overlay_pack.binding_mode,
            OverlayBindingMode::Bound
        ) && !matches!(
            input.parking_program.binding_source,
            ParkingBindingSource::HeuristicOnly
        ),
        notes,
    }
}

pub fn parking_ratio_for_type(pack: &LocalOverlayParkingInput, t: UnitType) -> f64 {
    pack.ratios_by_unit_type
        .get(t.as_key())
        .copied()
        .unwrap_or_else(|| match t {
            UnitType::Studio => 1.0,
            UnitType::OneBedroom => 1.25,
            UnitType::TwoBedroom => 1.5,
            UnitType::ThreeBedroom => 2.0,
        })
}

pub fn evaluate_parking_binding(
    input: &OverlayAwareLayoutInput,
    output: &LayoutOutput,
) -> ParkingBindingEvaluation {
    let counts = allocate_integer_unit_counts(
        output.program.dwelling_units_total,
        &output.normalized_input.unit_mix_seed,
    );
    let mut unit_stalls = 0.0;
    for (idx, t) in UnitType::all().iter().enumerate() {
        unit_stalls +=
            counts[idx] as f64 * parking_ratio_for_type(&input.local_overlay_pack.parking, *t);
    }

    let guest_ratio = input
        .parking_program
        .guest_stalls_override
        .map(|x| x as f64)
        .unwrap_or_else(|| {
            output.program.dwelling_units_total as f64
                * input.local_overlay_pack.parking.guest_stalls_per_du
        });
    let retail_stalls = output.program.retail_area_sf
        / input
            .local_overlay_pack
            .parking
            .retail_sf_per_stall
            .max(1.0);
    let base = unit_stalls + guest_ratio + retail_stalls;
    let max_reduction = input.local_overlay_pack.parking.transit_reduction_max_ratio;
    let reduction = input.parking_program.tdm_reduction_ratio.min(max_reduction);
    let reduced = (base * (1.0 - reduction)).max(0.0);
    let required_stalls = input
        .parking_program
        .required_stalls_override
        .unwrap_or_else(|| reduced.ceil() as u32);
    let mut provided_estimate = required_stalls + input.parking_program.accessible_stall_buffer;
    if let Some(cap) = input.parking_program.provided_stalls_cap {
        provided_estimate = provided_estimate.min(cap);
    }

    let confidence = match input.parking_program.binding_source {
        ParkingBindingSource::LocalOverlay => "high",
        ParkingBindingSource::UserBound => "medium",
        ParkingBindingSource::HeuristicOnly => "low",
    }
    .to_string();

    ParkingBindingEvaluation {
        binding_source: input.parking_program.binding_source,
        required_stalls,
        provided_stalls_estimate: provided_estimate,
        confidence,
        notes: vec![
            format!(
                "retail_sf_per_stall = {:.2}",
                input.local_overlay_pack.parking.retail_sf_per_stall
            ),
            format!("tdm_reduction_applied = {:.3}", reduction),
        ],
    }
}

pub fn evaluate_repeatability(
    input: &OverlayAwareLayoutInput,
    output: &LayoutOutput,
) -> RepeatabilityEvaluation {
    let base_score = output.selected_candidate.repeatability_score;
    let repair_area_ratio = if input.levels.podium_levels > 0
        || input
            .shape_parameters
            .as_ref()
            .and_then(|x| x.transfer_band_depth_ft)
            .is_some()
    {
        0.14
    } else if input.levels.typical_floor {
        0.08
    } else {
        0.05
    };

    let unit_order_swaps = if input.repeatability_controls.allow_transfer_floor_split
        && input.levels.podium_levels > 0
    {
        2
    } else {
        1
    };

    let penalty =
        if repair_area_ratio > input.repeatability_controls.max_local_repair_area_ratio {
            0.08
        } else {
            0.0
        } + if unit_order_swaps > input.repeatability_controls.max_unit_order_swaps_per_floor {
            0.06
        } else {
            0.0
        };

    let score = clamp(base_score - penalty, 0.0, 1.0);
    let status = if score < input.repeatability_controls.fail_threshold {
        "fail"
    } else if score < input.repeatability_controls.warn_threshold {
        "warn"
    } else {
        "pass"
    }
    .to_string();

    RepeatabilityEvaluation {
        score,
        warn_threshold: input.repeatability_controls.warn_threshold,
        fail_threshold: input.repeatability_controls.fail_threshold,
        repair_area_ratio,
        unit_order_swaps,
        status,
        notes: vec![
            "overlay-aware repeats typical floors with explicit repair-budget accounting."
                .to_string(),
            "transfer floors can split family identity without unlocking the upper core group."
                .to_string(),
        ],
    }
}

pub fn build_projection_bundle(
    input: &OverlayAwareLayoutInput,
    output: &LayoutOutput,
) -> ProjectionBundle {
    if !input.repo_export.enabled
        || matches!(
            input.repo_export.projection_bundle_mode,
            ProjectionBundleMode::None
        )
    {
        return ProjectionBundle {
            enabled: false,
            mode: ProjectionBundleMode::None,
            space_semantic_index: Vec::new(),
            level_family_index: Vec::new(),
            notes: vec!["projection bundle disabled".to_string()],
        };
    }

    let repo_integration_input = input.to_repo_integration_input();
    let project_doc = build_project_doc_export_base(&repo_integration_input, output).doc;
    let levels = project_doc
        .as_ref()
        .map(|d| d.levels.clone())
        .unwrap_or_default();

    let mut space_semantic_index = Vec::<ProjectionSpaceIndexRecord>::new();
    let mut seq = 1usize;
    for floor in &output.selected_candidate.floors {
        let level_id = level_id_for_export_levels(&levels, floor.level_index);
        for placement in &floor.spaces {
            space_semantic_index.push(ProjectionSpaceIndexRecord {
                space_id: format!("space-auto-{:03}", seq),
                level_id: level_id.clone(),
                category: placement.category.clone(),
                space_name: placement.space_name.clone(),
                lineage_key: format!("floor_{:02}/space_{:03}", floor.level_index + 1, seq),
            });
            seq += 1;
        }
    }

    let mut level_family_index = Vec::<ProjectionLevelFamilyRecord>::new();
    for floor in &output.selected_candidate.floors {
        let level_id = level_id_for_export_levels(&levels, floor.level_index);
        let role = if output
            .selected_candidate
            .floors
            .first()
            .map(|x| x.family_id.as_str())
            == Some(floor.family_id.as_str())
        {
            "family_anchor"
        } else {
            "family_member"
        };
        level_family_index.push(ProjectionLevelFamilyRecord {
            level_id,
            family_id: floor.family_id.clone(),
            role: role.to_string(),
        });
    }

    ProjectionBundle {
        enabled: true,
        mode: input.repo_export.projection_bundle_mode,
        space_semantic_index,
        level_family_index,
        notes: vec![
            "Projection bundle preserves category and lineage keys adjacent to ProjectDoc."
                .to_string(),
            "ProjectDoc remains editor-facing and intentionally thinner than engine output."
                .to_string(),
        ],
    }
}

pub fn evaluate_repo_contract_with_runtime_guard(
    input: &OverlayAwareLayoutInput,
) -> OverlayAwareRepoContractEvaluation {
    let requested_mode = input.repo_export.integration_mode;
    let mut resolved_mode = requested_mode;
    let mut contract_safe = true;
    let mut notes = Vec::<String>::new();

    match requested_mode {
        RepoIntegrationMode::OfflineBatch => {
            notes.push(
                "OfflineBatch remains outside the live editor ownership boundary.".to_string(),
            );
        }
        RepoIntegrationMode::RepoCaseGeneration => {
            notes.push("RepoCaseGeneration is contract-safe when ProjectDoc snapshots and projection bundles are generated offline.".to_string());
        }
        RepoIntegrationMode::RepoRuntimePreview => match input.repo_export.runtime_preview_guard {
            RuntimePreviewGuard::ProposalPatchOnly => {
                notes.push(
                    "RepoRuntimePreview is limited to proposal_patch_only in overlay-aware."
                        .to_string(),
                );
            }
            RuntimePreviewGuard::ExplicitArchitectureException => {
                notes.push("An explicit architecture exception is required for any stronger runtime preview path.".to_string());
            }
            RuntimePreviewGuard::Disabled => {
                contract_safe = false;
                resolved_mode = RepoIntegrationMode::RepoCaseGeneration;
                notes.push("Runtime preview without a guard is not contract-safe; the mode should be downgraded.".to_string());
            }
        },
    }

    if input.feasibility_controls.strict_repo_contract
        && matches!(requested_mode, RepoIntegrationMode::RepoRuntimePreview)
        && matches!(
            input.repo_export.runtime_preview_guard,
            RuntimePreviewGuard::Disabled
        )
    {
        contract_safe = false;
        resolved_mode = RepoIntegrationMode::RepoCaseGeneration;
    }

    OverlayAwareRepoContractEvaluation {
        requested_mode,
        resolved_mode,
        runtime_preview_guard: input.repo_export.runtime_preview_guard,
        contract_safe,
        notes,
    }
}

pub fn build_project_doc_export_with_projection_bundle(
    input: &OverlayAwareLayoutInput,
    output: &LayoutOutput,
    projection_bundle: &ProjectionBundle,
) -> OverlayAwareProjectDocExport {
    let repo_integration_input = input.to_repo_integration_input();
    let base = build_project_doc_export_base(&repo_integration_input, output);

    OverlayAwareProjectDocExport {
        enabled: base.enabled,
        target_format: base.target_format,
        preferred_view: base.preferred_view,
        projection_bundle_mode: match input.repo_export.projection_bundle_mode {
            ProjectionBundleMode::None => "none".to_string(),
            ProjectionBundleMode::AdjacentJson => "adjacent_json".to_string(),
            ProjectionBundleMode::EmbeddedMetadata => "embedded_metadata".to_string(),
        },
        semantic_index_included: projection_bundle.enabled
            && input.repo_export.include_semantic_index,
        level_family_index_included: projection_bundle.enabled
            && input.repo_export.include_level_family_index,
        doc: base.doc,
        notes: {
            let mut notes = base.notes;
            if projection_bundle.enabled {
                notes
                    .push("projection bundle should be preserved alongside ProjectDoc".to_string());
            }
            notes
        },
    }
}

pub fn classify_feasibility_status_with_local_overlay(
    input: &OverlayAwareLayoutInput,
    core: &LayoutOutput,
    repo: &OverlayAwareRepoContractEvaluation,
    preflight: &[UnclearZone],
    postsolve: &[UnclearZone],
    repeatability: &RepeatabilityEvaluation,
    overlay: &OverlayEvaluation,
    projection: &ProjectionBundle,
) -> FeasibilityStatus {
    if input.feasibility_controls.strict_repo_contract && !repo.contract_safe {
        return FeasibilityStatus::NotRepoContractSafe;
    }

    if matches!(core.solution_status, SolutionStatus::Infeasible) {
        return FeasibilityStatus::DeferredZonesPresent;
    }

    if input.feasibility_controls.repeatability_fail_as_deferred && repeatability.status == "fail" {
        return FeasibilityStatus::DeferredZonesPresent;
    }

    if input.repo_export.enabled
        && input
            .feasibility_controls
            .require_projection_bundle_for_repo_export
        && !projection.enabled
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }

    if input
        .feasibility_controls
        .require_bound_local_overlay_for_parking
        && input.constraints.parking_mode != ParkingMode::None
        && !overlay.parking_bound
    {
        return FeasibilityStatus::ConditionallyFeasible;
    }

    if !preflight.is_empty() || !postsolve.is_empty() {
        return FeasibilityStatus::ConditionallyFeasible;
    }

    FeasibilityStatus::FullyFeasible
}

