pub fn count_longest_split_run(samples: &[SpatialTopologyIntervalSample]) -> usize {
    let mut best = 0usize;
    let mut cur = 0usize;
    for sample in samples {
        if sample.intervals.len() >= 2 {
            cur += 1;
            best = best.max(cur);
        } else {
            cur = 0;
        }
    }
    best
}

pub fn stable_segment_count_from_samples(
    samples: &[SpatialTopologyIntervalSample],
    break_ft: f64,
    split_delta: f64,
) -> usize {
    if samples.is_empty() {
        return 1;
    }

    let mut count = 1usize;
    let mut prev_primary = 0.0_f64;
    let mut prev_split = 0.0_f64;
    let mut prev_n = 0usize;

    for (i, sample) in samples.iter().enumerate() {
        let lengths: Vec<f64> = sample
            .intervals
            .iter()
            .map(|(a, b)| (b - a).abs())
            .collect();
        let total = lengths.iter().copied().sum::<f64>();
        let primary = lengths.iter().copied().fold(0.0_f64, f64::max);
        let split = if total <= EPS {
            0.0
        } else {
            1.0 - primary / total
        };

        if i > 0
            && ((primary - prev_primary).abs() > break_ft
                || (split - prev_split).abs() > split_delta
                || sample.intervals.len() != prev_n)
        {
            count += 1;
        }

        prev_primary = primary;
        prev_split = split;
        prev_n = sample.intervals.len();
    }

    count.max(1)
}

pub fn junction_count_from_samples(
    samples: &[SpatialTopologyIntervalSample],
    break_ft: f64,
    split_delta: f64,
) -> usize {
    if samples.len() <= 1 {
        return 0;
    }

    let mut count = 0usize;
    let mut prev_primary = 0.0_f64;
    let mut prev_split = 0.0_f64;
    let mut prev_n = 0usize;

    for (i, sample) in samples.iter().enumerate() {
        let lengths: Vec<f64> = sample
            .intervals
            .iter()
            .map(|(a, b)| (b - a).abs())
            .collect();
        let total = lengths.iter().copied().sum::<f64>();
        let primary = lengths.iter().copied().fold(0.0_f64, f64::max);
        let split = if total <= EPS {
            0.0
        } else {
            1.0 - primary / total
        };

        if i > 0
            && ((primary - prev_primary).abs() > break_ft
                || (split - prev_split).abs() > split_delta
                || sample.intervals.len() != prev_n)
        {
            count += 1;
        }

        prev_primary = primary;
        prev_split = split;
        prev_n = sample.intervals.len();
    }

    count
}

pub fn infer_shape_score_map(
    input: &ShapeStrategyLayoutInput,
    base_floor: &SpatialGeometryFloorAllocationSummary,
    topo: &SpatialTopologyFloorSummary,
    split_span_ratio: f64,
    common_kernel_score: f64,
) -> Vec<(BuildingShape, f64)> {
    let linearity_ratio = if base_floor.effective_frontage_ft <= EPS {
        0.0
    } else {
        clamp(
            topo.longest_frontage_run_ft / base_floor.effective_frontage_ft,
            0.0,
            1.0,
        )
    };

    let branch_penalty_bar = clamp(
        topo.branch_zone_count_estimate as f64
            / (input.shape_strategy_controls.bar.max_branch_count.max(1) as f64 + 1.0),
        0.0,
        1.0,
    );
    let bar_fit = clamp(
        0.45 * linearity_ratio
            + 0.20 * (1.0 - topo.interval_split_ratio_mean)
            + 0.15 * topo.run_continuity_score
            + 0.20 * (1.0 - branch_penalty_bar),
        0.0,
        1.0,
    );

    let elbow_angle_error_deg = 90.0 * clamp(1.0 - topo.run_balance_ratio, 0.0, 1.0);
    let elbow_angle_score = clamp(
        1.0 - elbow_angle_error_deg
            / input
                .shape_strategy_controls
                .l_shape
                .elbow_angle_tolerance_deg
                .max(EPS),
        0.0,
        1.0,
    );
    let l_fit = clamp(
        0.35 * elbow_angle_score
            + 0.35 * topo.run_balance_ratio
            + 0.15 * topo.run_continuity_score
            + 0.15 * topo.service_reach_score,
        0.0,
        1.0,
    );

    let courtyard_open_ratio = clamp(1.0 - split_span_ratio, 0.0, 1.0);
    let courtyard_open_width_ft = courtyard_open_ratio * topo.longest_frontage_run_ft;
    let u_fit = clamp(
        0.30 * courtyard_open_ratio
            + 0.30 * topo.run_balance_ratio
            + 0.20 * topo.run_continuity_score
            + 0.20 * topo.detour_score,
        0.0,
        1.0,
    );

    let inner_frontage_ratio = clamp(
        topo.interval_split_ratio_mean + 0.25 * split_span_ratio,
        0.0,
        1.0,
    );
    let ring_closure_ratio = if input.shape_decomposition_controls.enable_cycle_detection {
        clamp(split_span_ratio + 0.20 * topo.run_balance_ratio, 0.0, 1.0)
    } else {
        0.0
    };
    let o_fit = clamp(
        0.40 * ring_closure_ratio
            + 0.20 * inner_frontage_ratio
            + 0.20 * topo.service_reach_score
            + 0.20 * topo.residual_compactness_estimate,
        0.0,
        1.0,
    );

    let connector_width_ft =
        (topo.longest_frontage_run_ft / (topo.frontage_run_count.max(1) as f64)).max(0.0);
    let connector_score = clamp(
        connector_width_ft
            / input
                .shape_strategy_controls
                .h_shape
                .min_connector_width_ft
                .max(EPS),
        0.0,
        1.0,
    );
    let h_fit = clamp(
        0.30 * topo.run_balance_ratio
            + 0.25 * connector_score
            + 0.25 * topo.run_balance_score
            + 0.20 * topo.detour_score,
        0.0,
        1.0,
    );

    let target_core_area_ratio = input.shape_strategy_controls.tower.target_core_area_ratio;
    let core_compactness_ratio = clamp(
        1.0 - (target_core_area_ratio - 0.18).abs() / target_core_area_ratio.max(EPS),
        0.0,
        1.0,
    );
    let perimeter_arc_coverage_ratio = clamp(
        0.55 * topo.run_continuity_score + 0.45 * linearity_ratio,
        0.0,
        1.0,
    );
    let tower_fit = clamp(
        0.35 * core_compactness_ratio
            + 0.35 * perimeter_arc_coverage_ratio.max(linearity_ratio)
            + 0.15 * topo.service_reach_score
            + 0.15 * clamp(1.0 - topo.branch_zone_count_estimate as f64 / 4.0, 0.0, 1.0),
        0.0,
        1.0,
    );

    let hub_offset_ft = topo.service_reach_max_ft * topo.interval_split_ratio_mean * 0.18;
    let hub_offset_score = clamp(
        1.0 - hub_offset_ft
            / input
                .shape_strategy_controls
                .x_shape
                .max_hub_offset_ft
                .max(EPS),
        0.0,
        1.0,
    );
    let arm_symmetry_ratio = clamp(
        0.5 * topo.run_balance_ratio + 0.5 * (1.0 - topo.depth_break_ratio),
        0.0,
        1.0,
    );
    let x_fit = clamp(
        0.35 * arm_symmetry_ratio
            + 0.25 * hub_offset_score
            + 0.20 * topo.run_balance_score
            + 0.20 * topo.detour_score,
        0.0,
        1.0,
    );

    let cluster_lobe_count_estimate =
        (topo.branch_zone_count_estimate + 1).max(topo.frontage_run_count);
    let connector_efficiency_ratio = clamp(
        topo.run_continuity_score * topo.service_reach_score,
        0.0,
        1.0,
    );
    let lobe_balance_ratio = clamp(
        0.5 * topo.run_balance_ratio + 0.5 * topo.residual_compactness_estimate,
        0.0,
        1.0,
    );
    let cluster_fit = clamp(
        0.30 * lobe_balance_ratio
            + 0.30 * connector_efficiency_ratio
            + 0.20 * topo.service_reach_score
            + 0.20 * topo.residual_compactness_estimate,
        0.0,
        1.0,
    );

    let free_form_fit = clamp(
        0.40 * split_span_ratio.max(0.65)
            + 0.20 * cluster_fit.max(x_fit).max(u_fit).max(l_fit)
            + 0.20 * common_kernel_score
            + 0.20 * topo.service_reach_score,
        0.0,
        1.0,
    );

    let perimeter_partial_fit = clamp(
        0.35 * ring_closure_ratio
            + 0.25 * courtyard_open_ratio
            + 0.20 * topo.run_balance_ratio
            + 0.20 * topo.run_continuity_score,
        0.0,
        1.0,
    );

    let mut scores = vec![
        (BuildingShape::Bar, bar_fit),
        (BuildingShape::LShape, l_fit),
        (BuildingShape::UShape, u_fit),
        (BuildingShape::OShape, o_fit),
        (BuildingShape::HShape, h_fit),
        (BuildingShape::Tower, tower_fit),
        (BuildingShape::XShape, x_fit),
        (BuildingShape::Cluster, cluster_fit),
        (BuildingShape::FreeForm, free_form_fit),
        (BuildingShape::PerimeterPartial, perimeter_partial_fit),
    ];

    if input
        .shape_decomposition_controls
        .enable_declared_shape_crosscheck
    {
        for (shape, score) in &mut scores {
            if *shape == input.building_shape {
                *score = clamp(*score + 0.08, 0.0, 1.0);
            }
        }
    }

    scores
}

pub fn common_kernel_metrics(
    input: &ShapeStrategyLayoutInput,
    base_floor: &SpatialGeometryFloorAllocationSummary,
    topo: &SpatialTopologyFloorSummary,
    floor: &FloorOutput,
) -> ShapeStrategyCommonKernelMetrics {
    let centroid = poly_centroid(&floor.footprint_polygon);
    let (axis_u, _) = resolve_primary_axis(
        &input
            .to_spatial_topology_input()
            .to_spatial_geometry_input(),
        &floor.footprint_polygon,
    );
    let frame = LocalFrame::new(centroid, axis_u);
    let samples = sample_interval_field(
        &floor.footprint_polygon,
        &frame,
        input.shape_decomposition_controls.skeleton_sampling_step_ft,
        input.topology_geometry_controls.interval_merge_gap_ft,
    );

    let stable_segment_count_estimate = stable_segment_count_from_samples(
        &samples,
        input
            .shape_decomposition_controls
            .topology_transition_break_ft,
        input.topology_geometry_controls.split_detection_ratio,
    );
    let junction_count_estimate = junction_count_from_samples(
        &samples,
        input
            .shape_decomposition_controls
            .topology_transition_break_ft,
        input.topology_geometry_controls.split_detection_ratio,
    );
    let split_run = count_longest_split_run(&samples);
    let split_span_ratio = if samples.is_empty() {
        0.0
    } else {
        split_run as f64 / samples.len() as f64
    };

    let ring_count_estimate = if input.shape_decomposition_controls.enable_cycle_detection
        && split_span_ratio >= input.shape_strategy_controls.o_shape.min_ring_closure_ratio
    {
        1usize
    } else {
        0usize
    };

    let wing_count_estimate = topo
        .frontage_run_count
        .max(topo.branch_zone_count_estimate + 1);
    let skeleton_edge_count_estimate = stable_segment_count_estimate.max(wing_count_estimate);
    let stable_segment_score = clamp(
        1.0 - (stable_segment_count_estimate.saturating_sub(1) as f64) / 7.0,
        0.0,
        1.0,
    );
    let junction_stability_score = clamp(
        1.0 - junction_count_estimate as f64
            / (skeleton_edge_count_estimate + ring_count_estimate).max(1) as f64,
        0.0,
        1.0,
    );
    let cycle_consistency_score = if ring_count_estimate > 0 {
        split_span_ratio
    } else {
        clamp(1.0 - 0.5 * split_span_ratio, 0.0, 1.0)
    };

    let common_kernel_score = clamp(
        0.24 * base_floor.allocation_score
            + 0.24 * topo.topology_score
            + 0.18 * stable_segment_score
            + 0.18 * junction_stability_score
            + 0.16 * cycle_consistency_score,
        0.0,
        1.0,
    );

    ShapeStrategyCommonKernelMetrics {
        stable_segment_count_estimate,
        skeleton_edge_count_estimate,
        junction_count_estimate,
        ring_count_estimate,
        wing_count_estimate,
        split_span_ratio,
        common_kernel_score,
    }
}

pub fn select_shape_strategy(
    input: &ShapeStrategyLayoutInput,
    scores: &[(BuildingShape, f64)],
    declared_shape: BuildingShape,
) -> (BuildingShape, ShapeStrategySource, bool) {
    let declared_score = scores
        .iter()
        .find(|(shape, _)| *shape == declared_shape)
        .map(|(_, score)| *score)
        .unwrap_or(0.0);
    let best = scores
        .iter()
        .copied()
        .max_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal))
        .unwrap_or((declared_shape, declared_score));

    match input.shape_strategy_controls.strategy_selection_mode {
        ShapeStrategySelectionMode::DeclaredShapeFirst => {
            if declared_score + EPS >= input.shape_strategy_controls.shape_match_warn_below {
                (declared_shape, ShapeStrategySource::DeclaredShape, false)
            } else if input.shape_strategy_controls.allow_strategy_fallback {
                (
                    best.0,
                    ShapeStrategySource::Fallback,
                    best.0 != declared_shape,
                )
            } else {
                (declared_shape, ShapeStrategySource::DeclaredShape, false)
            }
        }
        ShapeStrategySelectionMode::InferredShapeFirst => {
            if best.1 + EPS >= input.shape_strategy_controls.shape_match_warn_below {
                (
                    best.0,
                    ShapeStrategySource::InferredShape,
                    best.0 != declared_shape,
                )
            } else if input.shape_strategy_controls.allow_strategy_fallback {
                (
                    declared_shape,
                    ShapeStrategySource::Fallback,
                    best.0 != declared_shape,
                )
            } else {
                (
                    best.0,
                    ShapeStrategySource::InferredShape,
                    best.0 != declared_shape,
                )
            }
        }
        ShapeStrategySelectionMode::Hybrid => (
            best.0,
            ShapeStrategySource::Hybrid,
            best.0 != declared_shape,
        ),
    }
}

pub fn strategy_specific_metrics(
    input: &ShapeStrategyLayoutInput,
    strategy: BuildingShape,
    base_floor: &SpatialGeometryFloorAllocationSummary,
    topo: &SpatialTopologyFloorSummary,
    common: &ShapeStrategyCommonKernelMetrics,
    best_shape_score: f64,
    score_map: &[(BuildingShape, f64)],
) -> (ShapeStrategySpecificMetrics, f64, f64) {
    let linearity_ratio = if base_floor.effective_frontage_ft <= EPS {
        0.0
    } else {
        clamp(
            topo.longest_frontage_run_ft / base_floor.effective_frontage_ft,
            0.0,
            1.0,
        )
    };
    let elbow_angle_error_deg = 90.0 * clamp(1.0 - topo.run_balance_ratio, 0.0, 1.0);
    let courtyard_open_ratio = clamp(1.0 - common.split_span_ratio, 0.0, 1.0);
    let courtyard_open_width_ft = courtyard_open_ratio * topo.longest_frontage_run_ft;
    let ring_closure_ratio = if common.ring_count_estimate > 0 {
        common.split_span_ratio
    } else {
        0.0
    };
    let inner_frontage_ratio = clamp(
        topo.interval_split_ratio_mean + 0.25 * common.split_span_ratio,
        0.0,
        1.0,
    );
    let dual_bar_balance_ratio = topo.run_balance_ratio;
    let connector_width_ft =
        (topo.longest_frontage_run_ft / topo.frontage_run_count.max(1) as f64).max(0.0);
    let core_compactness_ratio = clamp(
        1.0 - (input.shape_strategy_controls.tower.target_core_area_ratio - 0.18).abs()
            / input
                .shape_strategy_controls
                .tower
                .target_core_area_ratio
                .max(EPS),
        0.0,
        1.0,
    );
    let perimeter_arc_coverage_ratio =
        linearity_ratio.max(0.5 * topo.run_continuity_score + 0.5 * topo.service_reach_score);
    let arm_symmetry_ratio = clamp(
        0.5 * topo.run_balance_ratio + 0.5 * (1.0 - topo.depth_break_ratio),
        0.0,
        1.0,
    );
    let hub_offset_ft = topo.service_reach_max_ft * topo.interval_split_ratio_mean * 0.18;
    let cluster_lobe_count_estimate = common
        .wing_count_estimate
        .max(topo.branch_zone_count_estimate + 1);
    let connector_efficiency_ratio = clamp(
        topo.run_continuity_score * topo.service_reach_score,
        0.0,
        1.0,
    );
    let lobe_balance_ratio = clamp(
        0.5 * topo.run_balance_ratio + 0.5 * topo.residual_compactness_estimate,
        0.0,
        1.0,
    );

    let top_scores = {
        let mut s = score_map.to_vec();
        s.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(Ordering::Equal));
        s
    };
    let top_k = input
        .shape_strategy_controls
        .max_secondary_strategies
        .max(1);
    let hybrid_score_sum = top_scores.iter().take(top_k).map(|(_, v)| *v).sum::<f64>();
    let hybrid_coverage_ratio = clamp(hybrid_score_sum / top_k as f64, 0.0, 1.0);

    let mut metrics = ShapeStrategySpecificMetrics::default();
    let strategy_fit_score = match strategy {
        BuildingShape::Bar => {
            metrics.linearity_ratio = Some(linearity_ratio);
            clamp(
                0.45 * linearity_ratio
                    + 0.20 * (1.0 - topo.interval_split_ratio_mean)
                    + 0.15 * topo.run_continuity_score
                    + 0.20 * clamp(1.0 - topo.branch_zone_count_estimate as f64 / 3.0, 0.0, 1.0),
                0.0,
                1.0,
            )
        }
        BuildingShape::LShape => {
            metrics.elbow_angle_error_deg = Some(elbow_angle_error_deg);
            metrics.arm_balance_ratio = Some(topo.run_balance_ratio);
            let elbow_score = clamp(
                1.0 - elbow_angle_error_deg
                    / input
                        .shape_strategy_controls
                        .l_shape
                        .elbow_angle_tolerance_deg
                        .max(EPS),
                0.0,
                1.0,
            );
            clamp(
                0.35 * elbow_score
                    + 0.35 * topo.run_balance_ratio
                    + 0.15 * topo.run_continuity_score
                    + 0.15 * topo.service_reach_score,
                0.0,
                1.0,
            )
        }
        BuildingShape::UShape => {
            metrics.courtyard_open_width_ft = Some(courtyard_open_width_ft);
            metrics.courtyard_open_ratio = Some(courtyard_open_ratio);
            metrics.arm_balance_ratio = Some(topo.run_balance_ratio);
            clamp(
                0.30 * courtyard_open_ratio
                    + 0.30 * topo.run_balance_ratio
                    + 0.20 * topo.run_continuity_score
                    + 0.20 * topo.detour_score,
                0.0,
                1.0,
            )
        }
        BuildingShape::OShape => {
            metrics.ring_closure_ratio = Some(ring_closure_ratio);
            metrics.inner_frontage_ratio = Some(inner_frontage_ratio);
            clamp(
                0.40 * ring_closure_ratio
                    + 0.20 * inner_frontage_ratio
                    + 0.20 * topo.service_reach_score
                    + 0.20 * topo.residual_compactness_estimate,
                0.0,
                1.0,
            )
        }
        BuildingShape::HShape => {
            metrics.dual_bar_balance_ratio = Some(dual_bar_balance_ratio);
            metrics.connector_width_ft = Some(connector_width_ft);
            let connector_score = clamp(
                connector_width_ft
                    / input
                        .shape_strategy_controls
                        .h_shape
                        .min_connector_width_ft
                        .max(EPS),
                0.0,
                1.0,
            );
            clamp(
                0.30 * dual_bar_balance_ratio
                    + 0.25 * connector_score
                    + 0.25 * topo.run_balance_score
                    + 0.20 * topo.detour_score,
                0.0,
                1.0,
            )
        }
        BuildingShape::Tower => {
            metrics.core_compactness_ratio = Some(core_compactness_ratio);
            metrics.perimeter_arc_coverage_ratio = Some(perimeter_arc_coverage_ratio);
            clamp(
                0.35 * core_compactness_ratio
                    + 0.35 * perimeter_arc_coverage_ratio
                    + 0.15 * topo.service_reach_score
                    + 0.15 * clamp(1.0 - topo.branch_zone_count_estimate as f64 / 4.0, 0.0, 1.0),
                0.0,
                1.0,
            )
        }
        BuildingShape::XShape => {
            metrics.arm_symmetry_ratio = Some(arm_symmetry_ratio);
            metrics.hub_offset_ft = Some(hub_offset_ft);
            let hub_offset_score = clamp(
                1.0 - hub_offset_ft
                    / input
                        .shape_strategy_controls
                        .x_shape
                        .max_hub_offset_ft
                        .max(EPS),
                0.0,
                1.0,
            );
            clamp(
                0.35 * arm_symmetry_ratio
                    + 0.25 * hub_offset_score
                    + 0.20 * topo.run_balance_score
                    + 0.20 * topo.detour_score,
                0.0,
                1.0,
            )
        }
        BuildingShape::Cluster => {
            metrics.cluster_lobe_count_estimate = Some(cluster_lobe_count_estimate);
            metrics.connector_efficiency_ratio = Some(connector_efficiency_ratio);
            metrics.lobe_balance_ratio = Some(lobe_balance_ratio);
            clamp(
                0.30 * lobe_balance_ratio
                    + 0.30 * connector_efficiency_ratio
                    + 0.20 * topo.service_reach_score
                    + 0.20 * topo.residual_compactness_estimate,
                0.0,
                1.0,
            )
        }
        BuildingShape::FreeForm => {
            metrics.hybrid_coverage_ratio = Some(hybrid_coverage_ratio);
            clamp(
                0.40 * hybrid_coverage_ratio
                    + 0.20 * best_shape_score
                    + 0.20 * common.common_kernel_score
                    + 0.20 * topo.service_reach_score,
                0.0,
                1.0,
            )
        }
        BuildingShape::PerimeterPartial => {
            metrics.ring_closure_ratio = Some(ring_closure_ratio);
            metrics.courtyard_open_ratio = Some(courtyard_open_ratio);
            metrics.arm_balance_ratio = Some(topo.run_balance_ratio);
            clamp(
                0.35 * ring_closure_ratio
                    + 0.25 * courtyard_open_ratio
                    + 0.20 * topo.run_balance_ratio
                    + 0.20 * topo.run_continuity_score,
                0.0,
                1.0,
            )
        }
    };

    let shape_score = clamp(
        0.45 * common.common_kernel_score + 0.55 * strategy_fit_score,
        0.0,
        1.0,
    );
    (metrics, strategy_fit_score, shape_score)
}

pub fn summarize_floor_shape(
    input: &ShapeStrategyLayoutInput,
    base_floor: &SpatialGeometryFloorAllocationSummary,
    topo: &SpatialTopologyFloorSummary,
    floor: &FloorOutput,
) -> ShapeStrategyFloorSummary {
    let common = common_kernel_metrics(input, base_floor, topo, floor);
    let score_map = infer_shape_score_map(
        input,
        base_floor,
        topo,
        common.split_span_ratio,
        common.common_kernel_score,
    );
    let best_inferred = score_map
        .iter()
        .copied()
        .max_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal))
        .unwrap_or((input.building_shape, 0.0));

    let declared_score = score_map
        .iter()
        .find(|(shape, _)| *shape == input.building_shape)
        .map(|(_, score)| *score)
        .unwrap_or(best_inferred.1);

    let shape_match_score = if best_inferred.0 == input.building_shape {
        declared_score.max(best_inferred.1).max(0.75)
    } else {
        clamp(declared_score / best_inferred.1.max(EPS), 0.0, 1.0)
    };

    let (selected_strategy_shape, source, strategy_fallback_used) =
        select_shape_strategy(input, &score_map, input.building_shape);

    let best_shape_score = score_map.iter().map(|(_, s)| *s).fold(0.0_f64, f64::max);
    let (strategy_specific_metrics, strategy_fit_score, shape_score) = if matches!(
        input.shape_strategy_controls.strategy_selection_mode,
        ShapeStrategySelectionMode::Hybrid
    ) && input.building_shape
        == BuildingShape::FreeForm
    {
        strategy_specific_metrics(
            input,
            BuildingShape::FreeForm,
            base_floor,
            topo,
            &common,
            best_shape_score,
            &score_map,
        )
    } else {
        strategy_specific_metrics(
            input,
            selected_strategy_shape,
            base_floor,
            topo,
            &common,
            best_shape_score,
            &score_map,
        )
    };

    let hybrid_coverage_ratio = strategy_specific_metrics
        .hybrid_coverage_ratio
        .unwrap_or(0.0);
    let common_kernel_status = if common.common_kernel_score < 0.58 {
        PassWarnFailStatus::Fail
    } else if common.common_kernel_score < 0.75 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };
    let strategy_status = if shape_score < 0.58
        || (input
            .feasibility_controls
            .require_declared_shape_strategy_match
            && best_inferred.0 != input.building_shape
            && shape_match_score < input.shape_strategy_controls.shape_match_warn_below)
    {
        PassWarnFailStatus::Fail
    } else if shape_score < 0.75
        || shape_match_score < input.shape_strategy_controls.shape_match_warn_below
        || strategy_fallback_used
        || (matches!(
            input.shape_strategy_controls.strategy_selection_mode,
            ShapeStrategySelectionMode::Hybrid
        ) && hybrid_coverage_ratio
            < input
                .shape_strategy_controls
                .hybrid_strategy_min_coverage_ratio)
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    let selected_strategy = if matches!(
        input.shape_strategy_controls.strategy_selection_mode,
        ShapeStrategySelectionMode::Hybrid
    ) && input.building_shape == BuildingShape::FreeForm
    {
        SelectedShapeStrategy::Hybrid
    } else {
        SelectedShapeStrategy::Shape(selected_strategy_shape)
    };

    let mut notes = vec![
        format!(
            "declared_shape = {}",
            building_shape_as_str(input.building_shape)
        ),
        format!(
            "inferred_shape = {}",
            building_shape_as_str(best_inferred.0)
        ),
        format!("selected_strategy = {}", selected_strategy),
    ];

    if strategy_fallback_used {
        notes.push("declared strategy was weak on this floor, so shape-strategy selected a fallback or inferred strategy.".to_string());
    }
    if shape_match_score < input.shape_strategy_controls.shape_match_warn_below {
        notes
            .push("declared shape and inferred graph signature do not match strongly.".to_string());
    }
    if matches!(
        input.shape_strategy_controls.strategy_selection_mode,
        ShapeStrategySelectionMode::Hybrid
    ) && hybrid_coverage_ratio > EPS
    {
        notes.push("hybrid strategy blending is active on this floor.".to_string());
    }

    ShapeStrategyFloorSummary {
        level_index: floor.level_index,
        family_id: floor.family_id.clone(),
        declared_shape: input.building_shape,
        inferred_shape: best_inferred.0,
        selected_strategy,
        strategy_source: source,
        allocation_score: base_floor.allocation_score,
        topology_score: topo.topology_score,
        shape_match_score,
        common_kernel_score: common.common_kernel_score,
        strategy_fit_score,
        shape_score,
        stable_segment_count_estimate: common.stable_segment_count_estimate,
        skeleton_edge_count_estimate: common.skeleton_edge_count_estimate,
        junction_count_estimate: common.junction_count_estimate,
        ring_count_estimate: common.ring_count_estimate,
        wing_count_estimate: common.wing_count_estimate,
        strategy_fallback_used,
        hybrid_coverage_ratio,
        common_kernel_status,
        strategy_status,
        strategy_specific_metrics,
        notes,
    }
}

pub fn evaluate_shape_decomposition(
    input: &ShapeStrategyLayoutInput,
    output: &SpatialTopologyLayoutOutput,
) -> (ShapeDecompositionEvaluation, Vec<ShapeStrategyFloorSummary>) {
    let mut floors = Vec::<ShapeStrategyFloorSummary>::new();

    for floor in &output.core_output.selected_candidate.floors {
        if let (Some(base_floor), Some(topo_floor)) = (
            output
                .per_floor_allocation_summaries
                .iter()
                .find(|x| x.level_index == floor.level_index),
            output
                .per_floor_topology_summaries
                .iter()
                .find(|x| x.level_index == floor.level_index),
        ) {
            floors.push(summarize_floor_shape(input, base_floor, topo_floor, floor));
        }
    }

    let mean_common_kernel_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.common_kernel_score)
            .collect::<Vec<f64>>(),
    );
    let mean_strategy_fit_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.strategy_fit_score)
            .collect::<Vec<f64>>(),
    );
    let mean_shape_score = mean_f64(&floors.iter().map(|x| x.shape_score).collect::<Vec<f64>>());
    let mean_shape_match_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.shape_match_score)
            .collect::<Vec<f64>>(),
    );

    let floors_with_strategy_fallback_count =
        floors.iter().filter(|x| x.strategy_fallback_used).count();
    let floors_with_hybrid_strategy_count = floors
        .iter()
        .filter(|x| x.selected_strategy.is_hybrid())
        .count();
    let floors_with_declared_shape_mismatch_count = floors
        .iter()
        .filter(|x| x.declared_shape != x.inferred_shape)
        .count();

    let overall_status =
        if floors.iter().any(|x| x.strategy_status.is_fail()) || mean_shape_score < 0.60 {
            PassWarnFailStatus::Fail
        } else if floors.iter().any(|x| x.strategy_status.is_warn()) || mean_shape_score < 0.78 {
            PassWarnFailStatus::Warn
        } else {
            PassWarnFailStatus::Pass
        };

    let notes = vec![
        "shape-strategy first builds a common morphology kernel and only then applies shape-specific allocation strategies.".to_string(),
        "Per-floor summaries show declared shape, inferred graph family, selected strategy, and any fallback/hybrid usage.".to_string(),
    ];

    (
        ShapeDecompositionEvaluation {
            overall_status,
            strategy_selection_mode: input.shape_strategy_controls.strategy_selection_mode,
            mean_common_kernel_score,
            mean_strategy_fit_score,
            mean_shape_score,
            mean_shape_match_score,
            floors_with_strategy_fallback_count,
            floors_with_hybrid_strategy_count,
            floors_with_declared_shape_mismatch_count,
            notes,
        },
        floors,
    )
}

impl ShapeStrategyLayoutInput {
    pub fn validate(&self) -> Vec<ValidationIssue> {
        let mut issues = self.to_spatial_topology_input().validate();

        if self.shape_decomposition_controls.skeleton_sampling_step_ft <= 0.0 {
            issues.push(ValidationIssue::error(
                "skeleton_sampling_step_nonpositive",
                "shape_decomposition_controls.skeleton_sampling_step_ft must be > 0",
            ));
        }

        if self.shape_decomposition_controls.junction_merge_radius_ft <= 0.0 {
            issues.push(ValidationIssue::error(
                "junction_merge_radius_nonpositive",
                "shape_decomposition_controls.junction_merge_radius_ft must be > 0",
            ));
        }

        if self.shape_decomposition_controls.min_wing_span_ft <= 0.0 {
            issues.push(ValidationIssue::error(
                "min_wing_span_nonpositive",
                "shape_decomposition_controls.min_wing_span_ft must be > 0",
            ));
        }

        if self.shape_decomposition_controls.min_hub_area_sf <= 0.0 {
            issues.push(ValidationIssue::error(
                "min_hub_area_nonpositive",
                "shape_decomposition_controls.min_hub_area_sf must be > 0",
            ));
        }

        if self.shape_strategy_controls.max_secondary_strategies == 0 {
            issues.push(ValidationIssue::error(
                "max_secondary_strategies_zero",
                "shape_strategy_controls.max_secondary_strategies must be >= 1",
            ));
        }

        if self.shape_strategy_controls.shape_match_warn_below < 0.0
            || self.shape_strategy_controls.shape_match_warn_below > 1.0
        {
            issues.push(ValidationIssue::error(
                "shape_match_warn_below_invalid",
                "shape_strategy_controls.shape_match_warn_below must be in [0, 1]",
            ));
        }

        if self
            .shape_strategy_controls
            .hybrid_strategy_min_coverage_ratio
            < 0.0
            || self
                .shape_strategy_controls
                .hybrid_strategy_min_coverage_ratio
                > 1.0
        {
            issues.push(ValidationIssue::error(
                "hybrid_strategy_min_coverage_ratio_invalid",
                "shape_strategy_controls.hybrid_strategy_min_coverage_ratio must be in [0, 1]",
            ));
        }

        if self.feasibility_controls.max_floorplan_shape_warnings > self.levels.count as usize {
            issues.push(ValidationIssue::warning(
                "shape_warning_budget_high",
                "feasibility_controls.max_floorplan_shape_warnings is higher than the total level count.",
            ));
        }

        issues
    }

    pub fn to_spatial_topology_input(&self) -> SpatialTopologyLayoutInput {
        SpatialTopologyLayoutInput {
            jurisdiction_profile: self.jurisdiction_profile.clone(),
            building_shape: self.building_shape,
            building_construction_type: self.building_construction_type,
            site_polygon: self.site_polygon.clone(),
            site_controls: self.site_controls.clone(),
            levels: self.levels.clone(),
            unit_mix: self.unit_mix.clone(),
            constraints: self.constraints.clone(),
            residential_features: self.residential_features.clone(),
            vertical_rules: self.vertical_rules.clone(),
            amenities: self.amenities.clone(),
            targets: self.targets.clone(),
            optimization: self.optimization.clone(),
            code_profile_overrides: self.code_profile_overrides.clone(),
            shape_parameters: self.shape_parameters.clone(),
            solver_controls: self.solver_controls.clone(),
            user_overrides: self.user_overrides.clone(),
            local_overlay_pack: self.local_overlay_pack.clone(),
            parking_program: self.parking_program.clone(),
            repeatability_controls: self.repeatability_controls.clone(),
            repo_export: self.repo_export.clone(),
            feasibility_controls: SpatialTopologyFeasibilityControls {
                strict_repo_contract: self.feasibility_controls.strict_repo_contract,
                mark_unclear_before_deep_solve: self
                    .feasibility_controls
                    .mark_unclear_before_deep_solve,
                allow_deferred_zones: self.feasibility_controls.allow_deferred_zones,
                max_unclear_zones: self.feasibility_controls.max_unclear_zones,
                require_bound_local_overlay_for_parking: self
                    .feasibility_controls
                    .require_bound_local_overlay_for_parking,
                require_projection_bundle_for_repo_export: self
                    .feasibility_controls
                    .require_projection_bundle_for_repo_export,
                max_projection_semantic_loss_records: self
                    .feasibility_controls
                    .max_projection_semantic_loss_records,
                repeatability_fail_as_deferred: self
                    .feasibility_controls
                    .repeatability_fail_as_deferred,
                spatial_geometry_fail_as_deferred: self
                    .feasibility_controls
                    .spatial_geometry_fail_as_deferred,
                max_floorplan_geometry_warnings: self
                    .feasibility_controls
                    .max_floorplan_geometry_warnings,
                topology_fail_as_deferred: self.feasibility_controls.topology_fail_as_deferred,
                max_floorplan_topology_warnings: self
                    .feasibility_controls
                    .max_floorplan_topology_warnings,
            },
            floor_geometry_controls: self.floor_geometry_controls.clone(),
            space_allocation_controls: self.space_allocation_controls.clone(),
            topology_geometry_controls: self.topology_geometry_controls.clone(),
            allocation_graph_controls: self.allocation_graph_controls.clone(),
        }
    }
}

pub fn identify_preflight_unclear_zones_with_shape_decomposition(
    input: &ShapeStrategyLayoutInput,
) -> Vec<UnclearZone> {
    let mut zones =
        identify_preflight_unclear_zones_with_spatial_topology(&input.to_spatial_topology_input());

    if matches!(
        input.building_shape,
        BuildingShape::FreeForm
            | BuildingShape::Cluster
            | BuildingShape::XShape
            | BuildingShape::PerimeterPartial
    ) && !matches!(
        input.shape_strategy_controls.strategy_selection_mode,
        ShapeStrategySelectionMode::Hybrid | ShapeStrategySelectionMode::InferredShapeFirst
    ) {
        zones.push(UnclearZone::new(
            "shape_strategy_mode_too_rigid",
            ValidationSeverity::Warning,
            SolvePhase::ProgramTargets,
            "space-shape-strategy",
            "A high-variance shape family is using a rigid declared-shape-first strategy path.",
            "Hybrid or inferred strategy selection is usually safer for complex branched/free-form floor families.",
            LayoutEngineLayer::ConstructiveTopology,
            false,
        ));
    }

    if matches!(
        input.building_shape,
        BuildingShape::OShape | BuildingShape::PerimeterPartial
    ) && !input.shape_decomposition_controls.enable_cycle_detection
    {
        zones.push(UnclearZone::new(
            "cycle_detection_disabled_for_ring_family",
            ValidationSeverity::Warning,
            SolvePhase::InputNormalization,
            "space-shape-strategy",
            "Cycle detection is disabled on a ring-like floor family.",
            "Closed-ring vs open-ring classification becomes lower-confidence.",
            LayoutEngineLayer::ConstructiveTopology,
            false,
        ));
    }

    if matches!(input.building_shape, BuildingShape::FreeForm)
        && input.shape_strategy_controls.free_form.max_strategy_count <= 1
    {
        zones.push(UnclearZone::new(
            "free_form_hybrid_budget_too_low",
            ValidationSeverity::Warning,
            SolvePhase::ProgramTargets,
            "space-shape-strategy",
            "The free-form strategy budget allows only one strategy family.",
            "Hybrid decomposition quality may be artificially capped.",
            LayoutEngineLayer::ConstructiveTopology,
            false,
        ));
    }

    zones
}

pub fn identify_postsolve_unclear_zones_with_shape_decomposition(
    input: &ShapeStrategyLayoutInput,
    base: &SpatialTopologyLayoutOutput,
    shape_eval: &ShapeDecompositionEvaluation,
    floors: &[ShapeStrategyFloorSummary],
) -> Vec<UnclearZone> {
    let mut zones = identify_postsolve_unclear_zones_with_spatial_topology(
        &input.to_spatial_topology_input(),
        &SpatialGeometryLayoutOutput {
            engine_layer: base.engine_layer.clone(),
            feasibility_status: base.feasibility_status.clone(),
            repo_contract_evaluation: base.repo_contract_evaluation.clone(),
            local_overlay_evaluation: base.local_overlay_evaluation.clone(),
            parking_binding_evaluation: base.parking_binding_evaluation.clone(),
            repeatability_evaluation: base.repeatability_evaluation.clone(),
            spatial_geometry_evaluation: base.spatial_geometry_evaluation.clone(),
            per_floor_allocation_summaries: base.per_floor_allocation_summaries.clone(),
            preflight_unclear_zones: base.preflight_unclear_zones.clone(),
            postsolve_unclear_zones: base.postsolve_unclear_zones.clone(),
            project_doc_export: base.project_doc_export.clone(),
            projection_bundle: base.projection_bundle.clone(),
            core_output: base.core_output.clone(),
        },
        &base.spatial_topology_evaluation,
        &base.per_floor_topology_summaries,
    );

    if !shape_eval.overall_status.is_pass() {
        zones.push(UnclearZone::new(
            "shape_strategy_quality_low",
            if shape_eval.overall_status.is_fail() {
                ValidationSeverity::Error
            } else {
                ValidationSeverity::Warning
            },
            SolvePhase::SpaceLayout,
            "space-shape-strategy",
            "Per-floor common-kernel or shape-strategy evaluation does not remain inside the preferred shape-strategy band.",
            "Manual review is still needed for strategy choice, decomposition quality, or shape mismatch.",
            LayoutEngineLayer::ConstructiveTopology,
            shape_eval.overall_status.is_fail(),
        ));
    }

    if floors.iter().any(|x| x.strategy_fallback_used) {
        zones.push(UnclearZone::new(
            "shape_strategy_fallback_used",
            ValidationSeverity::Info,
            SolvePhase::SpaceLayout,
            "space-shape-strategy",
            "At least one floor fell back from the declared strategy to an inferred or hybrid strategy.",
            "The floor remains solvable, but declared-shape assumptions may be too rigid or inaccurate.",
            LayoutEngineLayer::ConstructiveTopology,
            false,
        ));
    }

    if floors.iter().any(|x| x.declared_shape != x.inferred_shape) {
        zones.push(UnclearZone::new(
            "declared_shape_inferred_shape_mismatch",
            ValidationSeverity::Warning,
            SolvePhase::SpaceLayout,
            "space-shape-strategy",
            "At least one floor has a declared shape that does not match the inferred morphology graph family.",
            "This can indicate transfer floors, drift, or a shape family that needs a hybrid strategy in constructive-topology.",
            LayoutEngineLayer::ConstructiveTopology,
            false,
        ));
    }

    if floors.iter().any(|x| {
        x.selected_strategy.is_hybrid()
            && x.hybrid_coverage_ratio
                < input
                    .shape_strategy_controls
                    .hybrid_strategy_min_coverage_ratio
    }) {
        zones.push(UnclearZone::new(
            "hybrid_strategy_coverage_low",
            ValidationSeverity::Warning,
            SolvePhase::SpaceLayout,
            "space-shape-strategy",
            "Hybrid strategy coverage remains below the preferred threshold on at least one floor.",
            "Free-form synthesis still needs stronger exact decomposition in constructive-topology.",
            LayoutEngineLayer::ConstructiveTopology,
            false,
        ));
    }

    if matches!(
        input.building_shape,
        BuildingShape::FreeForm | BuildingShape::Cluster | BuildingShape::PerimeterPartial
    ) {
        zones.push(UnclearZone::new(
            "hybrid_shape_solver_still_schematic",
            ValidationSeverity::Warning,
            SolvePhase::SpaceLayout,
            "space-shape-strategy",
            "shape-strategy separates common-kernel and shape-specific strategies, but hybrid distributed shapes still rely on graph-like scoring instead of exact global optimization.",
            "Exact combinatorial embedding is deferred to constructive-topology.",
            LayoutEngineLayer::ConstructiveTopology,
            false,
        ));
    }

    zones
}

pub fn identify_postsolve_unclear_zones_from_shape_strategy_base(
    input: &ShapeStrategyLayoutInput,
    base: &ShapeStrategyLayoutOutput,
    shape_eval: &ShapeDecompositionEvaluation,
    floors: &[ShapeStrategyFloorSummary],
) -> Vec<UnclearZone> {
    let base = SpatialTopologyLayoutOutput {
        engine_layer: base.engine_layer.clone(),
        feasibility_status: base.feasibility_status.clone(),
        repo_contract_evaluation: base.repo_contract_evaluation.clone(),
        local_overlay_evaluation: base.local_overlay_evaluation.clone(),
        parking_binding_evaluation: base.parking_binding_evaluation.clone(),
        repeatability_evaluation: base.repeatability_evaluation.clone(),
        spatial_geometry_evaluation: base.spatial_geometry_evaluation.clone(),
        per_floor_allocation_summaries: base.per_floor_allocation_summaries.clone(),
        spatial_topology_evaluation: base.spatial_topology_evaluation.clone(),
        per_floor_topology_summaries: base.per_floor_topology_summaries.clone(),
        preflight_unclear_zones: base.preflight_unclear_zones.clone(),
        postsolve_unclear_zones: base.postsolve_unclear_zones.clone(),
        project_doc_export: base.project_doc_export.clone(),
        projection_bundle: base.projection_bundle.clone(),
        core_output: base.core_output.clone(),
    };
    identify_postsolve_unclear_zones_with_shape_decomposition(input, &base, shape_eval, floors)
}

pub fn classify_feasibility_status_with_shape_decomposition(
    input: &ShapeStrategyLayoutInput,
    base: &SpatialTopologyLayoutOutput,
    preflight: &[UnclearZone],
    postsolve: &[UnclearZone],
    shape_eval: &ShapeDecompositionEvaluation,
    floors: &[ShapeStrategyFloorSummary],
) -> FeasibilityStatus {
    match base.feasibility_status {
        FeasibilityStatus::NotRepoContractSafe => return FeasibilityStatus::NotRepoContractSafe,
        FeasibilityStatus::DeferredZonesPresent => return FeasibilityStatus::DeferredZonesPresent,
        _ => {}
    }

    if input.feasibility_controls.shape_strategy_fail_as_deferred
        && shape_eval.overall_status.is_fail()
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }

    let shape_warning_count = floors
        .iter()
        .filter(|x| !x.strategy_status.is_pass())
        .count();
    if input.feasibility_controls.shape_strategy_fail_as_deferred
        && shape_warning_count > input.feasibility_controls.max_floorplan_shape_warnings
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }

    if !preflight.is_empty() || !postsolve.is_empty() || shape_eval.overall_status.is_warn() {
        return FeasibilityStatus::ConditionallyFeasible;
    }

    base.feasibility_status
}

impl ShapeStrategyLayoutEngine {
    pub fn run(&self, input: ShapeStrategyLayoutInput) -> ShapeStrategyLayoutOutput {
        let base = self.inner.run(input.to_spatial_topology_input());
        let (shape_decomposition_evaluation, per_floor_shape_summaries) =
            evaluate_shape_decomposition(&input, &base);
        let preflight_unclear_zones =
            identify_preflight_unclear_zones_with_shape_decomposition(&input);
        let postsolve_unclear_zones = identify_postsolve_unclear_zones_with_shape_decomposition(
            &input,
            &base,
            &shape_decomposition_evaluation,
            &per_floor_shape_summaries,
        );
        let feasibility_status = classify_feasibility_status_with_shape_decomposition(
            &input,
            &base,
            &preflight_unclear_zones,
            &postsolve_unclear_zones,
            &shape_decomposition_evaluation,
            &per_floor_shape_summaries,
        );

        ShapeStrategyLayoutOutput {
            engine_layer: LayoutEngineLayer::ShapeStrategy,
            feasibility_status,
            repo_contract_evaluation: base.repo_contract_evaluation.clone(),
            local_overlay_evaluation: base.local_overlay_evaluation.clone(),
            parking_binding_evaluation: base.parking_binding_evaluation.clone(),
            repeatability_evaluation: base.repeatability_evaluation.clone(),
            spatial_geometry_evaluation: base.spatial_geometry_evaluation.clone(),
            per_floor_allocation_summaries: base.per_floor_allocation_summaries.clone(),
            spatial_topology_evaluation: base.spatial_topology_evaluation.clone(),
            per_floor_topology_summaries: base.per_floor_topology_summaries.clone(),
            shape_decomposition_evaluation,
            per_floor_shape_summaries,
            preflight_unclear_zones,
            postsolve_unclear_zones,
            project_doc_export: base.project_doc_export.clone(),
            projection_bundle: base.projection_bundle.clone(),
            core_output: base.core_output.clone(),
        }
    }
}

