/* =============================================================================
Constructive topology layer
--------------------------------------------------------------------------------
What this layer adds:
1. Keeps the full shape-strategy morphology + shape-strategy audit.
2. Adds buildable envelope controls and constructive topology summaries.
3. Adds corridor graph summaries, space packing summaries, and repair-search summaries.
4. Separates constructor-like diagnostics from evaluator-only bundles.
5. Keeps deterministic, bounded, repo-safe behavior.
============================================================================= */

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ConstructiveDecompositionStack {
    CdtDualClearanceHybrid,
    StraightSkeletonExperimental,
    ConvexBandFallback,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ConstructiveCorridorRoutingMode {
    SpineTreeWithLoopRepair,
    LoopSpineWithBranches,
    BranchSpineOnly,
    Hybrid,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ConstructivePackingMode {
    FrontageSlotDpWithClipRepair,
    ServiceFirstThenUnits,
    ExperimentalConstraintLocalSearch,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ConstructiveCandidateGenerationMode {
    ShapeSeededTopologyRepair,
    TopologySeeded,
    DeterministicSeeded,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ConstructiveRepairTieBreakMode {
    ScoreThenRepairCountThenFrontageLossThenLevelIndex,
    ScoreThenAreaThenLevelThenId,
}

pub fn constructive_stack_as_str(x: ConstructiveDecompositionStack) -> &'static str {
    match x {
        ConstructiveDecompositionStack::CdtDualClearanceHybrid => "cdt_dual_clearance_hybrid",
        ConstructiveDecompositionStack::StraightSkeletonExperimental => {
            "straight_skeleton_experimental"
        }
        ConstructiveDecompositionStack::ConvexBandFallback => "convex_band_fallback",
    }
}

pub fn corridor_routing_mode_as_str(x: ConstructiveCorridorRoutingMode) -> &'static str {
    match x {
        ConstructiveCorridorRoutingMode::SpineTreeWithLoopRepair => "spine_tree_with_loop_repair",
        ConstructiveCorridorRoutingMode::LoopSpineWithBranches => "loop_spine_with_branches",
        ConstructiveCorridorRoutingMode::BranchSpineOnly => "branch_spine_only",
        ConstructiveCorridorRoutingMode::Hybrid => "hybrid",
    }
}

pub fn packing_mode_as_str(x: ConstructivePackingMode) -> &'static str {
    match x {
        ConstructivePackingMode::FrontageSlotDpWithClipRepair => {
            "frontage_slot_dp_with_clip_repair"
        }
        ConstructivePackingMode::ServiceFirstThenUnits => "service_first_then_units",
        ConstructivePackingMode::ExperimentalConstraintLocalSearch => {
            "experimental_constraint_local_search"
        }
    }
}

pub fn candidate_generation_mode_as_str(x: ConstructiveCandidateGenerationMode) -> &'static str {
    match x {
        ConstructiveCandidateGenerationMode::ShapeSeededTopologyRepair => {
            "shape_seeded_topology_repair"
        }
        ConstructiveCandidateGenerationMode::TopologySeeded => "topology_seeded",
        ConstructiveCandidateGenerationMode::DeterministicSeeded => "deterministic_seeded",
    }
}

pub fn repair_tie_break_mode_as_str(x: ConstructiveRepairTieBreakMode) -> &'static str {
    match x {
        ConstructiveRepairTieBreakMode::ScoreThenRepairCountThenFrontageLossThenLevelIndex => {
            "score_then_repair_count_then_frontage_loss_then_level_index"
        }
        ConstructiveRepairTieBreakMode::ScoreThenAreaThenLevelThenId => {
            "score_then_area_then_level_then_id"
        }
    }
}

