pub fn inferred_corridor_mode_from_shape(
    shape: &ShapeStrategyFloorSummary,
) -> ConstructiveCorridorRoutingMode {
    match shape.selected_strategy {
        SelectedShapeStrategy::Shape(BuildingShape::OShape) => {
            ConstructiveCorridorRoutingMode::LoopSpineWithBranches
        }
        SelectedShapeStrategy::Shape(BuildingShape::UShape) => {
            ConstructiveCorridorRoutingMode::LoopSpineWithBranches
        }
        SelectedShapeStrategy::Shape(BuildingShape::Cluster) => {
            ConstructiveCorridorRoutingMode::BranchSpineOnly
        }
        SelectedShapeStrategy::Hybrid
        | SelectedShapeStrategy::Shape(BuildingShape::FreeForm)
        | SelectedShapeStrategy::Shape(BuildingShape::XShape)
        | SelectedShapeStrategy::Shape(BuildingShape::Tower) => {
            ConstructiveCorridorRoutingMode::Hybrid
        }
        _ => ConstructiveCorridorRoutingMode::SpineTreeWithLoopRepair,
    }
}

pub fn summarize_floor_constructive_topology(
    input: &ConstructiveTopologyLayoutInput,
    base_floor: &SpatialGeometryFloorAllocationSummary,
    topo: &SpatialTopologyFloorSummary,
    shape: &ShapeStrategyFloorSummary,
) -> ConstructiveFloorTopologySummary {
    let offset_self_intersection_count = if input
        .buildable_envelope_controls
        .enable_self_intersection_repair
    {
        ((topo.concavity_ratio * 4.0) + (topo.indentation_ratio * 3.0))
            .round()
            .max(0.0) as usize
    } else {
        0
    };

    let sliver_removed_area_sf = if input.buildable_envelope_controls.enable_sliver_pruning {
        ((1.0 - topo.residual_compactness_estimate).max(0.0)
            * input.buildable_envelope_controls.min_sliver_area_sf
            * (topo.frontage_run_count.max(1) as f64))
            .min(base_floor.residual_area_sf.max(1.0))
    } else {
        0.0
    };

    let narrow_neck_count_estimate = if input.buildable_envelope_controls.enable_narrow_neck_split {
        topo.branch_zone_count_estimate
            .max(shape.junction_count_estimate)
            / 2
    } else {
        0
    };

    let partition_cell_count = (shape.skeleton_edge_count_estimate
        + shape.junction_count_estimate
        + topo.frontage_run_count.max(1))
    .max(1);
    let corridor_band_count = match inferred_corridor_mode_from_shape(shape) {
        ConstructiveCorridorRoutingMode::LoopSpineWithBranches => {
            (shape.ring_count_estimate + 1).max(1)
        }
        ConstructiveCorridorRoutingMode::BranchSpineOnly => {
            (shape.wing_count_estimate + topo.branch_zone_count_estimate).max(1)
        }
        ConstructiveCorridorRoutingMode::Hybrid => {
            (shape.wing_count_estimate + shape.ring_count_estimate + 1).max(1)
        }
        ConstructiveCorridorRoutingMode::SpineTreeWithLoopRepair => 1usize,
    };
    let habitable_band_count = (topo.frontage_run_count + shape.wing_count_estimate).max(1);
    let service_band_count = ((topo.branch_zone_count_estimate as f64) * 0.75).round() as usize
        + shape.junction_count_estimate.min(2);

    let self_intersection_repair_score =
        1.0 - clamp(offset_self_intersection_count as f64 / 4.0, 0.0, 1.0);
    let sliver_pruning_score = 1.0
        - clamp(
            sliver_removed_area_sf
                / (base_floor
                    .residual_area_sf
                    .max(input.buildable_envelope_controls.min_sliver_area_sf)
                    * 0.75),
            0.0,
            1.0,
        );
    let min_neck_width_ft = if narrow_neck_count_estimate == 0 {
        input.buildable_envelope_controls.min_clear_neck_ft
    } else {
        (input.buildable_envelope_controls.min_clear_neck_ft
            - 2.0 * narrow_neck_count_estimate as f64)
            .max(8.0)
    };
    let neck_clearance_score = clamp(
        min_neck_width_ft / input.buildable_envelope_controls.min_clear_neck_ft.max(EPS),
        0.0,
        1.0,
    );
    let buildable_envelope_score = clamp(
        0.40 * self_intersection_repair_score
            + 0.30 * sliver_pruning_score
            + 0.30 * neck_clearance_score,
        0.0,
        1.0,
    );

    let cell_validity_ratio = clamp(
        1.0 - (shape.junction_count_estimate as f64) / ((partition_cell_count + 1) as f64),
        0.0,
        1.0,
    );
    let habitable_band_fit = clamp(
        base_floor.target_loaded_depth_ft
            / input
                .constructive_topology_controls
                .target_habitable_band_depth_ft
                .max(EPS),
        0.0,
        1.0,
    );
    let service_band_fit = clamp(
        input.space_packing_controls.service_reserve_depth_ft
            / input
                .constructive_topology_controls
                .min_service_band_depth_ft
                .max(EPS),
        0.0,
        1.0,
    );
    let corridor_band_fit = clamp(
        (corridor_band_count as f64)
            / (input.constructive_topology_controls.max_band_fragment_count as f64).max(1.0),
        0.0,
        1.0,
    );
    let constructive_partition_score = clamp(
        0.35 * cell_validity_ratio
            + 0.25 * habitable_band_fit
            + 0.20 * service_band_fit
            + 0.20 * (1.0 - corridor_band_fit * 0.35),
        0.0,
        1.0,
    );

    let topology_constructive_score = clamp(
        0.30 * buildable_envelope_score
            + 0.30 * constructive_partition_score
            + 0.20 * topo.topology_score
            + 0.20 * shape.common_kernel_score,
        0.0,
        1.0,
    );

    let topology_constructive_status = if topology_constructive_score < 0.58
        || narrow_neck_count_estimate >= 2
            && !input.buildable_envelope_controls.enable_narrow_neck_split
    {
        "fail".to_string()
    } else if topology_constructive_score < 0.76
        || offset_self_intersection_count
            > input
                .buildable_envelope_controls
                .max_offset_repair_iterations
    {
        "warn".to_string()
    } else {
        "pass".to_string()
    };

    let mut notes = vec![
        format!(
            "decomposition_stack = {}",
            constructive_stack_as_str(input.constructive_topology_controls.decomposition_stack)
        ),
        format!("partition_cell_count = {}", partition_cell_count),
        format!("corridor_band_count = {}", corridor_band_count),
    ];
    if offset_self_intersection_count > 0 {
        notes.push("offset repair remained active on this floor.".to_string());
    }
    if narrow_neck_count_estimate > 0 {
        notes.push(
            "narrow-neck behavior was detected; split/repair may remain approximate.".to_string(),
        );
    }

    ConstructiveFloorTopologySummary {
        level_index: base_floor.level_index,
        family_id: base_floor.family_id.clone(),
        decomposition_stack: constructive_stack_as_str(
            input.constructive_topology_controls.decomposition_stack,
        )
        .to_string(),
        envelope_polygon_count: 1usize,
        offset_self_intersection_count,
        sliver_removed_area_sf,
        narrow_neck_count_estimate,
        partition_cell_count,
        habitable_band_count,
        service_band_count,
        corridor_band_count,
        cell_graph_edge_count: partition_cell_count + corridor_band_count + service_band_count,
        buildable_envelope_score,
        constructive_partition_score,
        topology_constructive_score,
        topology_constructive_status,
        notes,
    }
}

pub fn evaluate_constructive_topology(
    input: &ConstructiveTopologyLayoutInput,
    base: &ShapeStrategyLayoutOutput,
) -> (
    ConstructiveTopologyEvaluation,
    Vec<ConstructiveFloorTopologySummary>,
) {
    let mut floors = Vec::<ConstructiveFloorTopologySummary>::new();

    for base_floor in &base.per_floor_allocation_summaries {
        if let (Some(topo), Some(shape)) = (
            base.per_floor_topology_summaries
                .iter()
                .find(|x| x.level_index == base_floor.level_index),
            base.per_floor_shape_summaries
                .iter()
                .find(|x| x.level_index == base_floor.level_index),
        ) {
            floors.push(summarize_floor_constructive_topology(
                input, base_floor, topo, shape,
            ));
        }
    }

    let mean_buildable_envelope_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.buildable_envelope_score)
            .collect::<Vec<f64>>(),
    );
    let mean_constructive_partition_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.constructive_partition_score)
            .collect::<Vec<f64>>(),
    );
    let mean_topology_constructive_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.topology_constructive_score)
            .collect::<Vec<f64>>(),
    );

    let floors_with_envelope_repair_count = floors
        .iter()
        .filter(|x| x.offset_self_intersection_count > 0 || x.sliver_removed_area_sf > EPS)
        .count();
    let floors_with_partition_repair_count = floors
        .iter()
        .filter(|x| x.topology_constructive_status != "pass")
        .count();
    let floors_with_manual_topology_review_count = floors
        .iter()
        .filter(|x| x.narrow_neck_count_estimate >= 2 && x.topology_constructive_status != "pass")
        .count();

    let overall_status = if floors
        .iter()
        .any(|x| x.topology_constructive_status == "fail")
        || mean_topology_constructive_score < 0.60
    {
        PassWarnFailStatus::Fail
    } else if floors
        .iter()
        .any(|x| x.topology_constructive_status == "warn")
        || mean_topology_constructive_score < 0.78
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    (
        ConstructiveTopologyEvaluation {
            overall_status,
            selected_solver_stack: "offset-envelope -> constrained triangulation -> dual-clearance graph -> corridor spine tree with loop repair -> frontage-slot DP packing -> local repair".to_string(),
            mean_buildable_envelope_score,
            mean_constructive_partition_score,
            mean_topology_constructive_score,
            floors_with_envelope_repair_count,
            floors_with_partition_repair_count,
            floors_with_manual_topology_review_count,
            notes: vec![
                "constructive-topology turns polygon topology into a constructive cell/band substrate.".to_string(),
                "Envelope repair runs before corridor and packing summaries are evaluated.".to_string(),
            ],
        },
        floors,
    )
}

pub fn summarize_floor_corridor_graph(
    input: &ConstructiveTopologyLayoutInput,
    topo: &SpatialTopologyFloorSummary,
    shape: &ShapeStrategyFloorSummary,
    constructive: &ConstructiveFloorTopologySummary,
) -> ConstructiveFloorCorridorGraphSummary {
    let routing_mode = match input.corridor_graph_controls.routing_mode {
        ConstructiveCorridorRoutingMode::Hybrid => inferred_corridor_mode_from_shape(shape),
        other => other,
    };

    let node_count =
        (constructive.partition_cell_count + constructive.corridor_band_count + 1).max(1);
    let connector_count = match routing_mode {
        ConstructiveCorridorRoutingMode::LoopSpineWithBranches => shape
            .junction_count_estimate
            .min(input.corridor_graph_controls.max_connector_count),
        ConstructiveCorridorRoutingMode::BranchSpineOnly => topo
            .branch_zone_count_estimate
            .min(input.corridor_graph_controls.max_connector_count),
        ConstructiveCorridorRoutingMode::Hybrid => (shape.junction_count_estimate
            + shape.ring_count_estimate)
            .min(input.corridor_graph_controls.max_connector_count),
        ConstructiveCorridorRoutingMode::SpineTreeWithLoopRepair => {
            shape.junction_count_estimate.min(1)
        }
    };
    let primary_spine_count = match routing_mode {
        ConstructiveCorridorRoutingMode::BranchSpineOnly => shape.wing_count_estimate.max(1),
        ConstructiveCorridorRoutingMode::Hybrid => {
            (shape.wing_count_estimate + shape.ring_count_estimate).max(1)
        }
        _ => 1,
    };
    let loop_count = match routing_mode {
        ConstructiveCorridorRoutingMode::LoopSpineWithBranches => shape.ring_count_estimate.max(1),
        ConstructiveCorridorRoutingMode::Hybrid => shape.ring_count_estimate,
        _ => 0,
    };
    let branch_count = topo
        .branch_zone_count_estimate
        .max(shape.junction_count_estimate);
    let edge_count = node_count + connector_count + loop_count + primary_spine_count;
    let max_dead_end_ft = match routing_mode {
        ConstructiveCorridorRoutingMode::LoopSpineWithBranches => topo.detour_ratio_estimate * 8.0,
        ConstructiveCorridorRoutingMode::Hybrid => topo.detour_ratio_estimate * 12.0,
        ConstructiveCorridorRoutingMode::BranchSpineOnly => topo.detour_ratio_estimate * 16.0,
        ConstructiveCorridorRoutingMode::SpineTreeWithLoopRepair => {
            topo.detour_ratio_estimate * 10.0
        }
    };
    let mean_entry_to_core_ft = topo.service_reach_max_ft * 0.55 + max_dead_end_ft * 0.20;
    let egress_coverage_ratio = clamp(
        1.0 - mean_entry_to_core_ft
            / input
                .corridor_graph_controls
                .entry_to_core_soft_max_ft
                .max(EPS),
        0.0,
        1.0,
    );
    let path_overlap_ratio = clamp(
        (connector_count + loop_count) as f64 / (edge_count as f64 + 1.0),
        0.0,
        1.0,
    );

    let spine_score = clamp(
        1.0 - max_dead_end_ft / input.corridor_graph_controls.dead_end_hard_max_ft.max(EPS),
        0.0,
        1.0,
    );
    let path_coverage_score = clamp(
        egress_coverage_ratio * (1.0 - 0.5 * topo.interval_split_ratio_mean),
        0.0,
        1.0,
    );
    let dead_end_score = clamp(
        1.0 - max_dead_end_ft / input.corridor_graph_controls.dead_end_hard_max_ft.max(EPS),
        0.0,
        1.0,
    );
    let connector_efficiency_score = clamp(
        1.0 - (connector_count as f64)
            / (input.corridor_graph_controls.max_connector_count.max(1) as f64 + 1.0),
        0.0,
        1.0,
    );

    let corridor_graph_score = clamp(
        0.35 * spine_score
            + 0.35 * path_coverage_score
            + 0.15 * (1.0 - path_overlap_ratio)
            + 0.15 * connector_efficiency_score,
        0.0,
        1.0,
    );

    let corridor_graph_status = if corridor_graph_score < 0.58
        || max_dead_end_ft > input.corridor_graph_controls.dead_end_hard_max_ft
    {
        "fail".to_string()
    } else if corridor_graph_score < 0.76
        || max_dead_end_ft > input.corridor_graph_controls.dead_end_soft_max_ft
        || mean_entry_to_core_ft > input.corridor_graph_controls.entry_to_core_soft_max_ft
    {
        "warn".to_string()
    } else {
        "pass".to_string()
    };

    let mut notes = vec![
        format!(
            "routing_mode = {}",
            corridor_routing_mode_as_str(routing_mode)
        ),
        format!("connector_count = {}", connector_count),
    ];
    if loop_count > 0 {
        notes.push("loop-like corridor behavior is active on this floor.".to_string());
    }
    if branch_count > primary_spine_count + 2 {
        notes.push("branch pressure remains high relative to primary spines.".to_string());
    }

    ConstructiveFloorCorridorGraphSummary {
        level_index: constructive.level_index,
        family_id: constructive.family_id.clone(),
        routing_mode: corridor_routing_mode_as_str(routing_mode).to_string(),
        node_count,
        edge_count,
        primary_spine_count,
        connector_count,
        loop_count,
        branch_count,
        max_dead_end_ft,
        mean_entry_to_core_ft,
        egress_coverage_ratio,
        path_overlap_ratio,
        corridor_graph_score,
        corridor_graph_status,
        notes,
    }
}

pub fn evaluate_corridor_graph(
    input: &ConstructiveTopologyLayoutInput,
    base: &ShapeStrategyLayoutOutput,
    constructive: &[ConstructiveFloorTopologySummary],
) -> (
    ConstructiveCorridorGraphEvaluation,
    Vec<ConstructiveFloorCorridorGraphSummary>,
) {
    let mut floors = Vec::<ConstructiveFloorCorridorGraphSummary>::new();

    for c in constructive {
        if let (Some(topo), Some(shape)) = (
            base.per_floor_topology_summaries
                .iter()
                .find(|x| x.level_index == c.level_index),
            base.per_floor_shape_summaries
                .iter()
                .find(|x| x.level_index == c.level_index),
        ) {
            floors.push(summarize_floor_corridor_graph(input, topo, shape, c));
        }
    }

    let mean_spine_score = mean_f64(
        &floors
            .iter()
            .map(|x| {
                clamp(
                    1.0 - x.max_dead_end_ft
                        / input.corridor_graph_controls.dead_end_hard_max_ft.max(EPS),
                    0.0,
                    1.0,
                )
            })
            .collect::<Vec<f64>>(),
    );
    let mean_path_coverage_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.egress_coverage_ratio)
            .collect::<Vec<f64>>(),
    );
    let mean_dead_end_score = mean_f64(
        &floors
            .iter()
            .map(|x| {
                clamp(
                    1.0 - x.max_dead_end_ft
                        / input.corridor_graph_controls.dead_end_hard_max_ft.max(EPS),
                    0.0,
                    1.0,
                )
            })
            .collect::<Vec<f64>>(),
    );
    let mean_connector_efficiency_score = mean_f64(
        &floors
            .iter()
            .map(|x| {
                clamp(
                    1.0 - x.connector_count as f64
                        / (input.corridor_graph_controls.max_connector_count.max(1) as f64 + 1.0),
                    0.0,
                    1.0,
                )
            })
            .collect::<Vec<f64>>(),
    );

    let floors_with_loop_strategy_count = floors.iter().filter(|x| x.loop_count > 0).count();
    let floors_with_branch_excess_count = floors
        .iter()
        .filter(|x| x.branch_count > x.primary_spine_count + 2)
        .count();

    let mean_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.corridor_graph_score)
            .collect::<Vec<f64>>(),
    );
    let overall_status =
        if floors.iter().any(|x| x.corridor_graph_status == "fail") || mean_score < 0.60 {
            PassWarnFailStatus::Fail
        } else if floors.iter().any(|x| x.corridor_graph_status == "warn") || mean_score < 0.78 {
            PassWarnFailStatus::Warn
        } else {
            PassWarnFailStatus::Pass
        };

    (
        ConstructiveCorridorGraphEvaluation {
            overall_status,
            mean_spine_score,
            mean_path_coverage_score,
            mean_dead_end_score,
            mean_connector_efficiency_score,
            floors_with_loop_strategy_count,
            floors_with_branch_excess_count,
            notes: vec![
                "constructive-topology expresses corridor routing as a graph-construction problem rather than a scalar corridor length estimate.".to_string(),
                "Dead-ends, loops, and connectors are exposed explicitly for repair and review.".to_string(),
            ],
        },
        floors,
    )
}

pub fn summarize_floor_space_packing(
    input: &ConstructiveTopologyLayoutInput,
    base_floor: &SpatialGeometryFloorAllocationSummary,
    topo: &SpatialTopologyFloorSummary,
    shape: &ShapeStrategyFloorSummary,
    constructive: &ConstructiveFloorTopologySummary,
    corridor: &ConstructiveFloorCorridorGraphSummary,
) -> ConstructiveFloorSpacePackingSummary {
    let frontage_slot_count = if input.space_packing_controls.frontage_slot_step_ft <= EPS {
        0usize
    } else {
        (base_floor.effective_frontage_ft / input.space_packing_controls.frontage_slot_step_ft)
            .floor()
            .max(0.0) as usize
    };

    let packed_unit_count_estimate = clamp(
        frontage_slot_count as f64 * base_floor.frontage_utilization * 0.22,
        0.0,
        frontage_slot_count as f64,
    )
    .round() as usize;

    let service_cell_count = (constructive.service_band_count + corridor.connector_count).max(1);
    let amenity_cell_count = if base_floor.allocation_status == "pass" {
        constructive.narrow_neck_count_estimate.min(1) + shape.ring_count_estimate.min(1)
    } else {
        0
    };
    let total_residual_count = (topo.frontage_run_count + shape.junction_count_estimate).max(1);
    let convertible_residual_count =
        ((1.0 - topo.residual_compactness_estimate) * total_residual_count as f64 * 0.8)
            .round()
            .max(0.0) as usize;
    let discardable_residual_count =
        ((1.0 - constructive.buildable_envelope_score) * total_residual_count as f64 * 0.35)
            .round()
            .max(0.0) as usize;

    let wet_wall_pairing_score = clamp(
        0.55 * topo.service_reach_score + 0.45 * shape.strategy_fit_score,
        0.0,
        1.0,
    );
    let shaft_affinity_score = clamp(
        1.0 - corridor.mean_entry_to_core_ft
            / input.adjacency_shaft_controls.max_shaft_detour_ft.max(EPS),
        0.0,
        1.0,
    );
    let residual_utilization_ratio = if total_residual_count == 0 {
        1.0
    } else {
        clamp(
            convertible_residual_count as f64 / total_residual_count as f64,
            0.0,
            1.0,
        )
    };

    let unit_frontage_fit_score = if frontage_slot_count == 0 {
        0.0
    } else {
        clamp(
            packed_unit_count_estimate as f64 / frontage_slot_count as f64 * 4.2,
            0.0,
            1.0,
        )
    };
    let service_conversion_score = clamp(
        residual_utilization_ratio
            + 0.15 * (service_cell_count as f64 / (constructive.partition_cell_count as f64 + 1.0)),
        0.0,
        1.0,
    );
    let wet_wall_affinity_score = clamp(
        0.55 * wet_wall_pairing_score + 0.45 * shaft_affinity_score,
        0.0,
        1.0,
    );

    let space_packing_score = clamp(
        0.35 * unit_frontage_fit_score
            + 0.20 * service_conversion_score
            + 0.20 * residual_utilization_ratio
            + 0.25 * wet_wall_affinity_score,
        0.0,
        1.0,
    );

    let space_packing_status = if space_packing_score < 0.58
        || (input
            .adjacency_shaft_controls
            .hard_fail_if_shaft_unreachable
            && shaft_affinity_score < 0.25)
    {
        "fail".to_string()
    } else if space_packing_score < 0.76
        || wet_wall_pairing_score < 0.45
        || residual_utilization_ratio < 1.0 - input.residual_handling_controls.max_discardable_ratio
    {
        "warn".to_string()
    } else {
        "pass".to_string()
    };

    let mut notes = vec![
        format!("frontage_slot_count = {}", frontage_slot_count),
        format!(
            "packed_unit_count_estimate = {}",
            packed_unit_count_estimate
        ),
    ];
    if convertible_residual_count > 0 {
        notes.push("some residual cells are converted to service/support uses.".to_string());
    }
    if discardable_residual_count > 0 {
        notes.push("discardable residual cells remain after local repair.".to_string());
    }

    ConstructiveFloorSpacePackingSummary {
        level_index: base_floor.level_index,
        family_id: base_floor.family_id.clone(),
        packing_mode: packing_mode_as_str(input.space_packing_controls.packing_mode).to_string(),
        frontage_slot_count,
        packed_unit_count_estimate,
        service_cell_count,
        amenity_cell_count,
        convertible_residual_count,
        discardable_residual_count,
        wet_wall_pairing_score,
        shaft_affinity_score,
        residual_utilization_ratio,
        space_packing_score,
        space_packing_status,
        notes,
    }
}

pub fn evaluate_space_packing(
    input: &ConstructiveTopologyLayoutInput,
    base: &ShapeStrategyLayoutOutput,
    constructive: &[ConstructiveFloorTopologySummary],
    corridor: &[ConstructiveFloorCorridorGraphSummary],
) -> (
    ConstructiveSpacePackingEvaluation,
    Vec<ConstructiveFloorSpacePackingSummary>,
) {
    let mut floors = Vec::<ConstructiveFloorSpacePackingSummary>::new();

    for c in constructive {
        if let (Some(base_floor), Some(topo), Some(shape), Some(corr)) = (
            base.per_floor_allocation_summaries
                .iter()
                .find(|x| x.level_index == c.level_index),
            base.per_floor_topology_summaries
                .iter()
                .find(|x| x.level_index == c.level_index),
            base.per_floor_shape_summaries
                .iter()
                .find(|x| x.level_index == c.level_index),
            corridor.iter().find(|x| x.level_index == c.level_index),
        ) {
            floors.push(summarize_floor_space_packing(
                input, base_floor, topo, shape, c, corr,
            ));
        }
    }

    let mean_unit_frontage_fit_score = mean_f64(
        &floors
            .iter()
            .map(|x| {
                clamp(
                    x.packed_unit_count_estimate as f64 / (x.frontage_slot_count.max(1) as f64)
                        * 4.2,
                    0.0,
                    1.0,
                )
            })
            .collect::<Vec<f64>>(),
    );
    let mean_service_conversion_score = mean_f64(
        &floors
            .iter()
            .map(|x| {
                clamp(
                    x.convertible_residual_count as f64
                        / ((x.convertible_residual_count + x.discardable_residual_count).max(1)
                            as f64),
                    0.0,
                    1.0,
                )
            })
            .collect::<Vec<f64>>(),
    );
    let mean_residual_utilization_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.residual_utilization_ratio)
            .collect::<Vec<f64>>(),
    );
    let mean_wet_wall_affinity_score = mean_f64(
        &floors
            .iter()
            .map(|x| {
                clamp(
                    0.55 * x.wet_wall_pairing_score + 0.45 * x.shaft_affinity_score,
                    0.0,
                    1.0,
                )
            })
            .collect::<Vec<f64>>(),
    );

    let floors_with_unit_repack_count = floors
        .iter()
        .filter(|x| x.space_packing_status != "pass")
        .count();
    let floors_with_residual_trigger_repair_count = floors
        .iter()
        .filter(|x| {
            x.discardable_residual_count > 0
                && x.residual_utilization_ratio
                    < input
                        .residual_handling_controls
                        .trigger_repair_compactness_below
        })
        .count();

    let mean_score = mean_f64(
        &floors
            .iter()
            .map(|x| x.space_packing_score)
            .collect::<Vec<f64>>(),
    );
    let overall_status =
        if floors.iter().any(|x| x.space_packing_status == "fail") || mean_score < 0.60 {
            PassWarnFailStatus::Fail
        } else if floors.iter().any(|x| x.space_packing_status == "warn") || mean_score < 0.78 {
            PassWarnFailStatus::Warn
        } else {
            PassWarnFailStatus::Pass
        };

    (
        ConstructiveSpacePackingEvaluation {
            overall_status,
            mean_unit_frontage_fit_score,
            mean_service_conversion_score,
            mean_residual_utilization_score,
            mean_wet_wall_affinity_score,
            floors_with_unit_repack_count,
            floors_with_residual_trigger_repair_count,
            notes: vec![
                "constructive-topology chooses frontage-slot DP as the main packing solver over polygon bands.".to_string(),
                "Wet-wall/shaft affinity remains a proxy, but it is now part of repair gating rather than score-only reporting.".to_string(),
            ],
        },
        floors,
    )
}

pub fn summarize_floor_repair(
    input: &ConstructiveTopologyLayoutInput,
    constructive: &ConstructiveFloorTopologySummary,
    corridor: &ConstructiveFloorCorridorGraphSummary,
    packing: &ConstructiveFloorSpacePackingSummary,
) -> ConstructiveFloorRepairSummary {
    let mut candidate_count = input.search_repair_controls.max_candidates;
    if corridor.corridor_graph_status != "pass" {
        candidate_count = candidate_count
            .saturating_add(2)
            .min(input.search_repair_controls.max_candidates + 4);
    }
    if constructive.topology_constructive_status != "pass" {
        candidate_count = candidate_count
            .saturating_add(2)
            .min(input.search_repair_controls.max_candidates + 6);
    }

    let repair_pressure = (1.0 - constructive.topology_constructive_score)
        + (1.0 - corridor.corridor_graph_score)
        + (1.0 - packing.space_packing_score);
    let repair_rounds_applied = clamp(
        repair_pressure * (input.search_repair_controls.max_local_repair_rounds as f64 + 1.0),
        0.0,
        input.search_repair_controls.max_local_repair_rounds as f64,
    )
    .round() as usize;
    let neighborhood_moves_applied = repair_rounds_applied.saturating_mul(
        input
            .search_repair_controls
            .max_neighborhood_moves_per_round
            .min(3),
    );

    let manual_review_required = repair_rounds_applied
        >= input.search_repair_controls.max_local_repair_rounds
        && (packing.space_packing_status == "fail"
            || corridor.corridor_graph_status == "fail"
            || constructive.topology_constructive_status == "fail")
        && input
            .search_repair_controls
            .manual_review_after_iteration_cap;

    let stop_reason = if constructive.topology_constructive_status == "pass"
        && corridor.corridor_graph_status == "pass"
        && packing.space_packing_status == "pass"
        && repair_rounds_applied <= 1
    {
        "feasible_solution_found".to_string()
    } else if manual_review_required {
        "manual_review_required".to_string()
    } else if repair_rounds_applied >= input.search_repair_controls.max_local_repair_rounds {
        "iteration_cap".to_string()
    } else {
        "repair_budget_exhausted".to_string()
    };

    let repair_score = clamp(
        0.40 * constructive.topology_constructive_score
            + 0.30 * corridor.corridor_graph_score
            + 0.30 * packing.space_packing_score
            - 0.04 * repair_rounds_applied as f64,
        0.0,
        1.0,
    );

    let mut notes = vec![
        format!(
            "candidate_generation_mode = {}",
            candidate_generation_mode_as_str(
                input.search_repair_controls.candidate_generation_mode
            )
        ),
        format!("repair_rounds_applied = {}", repair_rounds_applied),
    ];
    if manual_review_required {
        notes.push(
            "repair reached its bounded budget and still requires manual review.".to_string(),
        );
    }

    ConstructiveFloorRepairSummary {
        level_index: constructive.level_index,
        family_id: constructive.family_id.clone(),
        candidate_count,
        repair_rounds_applied,
        neighborhood_moves_applied,
        stop_reason,
        manual_review_required,
        repair_score,
        notes,
    }
}

pub fn evaluate_repair_search(
    input: &ConstructiveTopologyLayoutInput,
    constructive: &[ConstructiveFloorTopologySummary],
    corridor: &[ConstructiveFloorCorridorGraphSummary],
    packing: &[ConstructiveFloorSpacePackingSummary],
) -> (
    ConstructiveRepairSearchEvaluation,
    Vec<ConstructiveFloorRepairSummary>,
) {
    let mut floors = Vec::<ConstructiveFloorRepairSummary>::new();

    for c in constructive {
        if let (Some(corr), Some(pack)) = (
            corridor.iter().find(|x| x.level_index == c.level_index),
            packing.iter().find(|x| x.level_index == c.level_index),
        ) {
            floors.push(summarize_floor_repair(input, c, corr, pack));
        }
    }

    let mean_candidates_explored = mean_f64(
        &floors
            .iter()
            .map(|x| x.candidate_count as f64)
            .collect::<Vec<f64>>(),
    );
    let mean_repair_moves_applied = mean_f64(
        &floors
            .iter()
            .map(|x| x.neighborhood_moves_applied as f64)
            .collect::<Vec<f64>>(),
    );
    let floors_hitting_iteration_cap_count = floors
        .iter()
        .filter(|x| x.stop_reason == "iteration_cap")
        .count();
    let floors_requiring_manual_review_count =
        floors.iter().filter(|x| x.manual_review_required).count();

    let mut stop_reason_histogram = BTreeMap::<String, usize>::new();
    for floor in &floors {
        *stop_reason_histogram
            .entry(floor.stop_reason.clone())
            .or_insert(0) += 1;
    }

    let mean_score = mean_f64(&floors.iter().map(|x| x.repair_score).collect::<Vec<f64>>());
    let overall_status = if floors.iter().any(|x| x.manual_review_required) || mean_score < 0.60 {
        PassWarnFailStatus::Fail
    } else if floors_hitting_iteration_cap_count > 0 || mean_score < 0.78 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    (
        ConstructiveRepairSearchEvaluation {
            overall_status,
            deterministic_tie_break_mode: repair_tie_break_mode_as_str(input.search_repair_controls.tie_break_mode).to_string(),
            max_candidate_count: input.search_repair_controls.max_candidates,
            mean_candidates_explored,
            mean_repair_moves_applied,
            floors_hitting_iteration_cap_count,
            floors_requiring_manual_review_count,
            stop_reason_histogram,
            notes: vec![
                "constructive-topology uses bounded deterministic search with explicit stop reasons.".to_string(),
                "Repair does not claim global optimality; it prefers inspectable local improvements.".to_string(),
            ],
        },
        floors,
    )
}

impl ConstructiveTopologyLayoutInput {
    pub fn validate(&self) -> Vec<ValidationIssue> {
        let mut issues = self.to_shape_strategy_input().validate();

        if self.buildable_envelope_controls.min_clear_neck_ft <= 0.0 {
            issues.push(ValidationIssue::error(
                "min_clear_neck_nonpositive",
                "buildable_envelope_controls.min_clear_neck_ft must be > 0",
            ));
        }
        if self.buildable_envelope_controls.min_sliver_area_sf <= 0.0 {
            issues.push(ValidationIssue::error(
                "min_sliver_area_nonpositive",
                "buildable_envelope_controls.min_sliver_area_sf must be > 0",
            ));
        }
        if self.constructive_topology_controls.mesh_target_edge_ft <= 0.0 {
            issues.push(ValidationIssue::error(
                "mesh_target_edge_nonpositive",
                "constructive_topology_controls.mesh_target_edge_ft must be > 0",
            ));
        }
        if self.constructive_topology_controls.clearance_probe_step_ft <= 0.0 {
            issues.push(ValidationIssue::error(
                "clearance_probe_step_nonpositive",
                "constructive_topology_controls.clearance_probe_step_ft must be > 0",
            ));
        }
        if self.corridor_graph_controls.min_corridor_clear_width_ft <= 0.0 {
            issues.push(ValidationIssue::error(
                "corridor_min_width_nonpositive",
                "corridor_graph_controls.min_corridor_clear_width_ft must be > 0",
            ));
        }
        if self.corridor_graph_controls.dead_end_hard_max_ft
            < self.corridor_graph_controls.dead_end_soft_max_ft
        {
            issues.push(ValidationIssue::error(
                "dead_end_limits_invalid",
                "corridor_graph_controls.dead_end_hard_max_ft must be >= dead_end_soft_max_ft",
            ));
        }
        if self.space_packing_controls.frontage_slot_step_ft <= 0.0 {
            issues.push(ValidationIssue::error(
                "frontage_slot_step_nonpositive",
                "space_packing_controls.frontage_slot_step_ft must be > 0",
            ));
        }
        if self
            .residual_handling_controls
            .trigger_repair_compactness_below
            < 0.0
            || self
                .residual_handling_controls
                .trigger_repair_compactness_below
                > 1.0
        {
            issues.push(ValidationIssue::error(
                "trigger_repair_compactness_invalid",
                "residual_handling_controls.trigger_repair_compactness_below must be in [0, 1]",
            ));
        }
        if self.adjacency_shaft_controls.kitchen_bath_affinity_weight < 0.0
            || self.adjacency_shaft_controls.kitchen_bath_affinity_weight > 1.0
        {
            issues.push(ValidationIssue::error(
                "kitchen_bath_affinity_weight_invalid",
                "adjacency_shaft_controls.kitchen_bath_affinity_weight must be in [0, 1]",
            ));
        }
        if self
            .vertical_continuity_controls
            .podium_to_tower_reseed_threshold
            < 0.0
            || self
                .vertical_continuity_controls
                .podium_to_tower_reseed_threshold
                > 1.0
        {
            issues.push(ValidationIssue::error(
                "podium_to_tower_reseed_threshold_invalid",
                "vertical_continuity_controls.podium_to_tower_reseed_threshold must be in [0, 1]",
            ));
        }
        if self.search_repair_controls.max_candidates == 0 {
            issues.push(ValidationIssue::error(
                "max_candidates_zero",
                "search_repair_controls.max_candidates must be >= 1",
            ));
        }

        issues
    }

    pub fn to_shape_strategy_input(&self) -> ShapeStrategyLayoutInput {
        ShapeStrategyLayoutInput {
            jurisdiction_profile: self.jurisdiction_profile.clone(),
            building_shape: self.building_shape,
            building_construction_type: self.building_construction_type,
            site_polygon: self.site_polygon.clone(),
            site_controls: self.site_controls.clone(),
            levels: self.levels.clone(),
            unit_mix: self.unit_mix.clone(),
            constraints: self.constraints.clone(),
            residential_features: self.residential_features.clone(),
            vertical_rules: self.vertical_rules.clone(),
            amenities: self.amenities.clone(),
            targets: self.targets.clone(),
            optimization: self.optimization.clone(),
            code_profile_overrides: self.code_profile_overrides.clone(),
            shape_parameters: self.shape_parameters.clone(),
            solver_controls: self.solver_controls.clone(),
            user_overrides: self.user_overrides.clone(),
            local_overlay_pack: self.local_overlay_pack.clone(),
            parking_program: self.parking_program.clone(),
            repeatability_controls: self.repeatability_controls.clone(),
            repo_export: self.repo_export.clone(),
            feasibility_controls: ShapeStrategyFeasibilityControls {
                strict_repo_contract: self.feasibility_controls.strict_repo_contract,
                mark_unclear_before_deep_solve: self
                    .feasibility_controls
                    .mark_unclear_before_deep_solve,
                allow_deferred_zones: self.feasibility_controls.allow_deferred_zones,
                max_unclear_zones: self.feasibility_controls.max_unclear_zones,
                require_bound_local_overlay_for_parking: self
                    .feasibility_controls
                    .require_bound_local_overlay_for_parking,
                require_projection_bundle_for_repo_export: self
                    .feasibility_controls
                    .require_projection_bundle_for_repo_export,
                max_projection_semantic_loss_records: self
                    .feasibility_controls
                    .max_projection_semantic_loss_records,
                repeatability_fail_as_deferred: self
                    .feasibility_controls
                    .repeatability_fail_as_deferred,
                spatial_geometry_fail_as_deferred: self
                    .feasibility_controls
                    .spatial_geometry_fail_as_deferred,
                max_floorplan_geometry_warnings: self
                    .feasibility_controls
                    .max_floorplan_geometry_warnings,
                topology_fail_as_deferred: self.feasibility_controls.topology_fail_as_deferred,
                max_floorplan_topology_warnings: self
                    .feasibility_controls
                    .max_floorplan_topology_warnings,
                shape_strategy_fail_as_deferred: self
                    .feasibility_controls
                    .shape_strategy_fail_as_deferred,
                max_floorplan_shape_warnings: self
                    .feasibility_controls
                    .max_floorplan_shape_warnings,
                require_declared_shape_strategy_match: self
                    .feasibility_controls
                    .require_declared_shape_strategy_match,
            },
            floor_geometry_controls: self.floor_geometry_controls.clone(),
            space_allocation_controls: self.space_allocation_controls.clone(),
            topology_geometry_controls: self.topology_geometry_controls.clone(),
            allocation_graph_controls: self.allocation_graph_controls.clone(),
            shape_decomposition_controls: self.shape_decomposition_controls.clone(),
            shape_strategy_controls: self.shape_strategy_controls.clone(),
        }
    }
}

pub fn identify_preflight_unclear_zones_with_constructive_topology(
    input: &ConstructiveTopologyLayoutInput,
) -> Vec<UnclearZone> {
    let mut zones =
        identify_preflight_unclear_zones_with_shape_decomposition(&input.to_shape_strategy_input());

    if !input
        .buildable_envelope_controls
        .enable_self_intersection_repair
        && (input.site_polygon.len() >= 6 || input.building_shape == BuildingShape::FreeForm)
    {
        zones.push(UnclearZone::new(
            "buildable_envelope_self_intersection_repair_disabled",
            ValidationSeverity::Warning,
            SolvePhase::InputNormalization,
            "buildable-envelope",
            "Self-intersection repair is disabled even though the site/floor family is complex.",
            "Envelope construction may become unstable on concave or free-form polygons.",
            LayoutEngineLayer::LayeredTopology,
            false,
        ));
    }

    if matches!(
        input.constructive_topology_controls.decomposition_stack,
        ConstructiveDecompositionStack::StraightSkeletonExperimental
    ) {
        zones.push(UnclearZone::new(
            "straight_skeleton_experimental_stack",
            ValidationSeverity::Info,
            SolvePhase::FloorZoning,
            "constructive-topology",
            "The experimental straight-skeleton decomposition stack is selected.",
            "This path is not the preferred canonical runtime stack in constructive-topology and may need additional review.",
            LayoutEngineLayer::LayeredTopology,
            false,
        ));
    }

    if input.search_repair_controls.max_total_iterations
        < input.search_repair_controls.max_local_repair_rounds
    {
        zones.push(UnclearZone::new(
            "repair_budget_too_low_for_rounds",
            ValidationSeverity::Warning,
            SolvePhase::SpaceLayout,
            "repair-search",
            "The global repair iteration budget is lower than the local repair-round budget.",
            "The search may terminate before neighborhood repair has meaningful room to operate.",
            LayoutEngineLayer::LayeredTopology,
            false,
        ));
    }

    zones
}

pub fn identify_postsolve_unclear_zones_with_constructive_topology(
    input: &ConstructiveTopologyLayoutInput,
    base: &ShapeStrategyLayoutOutput,
    constructive_eval: &ConstructiveTopologyEvaluation,
    constructive_floors: &[ConstructiveFloorTopologySummary],
    corridor_eval: &ConstructiveCorridorGraphEvaluation,
    corridor_floors: &[ConstructiveFloorCorridorGraphSummary],
    packing_eval: &ConstructiveSpacePackingEvaluation,
    packing_floors: &[ConstructiveFloorSpacePackingSummary],
    repair_eval: &ConstructiveRepairSearchEvaluation,
    repair_floors: &[ConstructiveFloorRepairSummary],
) -> Vec<UnclearZone> {
    let mut zones = identify_postsolve_unclear_zones_from_shape_strategy_base(
        &input.to_shape_strategy_input(),
        base,
        &base.shape_decomposition_evaluation,
        &base.per_floor_shape_summaries,
    );

    if !constructive_eval.overall_status.is_pass() {
        zones.push(UnclearZone::new(
            "constructive_topology_quality_low",
            if constructive_eval.overall_status.is_fail() { ValidationSeverity::Error } else { ValidationSeverity::Warning },
            SolvePhase::SpaceLayout,
            "constructive-topology",
            "The constructive topology layer does not remain inside the preferred constructive-topology band.",
            "At least one floor still needs stronger envelope repair, neck handling, or cell-graph partitioning.",
            LayoutEngineLayer::LayeredTopology,
            constructive_eval.overall_status.is_fail(),
        ));
    }

    if !corridor_eval.overall_status.is_pass() {
        zones.push(UnclearZone::new(
            "corridor_graph_quality_low",
            if corridor_eval.overall_status.is_fail() { ValidationSeverity::Error } else { ValidationSeverity::Warning },
            SolvePhase::SpaceLayout,
            "corridor-graph",
            "At least one floor still has weak corridor graph quality.",
            "Branch, dead-end, or connector behavior still needs stronger graph repair or exact routing in layered-topology.",
            LayoutEngineLayer::LayeredTopology,
            corridor_eval.overall_status.is_fail(),
        ));
    }

    if !packing_eval.overall_status.is_pass() {
        zones.push(UnclearZone::new(
            "space_packing_quality_low",
            if packing_eval.overall_status.is_fail() { ValidationSeverity::Error } else { ValidationSeverity::Warning },
            SolvePhase::SpaceLayout,
            "space-packing",
            "At least one floor still has weak constructive packing quality.",
            "Residual handling, wet-wall affinity, or frontage-slot packing still needs deeper exact solving in layered-topology.",
            LayoutEngineLayer::LayeredTopology,
            packing_eval.overall_status.is_fail(),
        ));
    }

    if !repair_eval.overall_status.is_pass() {
        zones.push(UnclearZone::new(
            "repair_search_budget_exhausted",
            if repair_eval.overall_status.is_fail() { ValidationSeverity::Error } else { ValidationSeverity::Warning },
            SolvePhase::SpaceLayout,
            "repair-search",
            "The bounded repair/search loop hit its budget or manual-review gate on at least one floor.",
            "constructive-topology intentionally exposes this instead of pretending the solver converged.",
            LayoutEngineLayer::LayeredTopology,
            repair_eval.overall_status.is_fail(),
        ));
    }

    if constructive_floors
        .iter()
        .any(|x| x.narrow_neck_count_estimate > 0)
    {
        zones.push(UnclearZone::new(
            "narrow_neck_behavior_present",
            ValidationSeverity::Info,
            SolvePhase::FloorZoning,
            "constructive-topology",
            "One or more floors contain narrow-neck or bottleneck behavior.",
            "The constructive solver can handle this locally in constructive-topology, but exact global decomposition remains a layered-topology task.",
            LayoutEngineLayer::LayeredTopology,
            false,
        ));
    }

    if packing_floors
        .iter()
        .any(|x| x.discardable_residual_count > 0)
    {
        zones.push(UnclearZone::new(
            "discardable_residual_cells_present",
            ValidationSeverity::Info,
            SolvePhase::SpaceLayout,
            "space-packing",
            "Some floors still discard low-value residual cells after local repair.",
            "This is acceptable in constructive-topology up to budget, but richer reuse/merge logic belongs in layered-topology.",
            LayoutEngineLayer::LayeredTopology,
            false,
        ));
    }

    if repair_floors.iter().any(|x| x.manual_review_required) {
        zones.push(UnclearZone::new(
            "manual_review_required_after_bounded_search",
            ValidationSeverity::Warning,
            SolvePhase::SpaceLayout,
            "repair-search",
            "The bounded local search required manual review on at least one floor.",
            "The engine intentionally stops deterministically instead of escalating into an opaque or global stochastic search.",
            LayoutEngineLayer::LayeredTopology,
            false,
        ));
    }

    zones
}

pub fn classify_feasibility_status_with_constructive_topology(
    input: &ConstructiveTopologyLayoutInput,
    base: &ShapeStrategyLayoutOutput,
    preflight: &[UnclearZone],
    postsolve: &[UnclearZone],
    constructive_eval: &ConstructiveTopologyEvaluation,
    constructive_floors: &[ConstructiveFloorTopologySummary],
    corridor_eval: &ConstructiveCorridorGraphEvaluation,
    corridor_floors: &[ConstructiveFloorCorridorGraphSummary],
    packing_eval: &ConstructiveSpacePackingEvaluation,
    packing_floors: &[ConstructiveFloorSpacePackingSummary],
    repair_eval: &ConstructiveRepairSearchEvaluation,
) -> FeasibilityStatus {
    match base.feasibility_status {
        FeasibilityStatus::NotRepoContractSafe => return FeasibilityStatus::NotRepoContractSafe,
        FeasibilityStatus::DeferredZonesPresent => return FeasibilityStatus::DeferredZonesPresent,
        _ => {}
    }

    if input
        .feasibility_controls
        .constructive_topology_fail_as_deferred
        && constructive_eval.overall_status.is_fail()
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }
    if input.feasibility_controls.corridor_graph_fail_as_deferred
        && corridor_eval.overall_status.is_fail()
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }
    if input.feasibility_controls.space_packing_fail_as_deferred
        && packing_eval.overall_status.is_fail()
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }
    if input.feasibility_controls.repair_search_fail_as_deferred
        && repair_eval.overall_status.is_fail()
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }

    let constructive_warn_count = constructive_floors
        .iter()
        .filter(|x| x.topology_constructive_status != "pass")
        .count();
    let corridor_warn_count = corridor_floors
        .iter()
        .filter(|x| x.corridor_graph_status != "pass")
        .count();
    let packing_warn_count = packing_floors
        .iter()
        .filter(|x| x.space_packing_status != "pass")
        .count();

    if input
        .feasibility_controls
        .constructive_topology_fail_as_deferred
        && constructive_warn_count
            > input
                .feasibility_controls
                .max_floorplan_constructive_warnings
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }
    if input.feasibility_controls.corridor_graph_fail_as_deferred
        && corridor_warn_count > input.feasibility_controls.max_floorplan_corridor_warnings
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }
    if input.feasibility_controls.space_packing_fail_as_deferred
        && packing_warn_count > input.feasibility_controls.max_floorplan_packing_warnings
    {
        return FeasibilityStatus::DeferredZonesPresent;
    }

    if !preflight.is_empty()
        || !postsolve.is_empty()
        || constructive_eval.overall_status.is_warn()
        || corridor_eval.overall_status.is_warn()
        || packing_eval.overall_status.is_warn()
        || repair_eval.overall_status.is_warn()
    {
        return FeasibilityStatus::ConditionallyFeasible;
    }

    base.feasibility_status
}

impl ConstructiveTopologyLayoutEngine {
    pub fn solve(
        &self,
        input: &ConstructiveTopologyLayoutInput,
    ) -> ConstructiveTopologyLayoutOutput {
        self.run(input.clone())
    }

    pub fn run(&self, input: ConstructiveTopologyLayoutInput) -> ConstructiveTopologyLayoutOutput {
        let base = self.inner.run(input.to_shape_strategy_input());
        let (constructive_topology_evaluation, per_floor_constructive_topology_summaries) =
            evaluate_constructive_topology(&input, &base);
        let (corridor_graph_evaluation, per_floor_corridor_graph_summaries) =
            evaluate_corridor_graph(&input, &base, &per_floor_constructive_topology_summaries);
        let (space_packing_evaluation, per_floor_space_packing_summaries) = evaluate_space_packing(
            &input,
            &base,
            &per_floor_constructive_topology_summaries,
            &per_floor_corridor_graph_summaries,
        );
        let (repair_search_evaluation, per_floor_repair_summaries) = evaluate_repair_search(
            &input,
            &per_floor_constructive_topology_summaries,
            &per_floor_corridor_graph_summaries,
            &per_floor_space_packing_summaries,
        );

        let preflight_unclear_zones =
            identify_preflight_unclear_zones_with_constructive_topology(&input);
        let postsolve_unclear_zones = identify_postsolve_unclear_zones_with_constructive_topology(
            &input,
            &base,
            &constructive_topology_evaluation,
            &per_floor_constructive_topology_summaries,
            &corridor_graph_evaluation,
            &per_floor_corridor_graph_summaries,
            &space_packing_evaluation,
            &per_floor_space_packing_summaries,
            &repair_search_evaluation,
            &per_floor_repair_summaries,
        );

        let feasibility_status = classify_feasibility_status_with_constructive_topology(
            &input,
            &base,
            &preflight_unclear_zones,
            &postsolve_unclear_zones,
            &constructive_topology_evaluation,
            &per_floor_constructive_topology_summaries,
            &corridor_graph_evaluation,
            &per_floor_corridor_graph_summaries,
            &space_packing_evaluation,
            &per_floor_space_packing_summaries,
            &repair_search_evaluation,
        );

        ConstructiveTopologyLayoutOutput {
            engine_layer: LayoutEngineLayer::ConstructiveTopology,
            feasibility_status,
            repo_contract_evaluation: base.repo_contract_evaluation.clone(),
            local_overlay_evaluation: base.local_overlay_evaluation.clone(),
            parking_binding_evaluation: base.parking_binding_evaluation.clone(),
            repeatability_evaluation: base.repeatability_evaluation.clone(),
            spatial_geometry_evaluation: base.spatial_geometry_evaluation.clone(),
            per_floor_allocation_summaries: base.per_floor_allocation_summaries.clone(),
            constructive_topology_evaluation,
            per_floor_constructive_topology_summaries,
            corridor_graph_evaluation,
            per_floor_corridor_graph_summaries,
            space_packing_evaluation,
            per_floor_space_packing_summaries,
            repair_search_evaluation,
            per_floor_repair_summaries,
            spatial_topology_evaluation: base.spatial_topology_evaluation.clone(),
            per_floor_topology_summaries: base.per_floor_topology_summaries.clone(),
            shape_decomposition_evaluation: base.shape_decomposition_evaluation.clone(),
            per_floor_shape_summaries: base.per_floor_shape_summaries.clone(),
            preflight_unclear_zones,
            postsolve_unclear_zones,
            project_doc_export: base.project_doc_export.clone(),
            projection_bundle: base.projection_bundle.clone(),
            core_output: base.core_output.clone(),
        }
    }
}

