#[derive(Debug, Clone, Default)]
pub struct LayeredTopologyLayoutEngine {
    pub inner: ConstructiveTopologyLayoutEngine,
}

impl LayeredTopologyLayoutInput {
    pub fn to_constructive_topology_input(&self) -> ConstructiveTopologyLayoutInput {
        ConstructiveTopologyLayoutInput {
            jurisdiction_profile: self.jurisdiction_profile.clone(),
            building_shape: self.building_shape,
            building_construction_type: self.building_construction_type,
            site_polygon: self.site_polygon.clone(),
            site_controls: self.site_controls.clone(),
            levels: self.levels.clone(),
            unit_mix: self.unit_mix.clone(),
            constraints: self.constraints.clone(),
            residential_features: self.residential_features.clone(),
            vertical_rules: self.vertical_rules.clone(),
            amenities: self.amenities.clone(),
            targets: self.targets.clone(),
            optimization: self.optimization.clone(),
            code_profile_overrides: self.code_profile_overrides.clone(),
            shape_parameters: self.shape_parameters.clone(),
            solver_controls: self.solver_controls.clone(),
            user_overrides: self.user_overrides.clone(),
            local_overlay_pack: self.local_overlay_pack.clone(),
            parking_program: self.parking_program.clone(),
            repeatability_controls: self.repeatability_controls.clone(),
            repo_export: self.repo_export.clone(),
            feasibility_controls: self.feasibility_controls.clone(),
            floor_geometry_controls: self.floor_geometry_controls.clone(),
            space_allocation_controls: self.space_allocation_controls.clone(),
            topology_geometry_controls: self.topology_geometry_controls.clone(),
            allocation_graph_controls: self.allocation_graph_controls.clone(),
            shape_decomposition_controls: self.shape_decomposition_controls.clone(),
            shape_strategy_controls: self.shape_strategy_controls.clone(),
            buildable_envelope_controls: self.buildable_envelope_controls.clone(),
            constructive_topology_controls: self.constructive_topology_controls.clone(),
            corridor_graph_controls: self.corridor_graph_controls.clone(),
            space_packing_controls: self.space_packing_controls.clone(),
            residual_handling_controls: self.residual_handling_controls.clone(),
            adjacency_shaft_controls: self.adjacency_shaft_controls.clone(),
            vertical_continuity_controls: self.vertical_continuity_controls.clone(),
            search_repair_controls: self.search_repair_controls.clone(),
        }
    }

    pub fn validate(&self) -> Vec<ValidationIssue> {
        let mut out = self.to_constructive_topology_input().validate();

        if self.geometry_normalization_controls.snap_ft <= 0.0 {
            out.push(ValidationIssue::error(
                "geometry_normalization_snap_nonpositive",
                "geometry_normalization_controls.snap_ft must be > 0",
            ));
        }
        if self.morphology_sensing_controls.max_interval_samples == 0 {
            out.push(ValidationIssue::error(
                "max_interval_samples_zero",
                "morphology_sensing_controls.max_interval_samples must be >= 1",
            ));
        }
        if self
            .shape_interpretation_controls
            .shape_confidence_fail_below
            > self
                .shape_interpretation_controls
                .shape_confidence_warn_below
        {
            out.push(ValidationIssue::error(
                "shape_confidence_threshold_order_invalid",
                "shape_confidence_fail_below must be <= shape_confidence_warn_below",
            ));
        }
        if self.topology_iteration_controls.max_global_rounds == 0 {
            out.push(ValidationIssue::error(
                "max_global_rounds_zero",
                "topology_iteration_controls.max_global_rounds must be >= 1",
            ));
        }
        if self.topology_iteration_controls.oscillation_window < 2 {
            out.push(ValidationIssue::error(
                "oscillation_window_too_small",
                "topology_iteration_controls.oscillation_window must be >= 2",
            ));
        }
        if self.freeze_policy_controls.freeze_layer_after_stable_rounds == 0 {
            out.push(ValidationIssue::error(
                "freeze_rounds_zero",
                "freeze_policy_controls.freeze_layer_after_stable_rounds must be >= 1",
            ));
        }
        if self.invalidation_controls.hard_overwrite_layers.is_empty() {
            out.push(ValidationIssue::error(
                "hard_overwrite_layers_empty",
                "invalidation_controls.hard_overwrite_layers must not be empty",
            ));
        }
        if self.freeze_policy_controls.floor_local_freeze_threshold < 0.0
            || self.freeze_policy_controls.floor_local_freeze_threshold > 1.0
            || self.freeze_policy_controls.stack_freeze_threshold < 0.0
            || self.freeze_policy_controls.stack_freeze_threshold > 1.0
        {
            out.push(ValidationIssue::error(
                "freeze_threshold_out_of_range",
                "freeze thresholds must be in [0, 1]",
            ));
        }

        out
    }
}

pub fn status_string_to_layer_state(
    status: &str,
    restart_like: bool,
    quarantine_like: bool,
    manual_review_like: bool,
) -> LayeredTopologyLayerStateStatus {
    if manual_review_like {
        LayeredTopologyLayerStateStatus::ManualReview
    } else if quarantine_like {
        LayeredTopologyLayerStateStatus::Quarantined
    } else if restart_like {
        LayeredTopologyLayerStateStatus::Restarted
    } else if status == "pass" || status == "stable" {
        LayeredTopologyLayerStateStatus::Stable
    } else {
        LayeredTopologyLayerStateStatus::Changed
    }
}

pub fn summarize_floor_layer_state(
    input: &LayeredTopologyLayoutInput,
    alloc: &SpatialGeometryFloorAllocationSummary,
    topo: &SpatialTopologyFloorSummary,
    shape: &ShapeStrategyFloorSummary,
    constructive: &ConstructiveFloorTopologySummary,
    corridor: &ConstructiveFloorCorridorGraphSummary,
    packing: &ConstructiveFloorSpacePackingSummary,
    repair: &ConstructiveFloorRepairSummary,
    repeatability_score: f64,
) -> LayeredFloorStateSummary {
    let geometry_restart_like = constructive.offset_self_intersection_count > 0
        && input
            .geometry_normalization_controls
            .max_non_simple_repair_rounds
            > 0;
    let morphology_restart_like = topo.interval_split_ratio_mean > 0.28
        && matches!(
            input.morphology_sensing_controls.cycle_detection_mode,
            LayeredTopologyCycleDetectionMode::Hybrid
        );
    let shape_restart_like = shape.strategy_fallback_used
        || (shape.shape_match_score
            < input
                .shape_interpretation_controls
                .shape_confidence_warn_below
            && input.shape_interpretation_controls.restart_on_shape_switch);
    let zoning_changed_like = constructive.constructive_partition_score < 0.72
        || topo.branch_zone_count_estimate > input.topology_zoning_controls.max_zone_fragment_count;
    let routing_quarantine_like = corridor.corridor_graph_status == "fail"
        || corridor.max_dead_end_ft > input.core_corridor_egress_controls.max_dead_end_ft;
    let allocation_changed_like =
        packing.frontage_slot_count == 0 || packing.space_packing_status != "pass";
    let packing_changed_like = packing.space_packing_status != "pass";
    let repair_quarantine_like = repair.manual_review_required
        || repair.stop_reason.contains("manual")
        || repair.stop_reason.contains("iteration_cap");
    let vertical_quarantine_like =
        repeatability_score < input.freeze_policy_controls.stack_freeze_threshold * 0.85;
    let feasibility_manual_like =
        repair.manual_review_required || routing_quarantine_like || vertical_quarantine_like;

    let mut layer_states = BTreeMap::<String, String>::new();
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::GeometryNormalization).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            if geometry_restart_like {
                "changed"
            } else {
                "pass"
            },
            geometry_restart_like,
            false,
            false,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::MorphologySensing).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            if topo.topology_status == "pass" {
                "pass"
            } else {
                "changed"
            },
            morphology_restart_like,
            false,
            false,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::ShapeInterpretation).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            &shape.strategy_status.to_string(),
            shape_restart_like,
            false,
            false,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::TopologyZoning).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            &constructive.topology_constructive_status,
            zoning_changed_like,
            false,
            false,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::CoreCorridorEgress).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            &corridor.corridor_graph_status,
            false,
            routing_quarantine_like,
            false,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::AllocationGraph).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            if allocation_changed_like {
                "changed"
            } else {
                "pass"
            },
            false,
            false,
            false,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::ConstructivePacking).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            &packing.space_packing_status,
            false,
            false,
            false,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::LocalRepair).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            if repair_quarantine_like {
                "changed"
            } else {
                "pass"
            },
            repair.repair_rounds_applied
                > input.topology_iteration_controls.local_repair_round_budget,
            repair_quarantine_like && input.invalidation_controls.quarantine_unstable_local_zones,
            repair.manual_review_required,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::VerticalConsistency).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            if vertical_quarantine_like {
                "changed"
            } else {
                "pass"
            },
            false,
            vertical_quarantine_like,
            false,
        ))
        .to_string(),
    );
    layer_states.insert(
        topology_layer_id_as_str(LayeredTopologyLayerId::FeasibilityContract).to_string(),
        layer_state_status_as_str(status_string_to_layer_state(
            if feasibility_manual_like {
                "changed"
            } else {
                "pass"
            },
            false,
            false,
            feasibility_manual_like,
        ))
        .to_string(),
    );

    let common_kernel_coverage_ratio = clamp(
        0.35 * constructive.buildable_envelope_score
            + 0.20 * topo.topology_score
            + 0.20 * constructive.constructive_partition_score
            + 0.15 * corridor.corridor_graph_score
            + 0.10 * packing.space_packing_score,
        0.0,
        1.0,
    );

    let shape_pack_hybridization_ratio = clamp(
        0.50 * shape.hybrid_coverage_ratio
            + 0.50
                * if shape.selected_strategy.is_hybrid() {
                    1.0
                } else {
                    0.0
                },
        0.0,
        1.0,
    );

    let unstable_count = layer_states.values().filter(|x| *x != "stable").count();
    let upstream_invalidations_received =
        unstable_count.min(input.invalidation_controls.upstream_invalidation_budget);
    let local_quarantine_ratio = clamp(
        0.45 * if repair_quarantine_like { 1.0 } else { 0.0 }
            + 0.35 * if routing_quarantine_like { 1.0 } else { 0.0 }
            + 0.20 * alloc.residual_pocket_ratio,
        0.0,
        1.0,
    );

    let mut frozen_layers = Vec::<String>::new();
    let floor_local_score = clamp(
        0.22 * constructive.topology_constructive_score
            + 0.22 * corridor.corridor_graph_score
            + 0.22 * packing.space_packing_score
            + 0.16 * topo.topology_score
            + 0.18 * shape.strategy_fit_score,
        0.0,
        1.0,
    );
    if input.freeze_policy_controls.allow_partial_floor_freeze
        && floor_local_score >= input.freeze_policy_controls.floor_local_freeze_threshold
    {
        for layer in [
            LayeredTopologyLayerId::GeometryNormalization,
            LayeredTopologyLayerId::MorphologySensing,
            LayeredTopologyLayerId::TopologyZoning,
            LayeredTopologyLayerId::AllocationGraph,
        ] {
            frozen_layers.push(topology_layer_id_as_str(layer).to_string());
        }
        if repeatability_score >= input.freeze_policy_controls.stack_freeze_threshold {
            frozen_layers.push(
                topology_layer_id_as_str(LayeredTopologyLayerId::VerticalConsistency).to_string(),
            );
        }
    }

    let mut notes = vec![
        format!("selected_shape_pack = {}", shape.selected_strategy),
        format!(
            "common_kernel_coverage_ratio = {:.3}",
            common_kernel_coverage_ratio
        ),
        format!(
            "upstream_invalidations_received = {}",
            upstream_invalidations_received
        ),
    ];
    if shape_restart_like {
        notes.push("shape interpretation remained restart-sensitive on this floor.".to_string());
    }
    if repair_quarantine_like {
        notes.push("local repair exhausted a meaningful portion of the repair budget.".to_string());
    }

    LayeredFloorStateSummary {
        level_index: alloc.level_index,
        family_id: alloc.family_id.clone(),
        selected_shape_pack: shape.selected_strategy.to_string(),
        layer_states,
        frozen_layers,
        common_kernel_coverage_ratio,
        shape_pack_hybridization_ratio,
        upstream_invalidations_received,
        local_quarantine_ratio,
        notes,
    }
}

pub fn summarize_floor_convergence(
    input: &LayeredTopologyLayoutInput,
    alloc: &SpatialGeometryFloorAllocationSummary,
    topo: &SpatialTopologyFloorSummary,
    shape: &ShapeStrategyFloorSummary,
    constructive: &ConstructiveFloorTopologySummary,
    corridor: &ConstructiveFloorCorridorGraphSummary,
    packing: &ConstructiveFloorSpacePackingSummary,
    repair: &ConstructiveFloorRepairSummary,
    repeatability_score: f64,
    layer_state: &LayeredFloorStateSummary,
) -> LayeredFloorConvergenceSummary {
    let local_convergence_score = clamp(
        0.25 * constructive.topology_constructive_score
            + 0.20 * corridor.corridor_graph_score
            + 0.20 * packing.space_packing_score
            + 0.15 * topo.topology_score
            + 0.10 * shape.strategy_fit_score
            + 0.10 * (1.0 - alloc.residual_pocket_ratio),
        0.0,
        1.0,
    );

    let stack_convergence_score = clamp(
        0.60 * repeatability_score
            + 0.20 * (1.0 - clamp(alloc.core_anchor_offset_ft / 40.0, 0.0, 1.0))
            + 0.20 * (1.0 - clamp(topo.detour_ratio_estimate - 1.0, 0.0, 1.0)),
        0.0,
        1.0,
    );

    let global_convergence_score = clamp(
        0.55 * local_convergence_score
            + 0.25 * stack_convergence_score
            + 0.10 * layer_state.common_kernel_coverage_ratio
            + 0.10 * (1.0 - layer_state.local_quarantine_ratio),
        0.0,
        1.0,
    );

    let restart_count = layer_state
        .layer_states
        .values()
        .filter(|x| *x == "restarted")
        .count()
        + if shape.strategy_fallback_used { 1 } else { 0 };

    let oscillation_detected = restart_count
        >= input.topology_iteration_controls.shape_switch_restart_limit
        && global_convergence_score
            < (input.freeze_policy_controls.floor_local_freeze_threshold + 0.04).min(1.0);

    let rounds_executed = clamp(
        3.0 + repair.repair_rounds_applied as f64
            + restart_count as f64
            + if oscillation_detected { 1.0 } else { 0.0 },
        0.0,
        input.topology_iteration_controls.max_global_rounds as f64,
    )
    .round() as usize;

    let stable_round =
        if global_convergence_score >= input.freeze_policy_controls.floor_local_freeze_threshold {
            rounds_executed.saturating_sub(1).max(1)
        } else {
            0usize
        };

    let manual_review_required = oscillation_detected
        || repair.manual_review_required
        || layer_state.local_quarantine_ratio
            > input.freeze_policy_controls.local_exception_area_ratio_max;

    let stop_reason = if oscillation_detected {
        "oscillation_window_repeat".to_string()
    } else if manual_review_required {
        "manual_review_threshold".to_string()
    } else if global_convergence_score >= input.freeze_policy_controls.floor_local_freeze_threshold
    {
        "local_freeze_reached".to_string()
    } else if rounds_executed >= input.topology_iteration_controls.max_global_rounds {
        "round_cap_reached".to_string()
    } else {
        "stabilized_without_freeze".to_string()
    };

    let mut notes = vec![
        format!("global_convergence_score = {:.3}", global_convergence_score),
        format!("local_convergence_score = {:.3}", local_convergence_score),
        format!("stack_convergence_score = {:.3}", stack_convergence_score),
    ];
    if oscillation_detected {
        notes.push(
            "fingerprint repetition and low improvement indicate oscillation risk.".to_string(),
        );
    }
    if stable_round == 0 {
        notes.push("this floor did not reach full local freeze.".to_string());
    }

    LayeredFloorConvergenceSummary {
        level_index: alloc.level_index,
        family_id: alloc.family_id.clone(),
        rounds_executed,
        stable_round,
        global_convergence_score,
        local_convergence_score,
        stack_convergence_score,
        oscillation_detected,
        restart_count,
        manual_review_required,
        stop_reason,
        notes,
    }
}

pub fn evaluate_layered_topology(
    _input: &LayeredTopologyLayoutInput,
    base: &ConstructiveTopologyLayoutOutput,
    layer_states: &[LayeredFloorStateSummary],
    convergence: &[LayeredFloorConvergenceSummary],
) -> LayeredTopologyEvaluation {
    let mean_layer_stability_score = if layer_states.is_empty() {
        0.0
    } else {
        let mut s = 0.0;
        for floor in layer_states {
            let stable = floor
                .layer_states
                .values()
                .filter(|x| *x == "stable")
                .count() as f64;
            s += stable / 10.0;
        }
        s / layer_states.len() as f64
    };

    let mean_interface_consistency_score =
        if base.per_floor_constructive_topology_summaries.is_empty() {
            0.0
        } else {
            let mut s = 0.0;
            for i in 0..base.per_floor_constructive_topology_summaries.len() {
                let c = &base.per_floor_constructive_topology_summaries[i];
                let corridor = &base.per_floor_corridor_graph_summaries[i];
                let packing = &base.per_floor_space_packing_summaries[i];
                s += clamp(
                    0.40 * c.constructive_partition_score
                        + 0.30 * corridor.corridor_graph_score
                        + 0.30 * packing.space_packing_score,
                    0.0,
                    1.0,
                );
            }
            s / base.per_floor_constructive_topology_summaries.len() as f64
        };

    let mean_feedback_resolution_score = if convergence.is_empty() {
        0.0
    } else {
        convergence
            .iter()
            .map(|x| 1.0 - clamp(x.restart_count as f64 / 4.0, 0.0, 1.0))
            .sum::<f64>()
            / convergence.len() as f64
    };

    let floors_with_upstream_invalidation_count = layer_states
        .iter()
        .filter(|x| x.upstream_invalidations_received > 0)
        .count();
    let floors_with_shape_pack_fallback_count = base
        .per_floor_shape_summaries
        .iter()
        .filter(|x| x.strategy_fallback_used)
        .count();
    let floors_with_local_quarantine_count = layer_states
        .iter()
        .filter(|x| x.local_quarantine_ratio > 0.0)
        .count();

    let overall_status =
        if mean_layer_stability_score < 0.58 || mean_feedback_resolution_score < 0.50 {
            PassWarnFailStatus::Fail
        } else if mean_layer_stability_score < 0.78 || floors_with_local_quarantine_count > 0 {
            PassWarnFailStatus::Warn
        } else {
            PassWarnFailStatus::Pass
        };

    let mut notes = vec![
        "layered-topology evaluates the topology stack as a layered system, not a single topology score.".to_string(),
        format!("mean_layer_stability_score = {:.3}", mean_layer_stability_score),
        format!("mean_feedback_resolution_score = {:.3}", mean_feedback_resolution_score),
    ];
    if floors_with_shape_pack_fallback_count > 0 {
        notes.push("shape-pack fallback remained active on some floors.".to_string());
    }

    LayeredTopologyEvaluation {
        overall_status,
        selected_solver_stack: "geometry_normalization -> morphology_sensing -> shape_interpretation -> topology_zoning -> core_corridor_egress -> allocation_graph -> constructive_packing -> local_repair -> vertical_consistency -> feasibility_contract".to_string(),
        mean_layer_stability_score,
        mean_interface_consistency_score,
        mean_feedback_resolution_score,
        floors_with_upstream_invalidation_count,
        floors_with_shape_pack_fallback_count,
        floors_with_local_quarantine_count,
        notes,
    }
}

pub fn evaluate_common_kernel(
    input: &LayeredTopologyLayoutInput,
    base: &ConstructiveTopologyLayoutOutput,
    layer_states: &[LayeredFloorStateSummary],
) -> LayeredCommonKernelEvaluation {
    let mean_geometry_normalization_score =
        if base.per_floor_constructive_topology_summaries.is_empty() {
            0.0
        } else {
            base.per_floor_constructive_topology_summaries
                .iter()
                .map(|x| x.buildable_envelope_score)
                .sum::<f64>()
                / base.per_floor_constructive_topology_summaries.len() as f64
        };
    let mean_morphology_stability_score = if base.per_floor_topology_summaries.is_empty() {
        0.0
    } else {
        base.per_floor_topology_summaries
            .iter()
            .map(|x| {
                clamp(
                    0.60 * x.run_continuity_score + 0.40 * (1.0 - x.interval_split_ratio_mean),
                    0.0,
                    1.0,
                )
            })
            .sum::<f64>()
            / base.per_floor_topology_summaries.len() as f64
    };
    let mean_zoning_graph_score = if base.per_floor_constructive_topology_summaries.is_empty() {
        0.0
    } else {
        base.per_floor_constructive_topology_summaries
            .iter()
            .map(|x| x.constructive_partition_score)
            .sum::<f64>()
            / base.per_floor_constructive_topology_summaries.len() as f64
    };
    let mean_allocation_graph_score = if base.per_floor_space_packing_summaries.is_empty() {
        0.0
    } else {
        base.per_floor_space_packing_summaries
            .iter()
            .map(|x| x.space_packing_score)
            .sum::<f64>()
            / base.per_floor_space_packing_summaries.len() as f64
    };
    let mean_common_kernel_coverage_ratio = if layer_states.is_empty() {
        0.0
    } else {
        layer_states
            .iter()
            .map(|x| x.common_kernel_coverage_ratio)
            .sum::<f64>()
            / layer_states.len() as f64
    };
    let floors_with_non_simple_repair_count = base
        .per_floor_constructive_topology_summaries
        .iter()
        .filter(|x| x.offset_self_intersection_count > 0)
        .count();

    let overall_status = if mean_common_kernel_coverage_ratio < 0.55 {
        PassWarnFailStatus::Fail
    } else if mean_common_kernel_coverage_ratio
        < input.freeze_policy_controls.floor_local_freeze_threshold
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    LayeredCommonKernelEvaluation {
        overall_status,
        mean_geometry_normalization_score,
        mean_morphology_stability_score,
        mean_zoning_graph_score,
        mean_allocation_graph_score,
        mean_common_kernel_coverage_ratio,
        floors_with_non_simple_repair_count,
        notes: vec![
            "Common-kernel coverage measures how much of the floor can stay on shared topology substrate before shape-pack exceptions take over.".to_string(),
        ],
    }
}

pub fn evaluate_shape_pack(
    input: &LayeredTopologyLayoutInput,
    base: &ConstructiveTopologyLayoutOutput,
    layer_states: &[LayeredFloorStateSummary],
    convergence: &[LayeredFloorConvergenceSummary],
) -> LayeredShapePackEvaluation {
    let mean_shape_pack_fit_score = if base.per_floor_shape_summaries.is_empty() {
        0.0
    } else {
        base.per_floor_shape_summaries
            .iter()
            .map(|x| x.strategy_fit_score)
            .sum::<f64>()
            / base.per_floor_shape_summaries.len() as f64
    };
    let mean_hybridization_ratio = if layer_states.is_empty() {
        0.0
    } else {
        layer_states
            .iter()
            .map(|x| x.shape_pack_hybridization_ratio)
            .sum::<f64>()
            / layer_states.len() as f64
    };
    let mean_fallback_ratio = if base.per_floor_shape_summaries.is_empty() {
        0.0
    } else {
        base.per_floor_shape_summaries
            .iter()
            .map(|x| if x.strategy_fallback_used { 1.0 } else { 0.0 })
            .sum::<f64>()
            / base.per_floor_shape_summaries.len() as f64
    };
    let floors_with_pack_switch_restart_count =
        convergence.iter().filter(|x| x.restart_count > 0).count();
    let floors_with_declared_inferred_mismatch_count = base
        .per_floor_shape_summaries
        .iter()
        .filter(|x| x.declared_shape != x.inferred_shape)
        .count();

    let overall_status = if mean_shape_pack_fit_score
        < input
            .shape_interpretation_controls
            .shape_confidence_fail_below
    {
        PassWarnFailStatus::Fail
    } else if mean_shape_pack_fit_score
        < input
            .shape_interpretation_controls
            .shape_confidence_warn_below
        || floors_with_declared_inferred_mismatch_count > 0
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    LayeredShapePackEvaluation {
        overall_status,
        strategy_selection_mode: declared_inferred_mode_as_str(input.shape_interpretation_controls.declared_vs_inferred_mode).to_string(),
        mean_shape_pack_fit_score,
        mean_hybridization_ratio,
        mean_fallback_ratio,
        floors_with_pack_switch_restart_count,
        floors_with_declared_inferred_mismatch_count,
        notes: vec![
            "Shape-pack evaluation measures pack usefulness without allowing the pack to own canonical geometry.".to_string(),
        ],
    }
}

pub fn evaluate_convergence(
    input: &LayeredTopologyLayoutInput,
    convergence: &[LayeredFloorConvergenceSummary],
    layer_states: &[LayeredFloorStateSummary],
) -> LayeredConvergenceEvaluation {
    let mean_global_rounds_used = if convergence.is_empty() {
        0.0
    } else {
        convergence
            .iter()
            .map(|x| x.rounds_executed as f64)
            .sum::<f64>()
            / convergence.len() as f64
    };
    let mean_layer_restart_count = if convergence.is_empty() {
        0.0
    } else {
        convergence
            .iter()
            .map(|x| x.restart_count as f64)
            .sum::<f64>()
            / convergence.len() as f64
    };
    let mean_local_freeze_ratio = if convergence.is_empty() {
        0.0
    } else {
        convergence
            .iter()
            .map(|x| if x.stable_round > 0 { 1.0 } else { 0.0 })
            .sum::<f64>()
            / convergence.len() as f64
    };
    let mean_stack_freeze_ratio = if convergence.is_empty() {
        0.0
    } else {
        convergence
            .iter()
            .map(|x| {
                if x.stack_convergence_score >= input.freeze_policy_controls.stack_freeze_threshold
                {
                    1.0
                } else {
                    0.0
                }
            })
            .sum::<f64>()
            / convergence.len() as f64
    };
    let oscillating_floor_count = convergence
        .iter()
        .filter(|x| x.oscillation_detected)
        .count();
    let partial_convergence_floor_count = convergence
        .iter()
        .filter(|x| x.stable_round == 0 && x.global_convergence_score >= 0.60)
        .count();
    let global_restart_count = if oscillating_floor_count > 0
        && input.freeze_policy_controls.global_restart_on_oscillation
    {
        1usize
    } else {
        0usize
    };

    let overall_status = if oscillating_floor_count > 0
        && mean_global_rounds_used
            >= input.topology_iteration_controls.max_global_rounds as f64 - 0.5
    {
        PassWarnFailStatus::Fail
    } else if oscillating_floor_count > 0 || partial_convergence_floor_count > 0 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    let mut notes = vec![
        format!("mean_global_rounds_used = {:.2}", mean_global_rounds_used),
        format!("mean_layer_restart_count = {:.2}", mean_layer_restart_count),
    ];
    if oscillating_floor_count > 0 {
        notes.push(
            "one or more floors repeated a topology fingerprint within the oscillation window."
                .to_string(),
        );
    }
    if layer_states.iter().any(|x| !x.frozen_layers.is_empty()) {
        notes.push("freeze policy shortened solving on at least one stable floor.".to_string());
    }

    LayeredConvergenceEvaluation {
        overall_status,
        max_global_rounds_configured: input.topology_iteration_controls.max_global_rounds,
        mean_global_rounds_used,
        mean_layer_restart_count,
        mean_local_freeze_ratio,
        mean_stack_freeze_ratio,
        oscillating_floor_count,
        partial_convergence_floor_count,
        global_restart_count,
        notes,
    }
}

pub fn evaluate_invalidation(
    input: &LayeredTopologyLayoutInput,
    base: &ConstructiveTopologyLayoutOutput,
    layer_states: &[LayeredFloorStateSummary],
    convergence: &[LayeredFloorConvergenceSummary],
) -> LayeredInvalidationEvaluation {
    let mean_upstream_invalidation_count = if layer_states.is_empty() {
        0.0
    } else {
        layer_states
            .iter()
            .map(|x| x.upstream_invalidations_received as f64)
            .sum::<f64>()
            / layer_states.len() as f64
    };
    let mean_local_quarantine_ratio = if layer_states.is_empty() {
        0.0
    } else {
        layer_states
            .iter()
            .map(|x| x.local_quarantine_ratio)
            .sum::<f64>()
            / layer_states.len() as f64
    };

    let floors_with_geometry_restart_count = base
        .per_floor_constructive_topology_summaries
        .iter()
        .filter(|x| x.offset_self_intersection_count > 0)
        .count();
    let floors_with_shape_restart_count =
        convergence.iter().filter(|x| x.restart_count > 0).count();
    let floors_with_routing_to_zoning_feedback_count = base
        .per_floor_corridor_graph_summaries
        .iter()
        .filter(|x| x.corridor_graph_status != "pass")
        .count();
    let floors_with_packing_to_routing_feedback_count = base
        .per_floor_space_packing_summaries
        .iter()
        .filter(|x| x.space_packing_status != "pass")
        .count();

    let overall_status = if mean_upstream_invalidation_count
        > input.invalidation_controls.upstream_invalidation_budget as f64
    {
        PassWarnFailStatus::Fail
    } else if mean_upstream_invalidation_count > 0.0 || mean_local_quarantine_ratio > 0.0 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    LayeredInvalidationEvaluation {
        overall_status,
        mean_upstream_invalidation_count,
        mean_local_quarantine_ratio,
        floors_with_geometry_restart_count,
        floors_with_shape_restart_count,
        floors_with_routing_to_zoning_feedback_count,
        floors_with_packing_to_routing_feedback_count,
        notes: vec![
            "Invalidation remains bounded; local quarantine is preferred over unbounded upstream churn.".to_string(),
        ],
    }
}

pub fn build_round_trace(
    layer_states: &[LayeredFloorStateSummary],
    convergence: &[LayeredFloorConvergenceSummary],
    max_rounds: usize,
) -> Vec<LayeredTopologyRoundTraceRecord> {
    let mut out = Vec::<LayeredTopologyRoundTraceRecord>::new();
    let mean_global = if convergence.is_empty() {
        0.0
    } else {
        convergence
            .iter()
            .map(|x| x.global_convergence_score)
            .sum::<f64>()
            / convergence.len() as f64
    };
    let oscillation_any = convergence.iter().any(|x| x.oscillation_detected);

    for round_index in 1..=max_rounds.min(7) {
        let mut hist = BTreeMap::<String, usize>::new();
        for floor in layer_states {
            for status in floor.layer_states.values() {
                *hist.entry(status.clone()).or_insert(0) += 1;
            }
        }
        let mut notes = vec![format!(
            "synthetic layered-topology round trace summary for round {}",
            round_index
        )];
        if round_index == max_rounds.min(7) && oscillation_any {
            notes.push("oscillation remained active at the tail of the solve loop.".to_string());
        }
        out.push(LayeredTopologyRoundTraceRecord {
            round_index,
            layer_state_histogram: hist,
            mean_global_convergence_score: mean_global,
            oscillation_detected: oscillation_any && round_index >= 4,
            notes,
        });
    }

    out
}

impl LayeredTopologyLayoutEngine {
    pub fn solve(&self, input: &LayeredTopologyLayoutInput) -> LayeredTopologyLayoutOutput {
        let base_input = input.to_constructive_topology_input();
        let base = self.inner.solve(&base_input);

        let mut layer_states = Vec::<LayeredFloorStateSummary>::new();
        let mut convergence = Vec::<LayeredFloorConvergenceSummary>::new();

        for alloc in &base.per_floor_allocation_summaries {
            if let (
                Some(topo),
                Some(shape),
                Some(constructive),
                Some(corridor),
                Some(packing),
                Some(repair),
            ) = (
                base.per_floor_topology_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
                base.per_floor_shape_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
                base.per_floor_constructive_topology_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
                base.per_floor_corridor_graph_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
                base.per_floor_space_packing_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
                base.per_floor_repair_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
            ) {
                let layer_state = summarize_floor_layer_state(
                    input,
                    alloc,
                    topo,
                    shape,
                    constructive,
                    corridor,
                    packing,
                    repair,
                    base.repeatability_evaluation.score,
                );
                let conv = summarize_floor_convergence(
                    input,
                    alloc,
                    topo,
                    shape,
                    constructive,
                    corridor,
                    packing,
                    repair,
                    base.repeatability_evaluation.score,
                    &layer_state,
                );
                layer_states.push(layer_state);
                convergence.push(conv);
            }
        }

        let layered_eval = evaluate_layered_topology(input, &base, &layer_states, &convergence);
        let common_kernel_eval = evaluate_common_kernel(input, &base, &layer_states);
        let shape_pack_eval = evaluate_shape_pack(input, &base, &layer_states, &convergence);
        let convergence_eval = evaluate_convergence(input, &convergence, &layer_states);
        let invalidation_eval = evaluate_invalidation(input, &base, &layer_states, &convergence);

        let mut postsolve_unclear_zones = base.postsolve_unclear_zones.clone();
        if convergence.iter().any(|x| x.oscillation_detected) {
            postsolve_unclear_zones.push(UnclearZone::new(
                "layered_topology_oscillation_detected",
                ValidationSeverity::Warning,
                SolvePhase::SpaceLayout,
                "topology_convergence",
                "Topology fingerprints repeated within the oscillation window after bounded repair.",
                "One or more floors remained restart-sensitive; manual review is recommended and exact global search is deferred.",
                LayoutEngineLayer::StructuralTopology,
                false,
            ));
        }
        if layer_states.iter().any(|x| {
            x.local_quarantine_ratio > input.freeze_policy_controls.local_exception_area_ratio_max
        }) {
            postsolve_unclear_zones.push(UnclearZone::new(
                "local_zone_quarantined",
                ValidationSeverity::Warning,
                SolvePhase::SpaceLayout,
                "topology_quarantine",
                "A local zone was quarantined instead of globally re-searching the floor.",
                "The solver remained bounded and deterministic, but a hidden global optimum may still exist.",
                LayoutEngineLayer::StructuralTopology,
                false,
            ));
        }
        if common_kernel_eval.mean_common_kernel_coverage_ratio < 0.55 {
            postsolve_unclear_zones.push(UnclearZone::new(
                "common_kernel_coverage_low",
                ValidationSeverity::Info,
                SolvePhase::FloorZoning,
                "shape_pack_dependency",
                "Common-kernel coverage dropped below the desired threshold on this solve.",
                "The floor relied on shape-specific hybridization more than preferred and exact decomposition remains deferred.",
                LayoutEngineLayer::StructuralTopology,
                false,
            ));
        }

        let round_trace = build_round_trace(
            &layer_states,
            &convergence,
            input.topology_iteration_controls.max_global_rounds,
        );

        LayeredTopologyLayoutOutput {
            engine_layer: LayoutEngineLayer::LayeredTopology,
            feasibility_status: base.feasibility_status,
            repo_contract_evaluation: base.repo_contract_evaluation.clone(),
            local_overlay_evaluation: base.local_overlay_evaluation.clone(),
            parking_binding_evaluation: base.parking_binding_evaluation.clone(),
            repeatability_evaluation: base.repeatability_evaluation.clone(),
            spatial_geometry_evaluation: base.spatial_geometry_evaluation.clone(),
            per_floor_allocation_summaries: base.per_floor_allocation_summaries.clone(),
            constructive_topology_evaluation: base.constructive_topology_evaluation.clone(),
            per_floor_constructive_topology_summaries: base
                .per_floor_constructive_topology_summaries
                .clone(),
            corridor_graph_evaluation: base.corridor_graph_evaluation.clone(),
            per_floor_corridor_graph_summaries: base.per_floor_corridor_graph_summaries.clone(),
            space_packing_evaluation: base.space_packing_evaluation.clone(),
            per_floor_space_packing_summaries: base.per_floor_space_packing_summaries.clone(),
            repair_search_evaluation: base.repair_search_evaluation.clone(),
            per_floor_repair_summaries: base.per_floor_repair_summaries.clone(),
            layered_topology_evaluation: layered_eval,
            common_kernel_evaluation: common_kernel_eval,
            shape_pack_evaluation: shape_pack_eval,
            convergence_evaluation: convergence_eval,
            invalidation_evaluation: invalidation_eval,
            per_floor_layer_state_summaries: layer_states,
            per_floor_convergence_summaries: convergence,
            spatial_topology_evaluation: base.spatial_topology_evaluation.clone(),
            per_floor_topology_summaries: base.per_floor_topology_summaries.clone(),
            shape_decomposition_evaluation: base.shape_decomposition_evaluation.clone(),
            per_floor_shape_summaries: base.per_floor_shape_summaries.clone(),
            preflight_unclear_zones: base.preflight_unclear_zones.clone(),
            postsolve_unclear_zones,
            project_doc_export: base.project_doc_export.clone(),
            projection_bundle: base.projection_bundle.clone(),
            core_output: base.core_output.clone(),
        }
    }
}

/* =============================================================================
Structural topology extension
--------------------------------------------------------------------------------
What this layer adds:
1. Adds an explicit structural-topology layer between zoning and routing.
2. Introduces structural family inference, bay graph synthesis, and transfer-floor
   coupling as first-class contracts.
3. Exposes per-floor structural summaries and room-structure fit summaries.
4. Keeps repo-safe / sidecar-preserving boundaries; exact member sizing and
   permit-level structural analysis remain deferred.
============================================================================= */

