pub struct OpeningAwareLayoutEngine {
    pub inner: StructuralTopologyLayoutEngine,
}

impl OpeningAwareLayoutInput {
    pub fn to_structural_topology_input(&self) -> StructuralTopologyLayoutInput {
        StructuralTopologyLayoutInput {
            jurisdiction_profile: self.jurisdiction_profile.clone(),
            building_shape: self.building_shape,
            building_construction_type: self.building_construction_type,
            site_polygon: self.site_polygon.clone(),
            site_controls: self.site_controls.clone(),
            levels: self.levels.clone(),
            unit_mix: self.unit_mix.clone(),
            constraints: self.constraints.clone(),
            residential_features: self.residential_features.clone(),
            vertical_rules: self.vertical_rules.clone(),
            amenities: self.amenities.clone(),
            targets: self.targets.clone(),
            optimization: self.optimization.clone(),
            code_profile_overrides: self.code_profile_overrides.clone(),
            shape_parameters: self.shape_parameters.clone(),
            solver_controls: self.solver_controls.clone(),
            user_overrides: self.user_overrides.clone(),
            local_overlay_pack: self.local_overlay_pack.clone(),
            parking_program: self.parking_program.clone(),
            repeatability_controls: self.repeatability_controls.clone(),
            repo_export: self.repo_export.clone(),
            feasibility_controls: self.feasibility_controls.clone(),
            floor_geometry_controls: self.floor_geometry_controls.clone(),
            space_allocation_controls: self.space_allocation_controls.clone(),
            topology_geometry_controls: self.topology_geometry_controls.clone(),
            allocation_graph_controls: self.allocation_graph_controls.clone(),
            shape_decomposition_controls: self.shape_decomposition_controls.clone(),
            shape_strategy_controls: self.shape_strategy_controls.clone(),
            buildable_envelope_controls: self.buildable_envelope_controls.clone(),
            constructive_topology_controls: self.constructive_topology_controls.clone(),
            corridor_graph_controls: self.corridor_graph_controls.clone(),
            space_packing_controls: self.space_packing_controls.clone(),
            residual_handling_controls: self.residual_handling_controls.clone(),
            adjacency_shaft_controls: self.adjacency_shaft_controls.clone(),
            vertical_continuity_controls: self.vertical_continuity_controls.clone(),
            search_repair_controls: self.search_repair_controls.clone(),
            geometry_normalization_controls: self.geometry_normalization_controls.clone(),
            morphology_sensing_controls: self.morphology_sensing_controls.clone(),
            shape_interpretation_controls: self.shape_interpretation_controls.clone(),
            topology_zoning_controls: self.topology_zoning_controls.clone(),
            core_corridor_egress_controls: self.core_corridor_egress_controls.clone(),
            topology_iteration_controls: self.topology_iteration_controls.clone(),
            invalidation_controls: self.invalidation_controls.clone(),
            freeze_policy_controls: self.freeze_policy_controls.clone(),
            structural_topology_controls: self.structural_topology_controls.clone(),
            structural_bay_controls: self.structural_bay_controls.clone(),
            transfer_structure_controls: self.transfer_structure_controls.clone(),
            structure_room_coupling_controls: self.structure_room_coupling_controls.clone(),
        }
    }
}

impl OpeningAwareLayoutEngine {
    pub fn solve(&self, input: &OpeningAwareLayoutInput) -> OpeningAwareLayoutOutput {
        let base_input = input.to_structural_topology_input();
        let base = self.inner.solve(&base_input);

        let mut opening_summaries = Vec::<OpeningAwareFloorLifeSafetySummary>::new();
        let mut vertical_summaries = Vec::<OpeningAwareFloorVerticalAccessSummary>::new();
        let mut parking_summaries = Vec::<OpeningAwareFloorParkingSummary>::new();
        let mut amenity_summaries = Vec::<OpeningAwareFloorAmenitySummary>::new();

        for alloc in &base.per_floor_allocation_summaries {
            if let (Some(corridor), Some(packing), Some(structural), Some(shape)) = (
                base.per_floor_corridor_graph_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
                base.per_floor_space_packing_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
                base.per_floor_structural_topology_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
                base.per_floor_shape_summaries
                    .iter()
                    .find(|x| x.level_index == alloc.level_index),
            ) {
                let opening = summarize_floor_opening_life_safety(
                    input, alloc, corridor, packing, structural,
                );
                let vertical = summarize_floor_vertical_access(
                    input,
                    alloc,
                    corridor,
                    structural,
                    &opening,
                    &base.core_output.verticals,
                );
                let parking = summarize_floor_parking_layout(input, &base, alloc);
                let amenity = summarize_floor_amenity_open_space(
                    input, &base, alloc, &opening, &parking, shape,
                );

                opening_summaries.push(opening);
                vertical_summaries.push(vertical);
                parking_summaries.push(parking);
                amenity_summaries.push(amenity);
            }
        }

        let roof_summaries = build_roof_plan_summaries(input, &base, &vertical_summaries);
        let site_zone_summaries = build_site_exterior_zone_summaries(input, &base);

        let opening_eval = evaluate_opening_life_safety(input, &opening_summaries);
        let vertical_eval = evaluate_vertical_access(input, &vertical_summaries);
        let roof_eval = evaluate_roof_plan(input, &roof_summaries);
        let site_eval = evaluate_site_exterior_layout(input, &site_zone_summaries);
        let parking_eval = evaluate_parking_layout(input, &base, &parking_summaries);
        let yield_eval = evaluate_yield_envelope(input, &base, &site_eval, &parking_eval);
        let material_eval = evaluate_material_topology(input, &base, &vertical_eval, &roof_eval);
        let amenity_eval = evaluate_amenity_open_space(
            input,
            &base,
            &amenity_summaries,
            &site_eval,
            &opening_eval,
            &parking_eval,
        );

        let mut preflight_unclear_zones = base.preflight_unclear_zones.clone();
        let mut postsolve_unclear_zones = base.postsolve_unclear_zones.clone();

        if input
            .material_topology_controls
            .construction_type_strategy_mode
            == "auto"
            && matches!(
                input.building_shape,
                BuildingShape::FreeForm | BuildingShape::Cluster
            )
        {
            preflight_unclear_zones.push(UnclearZone::new(
                "material_topology_low_confidence",
                ValidationSeverity::Warning,
                SolvePhase::FloorZoning,
                "material_topology",
                "Material-sensitive topology remains auto-selected on a highly irregular morphology.",
                "The solver stays bounded and inspectable, but construction-type-specific topology may still need manual review on this shape.",
                LayoutEngineLayer::ProgressiveTopology,
                false,
            ));
        }

        if !opening_eval.overall_status.is_pass() {
            postsolve_unclear_zones.push(UnclearZone::new(
                "door_window_legality_not_exact",
                ValidationSeverity::Warning,
                SolvePhase::SpaceLayout,
                "opening_life_safety",
                "Opening-aware topology detected pressure around door-node routing or habitable window eligibility.",
                "Opening-aware can route repairs and mark affected zones, but exact door/window legality remains deferred.",
                LayoutEngineLayer::ProgressiveTopology,
                false,
            ));
        }

        if !roof_eval.overall_status.is_pass() {
            postsolve_unclear_zones.push(UnclearZone::new(
                "roof_capacity_drainage_exact_missing",
                ValidationSeverity::Warning,
                SolvePhase::SpaceLayout,
                "roof_plan",
                "Roof-plan topology can be generated, but occupied-roof support, drainage, or mechanical conflicts still remain only partially resolved.",
                "Manual review is still needed before treating roof geometry as code-complete or structurally complete.",
                LayoutEngineLayer::ProgressiveTopology,
                false,
            ));
        }

        if !site_eval.overall_status.is_pass() || !parking_eval.overall_status.is_pass() {
            postsolve_unclear_zones.push(UnclearZone::new(
                "site_parking_open_space_tradeoff_manual_review",
                ValidationSeverity::Warning,
                SolvePhase::SpaceLayout,
                "site_exterior_parking_open_space",
                "Site exterior, parking frontage, or open-space balance remained near or beyond warning thresholds.",
                "The constructive pack is active, but exact site civil / parking detail / local ordinance interpretation still needs review.",
                LayoutEngineLayer::ProgressiveTopology,
                false,
            ));
        }

        if !yield_eval.height_cap_respected || !yield_eval.dwelling_unit_cap_respected {
            postsolve_unclear_zones.push(UnclearZone::new(
                "yield_envelope_tradeoff_manual_review",
                ValidationSeverity::Error,
                SolvePhase::OutputAssembly,
                "yield_envelope",
                "The selected candidate is under pressure from FAR, unit-cap, or story-height limits.",
                "Repair/search may still continue, but a clean contract-safe closeout needs tighter massing or local policy inputs.",
                LayoutEngineLayer::ProgressiveTopology,
                true,
            ));
        }

        OpeningAwareLayoutOutput {
            engine_layer: LayoutEngineLayer::OpeningAware,
            feasibility_status: base.feasibility_status,
            repo_contract_evaluation: base.repo_contract_evaluation.clone(),
            local_overlay_evaluation: base.local_overlay_evaluation.clone(),
            parking_binding_evaluation: base.parking_binding_evaluation.clone(),
            repeatability_evaluation: base.repeatability_evaluation.clone(),
            opening_life_safety_evaluation: opening_eval,
            per_floor_opening_life_safety_summaries: opening_summaries,
            vertical_access_evaluation: vertical_eval,
            per_floor_vertical_access_summaries: vertical_summaries,
            roof_plan_evaluation: roof_eval,
            roof_plan_summaries: roof_summaries,
            site_exterior_layout_evaluation: site_eval,
            site_exterior_zone_summaries: site_zone_summaries,
            parking_layout_evaluation: parking_eval,
            per_floor_parking_layout_summaries: parking_summaries,
            yield_envelope_evaluation: yield_eval,
            material_topology_evaluation: material_eval,
            amenity_open_space_evaluation: amenity_eval,
            per_floor_amenity_open_space_summaries: amenity_summaries,
            spatial_geometry_evaluation: base.spatial_geometry_evaluation.clone(),
            per_floor_allocation_summaries: base.per_floor_allocation_summaries.clone(),
            constructive_topology_evaluation: base.constructive_topology_evaluation.clone(),
            per_floor_constructive_topology_summaries: base
                .per_floor_constructive_topology_summaries
                .clone(),
            corridor_graph_evaluation: base.corridor_graph_evaluation.clone(),
            per_floor_corridor_graph_summaries: base.per_floor_corridor_graph_summaries.clone(),
            space_packing_evaluation: base.space_packing_evaluation.clone(),
            per_floor_space_packing_summaries: base.per_floor_space_packing_summaries.clone(),
            repair_search_evaluation: base.repair_search_evaluation.clone(),
            layered_topology_evaluation: base.layered_topology_evaluation.clone(),
            common_kernel_evaluation: base.common_kernel_evaluation.clone(),
            shape_pack_evaluation: base.shape_pack_evaluation.clone(),
            convergence_evaluation: base.convergence_evaluation.clone(),
            invalidation_evaluation: base.invalidation_evaluation.clone(),
            structural_topology_evaluation: base.structural_topology_evaluation.clone(),
            per_floor_structural_topology_summaries: base
                .per_floor_structural_topology_summaries
                .clone(),
            structural_bay_evaluation: base.structural_bay_evaluation.clone(),
            per_floor_structural_bay_summaries: base.per_floor_structural_bay_summaries.clone(),
            structure_room_coupling_evaluation: base.structure_room_coupling_evaluation.clone(),
            per_floor_room_structural_fit_summaries: base
                .per_floor_room_structural_fit_summaries
                .clone(),
            transfer_structure_evaluation: base.transfer_structure_evaluation.clone(),
            per_floor_transfer_structure_summaries: base
                .per_floor_transfer_structure_summaries
                .clone(),
            per_floor_layer_state_summaries: base.per_floor_layer_state_summaries.clone(),
            per_floor_convergence_summaries: base.per_floor_convergence_summaries.clone(),
            per_floor_repair_summaries: base.per_floor_repair_summaries.clone(),
            spatial_topology_evaluation: base.spatial_topology_evaluation.clone(),
            per_floor_topology_summaries: base.per_floor_topology_summaries.clone(),
            shape_decomposition_evaluation: base.shape_decomposition_evaluation.clone(),
            per_floor_shape_summaries: base.per_floor_shape_summaries.clone(),
            preflight_unclear_zones,
            postsolve_unclear_zones,
            project_doc_export: base.project_doc_export.clone(),
            projection_bundle: base.projection_bundle.clone(),
            core_output: base.core_output.clone(),
        }
    }
}

fn site_frontage_total_ft(input: &OpeningAwareLayoutInput) -> f64 {
    if input.site_polygon.len() < 2 {
        return 0.0;
    }
    let indices = if input.site_controls.frontage_edge_indices.is_empty() {
        (0..input.site_polygon.len()).collect::<Vec<_>>()
    } else {
        input
            .site_controls
            .frontage_edge_indices
            .iter()
            .map(|idx| *idx as usize)
            .collect::<Vec<_>>()
    };
    indices
        .iter()
        .map(|&i| {
            let a = input.site_polygon[i % input.site_polygon.len()];
            let b = input.site_polygon[(i + 1) % input.site_polygon.len()];
            a.distance_to(b)
        })
        .sum::<f64>()
}

fn above_grade_story_count(input: &OpeningAwareLayoutInput) -> u32 {
    input
        .levels
        .count
        .saturating_sub(input.levels.below_grade_count)
        .max(1)
}

fn resolved_material_strategy(input: &OpeningAwareLayoutInput) -> String {
    match input
        .material_topology_controls
        .construction_type_strategy_mode
        .as_str()
    {
        "force_type_v" => "wood_frame_bar".to_string(),
        "force_type_iii" => "light_gauge_perimeter_wall".to_string(),
        "force_type_v_over_i" => "podium_wood_hybrid".to_string(),
        "force_type_iii_over_i" => "podium_type_iii_hybrid".to_string(),
        "force_type_i" => "concrete_tower_core".to_string(),
        _ => match input.building_construction_type {
            BuildingConstructionType::TypeV => "wood_frame_bar".to_string(),
            BuildingConstructionType::TypeIII => "light_gauge_perimeter_wall".to_string(),
            BuildingConstructionType::TypeVOverI => "podium_wood_hybrid".to_string(),
            BuildingConstructionType::TypeIIIOverI => "podium_type_iii_hybrid".to_string(),
            BuildingConstructionType::TypeI => "concrete_tower_core".to_string(),
        },
    }
}

fn material_roof_penalty(input: &OpeningAwareLayoutInput, occupied_roof_ratio: f64) -> f64 {
    let base_penalty = match input.building_construction_type {
        BuildingConstructionType::TypeV => 0.35,
        BuildingConstructionType::TypeIII => 0.28,
        BuildingConstructionType::TypeVOverI => 0.18,
        BuildingConstructionType::TypeIIIOverI => 0.16,
        BuildingConstructionType::TypeI => 0.10,
    };
    clamp(base_penalty * occupied_roof_ratio, 0.0, 1.0)
}

fn summarize_floor_opening_life_safety(
    input: &OpeningAwareLayoutInput,
    alloc: &SpatialGeometryFloorAllocationSummary,
    corridor: &ConstructiveFloorCorridorGraphSummary,
    packing: &ConstructiveFloorSpacePackingSummary,
    structural: &StructuralFloorTopologySummary,
) -> OpeningAwareFloorLifeSafetySummary {
    let door_node_count = corridor.node_count
        + packing.packed_unit_count_estimate
        + corridor.connector_count
        + corridor.branch_count;
    let window_eligible_frontage_ratio = if input
        .opening_life_safety_controls
        .enable_window_eligibility_proxy
    {
        clamp(
            alloc.effective_frontage_ft
                * (1.0 - alloc.non_orthogonal_edge_ratio * 0.25)
                * (1.0 - structural.column_keepout_ratio * 0.35)
                / alloc.frontage_demand_ft.max(1.0),
            0.0,
            1.20,
        )
    } else {
        1.0
    };
    let max_common_path_ratio = corridor.max_dead_end_ft
        / input
            .vertical_access_topology_controls
            .max_stair_to_unit_entry_travel_ft
            .max(EPS);
    let entry_door_conflict_count = ((corridor.branch_count as f64)
        * (1.0 - packing.shaft_affinity_score))
        .round()
        .max(0.0) as usize;
    let windowless_habitable_warning_count = if input
        .opening_life_safety_controls
        .bedroom_window_required_for_habitable
        && window_eligible_frontage_ratio < 0.75
    {
        ((packing.packed_unit_count_estimate as f64)
            * (0.75 - window_eligible_frontage_ratio).max(0.0)
            * 0.25)
            .ceil() as usize
    } else {
        0
    };

    let opening_status = if max_common_path_ratio > 1.05 || windowless_habitable_warning_count > 2 {
        PassWarnFailStatus::Fail
    } else if max_common_path_ratio > input.opening_life_safety_controls.common_path_warn_ratio
        || entry_door_conflict_count > 0
        || windowless_habitable_warning_count > 0
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    let mut notes = vec![
        format!(
            "door-node graph active = {}",
            input
                .opening_life_safety_controls
                .route_graph_includes_door_nodes
        ),
        format!(
            "window eligible frontage ratio = {:.3}",
            window_eligible_frontage_ratio
        ),
    ];
    if windowless_habitable_warning_count > 0 {
        notes.push("At least one packed run should be demoted or repaired because habitable frontage is under pressure.".to_string());
    }

    OpeningAwareFloorLifeSafetySummary {
        level_index: alloc.level_index,
        family_id: alloc.family_id.clone(),
        door_node_count,
        window_eligible_frontage_ratio,
        max_common_path_ratio,
        entry_door_conflict_count,
        windowless_habitable_warning_count,
        opening_status,
        notes,
    }
}

fn evaluate_opening_life_safety(
    _input: &OpeningAwareLayoutInput,
    summaries: &[OpeningAwareFloorLifeSafetySummary],
) -> OpeningAwareLifeSafetyEvaluation {
    let mean_window_eligible_frontage_ratio = if summaries.is_empty() {
        0.0
    } else {
        summaries
            .iter()
            .map(|x| x.window_eligible_frontage_ratio)
            .sum::<f64>()
            / summaries.len() as f64
    };
    let mean_common_path_ratio = if summaries.is_empty() {
        0.0
    } else {
        summaries
            .iter()
            .map(|x| x.max_common_path_ratio)
            .sum::<f64>()
            / summaries.len() as f64
    };
    let floors_with_door_node_overload_count =
        summaries.iter().filter(|x| x.door_node_count > 80).count();
    let floors_with_windowless_habitable_warning_count = summaries
        .iter()
        .filter(|x| x.windowless_habitable_warning_count > 0)
        .count();

    let overall_status =
        if mean_common_path_ratio > 1.05 || floors_with_windowless_habitable_warning_count > 1 {
            PassWarnFailStatus::Fail
        } else if mean_common_path_ratio > 0.90
            || floors_with_door_node_overload_count > 0
            || floors_with_windowless_habitable_warning_count > 0
        {
            PassWarnFailStatus::Warn
        } else {
            PassWarnFailStatus::Pass
        };

    OpeningAwareLifeSafetyEvaluation {
        overall_status,
        mean_window_eligible_frontage_ratio,
        mean_common_path_ratio,
        floors_with_door_node_overload_count,
        floors_with_windowless_habitable_warning_count,
        notes: vec![
            "Door-node life-safety remains a topology proxy, not a final code proof.".to_string(),
            "Window eligibility filters now influence packing and repair before feasibility freeze.".to_string(),
        ],
    }
}

fn summarize_floor_vertical_access(
    input: &OpeningAwareLayoutInput,
    alloc: &SpatialGeometryFloorAllocationSummary,
    corridor: &ConstructiveFloorCorridorGraphSummary,
    structural: &StructuralFloorTopologySummary,
    opening: &OpeningAwareFloorLifeSafetySummary,
    verticals: &VerticalState,
) -> OpeningAwareFloorVerticalAccessSummary {
    let stair_count = verticals.stairs as usize;
    let elevator_bank_count = match input
        .vertical_access_topology_controls
        .elevator_grouping_mode
        .as_str()
    {
        "split_bank" => (verticals.passenger_elevators.max(2) as f64 / 2.0).ceil() as usize,
        "tower_core" => 1,
        "distributed_lowrise" => verticals.passenger_elevators.max(1) as usize,
        _ => {
            if verticals.passenger_elevators <= 2 {
                1
            } else {
                2
            }
        }
    };
    let mut shaft_anchor_count =
        stair_count + verticals.passenger_elevators as usize + verticals.freight_elevators as usize;
    if input
        .vertical_access_topology_controls
        .allow_secondary_microshaft
        && corridor.branch_count >= 2
    {
        shaft_anchor_count += 1;
    }
    let max_stair_travel_ft = corridor.max_dead_end_ft + corridor.mean_entry_to_core_ft * 0.50;
    let stair_tip_coverage_ratio = clamp(
        1.0 - alloc.core_anchor_offset_ft / alloc.effective_frontage_ft.max(1.0)
            - structural.structure_driven_core_shift_ft / 20.0,
        0.0,
        1.0,
    );
    let shaft_branch_overflow_count =
        if corridor.branch_count as f64 * (1.0 - structural.room_structural_fit_score) > 1.0 {
            ((corridor.branch_count as f64) * (1.0 - structural.room_structural_fit_score)).ceil()
                as usize
        } else {
            0
        };
    let core_entry_distance_ft = corridor.mean_entry_to_core_ft;

    let vertical_access_status = if max_stair_travel_ft
        > input
            .vertical_access_topology_controls
            .max_stair_to_unit_entry_travel_ft
            * 1.05
        || shaft_branch_overflow_count > 2
        || opening.max_common_path_ratio > 1.05
    {
        PassWarnFailStatus::Fail
    } else if max_stair_travel_ft
        > input
            .vertical_access_topology_controls
            .max_stair_to_unit_entry_travel_ft
            * 0.90
        || stair_tip_coverage_ratio < 0.60
        || shaft_branch_overflow_count > 0
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    OpeningAwareFloorVerticalAccessSummary {
        level_index: alloc.level_index,
        family_id: alloc.family_id.clone(),
        selected_core_strategy: format!("{:?}", input.constraints.core_strategy),
        stair_count,
        elevator_bank_count,
        shaft_anchor_count,
        max_stair_travel_ft,
        stair_tip_coverage_ratio,
        shaft_branch_overflow_count,
        core_entry_distance_ft,
        vertical_access_status,
        notes: vec![
            format!(
                "stair placement mode = {}",
                input.vertical_access_topology_controls.stair_placement_mode
            ),
            format!(
                "shaft anchor mode = {}",
                input.vertical_access_topology_controls.shaft_anchor_mode
            ),
        ],
    }
}

fn evaluate_vertical_access(
    input: &OpeningAwareLayoutInput,
    summaries: &[OpeningAwareFloorVerticalAccessSummary],
) -> OpeningAwareVerticalAccessEvaluation {
    let mean_core_entry_distance_ft = if summaries.is_empty() {
        0.0
    } else {
        summaries
            .iter()
            .map(|x| x.core_entry_distance_ft)
            .sum::<f64>()
            / summaries.len() as f64
    };
    let mean_max_stair_travel_ratio = if summaries.is_empty() {
        0.0
    } else {
        summaries
            .iter()
            .map(|x| {
                x.max_stair_travel_ft
                    / input
                        .vertical_access_topology_controls
                        .max_stair_to_unit_entry_travel_ft
                        .max(EPS)
            })
            .sum::<f64>()
            / summaries.len() as f64
    };
    let floors_with_tip_stair_gap_count = summaries
        .iter()
        .filter(|x| x.stair_tip_coverage_ratio < 0.60)
        .count();
    let floors_with_shaft_branch_warning_count = summaries
        .iter()
        .filter(|x| x.shaft_branch_overflow_count > 0)
        .count();

    let overall_status = if mean_max_stair_travel_ratio > 1.05 {
        PassWarnFailStatus::Fail
    } else if mean_max_stair_travel_ratio > 0.90
        || floors_with_tip_stair_gap_count > 0
        || floors_with_shaft_branch_warning_count > 0
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    OpeningAwareVerticalAccessEvaluation {
        overall_status,
        mean_core_entry_distance_ft,
        mean_max_stair_travel_ratio,
        floors_with_tip_stair_gap_count,
        floors_with_shaft_branch_warning_count,
        notes: vec![
            "Vertical-access topology now owns stair/core/elevator/shaft placement summaries."
                .to_string(),
            "Exact shaft-room / duct-room / smoke compartment coordination remains deferred."
                .to_string(),
        ],
    }
}

fn has_accessible_roof_vertical_route(program: &ProgramState, verticals: &VerticalState) -> bool {
    verticals.passenger_elevators > 0
        || program.support_rows.iter().any(|row| {
            row.area_sf > EPS && row.space_name.to_lowercase().contains("wheelchair lift")
        })
}

fn build_roof_plan_summaries(
    input: &OpeningAwareLayoutInput,
    base: &StructuralTopologyLayoutOutput,
    _vertical_summaries: &[OpeningAwareFloorVerticalAccessSummary],
) -> Vec<OpeningAwareRoofPlanSummary> {
    let mut out = Vec::<OpeningAwareRoofPlanSummary>::new();
    let top_level_index = input.levels.count.saturating_sub(1);
    let roof_area_sf = base
        .core_output
        .selected_candidate
        .footprint_area_sf
        .max(1.0);
    let accessible_vertical_route = has_accessible_roof_vertical_route(
        &base.core_output.program,
        &base.core_output.verticals,
    );
    let occupied_roof = input.roof_plan_controls.allow_occupied_roof
        && base.core_output.program.outdoor_amenity_target_sf > 0.0;
    let accessible_route_complete = !occupied_roof
        || !input
            .roof_plan_controls
            .require_accessible_roof_route_if_occupied
        || accessible_vertical_route;
    let pool_zone_reserved = occupied_roof
        && input.roof_plan_controls.pool_allowed
        && base.core_output.program.outdoor_amenity_target_sf > 3000.0;
    let amenity_zone_count = if occupied_roof {
        1 + if pool_zone_reserved { 1 } else { 0 }
    } else {
        0
    };
    let mechanical_zone_count = 1 + if input.roof_plan_controls.reserve_mechanical_screen_zone {
        1
    } else {
        0
    };
    let roof_residual_reuse_ratio = clamp(
        (base.core_output.program.outdoor_amenity_target_sf / roof_area_sf).min(1.0) * 0.65
            + if occupied_roof { 0.20 } else { 0.0 }
            - if !accessible_route_complete {
                0.15
            } else {
                0.0
            },
        0.0,
        1.0,
    );
    let guard_buffer_conflict_count = if occupied_roof && roof_area_sf < 2500.0 {
        1
    } else {
        0
    };

    let mut top_roof_notes = vec![
        format!(
            "roof layout mode = {}",
            input.roof_plan_controls.roof_layout_mode
        ),
        format!(
            "solar pv priority = {}",
            input.roof_plan_controls.solar_pv_priority
        ),
    ];
    if accessible_vertical_route && base.core_output.verticals.passenger_elevators == 0 {
        top_roof_notes.push(
            "accessible vertical route satisfied via Wheelchair Lift support row".to_string(),
        );
    }

    out.push(OpeningAwareRoofPlanSummary {
        level_index: top_level_index,
        occupied_roof,
        accessible_route_complete,
        amenity_zone_count,
        mechanical_zone_count,
        overrun_zone_reserved: input.roof_plan_controls.reserve_elevator_overrun_zone
            || input.roof_plan_controls.reserve_stair_overrun_zone,
        pool_zone_reserved,
        roof_residual_reuse_ratio,
        guard_buffer_conflict_count,
        notes: top_roof_notes,
    });

    if input.levels.podium_levels > 0
        && input
            .amenity_open_space_controls
            .allow_outdoor_amenity_above_podium
    {
        out.push(OpeningAwareRoofPlanSummary {
            level_index: input.levels.below_grade_count
                + input.levels.podium_levels.saturating_sub(1),
            occupied_roof: true,
            accessible_route_complete: accessible_vertical_route,
            amenity_zone_count: 1,
            mechanical_zone_count: 1,
            overrun_zone_reserved: input.roof_plan_controls.reserve_stair_overrun_zone,
            pool_zone_reserved: input.site_exterior_layout_controls.pool_deck_allowed
                && input.roof_plan_controls.pool_allowed,
            roof_residual_reuse_ratio: clamp(roof_residual_reuse_ratio * 0.85, 0.0, 1.0),
            guard_buffer_conflict_count: 0,
            notes: vec![
                "Podium roof/deck candidate remains available because podium levels are present."
                    .to_string(),
            ],
        });
    }

    out
}

fn evaluate_roof_plan(
    _input: &OpeningAwareLayoutInput,
    summaries: &[OpeningAwareRoofPlanSummary],
) -> OpeningAwareRoofPlanEvaluation {
    let occupied_roof_count = summaries.iter().filter(|x| x.occupied_roof).count();
    let accessible_roof_complete_ratio = if occupied_roof_count == 0 {
        1.0
    } else {
        summaries
            .iter()
            .filter(|x| x.occupied_roof && x.accessible_route_complete)
            .count() as f64
            / occupied_roof_count as f64
    };
    let mean_roof_residual_reuse_ratio = if summaries.is_empty() {
        0.0
    } else {
        summaries
            .iter()
            .map(|x| x.roof_residual_reuse_ratio)
            .sum::<f64>()
            / summaries.len() as f64
    };
    let roofs_with_mechanical_amenity_conflict_count = summaries
        .iter()
        .filter(|x| {
            x.occupied_roof && x.mechanical_zone_count > 1 && x.guard_buffer_conflict_count > 0
        })
        .count();

    let overall_status = if accessible_roof_complete_ratio < 0.85 {
        PassWarnFailStatus::Fail
    } else if roofs_with_mechanical_amenity_conflict_count > 0
        || mean_roof_residual_reuse_ratio < 0.45
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    OpeningAwareRoofPlanEvaluation {
        overall_status,
        occupied_roof_count,
        accessible_roof_complete_ratio,
        mean_roof_residual_reuse_ratio,
        roofs_with_mechanical_amenity_conflict_count,
        notes: vec![
            "Roof plan now has an explicit priority order: overrun/mechanical -> accessible route -> occupied amenity -> residual reuse.".to_string(),
            "Exact roof capacity, drainage, and mechanical clash resolution remain deferred.".to_string(),
        ],
    }
}

fn build_site_exterior_zone_summaries(
    input: &OpeningAwareLayoutInput,
    base: &StructuralTopologyLayoutOutput,
) -> Vec<OpeningAwareSiteExteriorZoneSummary> {
    let mut out = Vec::<OpeningAwareSiteExteriorZoneSummary>::new();
    let site_area_sf = base.core_output.massing.site_area_sf.max(1.0);
    let residual_area_sf =
        (site_area_sf - base.core_output.selected_candidate.footprint_area_sf).max(0.0);
    let mut remaining = residual_area_sf;

    let accessible_route_area = remaining.min(residual_area_sf * 0.08).min(900.0);
    remaining -= accessible_route_area;
    out.push(OpeningAwareSiteExteriorZoneSummary {
        zone_id: "accessible_route".to_string(),
        zone_kind: "accessible_route".to_string(),
        area_sf: accessible_route_area,
        accessible_route_connected: true,
        screened_service: false,
        landscape_priority_score: 0.50,
        parking_interface_conflict: false,
        notes: vec![format!(
            "route mode = {}",
            input.site_exterior_layout_controls.accessible_route_mode
        )],
    });

    let forecourt_area = remaining.min(residual_area_sf * 0.12).min(
        input
            .site_exterior_layout_controls
            .min_entry_forecourt_depth_ft
            * site_frontage_total_ft(input)
            * 0.20,
    );
    remaining -= forecourt_area;
    out.push(OpeningAwareSiteExteriorZoneSummary {
        zone_id: "forecourt".to_string(),
        zone_kind: "forecourt".to_string(),
        area_sf: forecourt_area.max(0.0),
        accessible_route_connected: true,
        screened_service: false,
        landscape_priority_score: 0.55,
        parking_interface_conflict: false,
        notes: vec!["Entry forecourt is reserved before surface parking allocation.".to_string()],
    });

    let service_loading_area = if !input.site_controls.service_access_edge_indices.is_empty() {
        remaining.min(residual_area_sf * 0.08).min(1200.0)
    } else {
        0.0
    };
    remaining -= service_loading_area;
    out.push(OpeningAwareSiteExteriorZoneSummary {
        zone_id: "service_loading".to_string(),
        zone_kind: "service_loading".to_string(),
        area_sf: service_loading_area,
        accessible_route_connected: false,
        screened_service: input.site_exterior_layout_controls.service_loading_mode
            == "screened_side",
        landscape_priority_score: 0.10,
        parking_interface_conflict: false,
        notes: vec![format!(
            "service loading mode = {}",
            input.site_exterior_layout_controls.service_loading_mode
        )],
    });

    let utility_keepout_area = remaining.min((residual_area_sf * 0.03).max(120.0));
    remaining -= utility_keepout_area;
    out.push(OpeningAwareSiteExteriorZoneSummary {
        zone_id: "utility_keepout".to_string(),
        zone_kind: "utility_keepout".to_string(),
        area_sf: utility_keepout_area.max(0.0),
        accessible_route_connected: false,
        screened_service: true,
        landscape_priority_score: 0.05,
        parking_interface_conflict: false,
        notes: vec!["Utility / transformer / keep-out reserve remains schematic.".to_string()],
    });

    let surface_parking_area = if matches!(
        input.constraints.parking_mode,
        ParkingMode::Surface | ParkingMode::Mixed
    ) {
        remaining
            .min(base.parking_binding_evaluation.provided_stalls_estimate as f64 * 325.0)
            .min(residual_area_sf * 0.45)
    } else {
        0.0
    };
    remaining -= surface_parking_area;
    out.push(OpeningAwareSiteExteriorZoneSummary {
        zone_id: "surface_parking".to_string(),
        zone_kind: "surface_parking".to_string(),
        area_sf: surface_parking_area.max(0.0),
        accessible_route_connected: input
            .parking_layout_controls
            .accessible_stall_near_entry_bias,
        screened_service: false,
        landscape_priority_score: 0.05,
        parking_interface_conflict: surface_parking_area / site_area_sf
            > input
                .parking_layout_controls
                .max_surface_parking_frontage_share,
        notes: vec![format!(
            "surface stall layout mode = {}",
            input.parking_layout_controls.surface_stall_layout_mode
        )],
    });

    let exterior_amenity_area = if base.core_output.program.outdoor_amenity_target_sf > 0.0 {
        remaining
            .min(base.core_output.program.outdoor_amenity_target_sf * 0.55)
            .min(residual_area_sf * 0.18)
    } else {
        0.0
    };
    remaining -= exterior_amenity_area;
    out.push(OpeningAwareSiteExteriorZoneSummary {
        zone_id: "exterior_amenity".to_string(),
        zone_kind: "exterior_amenity".to_string(),
        area_sf: exterior_amenity_area.max(0.0),
        accessible_route_connected: true,
        screened_service: false,
        landscape_priority_score: if input
            .site_exterior_layout_controls
            .allow_exterior_amenity_on_residual_courts
        {
            0.80
        } else {
            0.45
        },
        parking_interface_conflict: false,
        notes: vec![
            "Exterior amenity is only kept after route/fire/service reservations.".to_string(),
        ],
    });

    let landscape_area = remaining
        .max(residual_area_sf * input.amenity_open_space_controls.min_landscape_ratio)
        .min(residual_area_sf);
    out.push(OpeningAwareSiteExteriorZoneSummary {
        zone_id: "landscape_open_space".to_string(),
        zone_kind: "landscape_open_space".to_string(),
        area_sf: landscape_area.max(0.0),
        accessible_route_connected: false,
        screened_service: input
            .amenity_open_space_controls
            .preserve_quiet_open_space_from_dropoff,
        landscape_priority_score: 0.90,
        parking_interface_conflict: false,
        notes: vec![format!(
            "landscape priority = {}",
            input
                .site_exterior_layout_controls
                .landscape_open_space_priority
        )],
    });

    out
}

fn evaluate_site_exterior_layout(
    input: &OpeningAwareLayoutInput,
    summaries: &[OpeningAwareSiteExteriorZoneSummary],
) -> OpeningAwareSiteExteriorEvaluation {
    let site_area_sf = polygon_area_sf(&input.site_polygon).max(1.0);
    let accessible_entry_route_count = input.site_controls.entry_edge_indices.len().max(1);
    let fire_access_coverage_ratio = if input.site_polygon.is_empty() {
        0.0
    } else {
        clamp(
            input.site_controls.fire_access_edge_indices.len() as f64
                / input.site_polygon.len() as f64,
            0.0,
            1.0,
        )
    };
    let service_loading_fit_score = if input.site_controls.service_access_edge_indices.is_empty() {
        0.55
    } else if summaries
        .iter()
        .any(|x| x.zone_kind == "service_loading" && x.area_sf > 0.0)
    {
        0.85
    } else {
        0.40
    };
    let landscape_open_space_ratio = summaries
        .iter()
        .filter(|x| x.zone_kind == "landscape_open_space" || x.zone_kind == "exterior_amenity")
        .map(|x| x.area_sf)
        .sum::<f64>()
        / site_area_sf;
    let exterior_amenity_count = summaries
        .iter()
        .filter(|x| x.zone_kind == "exterior_amenity" && x.area_sf > 0.0)
        .count();

    let overall_status = if landscape_open_space_ratio
        < input.amenity_open_space_controls.min_landscape_ratio * 0.80
        || fire_access_coverage_ratio < 0.35
    {
        PassWarnFailStatus::Fail
    } else if landscape_open_space_ratio < input.amenity_open_space_controls.min_landscape_ratio
        || service_loading_fit_score < 0.65
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    OpeningAwareSiteExteriorEvaluation {
        overall_status,
        accessible_entry_route_count,
        fire_access_coverage_ratio,
        service_loading_fit_score,
        landscape_open_space_ratio,
        exterior_amenity_count,
        notes: vec![
            "Site exterior is now zoned after route/fire/service reservations, before parking/open-space fill.".to_string(),
            "Exact grading, drainage, and utilities remain deferred.".to_string(),
        ],
    }
}

fn summarize_floor_parking_layout(
    input: &OpeningAwareLayoutInput,
    base: &StructuralTopologyLayoutOutput,
    alloc: &SpatialGeometryFloorAllocationSummary,
) -> OpeningAwareFloorParkingSummary {
    let required = base.parking_binding_evaluation.required_stalls as usize;
    let provided = base.parking_binding_evaluation.provided_stalls_estimate as usize;
    let parking_floors =
        (input.levels.below_grade_count + input.levels.podium_levels).max(1) as usize;

    let surface_total = match input.constraints.parking_mode {
        ParkingMode::Surface => provided,
        ParkingMode::Mixed => ((provided as f64) * 0.25).ceil() as usize,
        _ => 0,
    };
    let structured_total = provided.saturating_sub(surface_total);

    let on_ground = alloc.level_index == input.levels.below_grade_count;
    let in_below_grade = alloc.level_index < input.levels.below_grade_count;
    let in_podium = alloc.level_index >= input.levels.below_grade_count
        && alloc.level_index < input.levels.below_grade_count + input.levels.podium_levels;

    let surface_stall_count = if on_ground { surface_total } else { 0 };
    let structured_stall_count = match input.constraints.parking_mode {
        ParkingMode::Underground => {
            if in_below_grade {
                ((structured_total as f64) / input.levels.below_grade_count.max(1) as f64).ceil()
                    as usize
            } else {
                0
            }
        }
        ParkingMode::Podium => {
            if in_podium {
                ((structured_total as f64) / input.levels.podium_levels.max(1) as f64).ceil()
                    as usize
            } else {
                0
            }
        }
        ParkingMode::Structured => {
            if in_podium || in_below_grade || on_ground {
                ((structured_total as f64) / parking_floors as f64).ceil() as usize
            } else {
                0
            }
        }
        ParkingMode::Mixed => {
            if in_below_grade || in_podium {
                ((structured_total as f64) / parking_floors as f64).ceil() as usize
            } else {
                0
            }
        }
        _ => 0,
    };
    let accessible_stall_count = ((surface_stall_count + structured_stall_count) as f64 * 0.05)
        .ceil() as usize
        + if surface_stall_count + structured_stall_count > 0 {
            input.parking_program.accessible_stall_buffer as usize
        } else {
            0
        };
    let frontage_blocked_ratio = if on_ground && surface_stall_count > 0 {
        clamp(
            (surface_stall_count as f64 * 9.0) / site_frontage_total_ft(input).max(1.0),
            0.0,
            1.0,
        )
    } else {
        0.0
    };
    let ramp_conflict_count = if structured_stall_count > 0
        && input.parking_layout_controls.ramp_throat_reservation_ft > 0.0
        && alloc.effective_frontage_ft < 60.0
    {
        1
    } else {
        0
    };
    let dropoff_preserved = !on_ground
        || frontage_blocked_ratio
            <= input
                .parking_layout_controls
                .max_surface_parking_frontage_share;

    let mut notes = vec![
        format!("required stalls = {}", required),
        format!("provided stalls estimate = {}", provided),
    ];
    if on_ground && surface_stall_count > 0 {
        notes.push("Ground frontage is being consumed by surface stalls; drop-off is checked before parking fill.".to_string());
    }

    OpeningAwareFloorParkingSummary {
        level_index: alloc.level_index,
        surface_stall_count,
        structured_stall_count,
        accessible_stall_count,
        frontage_blocked_ratio,
        ramp_conflict_count,
        dropoff_preserved,
        notes,
    }
}

fn evaluate_parking_layout(
    input: &OpeningAwareLayoutInput,
    base: &StructuralTopologyLayoutOutput,
    summaries: &[OpeningAwareFloorParkingSummary],
) -> OpeningAwareParkingEvaluation {
    let total_surface_stalls = summaries
        .iter()
        .map(|x| x.surface_stall_count)
        .sum::<usize>();
    let total_structured_stalls = summaries
        .iter()
        .map(|x| x.structured_stall_count)
        .sum::<usize>();
    let accessible_stall_near_entry_ratio = if total_surface_stalls + total_structured_stalls == 0 {
        1.0
    } else if input
        .parking_layout_controls
        .accessible_stall_near_entry_bias
    {
        0.95
    } else {
        0.70
    };
    let mean_frontage_consumption_ratio = {
        let filtered = summaries
            .iter()
            .filter(|x| x.frontage_blocked_ratio > 0.0)
            .collect::<Vec<_>>();
        if filtered.is_empty() {
            0.0
        } else {
            filtered
                .iter()
                .map(|x| x.frontage_blocked_ratio)
                .sum::<f64>()
                / filtered.len() as f64
        }
    };
    let ramp_throat_reserved_count = summaries
        .iter()
        .filter(|x| x.structured_stall_count > 0)
        .count();
    let provided_total = total_surface_stalls + total_structured_stalls;
    let required_total = base.parking_binding_evaluation.required_stalls as usize;

    let overall_status = if (input.parking_layout_controls.stall_count_strict
        && provided_total + 1 < required_total)
        || mean_frontage_consumption_ratio
            > input
                .parking_layout_controls
                .max_surface_parking_frontage_share
                * 1.10
    {
        PassWarnFailStatus::Fail
    } else if mean_frontage_consumption_ratio
        > input
            .parking_layout_controls
            .max_surface_parking_frontage_share
        || accessible_stall_near_entry_ratio < 0.80
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    OpeningAwareParkingEvaluation {
        overall_status,
        total_surface_stalls,
        total_structured_stalls,
        accessible_stall_near_entry_ratio,
        mean_frontage_consumption_ratio,
        ramp_throat_reserved_count,
        notes: vec![
            "Parking remains a coupling-level solver in opening-aware: frontage, ramp throat, access route, and lobby/core conflicts are modeled, but detailed aisle geometry remains deferred.".to_string(),
        ],
    }
}

fn evaluate_yield_envelope(
    input: &OpeningAwareLayoutInput,
    base: &StructuralTopologyLayoutOutput,
    site_eval: &OpeningAwareSiteExteriorEvaluation,
    parking_eval: &OpeningAwareParkingEvaluation,
) -> OpeningAwareYieldEnvelopeEvaluation {
    let site_area_sf = base.core_output.massing.site_area_sf.max(1.0);
    let far_utilization_ratio = (base.core_output.selected_candidate.gross_floor_area_sf
        / site_area_sf)
        / input.targets.far_max.max(EPS);
    let dwelling_unit_cap_respected = input
        .targets
        .dwelling_units_cap
        .map(|cap| base.core_output.program.dwelling_units_total <= cap)
        .unwrap_or(true);

    let above_grade_story_count = above_grade_story_count(input) as f64;
    let podium_story_count = input
        .levels
        .podium_levels
        .min(above_grade_story_count as u32) as f64;
    let upper_story_count = (above_grade_story_count - podium_story_count).max(0.0);
    let material_story_adjust = match input.building_construction_type {
        BuildingConstructionType::TypeI => 0.30,
        BuildingConstructionType::TypeVOverI | BuildingConstructionType::TypeIIIOverI => 0.15,
        _ => 0.0,
    };
    let achieved_height_ft = if input.yield_envelope_controls.story_height_mode == "uniform" {
        above_grade_story_count
            * input
                .yield_envelope_controls
                .default_residential_story_height_ft
    } else {
        podium_story_count * input.yield_envelope_controls.podium_story_height_ft
            + upper_story_count
                * (input
                    .yield_envelope_controls
                    .default_residential_story_height_ft
                    + material_story_adjust)
    };
    let height_cap_respected = input
        .yield_envelope_controls
        .max_height_override_ft
        .map(|cap| achieved_height_ft <= cap + EPS)
        .unwrap_or(true);
    let average_story_height_ft = achieved_height_ft / above_grade_story_count.max(1.0);
    let open_space_tradeoff_score = clamp(
        site_eval.landscape_open_space_ratio
            / input
                .amenity_open_space_controls
                .min_landscape_ratio
                .max(EPS)
            * (1.0 - input.yield_envelope_controls.parking_tradeoff_weight)
            + (1.0 - parking_eval.mean_frontage_consumption_ratio)
                * input.yield_envelope_controls.parking_tradeoff_weight,
        0.0,
        1.0,
    );

    let overall_status = if far_utilization_ratio > 1.05
        || !height_cap_respected
        || (input.yield_envelope_controls.dwelling_unit_cap_mode == "hard"
            && !dwelling_unit_cap_respected)
    {
        PassWarnFailStatus::Fail
    } else if far_utilization_ratio > 0.98 || open_space_tradeoff_score < 0.55 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    OpeningAwareYieldEnvelopeEvaluation {
        overall_status,
        far_utilization_ratio,
        dwelling_unit_cap_respected,
        height_cap_respected,
        average_story_height_ft,
        open_space_tradeoff_score,
        notes: vec![
            "Yield-envelope governance now owns FAR / DU cap / story-height / open-space trade-off summary logic.".to_string(),
            "Local ordinance exact parsing remains outside opening-aware.".to_string(),
        ],
    }
}

fn evaluate_material_topology(
    input: &OpeningAwareLayoutInput,
    base: &StructuralTopologyLayoutOutput,
    vertical_eval: &OpeningAwareVerticalAccessEvaluation,
    roof_eval: &OpeningAwareRoofPlanEvaluation,
) -> OpeningAwareMaterialTopologyEvaluation {
    let selected_material_strategy = resolved_material_strategy(input);
    let construction_type_consistency_score = match input
        .material_topology_controls
        .construction_type_strategy_mode
        .as_str()
    {
        "auto" => 1.0,
        "force_type_v"
            if matches!(
                input.building_construction_type,
                BuildingConstructionType::TypeV
            ) =>
        {
            0.95
        }
        "force_type_iii"
            if matches!(
                input.building_construction_type,
                BuildingConstructionType::TypeIII
            ) =>
        {
            0.95
        }
        "force_type_v_over_i"
            if matches!(
                input.building_construction_type,
                BuildingConstructionType::TypeVOverI
            ) =>
        {
            0.95
        }
        "force_type_iii_over_i"
            if matches!(
                input.building_construction_type,
                BuildingConstructionType::TypeIIIOverI
            ) =>
        {
            0.95
        }
        "force_type_i"
            if matches!(
                input.building_construction_type,
                BuildingConstructionType::TypeI
            ) =>
        {
            0.95
        }
        _ => 0.60,
    };
    let material_core_fit_score = clamp(
        0.55 * base.structural_topology_evaluation.mean_load_path_score
            + 0.45 * (1.0 - vertical_eval.mean_max_stair_travel_ratio.min(1.0)),
        0.0,
        1.0,
    );
    let material_roof_support_penalty =
        material_roof_penalty(input, roof_eval.occupied_roof_count.min(1) as f64);
    let floors_requiring_transfer_due_to_material_change_count =
        match input.building_construction_type {
            BuildingConstructionType::TypeVOverI | BuildingConstructionType::TypeIIIOverI => {
                input.levels.podium_levels as usize
            }
            _ => 0,
        };

    let overall_status =
        if construction_type_consistency_score < 0.50 || material_core_fit_score < 0.45 {
            PassWarnFailStatus::Fail
        } else if material_roof_support_penalty > 0.30
            || floors_requiring_transfer_due_to_material_change_count > 0
        {
            PassWarnFailStatus::Warn
        } else {
            PassWarnFailStatus::Pass
        };

    OpeningAwareMaterialTopologyEvaluation {
        overall_status,
        selected_material_strategy,
        construction_type_consistency_score,
        material_core_fit_score,
        material_roof_support_penalty,
        floors_requiring_transfer_due_to_material_change_count,
        notes: vec![
            "Construction type now explicitly biases topology, but opening-aware still does not perform exact structural engineering.".to_string(),
        ],
    }
}

fn summarize_floor_amenity_open_space(
    input: &OpeningAwareLayoutInput,
    base: &StructuralTopologyLayoutOutput,
    alloc: &SpatialGeometryFloorAllocationSummary,
    opening: &OpeningAwareFloorLifeSafetySummary,
    parking: &OpeningAwareFloorParkingSummary,
    _shape: &ShapeStrategyFloorSummary,
) -> OpeningAwareFloorAmenitySummary {
    let on_ground = alloc.level_index == input.levels.below_grade_count;
    let on_top = alloc.level_index + 1 == input.levels.count;
    let roof_amenity = on_top
        && input.roof_plan_controls.allow_occupied_roof
        && base.core_output.program.outdoor_amenity_target_sf > 0.0;

    let indoor_amenity_count = if on_ground
        && input
            .amenity_open_space_controls
            .allow_indoor_amenity_on_ground_frontage
    {
        1 + usize::from(matches!(
            input.amenities.strategy,
            AmenityStrategy::Balanced | AmenityStrategy::Premium
        ))
    } else if alloc.level_index == input.levels.below_grade_count + input.levels.podium_levels
        && input.levels.podium_levels > 0
    {
        1
    } else {
        0
    };

    let outdoor_amenity_count = if roof_amenity {
        1 + usize::from(
            input.roof_plan_controls.pool_allowed
                && base.core_output.program.outdoor_amenity_target_sf > 3000.0,
        )
    } else if on_ground
        && input
            .site_exterior_layout_controls
            .allow_exterior_amenity_on_residual_courts
    {
        1
    } else {
        0
    };

    let open_space_sf = if on_ground {
        polygon_area_sf(&input.site_polygon)
            * input.amenity_open_space_controls.min_landscape_ratio
            * 0.50
    } else if roof_amenity {
        base.core_output.program.outdoor_amenity_target_sf * 0.55
    } else {
        0.0
    };

    let quiet_zone_conflict_count = if parking.frontage_blocked_ratio > 0.0
        && input
            .amenity_open_space_controls
            .preserve_quiet_open_space_from_dropoff
    {
        1
    } else if opening.window_eligible_frontage_ratio < 0.75 && indoor_amenity_count > 0 {
        1
    } else {
        0
    };

    OpeningAwareFloorAmenitySummary {
        level_index: alloc.level_index,
        indoor_amenity_count,
        outdoor_amenity_count,
        open_space_sf,
        roof_amenity,
        quiet_zone_conflict_count,
        notes: vec![
            format!(
                "indoor amenity priority = {}",
                input.amenity_open_space_controls.indoor_amenity_priority
            ),
            format!(
                "outdoor amenity priority = {}",
                input.amenity_open_space_controls.outdoor_amenity_priority
            ),
        ],
    }
}

fn evaluate_amenity_open_space(
    input: &OpeningAwareLayoutInput,
    base: &StructuralTopologyLayoutOutput,
    summaries: &[OpeningAwareFloorAmenitySummary],
    site_eval: &OpeningAwareSiteExteriorEvaluation,
    opening_eval: &OpeningAwareLifeSafetyEvaluation,
    parking_eval: &OpeningAwareParkingEvaluation,
) -> OpeningAwareAmenityEvaluation {
    let indoor_amenity_sf = base.core_output.program.indoor_amenity_target_sf;
    let outdoor_amenity_sf = base.core_output.program.outdoor_amenity_target_sf;
    let common_open_space_sf =
        polygon_area_sf(&input.site_polygon) * site_eval.landscape_open_space_ratio;
    let landscape_ratio = site_eval.landscape_open_space_ratio;
    let indoor_daylight_fit_score = clamp(
        opening_eval.mean_window_eligible_frontage_ratio.min(1.0)
            * input
                .amenity_open_space_controls
                .amenity_daylight_priority_weight
            + (1.0
                - input
                    .amenity_open_space_controls
                    .amenity_daylight_priority_weight)
                * 0.60,
        0.0,
        1.0,
    );
    let outdoor_noise_buffer_score = clamp(
        1.0 - parking_eval.mean_frontage_consumption_ratio * 0.70
            - (1.0 - site_eval.service_loading_fit_score) * 0.30,
        0.0,
        1.0,
    );
    let quiet_conflict_count = summaries
        .iter()
        .map(|x| x.quiet_zone_conflict_count)
        .sum::<usize>();

    let overall_status = if common_open_space_sf
        < input.amenity_open_space_controls.min_common_open_space_sf * 0.80
        || outdoor_noise_buffer_score < 0.35
    {
        PassWarnFailStatus::Fail
    } else if common_open_space_sf < input.amenity_open_space_controls.min_common_open_space_sf
        || quiet_conflict_count > 0
        || indoor_daylight_fit_score < 0.60
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    OpeningAwareAmenityEvaluation {
        overall_status,
        indoor_amenity_sf,
        outdoor_amenity_sf,
        common_open_space_sf,
        landscape_ratio,
        indoor_daylight_fit_score,
        outdoor_noise_buffer_score,
        notes: vec![
            "Amenity/open-space now treats common open space and landscape as first-class outputs, not only leftover zones.".to_string(),
        ],
    }
}

