fn progressive_stage_path_string(input: &ProgressiveTopologyLayoutInput) -> String {
    format!(
        "{} -> {} -> {} -> {}",
        input.multi_fidelity_topology_controls.coarse_stage_mode,
        input.multi_fidelity_topology_controls.backbone_stage_mode,
        input.multi_fidelity_topology_controls.allocation_stage_mode,
        input
            .multi_fidelity_topology_controls
            .exactification_stage_mode,
    )
}

fn summarize_progressive_stages(
    input: &ProgressiveTopologyLayoutInput,
    base: &OpeningAwareLayoutOutput,
) -> Vec<ProgressiveTopologyFloorStageSummary> {
    let n = base.per_floor_allocation_summaries.len();
    let path = progressive_stage_path_string(input);
    let mut out = Vec::<ProgressiveTopologyFloorStageSummary>::new();

    for idx in 0..n {
        let alloc = &base.per_floor_allocation_summaries[idx];
        let layer = base.per_floor_layer_state_summaries.get(idx);
        let conv = base.per_floor_convergence_summaries.get(idx);
        let repair = base.per_floor_repair_summaries.get(idx);
        let open = base.per_floor_opening_life_safety_summaries.get(idx);
        let vertical = base.per_floor_vertical_access_summaries.get(idx);
        let ctop = base.per_floor_constructive_topology_summaries.get(idx);
        let cgraph = base.per_floor_corridor_graph_summaries.get(idx);
        let spack = base.per_floor_space_packing_summaries.get(idx);
        let sroom = base.per_floor_room_structural_fit_summaries.get(idx);
        let transfer = base.per_floor_transfer_structure_summaries.get(idx);

        let coarse_topology_score = clamp(
            0.55 * layer.map(|x| x.common_kernel_coverage_ratio).unwrap_or(0.0)
                + 0.45 * ctop.map(|x| x.buildable_envelope_score).unwrap_or(0.0),
            0.0,
            1.0,
        );

        let backbone_score = clamp(
            0.35 * ctop.map(|x| x.constructive_partition_score).unwrap_or(0.0)
                + 0.30 * cgraph.map(|x| x.corridor_graph_score).unwrap_or(0.0)
                + 0.20
                    * base
                        .per_floor_structural_topology_summaries
                        .get(idx)
                        .map(|x| x.bay_fit_score)
                        .unwrap_or(0.0)
                + 0.15
                    * base
                        .per_floor_shape_summaries
                        .get(idx)
                        .map(|x| x.strategy_fit_score)
                        .unwrap_or(0.0),
            0.0,
            1.0,
        );

        let allocation_refinement_score = clamp(
            0.30 * alloc.allocation_score
                + 0.20 * spack.map(|x| x.space_packing_score).unwrap_or(0.0)
                + 0.15 * sroom.map(|x| x.dwelling_room_fit_score).unwrap_or(0.0)
                + 0.15
                    * open
                        .map(|x| x.window_eligible_frontage_ratio)
                        .unwrap_or(0.0)
                + 0.10 * (1.0 - open.map(|x| x.max_common_path_ratio).unwrap_or(1.0))
                + 0.10 * (1.0 - alloc.residual_pocket_ratio),
            0.0,
            1.0,
        );

        let hard_flags = open
            .map(|x| x.entry_door_conflict_count + x.windowless_habitable_warning_count)
            .unwrap_or(0)
            + vertical.map(|x| x.shaft_branch_overflow_count).unwrap_or(0)
            + transfer
                .map(|x| if x.repack_required { 1 } else { 0 })
                .unwrap_or(0)
            + repair
                .map(|x| if x.manual_review_required { 1 } else { 0 })
                .unwrap_or(0)
            + base
                .roof_plan_summaries
                .iter()
                .filter(|x| x.level_index == alloc.level_index && x.guard_buffer_conflict_count > 0)
                .count();

        let full_repack_count = conv.map(|x| x.restart_count).unwrap_or(0)
            + transfer
                .map(|x| if x.repack_required { 1 } else { 0 })
                .unwrap_or(0);

        let exactification_applied = if input
            .multi_fidelity_topology_controls
            .activate_exactification_only_on_flagged_zones
        {
            hard_flags > 0
                || allocation_refinement_score
                    < input
                        .multi_fidelity_topology_controls
                        .activate_fine_stage_below_score
        } else {
            input
                .multi_fidelity_topology_controls
                .exactification_stage_mode
                != "disabled"
        };

        let stable_after_stage = if !exactification_applied
            && coarse_topology_score >= 0.86
            && backbone_score >= 0.82
            && allocation_refinement_score >= 0.80
        {
            "stage_2_allocation"
        } else if !exactification_applied
            && backbone_score >= 0.78
            && allocation_refinement_score >= 0.74
        {
            "stage_1_backbone"
        } else if coarse_topology_score >= 0.80
            && hard_flags == 0
            && allocation_refinement_score >= 0.70
        {
            "stage_2_allocation"
        } else if exactification_applied {
            "stage_3_exactification"
        } else {
            "stage_0_coarse"
        }
        .to_string();

        let mut notes = Vec::<String>::new();
        notes.push(format!("path = {}", path));
        notes.push(format!("hard_flags = {}", hard_flags));
        if input
            .topology_runtime_controls
            .skip_stage_if_inputs_unchanged
        {
            notes.push("runtime skip is enabled when signatures do not change".to_string());
        }
        if full_repack_count
            > input
                .topology_runtime_controls
                .limit_full_floor_repack_count
        {
            notes.push("full-floor repack count exceeded preferred budget".to_string());
        }

        out.push(ProgressiveTopologyFloorStageSummary {
            level_index: alloc.level_index,
            selected_stage_path: path.clone(),
            stable_after_stage,
            coarse_topology_score,
            backbone_score,
            allocation_refinement_score,
            exactification_applied,
            full_repack_count,
            notes,
        });
    }

    out
}

fn evaluate_progressive_topology(
    input: &ProgressiveTopologyLayoutInput,
    base: &OpeningAwareLayoutOutput,
    per_floor: &[ProgressiveTopologyFloorStageSummary],
) -> ProgressiveTopologyEvaluation {
    let floors_requiring_exactification = per_floor
        .iter()
        .filter(|x| x.exactification_applied)
        .count();
    let floors_requiring_fine_stage = per_floor
        .iter()
        .filter(|x| x.backbone_score < 0.82 || x.allocation_refinement_score < 0.80)
        .count();
    let inherited_solution_ratio = if per_floor.is_empty() {
        0.0
    } else {
        per_floor
            .iter()
            .filter(|x| x.stable_after_stage != "stage_0_coarse")
            .count() as f64
            / per_floor.len() as f64
    };
    let global_passes_used = base
        .convergence_evaluation
        .mean_global_rounds_used
        .round()
        .max(0.0) as usize;
    let overall_status = if global_passes_used > input.topology_runtime_controls.max_global_passes
        || floors_requiring_exactification > per_floor.len().saturating_div(2)
    {
        PassWarnFailStatus::Fail
    } else if inherited_solution_ratio < 0.70
        || floors_requiring_fine_stage > per_floor.len().saturating_div(2)
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    ProgressiveTopologyEvaluation {
        overall_status,
        selected_stage_path: progressive_stage_path_string(input),
        global_passes_used,
        floors_requiring_fine_stage,
        floors_requiring_exactification,
        inherited_solution_ratio,
        notes: vec![
            "progressive-topology prefers inherited state and targeted exactification over repeated wide repack.".to_string(),
            "A later stage may only reopen the previous stage automatically when a major-break trigger fires.".to_string(),
        ],
    }
}

fn evaluate_door_window_refinement(
    input: &ProgressiveTopologyLayoutInput,
    base: &OpeningAwareLayoutOutput,
    per_floor: &[ProgressiveTopologyFloorStageSummary],
) -> ProgressiveTopologyDoorWindowEvaluation {
    let flagged_room_cluster_count = base
        .per_floor_opening_life_safety_summaries
        .iter()
        .filter(|x| {
            x.entry_door_conflict_count > 0
                || x.windowless_habitable_warning_count > 0
                || x.max_common_path_ratio
                    > input.opening_life_safety_controls.common_path_warn_ratio
        })
        .count();
    let mean_openable_frontage_ratio = if base.per_floor_opening_life_safety_summaries.is_empty() {
        0.0
    } else {
        base.per_floor_opening_life_safety_summaries
            .iter()
            .map(|x| x.window_eligible_frontage_ratio)
            .sum::<f64>()
            / base.per_floor_opening_life_safety_summaries.len() as f64
    };
    let door_clearance_warning_count = base
        .per_floor_opening_life_safety_summaries
        .iter()
        .map(|x| x.entry_door_conflict_count)
        .sum();
    let egress_cluster_repair_count = per_floor
        .iter()
        .filter(|x| x.exactification_applied)
        .count()
        .min(
            base.per_floor_repair_summaries
                .iter()
                .filter(|x| x.repair_rounds_applied > 0)
                .count(),
        );

    let overall_status = if flagged_room_cluster_count == 0 && mean_openable_frontage_ratio >= 0.82
    {
        PassWarnFailStatus::Pass
    } else if flagged_room_cluster_count <= per_floor.len().max(1) / 2
        && mean_openable_frontage_ratio >= 0.68
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Fail
    };

    ProgressiveTopologyDoorWindowEvaluation {
        overall_status,
        flagged_room_cluster_count,
        mean_openable_frontage_ratio,
        door_clearance_warning_count,
        egress_cluster_repair_count,
        notes: vec![
            format!("mode = {}", input.exactification_controls.door_window_refinement_mode),
            "progressive-topology refines door/window/egress on flagged room clusters instead of reopening the whole floor by default.".to_string(),
        ],
    }
}

fn evaluate_shaft_core_selection(
    input: &ProgressiveTopologyLayoutInput,
    base: &OpeningAwareLayoutOutput,
    _per_floor: &[ProgressiveTopologyFloorStageSummary],
) -> ProgressiveTopologyShaftCoreEvaluation {
    let mean_core_candidate_rank_score = if base.per_floor_vertical_access_summaries.is_empty() {
        0.0
    } else {
        base.per_floor_vertical_access_summaries
            .iter()
            .map(|x| {
                clamp(
                    1.0 - x.core_entry_distance_ft / x.max_stair_travel_ft.max(1.0),
                    0.0,
                    1.0,
                )
            })
            .sum::<f64>()
            / base.per_floor_vertical_access_summaries.len() as f64
    };
    let shaft_stack_alignment_ratio = if base.per_floor_room_structural_fit_summaries.is_empty() {
        0.0
    } else {
        base.per_floor_room_structural_fit_summaries
            .iter()
            .map(|x| x.shaft_affinity_score)
            .sum::<f64>()
            / base.per_floor_room_structural_fit_summaries.len() as f64
    };
    let microshaft_insertions = if input
        .vertical_access_topology_controls
        .allow_secondary_microshaft
    {
        base.per_floor_vertical_access_summaries
            .iter()
            .map(|x| x.shaft_branch_overflow_count.min(1))
            .sum()
    } else {
        0
    };
    let repack_due_to_core_shift_count = base
        .per_floor_transfer_structure_summaries
        .iter()
        .filter(|x| x.repack_required)
        .count()
        + base
            .per_floor_structural_topology_summaries
            .iter()
            .filter(|x| x.structure_driven_core_shift_ft > 6.0)
            .count();

    let overall_status = if mean_core_candidate_rank_score >= 0.75
        && shaft_stack_alignment_ratio >= 0.72
        && repack_due_to_core_shift_count == 0
    {
        PassWarnFailStatus::Pass
    } else if mean_core_candidate_rank_score >= 0.58 && shaft_stack_alignment_ratio >= 0.58 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Fail
    };

    ProgressiveTopologyShaftCoreEvaluation {
        overall_status,
        mean_core_candidate_rank_score,
        shaft_stack_alignment_ratio,
        microshaft_insertions,
        repack_due_to_core_shift_count,
        notes: vec![
            format!("mode = {}", input.exactification_controls.shaft_core_selection_mode),
            "progressive-topology keeps shaft/core selection under a bounded rank-then-repair policy rather than a broad restart policy.".to_string(),
        ],
    }
}

fn evaluate_roof_site_distribution(
    input: &ProgressiveTopologyLayoutInput,
    base: &OpeningAwareLayoutOutput,
    _per_floor: &[ProgressiveTopologyFloorStageSummary],
) -> ProgressiveTopologyRoofSiteEvaluation {
    let roof_conflict_local_repair_count = base
        .roof_plan_summaries
        .iter()
        .filter(|x| x.guard_buffer_conflict_count > 0)
        .count();
    let site_surface_distribution_score = clamp(
        0.45 * base
            .site_exterior_layout_evaluation
            .landscape_open_space_ratio
            + 0.30
                * (1.0
                    - base
                        .parking_layout_evaluation
                        .mean_frontage_consumption_ratio)
            + 0.25 * base.amenity_open_space_evaluation.landscape_ratio,
        0.0,
        1.0,
    );
    let open_space_preservation_ratio = clamp(
        base.amenity_open_space_evaluation.common_open_space_sf
            / input
                .amenity_open_space_controls
                .min_common_open_space_sf
                .max(1.0),
        0.0,
        1.0,
    );
    let parking_frontage_penalty_score = clamp(
        base.parking_layout_evaluation
            .mean_frontage_consumption_ratio,
        0.0,
        1.0,
    );

    let overall_status = if site_surface_distribution_score >= 0.72
        && parking_frontage_penalty_score
            <= input
                .parking_layout_controls
                .max_surface_parking_frontage_share
    {
        PassWarnFailStatus::Pass
    } else if site_surface_distribution_score >= 0.55 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Fail
    };

    ProgressiveTopologyRoofSiteEvaluation {
        overall_status,
        roof_conflict_local_repair_count,
        site_surface_distribution_score,
        open_space_preservation_ratio,
        parking_frontage_penalty_score,
        notes: vec![
            format!("roof mode = {}", input.exactification_controls.roof_refinement_mode),
            format!("surface distribution mode = {}", input.exactification_controls.parking_surface_distribution_mode),
            "progressive-topology runs roof/site/open-space/parking deeper only after the floor stack is sufficiently frozen.".to_string(),
        ],
    }
}

fn evaluate_runtime_budget(
    input: &ProgressiveTopologyLayoutInput,
    base: &OpeningAwareLayoutOutput,
    per_floor: &[ProgressiveTopologyFloorStageSummary],
) -> ProgressiveTopologyRuntimeBudgetEvaluation {
    let global_passes_used = base
        .convergence_evaluation
        .mean_global_rounds_used
        .round()
        .max(0.0) as usize;
    let local_repair_passes_used = base
        .per_floor_repair_summaries
        .iter()
        .map(|x| x.repair_rounds_applied)
        .max()
        .unwrap_or(0);
    let skipped_stage_count = per_floor
        .iter()
        .filter(|x| {
            x.stable_after_stage == "stage_1_backbone"
                || x.stable_after_stage == "stage_2_allocation"
        })
        .count();
    let full_floor_repack_count = per_floor.iter().map(|x| x.full_repack_count).sum();
    let mean_stage_count_per_floor = if per_floor.is_empty() {
        0.0
    } else {
        per_floor
            .iter()
            .map(|x| match x.stable_after_stage.as_str() {
                "stage_0_coarse" => 1.0,
                "stage_1_backbone" => 2.0,
                "stage_2_allocation" => 3.0,
                "stage_3_exactification" => 4.0,
                _ => 4.0,
            })
            .sum::<f64>()
            / per_floor.len() as f64
    };

    let overall_status = if global_passes_used > input.topology_runtime_controls.max_global_passes
        || local_repair_passes_used > input.topology_runtime_controls.max_local_repair_passes
        || full_floor_repack_count
            > input
                .topology_runtime_controls
                .limit_full_floor_repack_count
                * per_floor.len().max(1)
    {
        PassWarnFailStatus::Fail
    } else if mean_stage_count_per_floor > 3.4 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    ProgressiveTopologyRuntimeBudgetEvaluation {
        overall_status,
        global_passes_used,
        local_repair_passes_used,
        skipped_stage_count,
        full_floor_repack_count,
        mean_stage_count_per_floor,
        notes: vec![
            "progressive-topology measures runtime quality by how often the solver can stop early with inherited states intact.".to_string(),
            "Exactification is expected to be sparse; if it becomes common, the stage stack or thresholds should be retuned.".to_string(),
        ],
    }
}

/* =============================================================================
Allocation-readiness layer
--------------------------------------------------------------------------------
This layer keeps the progressive-topology substrate and adds:
1. shape-family allocation readiness gates
2. floor-role allocation completeness gates
3. typical-floor equivalence / harmonization summaries
4. area-ledger floor utilization summaries
5. overlap-free partition integrity summaries
============================================================================= */

