#[derive(Debug, Clone)]
struct CanonicalPolygon {
    polygon: Vec<Point2>,
    self_intersection_count: usize,
    pseudo_courtyard_resolved: bool,
    unstable: bool,
}

#[derive(Debug, Clone)]
struct LocalRoomSlot {
    topology_node_id: String,
    room_kind: String,
    semantic_room_kind: UnitRoomSemanticKind,
    partition: UnitRoomPartition,
    u0: f64,
    u1: f64,
    v0: f64,
    v1: f64,
    wet_wall_cluster_id: Option<String>,
    notes: Vec<String>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum UnitSide {
    Bottom,
    Top,
    Left,
    Right,
}

#[derive(Debug, Clone, Copy)]
struct UnitFrame {
    rect: Rect2,
    entry_side: UnitSide,
    width_ft: f64,
    depth_ft: f64,
}

impl UnitFrame {
    fn new(rect: Rect2, entry_side: UnitSide) -> Self {
        let (width_ft, depth_ft) = match entry_side {
            UnitSide::Bottom | UnitSide::Top => (rect.width(), rect.height()),
            UnitSide::Left | UnitSide::Right => (rect.height(), rect.width()),
        };
        Self {
            rect,
            entry_side,
            width_ft,
            depth_ft,
        }
    }

    fn frontage_side(&self) -> UnitSide {
        match self.entry_side {
            UnitSide::Bottom => UnitSide::Top,
            UnitSide::Top => UnitSide::Bottom,
            UnitSide::Left => UnitSide::Right,
            UnitSide::Right => UnitSide::Left,
        }
    }

    fn map_local_rect(&self, u0: f64, u1: f64, v0: f64, v1: f64) -> Rect2 {
        let u0 = clamp(u0, 0.0, self.width_ft);
        let u1 = clamp(u1, 0.0, self.width_ft);
        let v0 = clamp(v0, 0.0, self.depth_ft);
        let v1 = clamp(v1, 0.0, self.depth_ft);
        match self.entry_side {
            UnitSide::Bottom => Rect2::new(
                self.rect.min_x + u0,
                self.rect.min_y + v0,
                self.rect.min_x + u1,
                self.rect.min_y + v1,
            ),
            UnitSide::Top => Rect2::new(
                self.rect.min_x + u0,
                self.rect.max_y - v1,
                self.rect.min_x + u1,
                self.rect.max_y - v0,
            ),
            UnitSide::Left => Rect2::new(
                self.rect.min_x + v0,
                self.rect.min_y + u0,
                self.rect.min_x + v1,
                self.rect.min_y + u1,
            ),
            UnitSide::Right => Rect2::new(
                self.rect.max_x - v1,
                self.rect.min_y + u0,
                self.rect.max_x - v0,
                self.rect.min_y + u1,
            ),
        }
    }
}

fn snap_point(p: Point2, grid_ft: f64) -> Point2 {
    Point2::new(snap_ft(p.x, grid_ft), snap_ft(p.y, grid_ft))
}

fn signed_area(poly: &[Point2]) -> f64 {
    if poly.len() < 3 {
        return 0.0;
    }
    let mut s = 0.0;
    for i in 0..poly.len() {
        let a = poly[i];
        let b = poly[(i + 1) % poly.len()];
        s += a.x * b.y - b.x * a.y;
    }
    0.5 * s
}

fn remove_duplicate_points(poly: &[Point2], eps: f64) -> Vec<Point2> {
    let mut out = Vec::<Point2>::new();
    for p in poly {
        if out.last().map(|q| q.distance_to(*p) > eps).unwrap_or(true) {
            out.push(*p);
        }
    }
    if out.len() >= 2 && out[0].distance_to(*out.last().unwrap()) <= eps {
        out.pop();
    }
    out
}

fn remove_collinear_points(poly: &[Point2], eps: f64) -> Vec<Point2> {
    if poly.len() < 3 {
        return poly.to_vec();
    }
    let mut out = Vec::<Point2>::new();
    for i in 0..poly.len() {
        let a = poly[(i + poly.len() - 1) % poly.len()];
        let b = poly[i];
        let c = poly[(i + 1) % poly.len()];
        let ab = b.sub(a);
        let bc = c.sub(b);
        if ab.cross(bc).abs() > eps || ab.len() <= eps || bc.len() <= eps {
            out.push(b);
        }
    }
    out
}

fn orientation(a: Point2, b: Point2, c: Point2) -> f64 {
    b.sub(a).cross(c.sub(a))
}

fn on_segment(a: Point2, b: Point2, p: Point2, eps: f64) -> bool {
    p.x >= a.x.min(b.x) - eps
        && p.x <= a.x.max(b.x) + eps
        && p.y >= a.y.min(b.y) - eps
        && p.y <= a.y.max(b.y) + eps
        && orientation(a, b, p).abs() <= eps
}

fn segments_intersect(a1: Point2, a2: Point2, b1: Point2, b2: Point2, eps: f64) -> bool {
    let o1 = orientation(a1, a2, b1);
    let o2 = orientation(a1, a2, b2);
    let o3 = orientation(b1, b2, a1);
    let o4 = orientation(b1, b2, a2);

    if ((o1 > eps && o2 < -eps) || (o1 < -eps && o2 > eps))
        && ((o3 > eps && o4 < -eps) || (o3 < -eps && o4 > eps))
    {
        return true;
    }

    on_segment(a1, a2, b1, eps)
        || on_segment(a1, a2, b2, eps)
        || on_segment(b1, b2, a1, eps)
        || on_segment(b1, b2, a2, eps)
}

fn self_intersection_count(poly: &[Point2], eps: f64) -> usize {
    if poly.len() < 4 {
        return 0;
    }
    let mut count = 0usize;
    for i in 0..poly.len() {
        let a1 = poly[i];
        let a2 = poly[(i + 1) % poly.len()];
        for j in (i + 1)..poly.len() {
            if j == i || j == (i + 1) % poly.len() || (i == 0 && j == poly.len() - 1) {
                continue;
            }
            let b1 = poly[j];
            let b2 = poly[(j + 1) % poly.len()];
            if segments_intersect(a1, a2, b1, b2, eps) {
                count += 1;
            }
        }
    }
    count
}

fn canonicalize_polygon(
    poly: &[Point2],
    controls: &RoomSynthesisPolygonKernelControls,
) -> CanonicalPolygon {
    let snapped = poly
        .iter()
        .map(|p| snap_point(*p, controls.snap_grid_ft))
        .collect::<Vec<_>>();
    let deduped = remove_duplicate_points(&snapped, controls.collinear_epsilon_ft.max(EPS));
    let mut simplified = remove_collinear_points(&deduped, controls.collinear_epsilon_ft.max(EPS));
    if signed_area(&simplified) < 0.0 {
        simplified.reverse();
    }
    let self_intersection_count =
        self_intersection_count(&simplified, controls.self_touch_split_epsilon_ft.max(EPS));
    let bbox = bounding_rect(&simplified);
    let bbox_area = bbox.area().max(1.0);
    let poly_area = polygon_area_sf(&simplified);
    let pseudo_courtyard = simplified.len() >= 6 && poly_area / bbox_area < 0.78;
    let pseudo_courtyard_resolved =
        pseudo_courtyard && controls.resolve_pseudo_courtyard_mode != "mark_unclear";
    let unstable = self_intersection_count > 0 && controls.exact_overlap_mode == "mark_unclear";
    CanonicalPolygon {
        polygon: simplified,
        self_intersection_count,
        pseudo_courtyard_resolved,
        unstable,
    }
}

fn is_dwelling_space(space: &SpacePlacement) -> bool {
    space.category.to_lowercase().contains("dwelling")
}

fn infer_unit_type(space: &SpacePlacement) -> String {
    let n = space.space_name.to_lowercase();
    if n.contains("studio") {
        "studio".to_string()
    } else if n.contains("three") || n.contains("3br") {
        "three_bedroom".to_string()
    } else if n.contains("two") || n.contains("2br") {
        "two_bedroom".to_string()
    } else if n.contains("one") || n.contains("1br") {
        "one_bedroom".to_string()
    } else if space.area_sf >= 1180.0 {
        "three_bedroom".to_string()
    } else if space.area_sf >= 880.0 {
        "two_bedroom".to_string()
    } else if space.area_sf >= 560.0 {
        "one_bedroom".to_string()
    } else {
        "studio".to_string()
    }
}

fn corridor_rects_for_floor(floor: &FloorOutput) -> Vec<Rect2> {
    floor
        .spaces
        .iter()
        .filter(|s| s.category.to_lowercase().contains("circulation"))
        .map(|s| s.rect)
        .collect()
}

fn shared_overlap_len(a0: f64, a1: f64, b0: f64, b1: f64) -> f64 {
    (a1.min(b1) - a0.max(b0)).max(0.0)
}

fn detect_entry_side(rect: Rect2, corridors: &[Rect2]) -> UnitSide {
    let mut best = (UnitSide::Bottom, 0.0f64);
    for c in corridors {
        let bottom = if (rect.min_y - c.max_y).abs() <= 1.0 {
            shared_overlap_len(rect.min_x, rect.max_x, c.min_x, c.max_x)
        } else {
            0.0
        };
        let top = if (rect.max_y - c.min_y).abs() <= 1.0 {
            shared_overlap_len(rect.min_x, rect.max_x, c.min_x, c.max_x)
        } else {
            0.0
        };
        let left = if (rect.min_x - c.max_x).abs() <= 1.0 {
            shared_overlap_len(rect.min_y, rect.max_y, c.min_y, c.max_y)
        } else {
            0.0
        };
        let right = if (rect.max_x - c.min_x).abs() <= 1.0 {
            shared_overlap_len(rect.min_y, rect.max_y, c.min_y, c.max_y)
        } else {
            0.0
        };
        for (side, overlap) in [
            (UnitSide::Bottom, bottom),
            (UnitSide::Top, top),
            (UnitSide::Left, left),
            (UnitSide::Right, right),
        ] {
            if overlap > best.1 {
                best = (side, overlap);
            }
        }
    }
    if best.1 > 0.0 {
        best.0
    } else if rect.width() >= rect.height() {
        UnitSide::Bottom
    } else {
        UnitSide::Left
    }
}

fn reserve_on_side(rect: Rect2, side: UnitSide, clear_width_ft: f64, depth_ft: f64) -> Vec<Point2> {
    let w = clear_width_ft.max(1.0).min(match side {
        UnitSide::Bottom | UnitSide::Top => rect.width(),
        _ => rect.height(),
    });
    let d = depth_ft.max(0.5);
    let out = match side {
        UnitSide::Bottom => {
            let x0 = rect.center().x - w * 0.5;
            Rect2::new(x0, rect.min_y, x0 + w, (rect.min_y + d).min(rect.max_y))
        }
        UnitSide::Top => {
            let x0 = rect.center().x - w * 0.5;
            Rect2::new(x0, (rect.max_y - d).max(rect.min_y), x0 + w, rect.max_y)
        }
        UnitSide::Left => {
            let y0 = rect.center().y - w * 0.5;
            Rect2::new(rect.min_x, y0, (rect.min_x + d).min(rect.max_x), y0 + w)
        }
        UnitSide::Right => {
            let y0 = rect.center().y - w * 0.5;
            Rect2::new((rect.max_x - d).max(rect.min_x), y0, rect.max_x, y0 + w)
        }
    };
    out.to_polygon()
}

fn reserve_fixture_strip(
    rect: Rect2,
    count: usize,
    side: UnitSide,
    depth_ft: f64,
    id_prefix: &str,
    room_id: &str,
) -> Vec<RoomFixtureReserve> {
    let mut out = Vec::<RoomFixtureReserve>::new();
    if count == 0 {
        return out;
    }
    let span = match side {
        UnitSide::Bottom | UnitSide::Top => rect.width(),
        UnitSide::Left | UnitSide::Right => rect.height(),
    };
    let each = (span / count as f64).max(1.5);
    for i in 0..count {
        let poly = match side {
            UnitSide::Bottom => {
                let x0 = rect.min_x + each * i as f64;
                Rect2::new(
                    x0,
                    rect.min_y,
                    (x0 + each - 0.2).min(rect.max_x),
                    (rect.min_y + depth_ft).min(rect.max_y),
                )
                .to_polygon()
            }
            UnitSide::Top => {
                let x0 = rect.min_x + each * i as f64;
                Rect2::new(
                    x0,
                    (rect.max_y - depth_ft).max(rect.min_y),
                    (x0 + each - 0.2).min(rect.max_x),
                    rect.max_y,
                )
                .to_polygon()
            }
            UnitSide::Left => {
                let y0 = rect.min_y + each * i as f64;
                Rect2::new(
                    rect.min_x,
                    y0,
                    (rect.min_x + depth_ft).min(rect.max_x),
                    (y0 + each - 0.2).min(rect.max_y),
                )
                .to_polygon()
            }
            UnitSide::Right => {
                let y0 = rect.min_y + each * i as f64;
                Rect2::new(
                    (rect.max_x - depth_ft).max(rect.min_x),
                    y0,
                    rect.max_x,
                    (y0 + each - 0.2).min(rect.max_y),
                )
                .to_polygon()
            }
        };
        let kind = if id_prefix.starts_with("bath") {
            match i {
                0 => "lavatory",
                1 => "toilet",
                _ => "tub_or_shower",
            }
        } else {
            match i {
                0 => "fridge",
                1 => "sink",
                _ => "range",
            }
        };
        out.push(RoomFixtureReserve {
            fixture_id: format!("{}_{}_{}", room_id, id_prefix, i),
            fixture_kind: kind.to_string(),
            polygon: poly,
            associated_room_id: room_id.to_string(),
        });
    }
    out
}

fn unit_room_semantic_kind_slug(kind: UnitRoomSemanticKind) -> &'static str {
    match kind {
        UnitRoomSemanticKind::Foyer => "foyer",
        UnitRoomSemanticKind::Living => "living",
        UnitRoomSemanticKind::Dining => "dining",
        UnitRoomSemanticKind::Kitchen => "kitchen",
        UnitRoomSemanticKind::Bath => "bath",
        UnitRoomSemanticKind::Bedroom => "bedroom",
        UnitRoomSemanticKind::Closet => "closet",
        UnitRoomSemanticKind::LaundryNiche => "laundry_niche",
        UnitRoomSemanticKind::MechanicalCloset => "mechanical_closet",
        UnitRoomSemanticKind::PrivateHall => "private_hall",
        UnitRoomSemanticKind::CompactFallback => "compact_fallback",
    }
}

fn unit_room_partition_slug(partition: UnitRoomPartition) -> &'static str {
    match partition {
        UnitRoomPartition::Public => "public",
        UnitRoomPartition::Private => "private",
        UnitRoomPartition::Service => "service",
        UnitRoomPartition::Circulation => "circulation",
    }
}

fn unit_topology_edge_kind_slug(kind: UnitTopologyEdgeKind) -> &'static str {
    match kind {
        UnitTopologyEdgeKind::Access => "access",
        UnitTopologyEdgeKind::PrivacyBoundary => "privacy_boundary",
        UnitTopologyEdgeKind::WetAdjacency => "wet_adjacency",
        UnitTopologyEdgeKind::DaylightClaim => "daylight_claim",
        UnitTopologyEdgeKind::StructureCompatibility => "structure_compatibility",
        UnitTopologyEdgeKind::EntrySequence => "entry_sequence",
        UnitTopologyEdgeKind::PublicPrivateTransition => "public_private_transition",
        UnitTopologyEdgeKind::LivingChain => "living_chain",
        UnitTopologyEdgeKind::VerticalDependency => "vertical_dependency",
    }
}

fn unit_topology_node_by_label<'a>(
    topology: &'a UnitTopologyGraph,
    label: &str,
) -> Option<&'a UnitTopologyNode> {
    topology.nodes.iter().find(|node| node.label == label)
}

fn unit_topology_label_by_node_id(topology: &UnitTopologyGraph, node_id: &str) -> Option<String> {
    topology
        .nodes
        .iter()
        .find(|node| node.node_id == node_id)
        .map(|node| node.label.clone())
}

fn unit_topology_has_label(topology: &UnitTopologyGraph, label: &str) -> bool {
    unit_topology_node_by_label(topology, label).is_some()
}

fn make_unit_topology_node(
    unit_id: &str,
    label: &str,
    semantic_kind: UnitRoomSemanticKind,
    partition: UnitRoomPartition,
    required: bool,
    daylight_required: bool,
    frontage_priority: u8,
    wet_cluster_id: Option<&str>,
    structure_profile: &[&str],
    notes: Vec<String>,
) -> UnitTopologyNode {
    UnitTopologyNode {
        node_id: format!("{}_topo_{}", unit_id, label),
        semantic_kind,
        label: label.to_string(),
        partition,
        required,
        daylight_required,
        frontage_priority,
        wet_cluster_id: wet_cluster_id.map(|x| x.to_string()),
        structure_profile: structure_profile.iter().map(|x| x.to_string()).collect(),
        vertical_dependency_ids: Vec::new(),
        notes,
    }
}

fn make_unit_topology_edge(
    unit_id: &str,
    topology: &UnitTopologyGraph,
    from_label: &str,
    to_label: &str,
    edge_kind: UnitTopologyEdgeKind,
    required: bool,
    directed: bool,
    notes: Vec<String>,
) -> Option<UnitTopologyEdge> {
    let from = unit_topology_node_by_label(topology, from_label)?;
    let to = unit_topology_node_by_label(topology, to_label)?;
    Some(UnitTopologyEdge {
        edge_id: format!(
            "{}_{}_{}_{}",
            unit_id,
            unit_topology_edge_kind_slug(edge_kind),
            from_label,
            to_label
        ),
        from_node_id: from.node_id.clone(),
        to_node_id: to.node_id.clone(),
        edge_kind,
        directed,
        required,
        notes,
    })
}

fn push_unit_constraint(
    graph: &mut TopologyConstraintGraph,
    unit_id: &str,
    kind: TopologyConstraintKind,
    strength: TopologyConstraintStrength,
    subjects: &[&str],
    targets: &[&str],
    notes: Vec<String>,
) {
    let kind_slug = match kind {
        TopologyConstraintKind::MustTouch => "must_touch",
        TopologyConstraintKind::MustNotTouch => "must_not_touch",
        TopologyConstraintKind::AccessRequired => "access_required",
        TopologyConstraintKind::FrontageRequired => "frontage_required",
        TopologyConstraintKind::DaylightRequired => "daylight_required",
        TopologyConstraintKind::StackedWith => "stacked_with",
        TopologyConstraintKind::AvoidOverlapWith => "avoid_overlap_with",
        TopologyConstraintKind::PathToExitRequired => "path_to_exit_required",
        TopologyConstraintKind::ServiceReachRequired => "service_reach_required",
        TopologyConstraintKind::SameStackPreferred => "same_stack_preferred",
        TopologyConstraintKind::SameFloorRequired => "same_floor_required",
        TopologyConstraintKind::TransferAllowedOnlyIf => "transfer_allowed_only_if",
    };
    graph.constraints.push(TopologyConstraint {
        constraint_id: format!(
            "{}_constraint_{}_{}_{}",
            unit_id,
            kind_slug,
            subjects.join("_"),
            targets.join("_")
        ),
        scope: TopologyConstraintScope::Unit,
        constraint_kind: kind,
        strength,
        subject_refs: subjects.iter().map(|x| x.to_string()).collect(),
        target_refs: targets.iter().map(|x| x.to_string()).collect(),
        gate_condition: None,
        status: TopologyConstraintStatus::Deferred,
        evidence_refs: Vec::new(),
        notes,
    });
}

fn synthesize_unit_topology(
    unit_id: &str,
    unit_type: &str,
    input: &RoomSynthesisLayoutInput,
) -> UnitTopologyGraph {
    let wd_required = !matches!(
        input.residential_features.in_unit_wd.mode,
        InUnitWdMode::None
    );
    let mut nodes = Vec::<UnitTopologyNode>::new();
    nodes.push(make_unit_topology_node(
        unit_id,
        "foyer",
        UnitRoomSemanticKind::Foyer,
        UnitRoomPartition::Public,
        true,
        false,
        0,
        None,
        &["entry_buffer", "shallow_bay"],
        vec!["entry transition root".to_string()],
    ));
    nodes.push(make_unit_topology_node(
        unit_id,
        "living",
        UnitRoomSemanticKind::Living,
        UnitRoomPartition::Public,
        true,
        true,
        3,
        None,
        &["frontage_preferred", "shallow_bay"],
        vec![],
    ));
    nodes.push(make_unit_topology_node(
        unit_id,
        "dining",
        UnitRoomSemanticKind::Dining,
        UnitRoomPartition::Public,
        true,
        false,
        2,
        None,
        &["living_adjacent", "frontage_optional"],
        vec!["may inherit daylight through living adjacency".to_string()],
    ));
    nodes.push(make_unit_topology_node(
        unit_id,
        "kitchen",
        UnitRoomSemanticKind::Kitchen,
        UnitRoomPartition::Public,
        true,
        false,
        1,
        Some("wet_a"),
        &["wet_stack_preferred", "deep_bay"],
        vec![],
    ));
    nodes.push(make_unit_topology_node(
        unit_id,
        "bath_1",
        UnitRoomSemanticKind::Bath,
        if unit_type == "studio" {
            UnitRoomPartition::Service
        } else {
            UnitRoomPartition::Private
        },
        true,
        false,
        0,
        Some("wet_a"),
        &["wet_stack_required", "deep_bay"],
        vec![],
    ));
    nodes.push(make_unit_topology_node(
        unit_id,
        "closet_1",
        UnitRoomSemanticKind::Closet,
        UnitRoomPartition::Private,
        unit_type != "studio",
        false,
        0,
        None,
        &["interior_ok"],
        vec![],
    ));
    nodes.push(make_unit_topology_node(
        unit_id,
        "mechanical_closet_1",
        UnitRoomSemanticKind::MechanicalCloset,
        UnitRoomPartition::Service,
        true,
        false,
        0,
        Some("wet_a"),
        &["wet_stack_preferred", "beam_tolerant"],
        vec![],
    ));
    if wd_required && unit_type != "studio" {
        nodes.push(make_unit_topology_node(
            unit_id,
            "laundry_niche_1",
            UnitRoomSemanticKind::LaundryNiche,
            UnitRoomPartition::Service,
            true,
            false,
            0,
            Some("wet_a"),
            &["wet_stack_preferred", "interior_ok"],
            vec![],
        ));
    }
    if unit_type != "studio" {
        nodes.push(make_unit_topology_node(
            unit_id,
            "private_hall",
            UnitRoomSemanticKind::PrivateHall,
            UnitRoomPartition::Circulation,
            true,
            false,
            0,
            None,
            &["connector"],
            vec![],
        ));
        nodes.push(make_unit_topology_node(
            unit_id,
            "bedroom_1",
            UnitRoomSemanticKind::Bedroom,
            UnitRoomPartition::Private,
            true,
            true,
            2,
            None,
            &["frontage_preferred", "quiet_zone"],
            vec![],
        ));
    }
    if unit_type == "two_bedroom" || unit_type == "three_bedroom" {
        nodes.push(make_unit_topology_node(
            unit_id,
            "bedroom_2",
            UnitRoomSemanticKind::Bedroom,
            UnitRoomPartition::Private,
            true,
            true,
            2,
            None,
            &["frontage_preferred", "quiet_zone"],
            vec![],
        ));
        nodes.push(make_unit_topology_node(
            unit_id,
            "bath_2",
            UnitRoomSemanticKind::Bath,
            UnitRoomPartition::Service,
            true,
            false,
            0,
            Some("wet_a"),
            &["wet_stack_required", "deep_bay"],
            vec!["secondary bath inside service cluster".to_string()],
        ));
        nodes.push(make_unit_topology_node(
            unit_id,
            "closet_2",
            UnitRoomSemanticKind::Closet,
            UnitRoomPartition::Private,
            true,
            false,
            0,
            None,
            &["interior_ok"],
            vec![],
        ));
    }
    if unit_type == "three_bedroom" {
        nodes.push(make_unit_topology_node(
            unit_id,
            "bedroom_3",
            UnitRoomSemanticKind::Bedroom,
            UnitRoomPartition::Private,
            true,
            true,
            2,
            None,
            &["frontage_preferred", "quiet_zone"],
            vec!["third bedroom may trigger compact fallback during embedding".to_string()],
        ));
    }

    let mut graph = UnitTopologyGraph {
        graph_id: format!("{}_unit_topology", unit_id),
        unit_type: unit_type.to_string(),
        fallback_mode: None,
        nodes,
        edges: Vec::new(),
        contract_graph: TopologyConstraintGraph::empty(
            format!("{}_unit_contract", unit_id),
            "unit",
        ),
        access_chains: Vec::new(),
        daylight_ownerships: Vec::new(),
        structure_compatibility: Vec::new(),
        wet_zone_clusters: Vec::new(),
        notes: vec!["topology synthesized before geometry embedding".to_string()],
    };

    for (from_label, to_label, kind, required, directed, notes) in [
        (
            "foyer",
            "living",
            UnitTopologyEdgeKind::EntrySequence,
            true,
            false,
            vec!["entry reaches public living zone".to_string()],
        ),
        (
            "foyer",
            "kitchen",
            UnitTopologyEdgeKind::Access,
            true,
            false,
            vec![],
        ),
        (
            "living",
            "dining",
            UnitTopologyEdgeKind::LivingChain,
            true,
            false,
            vec![],
        ),
        (
            "dining",
            "kitchen",
            UnitTopologyEdgeKind::LivingChain,
            true,
            false,
            vec![],
        ),
        (
            "living",
            "private_hall",
            UnitTopologyEdgeKind::PublicPrivateTransition,
            unit_type != "studio",
            false,
            vec![],
        ),
        (
            "private_hall",
            "bedroom_1",
            UnitTopologyEdgeKind::Access,
            unit_type != "studio",
            false,
            vec![],
        ),
        (
            "private_hall",
            "bath_1",
            UnitTopologyEdgeKind::Access,
            unit_type != "studio",
            false,
            vec![],
        ),
        (
            "bedroom_1",
            "closet_1",
            UnitTopologyEdgeKind::Access,
            unit_type != "studio",
            false,
            vec![],
        ),
        (
            "bath_1",
            "kitchen",
            UnitTopologyEdgeKind::WetAdjacency,
            true,
            false,
            vec![],
        ),
        (
            "laundry_niche_1",
            "kitchen",
            UnitTopologyEdgeKind::WetAdjacency,
            wd_required && unit_type != "studio",
            false,
            vec![],
        ),
        (
            "laundry_niche_1",
            "mechanical_closet_1",
            UnitTopologyEdgeKind::WetAdjacency,
            wd_required && unit_type != "studio",
            false,
            vec![],
        ),
        (
            "mechanical_closet_1",
            "bath_1",
            UnitTopologyEdgeKind::StructureCompatibility,
            true,
            false,
            vec![],
        ),
        (
            "private_hall",
            "bedroom_2",
            UnitTopologyEdgeKind::Access,
            unit_type == "two_bedroom" || unit_type == "three_bedroom",
            false,
            vec![],
        ),
        (
            "private_hall",
            "bath_2",
            UnitTopologyEdgeKind::Access,
            unit_type == "two_bedroom" || unit_type == "three_bedroom",
            false,
            vec![],
        ),
        (
            "bedroom_2",
            "closet_2",
            UnitTopologyEdgeKind::Access,
            unit_type == "two_bedroom" || unit_type == "three_bedroom",
            false,
            vec![],
        ),
        (
            "bath_2",
            "kitchen",
            UnitTopologyEdgeKind::WetAdjacency,
            unit_type == "two_bedroom" || unit_type == "three_bedroom",
            false,
            vec![],
        ),
        (
            "private_hall",
            "bedroom_3",
            UnitTopologyEdgeKind::Access,
            unit_type == "three_bedroom",
            false,
            vec![],
        ),
    ] {
        if required {
            if let Some(edge) = make_unit_topology_edge(
                unit_id, &graph, from_label, to_label, kind, true, directed, notes,
            ) {
                graph.edges.push(edge);
            }
        }
    }

    graph
}

fn unit_topology_has_access(
    topology: &UnitTopologyGraph,
    from_label: &str,
    to_label: &str,
) -> bool {
    let from_id = unit_topology_node_by_label(topology, from_label).map(|x| x.node_id.clone());
    let to_id = unit_topology_node_by_label(topology, to_label).map(|x| x.node_id.clone());
    match (from_id, to_id) {
        (Some(from_id), Some(to_id)) => topology.edges.iter().any(|edge| {
            matches!(
                edge.edge_kind,
                UnitTopologyEdgeKind::Access
                    | UnitTopologyEdgeKind::EntrySequence
                    | UnitTopologyEdgeKind::LivingChain
                    | UnitTopologyEdgeKind::PublicPrivateTransition
            ) && ((edge.from_node_id == from_id && edge.to_node_id == to_id)
                || (!edge.directed && edge.from_node_id == to_id && edge.to_node_id == from_id))
        }),
        _ => false,
    }
}

fn evaluate_synthesized_unit_topology(
    topology: &mut UnitTopologyGraph,
    input: &RoomSynthesisLayoutInput,
) -> UnitTopologyValidation {
    if topology.access_chains.is_empty() {
        let mut chain = vec![
            "foyer".to_string(),
            "living".to_string(),
            "dining".to_string(),
        ];
        if topology.unit_type != "studio" {
            chain.push("private_hall".to_string());
            chain.push("bedroom_1".to_string());
        }
        topology.access_chains.push(RoomAccessChain {
            chain_id: format!("{}_access_chain_main", topology.graph_id),
            room_node_ids: chain
                .iter()
                .filter_map(|label| unit_topology_node_by_label(topology, label))
                .map(|node| node.node_id.clone())
                .collect(),
            direct_bedroom_exposure: false,
            notes: vec!["corridor -> foyer -> public zone -> private connector".to_string()],
        });
    }

    if topology.wet_zone_clusters.is_empty() {
        let wet_members = topology
            .nodes
            .iter()
            .filter(|node| node.wet_cluster_id.as_deref() == Some("wet_a"))
            .map(|node| node.node_id.clone())
            .collect::<Vec<_>>();
        if !wet_members.is_empty() {
            topology.wet_zone_clusters.push(WetZoneCluster {
                cluster_id: format!("{}_wet_a", topology.graph_id),
                member_node_ids: wet_members,
                legal_secondary_cluster: false,
                compactness_score: 1.0,
                fragmented: false,
                notes: vec!["primary wet/service cluster".to_string()],
            });
        }
    }

    if topology.daylight_ownerships.is_empty() {
        for node in &topology.nodes {
            topology.daylight_ownerships.push(RoomDaylightOwnership {
                room_node_id: node.node_id.clone(),
                ownership_mode: match node.semantic_kind {
                    UnitRoomSemanticKind::Living | UnitRoomSemanticKind::Bedroom => {
                        "direct_frontage".to_string()
                    }
                    UnitRoomSemanticKind::Dining => "inherited_from_living".to_string(),
                    _ => "not_required".to_string(),
                },
                inherited_from_room_node_id: if node.semantic_kind == UnitRoomSemanticKind::Dining {
                    unit_topology_node_by_label(topology, "living").map(|x| x.node_id.clone())
                } else {
                    None
                },
                satisfied: !node.daylight_required
                    || matches!(
                        node.semantic_kind,
                        UnitRoomSemanticKind::Living
                            | UnitRoomSemanticKind::Bedroom
                            | UnitRoomSemanticKind::Dining
                    ),
                frontage_priority: node.frontage_priority,
                notes: Vec::new(),
            });
        }
    }

    if topology.structure_compatibility.is_empty() {
        for node in &topology.nodes {
            topology
                .structure_compatibility
                .push(RoomStructureCompatibility {
                    room_node_id: node.node_id.clone(),
                    frontage_fit: matches!(
                        node.semantic_kind,
                        UnitRoomSemanticKind::Living
                            | UnitRoomSemanticKind::Dining
                            | UnitRoomSemanticKind::Bedroom
                    ),
                    wet_stack_fit: node.wet_cluster_id.is_some(),
                    beam_column_tolerance: if node.wet_cluster_id.is_some() {
                        "high".to_string()
                    } else if matches!(
                        node.semantic_kind,
                        UnitRoomSemanticKind::Living | UnitRoomSemanticKind::Bedroom
                    ) {
                        "low".to_string()
                    } else {
                        "medium".to_string()
                    },
                    bay_suitability: if node.wet_cluster_id.is_some() {
                        "deep_service".to_string()
                    } else if matches!(
                        node.semantic_kind,
                        UnitRoomSemanticKind::Living | UnitRoomSemanticKind::Bedroom
                    ) {
                        "frontage_shallow".to_string()
                    } else {
                        "flex".to_string()
                    },
                    overall_fit: true,
                    notes: node.structure_profile.clone(),
                });
        }
    }

    if topology.contract_graph.constraints.is_empty() {
        for label in ["living", "bedroom_1", "bedroom_2", "bedroom_3"] {
            if unit_topology_has_label(topology, label) {
                push_unit_constraint(
                    &mut topology.contract_graph,
                    topology.graph_id.as_str(),
                    TopologyConstraintKind::DaylightRequired,
                    TopologyConstraintStrength::Hard,
                    &[label],
                    &["frontage"],
                    vec![],
                );
                push_unit_constraint(
                    &mut topology.contract_graph,
                    topology.graph_id.as_str(),
                    TopologyConstraintKind::FrontageRequired,
                    TopologyConstraintStrength::Hard,
                    &[label],
                    &["frontage"],
                    vec![],
                );
            }
        }
        for label in ["bedroom_1", "bedroom_2", "bedroom_3"] {
            if unit_topology_has_label(topology, label) {
                push_unit_constraint(
                    &mut topology.contract_graph,
                    topology.graph_id.as_str(),
                    TopologyConstraintKind::MustNotTouch,
                    TopologyConstraintStrength::Hard,
                    &["foyer"],
                    &[label],
                    vec!["bedrooms should not open directly to entry".to_string()],
                );
                push_unit_constraint(
                    &mut topology.contract_graph,
                    topology.graph_id.as_str(),
                    TopologyConstraintKind::PathToExitRequired,
                    TopologyConstraintStrength::Hard,
                    &[label],
                    &["foyer"],
                    vec![],
                );
            }
        }
        for (a, b) in [
            ("living", "dining"),
            ("dining", "kitchen"),
            ("foyer", "living"),
        ] {
            if unit_topology_has_label(topology, a) && unit_topology_has_label(topology, b) {
                push_unit_constraint(
                    &mut topology.contract_graph,
                    topology.graph_id.as_str(),
                    TopologyConstraintKind::AccessRequired,
                    TopologyConstraintStrength::Hard,
                    &[a],
                    &[b],
                    vec![],
                );
            }
        }
        for label in [
            "bath_1",
            "bath_2",
            "kitchen",
            "laundry_niche_1",
            "mechanical_closet_1",
        ] {
            if unit_topology_has_label(topology, label) {
                push_unit_constraint(
                    &mut topology.contract_graph,
                    topology.graph_id.as_str(),
                    TopologyConstraintKind::ServiceReachRequired,
                    TopologyConstraintStrength::Hard,
                    &[label],
                    &["wet_a"],
                    vec![],
                );
            }
        }
    }

    let living_chain_pass = unit_topology_has_access(topology, "living", "dining")
        && unit_topology_has_access(topology, "dining", "kitchen");
    let entry_sequence_pass = unit_topology_has_access(topology, "foyer", "living");
    let privacy_pass = !["bedroom_1", "bedroom_2", "bedroom_3"]
        .iter()
        .any(|label| unit_topology_has_access(topology, "foyer", label));
    let bath_access_pass = if unit_topology_has_label(topology, "private_hall") {
        ["bath_1", "bath_2"]
            .iter()
            .filter(|label| unit_topology_has_label(topology, label))
            .all(|label| unit_topology_has_access(topology, "private_hall", label))
    } else {
        unit_topology_has_access(topology, "foyer", "bath_1")
    };
    let partition_pass = topology
        .nodes
        .iter()
        .any(|n| n.partition == UnitRoomPartition::Public)
        && topology
            .nodes
            .iter()
            .any(|n| n.partition == UnitRoomPartition::Service)
        && (!topology
            .nodes
            .iter()
            .any(|n| n.semantic_kind == UnitRoomSemanticKind::Bedroom)
            || topology
                .nodes
                .iter()
                .any(|n| n.partition == UnitRoomPartition::Private));
    let wet_zone_cluster_pass = topology
        .wet_zone_clusters
        .iter()
        .all(|cluster| !cluster.fragmented);
    let daylight_pass = topology
        .daylight_ownerships
        .iter()
        .all(|ownership| ownership.satisfied);
    let structure_pass = topology
        .structure_compatibility
        .iter()
        .all(|fit| fit.overall_fit);
    let internal_circulation_pass = topology.edges.len() as u32
        <= topology.nodes.len() as u32
            + input.room_topology_controls.max_internal_circulation_turns;
    let direct_bedroom_exposure = !privacy_pass;

    let topology_snapshot = topology.clone();
    for constraint in &mut topology.contract_graph.constraints {
        constraint.status = match constraint.constraint_kind {
            TopologyConstraintKind::MustNotTouch => {
                if constraint.subject_refs.iter().any(|a| {
                    constraint
                        .target_refs
                        .iter()
                        .any(|b| unit_topology_has_access(&topology_snapshot, a, b))
                }) {
                    TopologyConstraintStatus::Violated
                } else {
                    TopologyConstraintStatus::Satisfied
                }
            }
            TopologyConstraintKind::AccessRequired => {
                if constraint.subject_refs.iter().all(|a| {
                    constraint
                        .target_refs
                        .iter()
                        .all(|b| unit_topology_has_access(&topology_snapshot, a, b))
                }) {
                    TopologyConstraintStatus::Satisfied
                } else {
                    TopologyConstraintStatus::Violated
                }
            }
            TopologyConstraintKind::DaylightRequired | TopologyConstraintKind::FrontageRequired => {
                if constraint.subject_refs.iter().all(|label| {
                    unit_topology_node_by_label(&topology_snapshot, label)
                        .and_then(|node| {
                            topology_snapshot
                                .daylight_ownerships
                                .iter()
                                .find(|ownership| ownership.room_node_id == node.node_id)
                        })
                        .map(|ownership| ownership.satisfied)
                        .unwrap_or(false)
                }) {
                    TopologyConstraintStatus::Satisfied
                } else {
                    TopologyConstraintStatus::Violated
                }
            }
            TopologyConstraintKind::ServiceReachRequired => {
                if constraint.subject_refs.iter().all(|label| {
                    unit_topology_node_by_label(&topology_snapshot, label)
                        .and_then(|node| node.wet_cluster_id.clone())
                        .is_some()
                }) {
                    TopologyConstraintStatus::Satisfied
                } else {
                    TopologyConstraintStatus::Violated
                }
            }
            TopologyConstraintKind::PathToExitRequired => {
                if constraint.subject_refs.iter().all(|label| {
                    topology_snapshot.access_chains.iter().any(|chain| {
                        unit_topology_node_by_label(&topology_snapshot, label)
                            .map(|node| chain.room_node_ids.iter().any(|id| id == &node.node_id))
                            .unwrap_or(false)
                    })
                }) {
                    TopologyConstraintStatus::Satisfied
                } else {
                    TopologyConstraintStatus::Violated
                }
            }
            TopologyConstraintKind::SameStackPreferred
            | TopologyConstraintKind::SameFloorRequired
            | TopologyConstraintKind::StackedWith => TopologyConstraintStatus::Satisfied,
            TopologyConstraintKind::AvoidOverlapWith
            | TopologyConstraintKind::TransferAllowedOnlyIf
            | TopologyConstraintKind::MustTouch => TopologyConstraintStatus::Deferred,
        };
    }

    let hard_violation_count = topology
        .contract_graph
        .constraints
        .iter()
        .filter(|constraint| {
            constraint.strength == TopologyConstraintStrength::Hard
                && constraint.status == TopologyConstraintStatus::Violated
        })
        .count();
    let soft_violation_count = topology
        .contract_graph
        .constraints
        .iter()
        .filter(|constraint| {
            constraint.strength == TopologyConstraintStrength::Soft
                && constraint.status == TopologyConstraintStatus::Violated
        })
        .count();

    UnitTopologyValidation {
        overall_status: if hard_violation_count == 0 {
            "pass".to_string()
        } else {
            "warn".to_string()
        },
        living_chain_pass,
        privacy_pass,
        bath_access_pass,
        entry_sequence_pass,
        partition_pass,
        wet_zone_cluster_pass,
        daylight_pass,
        structure_pass,
        internal_circulation_pass,
        direct_bedroom_exposure,
        hard_violation_count,
        soft_violation_count,
        violated_constraint_ids: topology
            .contract_graph
            .constraints
            .iter()
            .filter(|constraint| constraint.status == TopologyConstraintStatus::Violated)
            .map(|constraint| constraint.constraint_id.clone())
            .collect(),
        notes: vec!["topology evaluated before geometry embedding".to_string()],
    }
}

fn push_slot_from_topology(
    slots: &mut Vec<LocalRoomSlot>,
    topology: &UnitTopologyGraph,
    label: &str,
    u0: f64,
    u1: f64,
    v0: f64,
    v1: f64,
    wet_wall_cluster_id: Option<&str>,
    notes: Vec<String>,
) {
    if let Some(node) = unit_topology_node_by_label(topology, label) {
        slots.push(LocalRoomSlot {
            topology_node_id: node.node_id.clone(),
            room_kind: label.to_string(),
            semantic_room_kind: node.semantic_kind,
            partition: node.partition,
            u0,
            u1,
            v0,
            v1,
            wet_wall_cluster_id: wet_wall_cluster_id.map(|x| x.to_string()),
            notes,
        });
    }
}

fn edge_specs_from_unit_topology(
    topology: &UnitTopologyGraph,
) -> Vec<(String, String, String, bool)> {
    topology
        .edges
        .iter()
        .filter_map(|edge| {
            let from_label = unit_topology_label_by_node_id(topology, &edge.from_node_id)?;
            let to_label = unit_topology_label_by_node_id(topology, &edge.to_node_id)?;
            Some((
                from_label,
                to_label,
                unit_topology_edge_kind_slug(edge.edge_kind).to_string(),
                edge.required,
            ))
        })
        .collect()
}

fn template_room_kinds(unit_type: &str) -> Vec<&'static str> {
    match unit_type {
        "studio" => vec![
            "foyer",
            "bath_1",
            "kitchen",
            "living",
            "dining",
            "closet_1",
            "mechanical_closet_1",
        ],
        "one_bedroom" => vec![
            "foyer",
            "private_hall",
            "bath_1",
            "kitchen",
            "living",
            "dining",
            "bedroom_1",
            "closet_1",
            "laundry_niche_1",
            "mechanical_closet_1",
        ],
        "two_bedroom" => vec![
            "foyer",
            "private_hall",
            "bath_1",
            "bath_2",
            "kitchen",
            "living",
            "dining",
            "bedroom_1",
            "bedroom_2",
            "closet_1",
            "closet_2",
            "laundry_niche_1",
            "mechanical_closet_1",
        ],
        _ => vec![
            "foyer",
            "private_hall",
            "bath_1",
            "bath_2",
            "kitchen",
            "living",
            "dining",
            "bedroom_1",
            "bedroom_2",
            "bedroom_3",
            "closet_1",
            "closet_2",
            "laundry_niche_1",
            "mechanical_closet_1",
        ],
    }
}

fn build_local_slots(
    unit_type: &str,
    frame: &UnitFrame,
    input: &RoomSynthesisLayoutInput,
) -> (
    Vec<LocalRoomSlot>,
    Vec<(String, String, String, bool)>,
    String,
    Vec<String>,
) {
    let topology = synthesize_unit_topology(&format!("legacy_{}", unit_type), unit_type, input);
    let (slots, edge_specs, entry_room_kind, manual_flags, _compact_fallback_used) =
        build_local_slots_from_topology(&topology, frame, input);
    (slots, edge_specs, entry_room_kind, manual_flags)
}

fn build_local_slots_from_topology(
    topology: &UnitTopologyGraph,
    frame: &UnitFrame,
    input: &RoomSynthesisLayoutInput,
) -> (
    Vec<LocalRoomSlot>,
    Vec<(String, String, String, bool)>,
    String,
    Vec<String>,
    bool,
) {
    let mut slots = Vec::<LocalRoomSlot>::new();
    let mut manual_flags = Vec::<String>::new();
    let mut compact_fallback_used = false;

    let unit_type = topology.unit_type.as_str();
    let w = frame.width_ft.max(8.0);
    let d = frame.depth_ft.max(12.0);
    let entry_d = clamp(
        input
            .dwelling_unit_room_solver_controls
            .entry_strip_depth_ft,
        4.0,
        d * 0.22,
    );
    let wet_end = clamp(
        entry_d
            + input
                .dwelling_unit_room_solver_controls
                .wet_wall_strip_depth_ft,
        entry_d + 4.0,
        d * 0.42,
    );
    let hall_d = clamp(
        input.dwelling_unit_room_solver_controls.hall_min_width_ft,
        3.0,
        (d - wet_end) * 0.24,
    );

    push_slot_from_topology(
        &mut slots,
        topology,
        "foyer",
        0.0,
        w,
        0.0,
        entry_d,
        None,
        vec![],
    );

    let mut service_cursor = 0.0;
    let service_labels = [
        ("bath_1", clamp(w * 0.20, 6.0, 8.0)),
        ("bath_2", clamp(w * 0.16, 5.5, 7.5)),
        ("kitchen", clamp(w * 0.26, 8.0, 12.0)),
        ("laundry_niche_1", clamp(w * 0.12, 3.5, 5.5)),
        ("mechanical_closet_1", clamp(w * 0.10, 2.5, 4.0)),
    ];
    for (label, pref_w) in service_labels {
        if unit_topology_has_label(topology, label) {
            let remaining = (w - service_cursor).max(0.0);
            if remaining <= 1.5 {
                compact_fallback_used = true;
                manual_flags.push(format!("service_strip_overflow_{}", label));
                continue;
            }
            let actual_w = pref_w.min(remaining);
            push_slot_from_topology(
                &mut slots,
                topology,
                label,
                service_cursor,
                service_cursor + actual_w,
                entry_d,
                wet_end,
                Some("wet_a"),
                Vec::new(),
            );
            service_cursor += actual_w;
        }
    }
    if unit_topology_has_label(topology, "closet_1")
        && unit_type == "studio"
        && service_cursor < w - 2.0
    {
        push_slot_from_topology(
            &mut slots,
            topology,
            "closet_1",
            service_cursor,
            w,
            entry_d,
            wet_end,
            None,
            vec![],
        );
    }

    if unit_type == "studio" {
        let public_split = wet_end + (d - wet_end) * 0.36;
        push_slot_from_topology(
            &mut slots,
            topology,
            "dining",
            0.0,
            w,
            wet_end,
            public_split,
            None,
            vec![],
        );
        push_slot_from_topology(
            &mut slots,
            topology,
            "living",
            0.0,
            w,
            public_split,
            d,
            None,
            vec![],
        );
    } else {
        let hall_v0 = wet_end;
        let hall_v1 = (wet_end + hall_d).min(d - 4.0);
        push_slot_from_topology(
            &mut slots,
            topology,
            "private_hall",
            0.0,
            w,
            hall_v0,
            hall_v1,
            None,
            vec![],
        );

        let front_v0 = hall_v1;
        if front_v0 >= d - 3.0 {
            compact_fallback_used = true;
            manual_flags.push("shallow_unit_depth_for_room_chain".to_string());
        }
        let front_depth = (d - front_v0).max(4.0);
        let public_split_v = front_v0 + front_depth * 0.38;

        if unit_type == "one_bedroom" {
            let bed_w = clamp(
                w * 0.38,
                input
                    .dwelling_unit_room_solver_controls
                    .minimum_bedroom_width_ft,
                w * 0.44,
            );
            let public_u0 = bed_w;
            if w - public_u0
                < input
                    .dwelling_unit_room_solver_controls
                    .minimum_living_frontage_ft
            {
                compact_fallback_used = true;
                manual_flags.push("compact_one_bedroom_frontage".to_string());
            }
            if unit_topology_has_label(topology, "closet_1") {
                let closet_v1 = front_v0 + front_depth * 0.18;
                push_slot_from_topology(
                    &mut slots,
                    topology,
                    "closet_1",
                    0.0,
                    bed_w,
                    front_v0,
                    closet_v1,
                    None,
                    vec![],
                );
                push_slot_from_topology(
                    &mut slots,
                    topology,
                    "bedroom_1",
                    0.0,
                    bed_w,
                    closet_v1,
                    d,
                    None,
                    vec![],
                );
            } else {
                push_slot_from_topology(
                    &mut slots,
                    topology,
                    "bedroom_1",
                    0.0,
                    bed_w,
                    front_v0,
                    d,
                    None,
                    vec![],
                );
            }
            push_slot_from_topology(
                &mut slots,
                topology,
                "dining",
                public_u0,
                w,
                front_v0,
                public_split_v,
                None,
                vec![],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "living",
                public_u0,
                w,
                public_split_v,
                d,
                None,
                vec![],
            );
        } else if unit_type == "two_bedroom" {
            let bed_w = clamp(
                w * 0.24,
                input
                    .dwelling_unit_room_solver_controls
                    .minimum_bedroom_width_ft,
                w * 0.29,
            );
            let public_u0 = bed_w;
            let public_u1 = (w - bed_w).max(public_u0 + 4.0);
            if public_u1 - public_u0
                < input
                    .dwelling_unit_room_solver_controls
                    .minimum_living_frontage_ft
            {
                compact_fallback_used = true;
                manual_flags.push("compact_two_bedroom_frontage".to_string());
            }
            push_slot_from_topology(
                &mut slots,
                topology,
                "bedroom_1",
                0.0,
                bed_w,
                front_v0,
                d,
                None,
                vec![],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "bedroom_2",
                w - bed_w,
                w,
                front_v0,
                d,
                None,
                vec![],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "closet_1",
                0.0,
                bed_w,
                front_v0,
                front_v0 + front_depth * 0.16,
                None,
                vec![],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "closet_2",
                w - bed_w,
                w,
                front_v0,
                front_v0 + front_depth * 0.16,
                None,
                vec![],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "dining",
                public_u0,
                public_u1,
                front_v0,
                public_split_v,
                None,
                vec![],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "living",
                public_u0,
                public_u1,
                public_split_v,
                d,
                None,
                vec![],
            );
        } else {
            compact_fallback_used = true;
            manual_flags.push("compact_three_bedroom_frontage".to_string());
            let bed_w = clamp(
                w * 0.22,
                input
                    .dwelling_unit_room_solver_controls
                    .minimum_bedroom_width_ft,
                w * 0.25,
            );
            let mid_u0 = bed_w;
            let mid_u1 = (w - bed_w).max(mid_u0 + 4.0);
            let middle_split_a = front_v0 + front_depth * 0.24;
            let middle_split_b = front_v0 + front_depth * 0.62;
            push_slot_from_topology(
                &mut slots,
                topology,
                "bedroom_1",
                0.0,
                bed_w,
                front_v0,
                d,
                None,
                vec![],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "bedroom_2",
                w - bed_w,
                w,
                front_v0,
                d,
                None,
                vec![],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "dining",
                mid_u0,
                mid_u1,
                front_v0,
                middle_split_a,
                None,
                vec!["compact dining band".to_string()],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "living",
                mid_u0,
                mid_u1,
                middle_split_a,
                middle_split_b,
                None,
                vec!["compact living band".to_string()],
            );
            push_slot_from_topology(
                &mut slots,
                topology,
                "bedroom_3",
                mid_u0,
                mid_u1,
                middle_split_b,
                d,
                None,
                vec!["third bedroom uses degraded middle bay".to_string()],
            );
        }
    }

    if d < input.volumetric_room_controls.default_clear_height_ft * 1.8 {
        compact_fallback_used = true;
        manual_flags.push("shallow_unit_depth_for_room_chain".to_string());
    }

    (
        slots,
        edge_specs_from_unit_topology(topology),
        "foyer".to_string(),
        manual_flags,
        compact_fallback_used,
    )
}

fn room_from_slot(
    unit_id: &str,
    slot_index: usize,
    slot: &LocalRoomSlot,
    frame: &UnitFrame,
    input: &RoomSynthesisLayoutInput,
    room_counter: &mut usize,
) -> RoomPlacement {
    let rect = frame.map_local_rect(slot.u0, slot.u1, slot.v0, slot.v1);
    let room_id = format!("{}_r{:02}_{}", unit_id, *room_counter, slot.room_kind);
    *room_counter += 1;
    let mut opening_reserves = Vec::<RoomOpeningReserve>::new();
    let mut fixture_reserves = Vec::<RoomFixtureReserve>::new();

    if slot.semantic_room_kind == UnitRoomSemanticKind::Foyer {
        opening_reserves.push(RoomOpeningReserve {
            opening_id: format!("{}_entry_door", room_id),
            opening_kind: "entry_door".to_string(),
            polygon: reserve_on_side(
                rect,
                frame.entry_side,
                input.opening_fixture_shaft_mep_controls.door_clear_width_ft,
                input
                    .opening_fixture_shaft_mep_controls
                    .entry_door_depth_reserve_ft,
            ),
            clear_width_ft: input.opening_fixture_shaft_mep_controls.door_clear_width_ft,
            associated_room_id: room_id.clone(),
        });
    }

    if input
        .opening_fixture_shaft_mep_controls
        .require_window_for_habitable_rooms
        && matches!(
            slot.semantic_room_kind,
            UnitRoomSemanticKind::Living
                | UnitRoomSemanticKind::Bedroom
                | UnitRoomSemanticKind::Dining
        )
    {
        opening_reserves.push(RoomOpeningReserve {
            opening_id: format!("{}_window", room_id),
            opening_kind: "window".to_string(),
            polygon: reserve_on_side(
                rect,
                frame.frontage_side(),
                input
                    .opening_fixture_shaft_mep_controls
                    .window_min_habitable_width_ft,
                1.5,
            ),
            clear_width_ft: input
                .opening_fixture_shaft_mep_controls
                .window_min_habitable_width_ft,
            associated_room_id: room_id.clone(),
        });
    }

    if slot.room_kind.starts_with("bath") {
        fixture_reserves.extend(reserve_fixture_strip(
            rect,
            3,
            frame.entry_side,
            input
                .opening_fixture_shaft_mep_controls
                .bath_fixture_clearance_ft
                .min(rect.height())
                .min(rect.width())
                * 0.4,
            "bath",
            &room_id,
        ));
    }
    if slot.room_kind == "kitchen" {
        fixture_reserves.extend(reserve_fixture_strip(
            rect,
            3,
            frame.entry_side,
            input
                .opening_fixture_shaft_mep_controls
                .kitchen_fixture_clearance_ft
                .min(rect.height())
                .min(rect.width())
                * 0.4,
            "kitchen",
            &room_id,
        ));
    }

    RoomPlacement {
        room_id,
        topology_node_id: Some(slot.topology_node_id.clone()),
        room_kind: slot.room_kind.clone(),
        semantic_room_kind: unit_room_semantic_kind_slug(slot.semantic_room_kind).to_string(),
        partition_kind: unit_room_partition_slug(slot.partition).to_string(),
        polygon: rect.to_polygon(),
        area_sf: rect.area(),
        z_min_ft: 0.0,
        z_max_ft: input.volumetric_room_controls.default_clear_height_ft,
        adjacency: Vec::new(),
        wet_wall_cluster_id: slot.wet_wall_cluster_id.clone(),
        daylight_ownership: None,
        structure_compatibility: None,
        opening_reserves,
        fixture_reserves,
        notes: {
            let mut n = slot.notes.clone();
            if rect.width() <= 1.0 || rect.height() <= 1.0 {
                n.push("degenerate_room_rect".to_string());
            }
            if slot_index == 0 {
                n.push("room_sequence_seed".to_string());
            }
            n
        },
    }
}

fn room_id_by_kind(rooms: &[RoomPlacement], kind: &str) -> Option<String> {
    rooms
        .iter()
        .find(|r| r.room_kind == kind)
        .map(|r| r.room_id.clone())
}

fn finalize_edges_and_adjacency(
    rooms: &mut [RoomPlacement],
    edge_specs: &[(String, String, String, bool)],
) -> Vec<RoomGraphEdge> {
    let mut out = Vec::<RoomGraphEdge>::new();
    for (from_kind, to_kind, edge_kind, required) in edge_specs {
        if let (Some(from_id), Some(to_id)) = (
            room_id_by_kind(rooms, from_kind),
            room_id_by_kind(rooms, to_kind),
        ) {
            out.push(RoomGraphEdge {
                from_room_id: from_id.clone(),
                to_room_id: to_id.clone(),
                edge_kind: edge_kind.clone(),
                required: *required,
            });
        }
    }
    for edge in &out {
        if let Some(r) = rooms.iter_mut().find(|r| r.room_id == edge.from_room_id) {
            if !r.adjacency.iter().any(|x| x == &edge.to_room_id) {
                r.adjacency.push(edge.to_room_id.clone());
            }
        }
        if let Some(r) = rooms.iter_mut().find(|r| r.room_id == edge.to_room_id) {
            if !r.adjacency.iter().any(|x| x == &edge.from_room_id) {
                r.adjacency.push(edge.from_room_id.clone());
            }
        }
    }
    out
}

fn exact_room_non_overlap_repair(
    layout: &mut UnitRoomLayout,
    input: &RoomSynthesisLayoutInput,
) -> (usize, f64) {
    let mut pair_count = 0usize;
    let mut area_total = 0.0;
    for _round in 0..input.room_exact_non_overlap_controls.max_repair_rounds {
        let mut any = false;
        for i in 0..layout.rooms.len() {
            for j in (i + 1)..layout.rooms.len() {
                let a = bounding_rect(&layout.rooms[i].polygon);
                let b = bounding_rect(&layout.rooms[j].polygon);
                let inter = rect_intersection_area(a, b);
                if inter
                    > input
                        .room_exact_non_overlap_controls
                        .pairwise_overlap_tolerance_sf
                {
                    pair_count += 1;
                    area_total += inter;
                    any = true;
                    if input.room_exact_non_overlap_controls.repair_mode == "trim_then_shift" {
                        let shrink = inter.sqrt() * 0.55;
                        let mut bb = b;
                        if bb.width() >= bb.height() {
                            bb.min_x = (bb.min_x + shrink).min(bb.max_x - 0.2);
                        } else {
                            bb.min_y = (bb.min_y + shrink).min(bb.max_y - 0.2);
                        }
                        layout.rooms[j].polygon = bb.to_polygon();
                        layout.rooms[j].area_sf = bb.area();
                        layout.rooms[j]
                            .notes
                            .push("trim_then_shift_overlap_repair".to_string());
                    } else if input.room_exact_non_overlap_controls.repair_mode == "priority_shrink"
                    {
                        let mut bb = b;
                        bb.max_x = (bb.max_x - 0.25).max(bb.min_x + 0.2);
                        layout.rooms[j].polygon = bb.to_polygon();
                        layout.rooms[j].area_sf = bb.area();
                        layout.rooms[j]
                            .notes
                            .push("priority_shrink_overlap_repair".to_string());
                    }
                }
            }
        }
        if !any {
            break;
        }
    }
    let mut remaining_pairs = 0usize;
    let mut remaining_area = 0.0;
    for i in 0..layout.rooms.len() {
        for j in (i + 1)..layout.rooms.len() {
            let a = bounding_rect(&layout.rooms[i].polygon);
            let b = bounding_rect(&layout.rooms[j].polygon);
            let inter = rect_intersection_area(a, b);
            if inter
                > input
                    .room_exact_non_overlap_controls
                    .pairwise_overlap_tolerance_sf
            {
                remaining_pairs += 1;
                remaining_area += inter;
            }
        }
    }
    layout.exact_non_overlap_pass = remaining_pairs == 0;
    if remaining_pairs > 0 {
        layout
            .manual_review_flags
            .push("remaining_room_overlap".to_string());
    }
    (remaining_pairs, remaining_area)
}

fn room_program_coverage_ratio(layout: &UnitRoomLayout) -> f64 {
    let required = template_room_kinds(&layout.unit_type);
    if required.is_empty() {
        return 1.0;
    }
    let hits = required
        .iter()
        .filter(|kind| layout.rooms.iter().any(|r| &r.room_kind == *kind))
        .count();
    hits as f64 / required.len() as f64
}

fn privacy_graph_pass(layout: &UnitRoomLayout) -> bool {
    layout.topology_validation.privacy_pass
}

fn bath_adjacency_pass(layout: &UnitRoomLayout, input: &RoomSynthesisLayoutInput) -> bool {
    let _ = input;
    layout.topology_validation.bath_access_pass
}

fn living_chain_pass(layout: &UnitRoomLayout) -> bool {
    layout.topology_validation.living_chain_pass
}

fn entry_sequence_pass(layout: &UnitRoomLayout) -> bool {
    layout.topology_validation.entry_sequence_pass
}

fn internal_circulation_pass(layout: &UnitRoomLayout, input: &RoomSynthesisLayoutInput) -> bool {
    let _ = input;
    layout.topology_validation.internal_circulation_pass
}

fn build_unit_room_layout(
    floor: &FloorOutput,
    space: &SpacePlacement,
    unit_index: usize,
    input: &RoomSynthesisLayoutInput,
) -> UnitRoomLayout {
    let unit_id = format!("L{:02}_U{:03}", floor.level_index, unit_index);
    let unit_type = infer_unit_type(space);
    let corridors = corridor_rects_for_floor(floor);
    let entry_side = detect_entry_side(space.rect, &corridors);
    let frame = UnitFrame::new(space.rect, entry_side);

    let mut synthesized_topology = synthesize_unit_topology(&unit_id, &unit_type, input);
    let topology_validation = evaluate_synthesized_unit_topology(&mut synthesized_topology, input);
    let (slots, edge_specs, entry_room_kind, mut manual_flags, compact_fallback_used) =
        build_local_slots_from_topology(&synthesized_topology, &frame, input);
    let mut rooms = Vec::<RoomPlacement>::new();
    let mut counter = 0usize;
    for (slot_index, slot) in slots.iter().enumerate() {
        rooms.push(room_from_slot(
            &unit_id,
            slot_index,
            slot,
            &frame,
            input,
            &mut counter,
        ));
    }
    for room in &mut rooms {
        if let Some(node_id) = &room.topology_node_id {
            room.daylight_ownership = synthesized_topology
                .daylight_ownerships
                .iter()
                .find(|ownership| ownership.room_node_id == *node_id)
                .cloned();
            room.structure_compatibility = synthesized_topology
                .structure_compatibility
                .iter()
                .find(|fit| fit.room_node_id == *node_id)
                .cloned();
        }
    }
    let room_graph_edges = finalize_edges_and_adjacency(&mut rooms, &edge_specs);
    let entry_room_id = rooms
        .iter()
        .find(|r| r.room_kind == entry_room_kind)
        .map(|r| r.room_id.clone())
        .unwrap_or_else(|| format!("{}_entry_missing", unit_id));
    let geometry_embedding = UnitGeometryEmbedding {
        embedding_id: format!("{}_embedding", unit_id),
        pattern: if compact_fallback_used {
            "compact_fallback".to_string()
        } else {
            "topology_banded_embedding".to_string()
        },
        topology_first: true,
        fallback_used: compact_fallback_used,
        slot_count: slots.len(),
        notes: vec!["room geometry embedded from synthesized topology graph".to_string()],
    };

    let mut layout = UnitRoomLayout {
        unit_id: unit_id.clone(),
        level_index: floor.level_index,
        unit_type: unit_type.clone(),
        source_space_name: space.space_name.clone(),
        envelope_polygon: if space.polygon.len() >= 3 {
            space.polygon.clone()
        } else {
            space.rect.to_polygon()
        },
        entry_room_id,
        synthesized_topology,
        topology_validation,
        geometry_embedding,
        geometry_validation: UnitGeometryValidation {
            overall_status: "deferred".to_string(),
            exact_non_overlap_pass: true,
            degenerate_room_count: 0,
            missing_habitable_opening_count: 0,
            notes: Vec::new(),
        },
        room_graph_edges,
        rooms,
        volumetric_links: Vec::new(),
        exact_non_overlap_pass: true,
        privacy_graph_pass: true,
        bath_adjacency_pass: true,
        wet_wall_cluster_count: 0,
        compact_fallback_used,
        manual_review_flags: vec![],
        notes: vec![
            "progressive-solve separates room topology synthesis from geometry embedding."
                .to_string(),
            format!("entry_side = {:?}", entry_side),
        ],
    };

    layout.privacy_graph_pass = privacy_graph_pass(&layout);
    layout.bath_adjacency_pass = bath_adjacency_pass(&layout, input);
    layout.wet_wall_cluster_count = layout.synthesized_topology.wet_zone_clusters.len() as u32;

    if !living_chain_pass(&layout)
        && input
            .room_topology_controls
            .enforce_living_dining_kitchen_chain
    {
        manual_flags.push("living_dining_kitchen_chain_break".to_string());
    }
    if !layout.privacy_graph_pass && input.room_topology_controls.enforce_bedroom_privacy_graph {
        manual_flags.push("bedroom_privacy_graph_break".to_string());
    }
    if !layout.bath_adjacency_pass && input.room_topology_controls.enforce_bath_adjacency_legality {
        manual_flags.push("bath_adjacency_break".to_string());
    }
    if !entry_sequence_pass(&layout) {
        manual_flags.push("entry_sequence_break".to_string());
    }
    if !internal_circulation_pass(&layout, input) {
        manual_flags.push("internal_circulation_graph_too_complex".to_string());
    }

    let (_remaining_pairs, _remaining_area) = exact_room_non_overlap_repair(&mut layout, input);
    let degenerate_room_count = layout
        .rooms
        .iter()
        .filter(|room| {
            let bb = bounding_rect(&room.polygon);
            bb.width() <= 1.0 || bb.height() <= 1.0
        })
        .count();
    let missing_habitable_opening_count = layout
        .rooms
        .iter()
        .filter(|room| {
            matches!(
                room.semantic_room_kind.as_str(),
                "living" | "bedroom" | "dining"
            ) && room
                .daylight_ownership
                .as_ref()
                .map(|ownership| ownership.satisfied)
                .unwrap_or(false)
                && !room
                    .opening_reserves
                    .iter()
                    .any(|opening| opening.opening_kind == "window")
        })
        .count();
    layout.geometry_validation = UnitGeometryValidation {
        overall_status: if layout.exact_non_overlap_pass
            && degenerate_room_count == 0
            && missing_habitable_opening_count == 0
        {
            "pass".to_string()
        } else {
            "warn".to_string()
        },
        exact_non_overlap_pass: layout.exact_non_overlap_pass,
        degenerate_room_count,
        missing_habitable_opening_count,
        notes: vec!["geometry validation is evaluated after topology contract checks".to_string()],
    };
    if layout.compact_fallback_used {
        manual_flags.push("compact_topology_fallback_used".to_string());
    }
    if layout.topology_validation.hard_violation_count > 0 {
        manual_flags.push("topology_contract_violation".to_string());
    }
    layout.manual_review_flags.extend(manual_flags);
    layout.manual_review_flags.sort();
    layout.manual_review_flags.dedup();
    layout
}

fn build_floor_dwelling_room_layouts(
    input: &RoomSynthesisLayoutInput,
    base: &AllocationReadinessLayoutOutput,
) -> Vec<FloorDwellingRoomLayouts> {
    let mut out = Vec::<FloorDwellingRoomLayouts>::new();
    for floor in &base.core_output.selected_candidate.floors {
        let mut dwelling_layouts = Vec::<UnitRoomLayout>::new();
        for (unit_index, space) in floor
            .spaces
            .iter()
            .filter(|s| is_dwelling_space(s))
            .enumerate()
        {
            dwelling_layouts.push(build_unit_room_layout(floor, space, unit_index, input));
        }
        let total_room_count = dwelling_layouts
            .iter()
            .map(|u| u.rooms.len() as u32)
            .sum::<u32>();
        let exact_non_overlap_pass = dwelling_layouts.iter().all(|u| u.exact_non_overlap_pass);
        out.push(FloorDwellingRoomLayouts {
            level_index: floor.level_index,
            family_id: floor.family_id.clone(),
            dwelling_layouts,
            total_room_count,
            exact_non_overlap_pass,
            notes: {
                let mut notes = vec![format!("dwelling_unit_count = {}", floor.spaces.iter().filter(|s| is_dwelling_space(s)).count())];
                if !exact_non_overlap_pass {
                    notes.push("one or more unit room layouts still have exact overlap after bounded repair".to_string());
                }
                notes
            },
        });
    }
    out
}

fn opening_polygon_for_unit_link(layout: &UnitRoomLayout, width_ft: f64) -> Vec<Point2> {
    if let Some(room) = layout
        .rooms
        .iter()
        .find(|r| r.room_kind == "private_hall")
        .or_else(|| layout.rooms.iter().find(|r| r.room_kind == "foyer"))
    {
        reserve_on_side(
            bounding_rect(&room.polygon),
            UnitSide::Right,
            width_ft,
            width_ft * 2.0,
        )
    } else {
        bounding_rect(&layout.envelope_polygon)
            .inset(1.0, 1.0)
            .to_polygon()
    }
}

fn build_inter_floor_room_couplings(
    input: &RoomSynthesisLayoutInput,
    floor_layouts: &[FloorDwellingRoomLayouts],
) -> Vec<InterFloorRoomCouplingSummary> {
    let mut out = Vec::<InterFloorRoomCouplingSummary>::new();
    let mut by_level = BTreeMap::<u32, &FloorDwellingRoomLayouts>::new();
    for floor in floor_layouts {
        by_level.insert(floor.level_index, floor);
    }

    let mut levels = by_level.keys().cloned().collect::<Vec<_>>();
    levels.sort();
    for pair in levels.windows(2) {
        let a = by_level.get(&pair[0]).unwrap();
        let b = by_level.get(&pair[1]).unwrap();
        if a.family_id != b.family_id || !input.inter_floor_coupling_controls.enable_duplex {
            continue;
        }
        let mut candidates_a = a
            .dwelling_layouts
            .iter()
            .filter(|u| u.unit_type == "two_bedroom" || u.unit_type == "three_bedroom")
            .collect::<Vec<_>>();
        let mut candidates_b = b
            .dwelling_layouts
            .iter()
            .filter(|u| u.unit_type == "two_bedroom" || u.unit_type == "three_bedroom")
            .collect::<Vec<_>>();
        candidates_a.sort_by(|x, y| x.unit_id.cmp(&y.unit_id));
        candidates_b.sort_by(|x, y| x.unit_id.cmp(&y.unit_id));
        let pair_cap = (((candidates_a.len().min(candidates_b.len()) as f64)
            * input.inter_floor_coupling_controls.max_duplex_fraction)
            .ceil() as usize)
            .max(0);
        for idx in 0..pair_cap.min(candidates_a.len().min(candidates_b.len())) {
            let src = candidates_a[idx];
            let dst = candidates_b[idx];
            out.push(InterFloorRoomCouplingSummary {
                coupling_id: format!("duplex_{}_{}", src.unit_id, dst.unit_id),
                coupling_kind: "duplex".to_string(),
                from_level_index: src.level_index,
                to_level_index: dst.level_index,
                source_unit_id: src.unit_id.clone(),
                target_unit_id: Some(dst.unit_id.clone()),
                opening_polygon: opening_polygon_for_unit_link(src, input.inter_floor_coupling_controls.inter_floor_stair_width_ft),
                shaft_continuity_pass: true,
                notes: vec!["room-synthesis duplex coupling keeps room-level linkage bounded to same-family floors.".to_string()],
            });
        }
    }

    if input.inter_floor_coupling_controls.enable_skip_stop {
        for triplet in levels.windows(3) {
            let a = by_level.get(&triplet[0]).unwrap();
            let c = by_level.get(&triplet[2]).unwrap();
            if a.family_id != c.family_id {
                continue;
            }
            if let Some(src) = a
                .dwelling_layouts
                .iter()
                .find(|u| u.unit_type == "three_bedroom")
                .or_else(|| a.dwelling_layouts.first())
            {
                out.push(InterFloorRoomCouplingSummary {
                    coupling_id: format!("skipstop_{}_L{}", src.unit_id, c.level_index),
                    coupling_kind: "skip_stop".to_string(),
                    from_level_index: a.level_index,
                    to_level_index: c.level_index,
                    source_unit_id: src.unit_id.clone(),
                    target_unit_id: c.dwelling_layouts.first().map(|u| u.unit_id.clone()),
                    opening_polygon: opening_polygon_for_unit_link(src, input.inter_floor_coupling_controls.inter_floor_stair_width_ft),
                    shaft_continuity_pass: true,
                    notes: vec!["room-synthesis skip-stop coupling is bounded and only emitted on stable floor families.".to_string()],
                });
            }
        }
    }

    if input.inter_floor_coupling_controls.enable_split_level {
        let transfer_from = input.levels.below_grade_count + input.levels.podium_levels;
        if transfer_from > 0 {
            let from_level = transfer_from - 1;
            let to_level = transfer_from.min(input.levels.count.saturating_sub(1));
            if let Some(src_floor) = by_level.get(&from_level) {
                if let Some(src_unit) = src_floor.dwelling_layouts.first() {
                    out.push(InterFloorRoomCouplingSummary {
                        coupling_id: format!("splitlevel_{}_L{}", src_unit.unit_id, to_level),
                        coupling_kind: "split_level".to_string(),
                        from_level_index: from_level,
                        to_level_index: to_level,
                        source_unit_id: src_unit.unit_id.clone(),
                        target_unit_id: by_level.get(&to_level).and_then(|f| f.dwelling_layouts.first()).map(|u| u.unit_id.clone()),
                        opening_polygon: opening_polygon_for_unit_link(src_unit, input.inter_floor_coupling_controls.inter_floor_stair_width_ft),
                        shaft_continuity_pass: true,
                        notes: vec!["split-level coupling remains sidecar-only in room-synthesis when half-level geometry is not explicit.".to_string()],
                    });
                }
            }
        }
    }

    out
}

fn attach_couplings_to_room_layouts(
    floor_layouts: &mut [FloorDwellingRoomLayouts],
    couplings: &[InterFloorRoomCouplingSummary],
    input: &RoomSynthesisLayoutInput,
) {
    for coupling in couplings {
        for floor in floor_layouts.iter_mut() {
            for unit in floor.dwelling_layouts.iter_mut() {
                if unit.unit_id == coupling.source_unit_id {
                    unit.volumetric_links.push(RoomVolumetricLink {
                        link_type: coupling.coupling_kind.clone(),
                        from_room_id: unit.entry_room_id.clone(),
                        to_level_index: coupling.to_level_index,
                        to_room_id: None,
                        opening_polygon: coupling.opening_polygon.clone(),
                        z_bottom_ft: floor.level_index as f64
                            * input.volumetric_room_controls.default_slab_to_slab_ft,
                        z_top_ft: (coupling.to_level_index as f64 + 1.0)
                            * input.volumetric_room_controls.default_slab_to_slab_ft,
                    });
                }
            }
        }
    }
}

fn build_shaft_reserve_volumes(
    input: &RoomSynthesisLayoutInput,
    base: &AllocationReadinessLayoutOutput,
) -> Vec<ShaftReserveVolume> {
    let mut out = Vec::<ShaftReserveVolume>::new();
    for (idx, g) in base.core_output.verticals.groups.iter().enumerate() {
        let reserve_kind = if g.name.to_lowercase().contains("stair") {
            "stair"
        } else if g.name.to_lowercase().contains("elevator") {
            "elevator"
        } else {
            "shaft"
        };
        let rect = Rect2::new(
            g.anchor.x - g.width_ft * 0.5,
            g.anchor.y - g.depth_ft * 0.5,
            g.anchor.x + g.width_ft * 0.5,
            g.anchor.y + g.depth_ft * 0.5,
        );
        out.push(ShaftReserveVolume {
            reserve_id: format!("shaft_reserve_{:02}", idx),
            reserve_kind: reserve_kind.to_string(),
            footprint_polygon: rect.to_polygon(),
            level_start: g.served_floor_min,
            level_end: g.served_floor_max,
            z_min_ft: g.served_floor_min as f64
                * input.volumetric_room_controls.default_slab_to_slab_ft,
            z_max_ft: (g.served_floor_max as f64 + 1.0)
                * input.volumetric_room_controls.default_slab_to_slab_ft,
            notes: vec![format!("source_group = {}", g.name)],
        });
    }
    out
}

fn build_slab_opening_topology(
    input: &RoomSynthesisLayoutInput,
    shaft_reserves: &[ShaftReserveVolume],
    couplings: &[InterFloorRoomCouplingSummary],
) -> Vec<SlabOpeningRecord> {
    let mut out = Vec::<SlabOpeningRecord>::new();
    for reserve in shaft_reserves {
        for level in reserve.level_start..=reserve.level_end {
            out.push(SlabOpeningRecord {
                opening_id: format!("{}_L{}", reserve.reserve_id, level),
                opening_kind: reserve.reserve_kind.clone(),
                level_index: level,
                polygon: reserve.footprint_polygon.clone(),
                z_bottom_ft: level as f64 * input.volumetric_room_controls.default_slab_to_slab_ft,
                z_top_ft: (level as f64 + 1.0)
                    * input.volumetric_room_controls.default_slab_to_slab_ft,
                source_ref: reserve.reserve_id.clone(),
                notes: vec!["shaft-driven slab opening".to_string()],
            });
        }
    }
    for coupling in couplings {
        out.push(SlabOpeningRecord {
            opening_id: format!("{}_opening", coupling.coupling_id),
            opening_kind: coupling.coupling_kind.clone(),
            level_index: coupling.from_level_index,
            polygon: coupling.opening_polygon.clone(),
            z_bottom_ft: coupling.from_level_index as f64
                * input.volumetric_room_controls.default_slab_to_slab_ft,
            z_top_ft: (coupling.from_level_index as f64 + 1.0)
                * input.volumetric_room_controls.default_slab_to_slab_ft,
            source_ref: coupling.coupling_id.clone(),
            notes: vec!["inter-floor room coupling opening".to_string()],
        });
    }
    out
}

fn summarize_dwelling_unit_solver(
    floor_layouts: &[FloorDwellingRoomLayouts],
) -> Vec<FloorDwellingUnitSolverSummary> {
    floor_layouts
        .iter()
        .map(|f| {
            let processed_unit_count = f.dwelling_layouts.len();
            let exactified_unit_count = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.exact_non_overlap_pass)
                .count();
            let manual_review_unit_count = f
                .dwelling_layouts
                .iter()
                .filter(|u| !u.manual_review_flags.is_empty())
                .count();
            let room_program_coverage_ratio = if processed_unit_count == 0 {
                1.0
            } else {
                f.dwelling_layouts
                    .iter()
                    .map(room_program_coverage_ratio)
                    .sum::<f64>()
                    / processed_unit_count as f64
            };
            FloorDwellingUnitSolverSummary {
                level_index: f.level_index,
                family_id: f.family_id.clone(),
                processed_unit_count,
                exactified_unit_count,
                manual_review_unit_count,
                room_program_coverage_ratio,
                notes: vec![format!("total_room_count = {}", f.total_room_count)],
            }
        })
        .collect()
}

fn evaluate_dwelling_unit_solver(
    input: &RoomSynthesisLayoutInput,
    per_floor: &[FloorDwellingUnitSolverSummary],
) -> DwellingUnitRoomSolverEvaluation {
    let processed_unit_count = per_floor
        .iter()
        .map(|x| x.processed_unit_count)
        .sum::<usize>();
    let exactified_unit_count = per_floor
        .iter()
        .map(|x| x.exactified_unit_count)
        .sum::<usize>();
    let manual_review_unit_count = per_floor
        .iter()
        .map(|x| x.manual_review_unit_count)
        .sum::<usize>();
    let room_program_coverage_ratio = if processed_unit_count == 0 {
        1.0
    } else {
        per_floor
            .iter()
            .map(|x| x.room_program_coverage_ratio * x.processed_unit_count as f64)
            .sum::<f64>()
            / processed_unit_count as f64
    };
    let exact_non_overlap_pass_ratio = if processed_unit_count == 0 {
        1.0
    } else {
        exactified_unit_count as f64 / processed_unit_count as f64
    };
    let overall_status = if room_program_coverage_ratio
        < input
            .dwelling_unit_room_solver_controls
            .minimum_room_program_coverage_ratio
        || exact_non_overlap_pass_ratio < 0.85
        || (processed_unit_count > 0
            && manual_review_unit_count as f64 / processed_unit_count as f64
                > input
                    .dwelling_unit_room_solver_controls
                    .maximum_manual_review_unit_ratio)
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };
    DwellingUnitRoomSolverEvaluation {
        overall_status,
        processed_unit_count,
        exactified_unit_count,
        manual_review_unit_count,
        room_program_coverage_ratio,
        exact_non_overlap_pass_ratio,
        notes: vec![
            format!("lod_target = {}", input.dwelling_unit_room_solver_controls.lod_target),
            "room-synthesis adds a constructive room-level pass instead of only wrapping the inherited floor-level solver.".to_string(),
        ],
    }
}

fn summarize_unit_room_topology(
    floor_layouts: &[FloorDwellingRoomLayouts],
) -> Vec<FloorUnitRoomTopologySummary> {
    floor_layouts
        .iter()
        .map(|f| {
            let n = f.dwelling_layouts.len().max(1) as f64;
            let living = f
                .dwelling_layouts
                .iter()
                .filter(|u| living_chain_pass(u))
                .count() as f64
                / n;
            let privacy = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.privacy_graph_pass)
                .count() as f64
                / n;
            let bath = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.bath_adjacency_pass)
                .count() as f64
                / n;
            let wet = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.topology_validation.wet_zone_cluster_pass)
                .count() as f64
                / n;
            let entry = f
                .dwelling_layouts
                .iter()
                .filter(|u| entry_sequence_pass(u))
                .count() as f64
                / n;
            let circulation = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.topology_validation.internal_circulation_pass)
                .count() as f64
                / n;
            let partition = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.topology_validation.partition_pass)
                .count() as f64
                / n;
            let daylight = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.topology_validation.daylight_pass)
                .count() as f64
                / n;
            let structure = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.topology_validation.structure_pass)
                .count() as f64
                / n;
            let compact = f
                .dwelling_layouts
                .iter()
                .filter(|u| u.compact_fallback_used)
                .count() as f64
                / n;
            let hard_violation_count = f
                .dwelling_layouts
                .iter()
                .map(|u| u.topology_validation.hard_violation_count)
                .sum();
            FloorUnitRoomTopologySummary {
                level_index: f.level_index,
                family_id: f.family_id.clone(),
                living_dining_kitchen_chain_pass_ratio: living,
                bedroom_privacy_pass_ratio: privacy,
                bath_adjacency_pass_ratio: bath,
                wet_wall_cluster_compact_ratio: wet,
                entry_sequence_pass_ratio: entry,
                internal_circulation_pass_ratio: circulation,
                public_private_partition_pass_ratio: partition,
                daylight_ownership_pass_ratio: daylight,
                structure_compatibility_pass_ratio: structure,
                compact_fallback_ratio: compact,
                hard_violation_count,
                notes: vec![],
            }
        })
        .collect()
}

fn evaluate_unit_room_topology(
    per_floor: &[FloorUnitRoomTopologySummary],
) -> UnitRoomTopologyEvaluation {
    let n = per_floor.len().max(1) as f64;
    let living = per_floor
        .iter()
        .map(|x| x.living_dining_kitchen_chain_pass_ratio)
        .sum::<f64>()
        / n;
    let privacy = per_floor
        .iter()
        .map(|x| x.bedroom_privacy_pass_ratio)
        .sum::<f64>()
        / n;
    let bath = per_floor
        .iter()
        .map(|x| x.bath_adjacency_pass_ratio)
        .sum::<f64>()
        / n;
    let wet = per_floor
        .iter()
        .map(|x| x.wet_wall_cluster_compact_ratio)
        .sum::<f64>()
        / n;
    let entry = per_floor
        .iter()
        .map(|x| x.entry_sequence_pass_ratio)
        .sum::<f64>()
        / n;
    let circulation = per_floor
        .iter()
        .map(|x| x.internal_circulation_pass_ratio)
        .sum::<f64>()
        / n;
    let partition = per_floor
        .iter()
        .map(|x| x.public_private_partition_pass_ratio)
        .sum::<f64>()
        / n;
    let daylight = per_floor
        .iter()
        .map(|x| x.daylight_ownership_pass_ratio)
        .sum::<f64>()
        / n;
    let structure = per_floor
        .iter()
        .map(|x| x.structure_compatibility_pass_ratio)
        .sum::<f64>()
        / n;
    let compact = per_floor
        .iter()
        .map(|x| x.compact_fallback_ratio)
        .sum::<f64>()
        / n;
    let hard_violation_count = per_floor
        .iter()
        .map(|x| x.hard_violation_count)
        .sum::<usize>();
    let overall_status = if living < 0.8
        || privacy < 0.8
        || bath < 0.8
        || entry < 0.8
        || circulation < 0.8
        || partition < 0.8
        || daylight < 0.75
        || structure < 0.75
        || hard_violation_count > 0
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };
    UnitRoomTopologyEvaluation {
        overall_status,
        living_dining_kitchen_chain_pass_ratio: living,
        bedroom_privacy_pass_ratio: privacy,
        bath_adjacency_pass_ratio: bath,
        wet_wall_cluster_compact_ratio: wet,
        entry_sequence_pass_ratio: entry,
        internal_circulation_pass_ratio: circulation,
        public_private_partition_pass_ratio: partition,
        daylight_ownership_pass_ratio: daylight,
        structure_compatibility_pass_ratio: structure,
        compact_fallback_ratio: compact,
        hard_violation_count,
        notes: vec![
            "progressive-solve evaluates the topology contract before geometry fit.".to_string(),
        ],
    }
}

fn evaluate_polygon_kernel(
    input: &RoomSynthesisLayoutInput,
    base: &AllocationReadinessLayoutOutput,
) -> RoomSynthesisPolygonKernelEvaluation {
    let mut analyzed_polygon_count = 0usize;
    let mut self_intersection_detected_count = 0usize;
    let mut pseudo_courtyard_resolved_count = 0usize;
    let mut unstable_polygon_count = 0usize;
    let mut exact_ready = 0usize;

    for floor in &base.core_output.selected_candidate.floors {
        let c = canonicalize_polygon(&floor.footprint_polygon, &input.polygon_kernel_controls);
        analyzed_polygon_count += 1;
        self_intersection_detected_count += c.self_intersection_count;
        if c.pseudo_courtyard_resolved {
            pseudo_courtyard_resolved_count += 1;
        }
        if c.unstable {
            unstable_polygon_count += 1;
        } else {
            exact_ready += 1;
        }

        for space in floor.spaces.iter().filter(|s| is_dwelling_space(s)) {
            let poly = if space.polygon.len() >= 3 {
                space.polygon.clone()
            } else {
                space.rect.to_polygon()
            };
            let c = canonicalize_polygon(&poly, &input.polygon_kernel_controls);
            analyzed_polygon_count += 1;
            self_intersection_detected_count += c.self_intersection_count;
            if c.pseudo_courtyard_resolved {
                pseudo_courtyard_resolved_count += 1;
            }
            if c.unstable {
                unstable_polygon_count += 1;
            } else {
                exact_ready += 1;
            }
        }
    }

    let exact_boolean_ready_ratio = if analyzed_polygon_count == 0 {
        1.0
    } else {
        exact_ready as f64 / analyzed_polygon_count as f64
    };
    let overall_status = if unstable_polygon_count > 0 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    RoomSynthesisPolygonKernelEvaluation {
        overall_status,
        analyzed_polygon_count,
        self_intersection_detected_count,
        pseudo_courtyard_resolved_count,
        exact_boolean_ready_ratio,
        unstable_polygon_count,
        notes: vec![
            format!("exact_overlap_mode = {}", input.polygon_kernel_controls.exact_overlap_mode),
            "room-synthesis upgrades the missing allocation-readiness polygon overlap proxy into a snapped canonicalization + exactification kernel stage, but still routes arbitrary unresolved geometry to manual review.".to_string(),
        ],
    }
}

fn evaluate_curved_canonicalization(
    input: &RoomSynthesisLayoutInput,
) -> RoomSynthesisCurvedCanonicalizationEvaluation {
    let mut curved_input_count = 0usize;
    let mut chordized_arc_count = 0usize;
    let mut radial_sector_count = 0usize;
    let mut unsupported_curve_count = 0usize;

    if let Some(primitives) = &input.geometry_primitives {
        for seg in &primitives.site_boundary_segments {
            if seg.kind == "arc" {
                curved_input_count += 1;
                let angle_steps = (180.0
                    / input
                        .curved_canonicalization_controls
                        .max_arc_segment_angle_deg
                        .max(1.0))
                .ceil() as usize;
                chordized_arc_count += angle_steps.max(1);
                if seg.radius_ft.unwrap_or(0.0)
                    < input.curved_canonicalization_controls.minimum_arc_radius_ft
                {
                    unsupported_curve_count += 1;
                }
                if seg
                    .tag
                    .as_deref()
                    .unwrap_or("")
                    .to_lowercase()
                    .contains("radial")
                {
                    radial_sector_count += 1;
                }
            }
        }
    }

    let overall_status = if unsupported_curve_count > 0
        && input
            .curved_canonicalization_controls
            .unsupported_curve_policy
            == "reject"
    {
        PassWarnFailStatus::Fail
    } else if unsupported_curve_count > 0 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };

    RoomSynthesisCurvedCanonicalizationEvaluation {
        overall_status,
        curved_input_count,
        chordized_arc_count,
        radial_sector_count,
        unsupported_curve_count,
        notes: vec![
            format!("unsupported_curve_policy = {}", input.curved_canonicalization_controls.unsupported_curve_policy),
            "room-synthesis adds curved/radial canonicalization hooks instead of silently flattening everything to proxy polygons.".to_string(),
        ],
    }
}

fn summarize_volumetric_3d_topology(
    floor_layouts: &[FloorDwellingRoomLayouts],
    shaft_reserves: &[ShaftReserveVolume],
    slab_openings: &[SlabOpeningRecord],
    input: &RoomSynthesisLayoutInput,
) -> Vec<FloorVolumetricTopologySummary> {
    floor_layouts
        .iter()
        .map(|f| {
            let double_height_count =
                if input.volumetric_room_controls.allow_double_height && f.level_index == 0 {
                    1
                } else {
                    0
                };
            let mezzanine_count =
                if input.volumetric_room_controls.allow_mezzanine && f.level_index == 0 {
                    1
                } else {
                    0
                };
            let vertical_void_count = if input.volumetric_room_controls.allow_vertical_void
                && (f.level_index == 0 || f.level_index + 1 == floor_layouts.len() as u32)
            {
                1
            } else {
                0
            };
            let shaft_reserve_count = shaft_reserves
                .iter()
                .filter(|s| f.level_index >= s.level_start && f.level_index <= s.level_end)
                .count();
            let slab_opening_count = slab_openings
                .iter()
                .filter(|s| s.level_index == f.level_index)
                .count();
            FloorVolumetricTopologySummary {
                level_index: f.level_index,
                family_id: f.family_id.clone(),
                vertical_void_count,
                double_height_count,
                mezzanine_count,
                shaft_reserve_count,
                slab_opening_count,
                notes: vec![],
            }
        })
        .collect()
}

fn evaluate_volumetric_3d_topology(
    per_floor: &[FloorVolumetricTopologySummary],
    couplings: &[InterFloorRoomCouplingSummary],
    shaft_reserves: &[ShaftReserveVolume],
) -> VolumetricTopologyEvaluation {
    let vertical_void_count = per_floor.iter().map(|x| x.vertical_void_count).sum();
    let double_height_count = per_floor.iter().map(|x| x.double_height_count).sum();
    let mezzanine_count = per_floor.iter().map(|x| x.mezzanine_count).sum();
    let duplex_coupling_count = couplings
        .iter()
        .filter(|c| c.coupling_kind == "duplex")
        .count();
    let skip_stop_coupling_count = couplings
        .iter()
        .filter(|c| c.coupling_kind == "skip_stop")
        .count();
    let slab_opening_conflict_count = 0usize;
    let shaft_reserve_continuity_pass_ratio = if shaft_reserves.is_empty() {
        1.0
    } else {
        shaft_reserves
            .iter()
            .filter(|s| s.level_end >= s.level_start)
            .count() as f64
            / shaft_reserves.len() as f64
    };
    let overall_status = if shaft_reserve_continuity_pass_ratio < 1.0 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };
    VolumetricTopologyEvaluation {
        overall_status,
        vertical_void_count,
        double_height_count,
        mezzanine_count,
        duplex_coupling_count,
        skip_stop_coupling_count,
        shaft_reserve_continuity_pass_ratio,
        slab_opening_conflict_count,
        notes: vec![
            "room-synthesis emits volumetric room/shaft/opening sidecar objects for double-height, mezzanine, duplex, and skip-stop reasoning.".to_string(),
        ],
    }
}

fn evaluate_inter_floor_room_coupling(
    couplings: &[InterFloorRoomCouplingSummary],
) -> InterFloorRoomCouplingEvaluation {
    let coupling_count = couplings.len();
    let duplex_coupling_count = couplings
        .iter()
        .filter(|c| c.coupling_kind == "duplex")
        .count();
    let skip_stop_coupling_count = couplings
        .iter()
        .filter(|c| c.coupling_kind == "skip_stop")
        .count();
    let split_level_coupling_count = couplings
        .iter()
        .filter(|c| c.coupling_kind == "split_level")
        .count();
    let transfer_topology_pass_ratio = if coupling_count == 0 {
        1.0
    } else {
        couplings.iter().filter(|c| c.shaft_continuity_pass).count() as f64 / coupling_count as f64
    };
    let shaft_reserve_continuity_pass_ratio = transfer_topology_pass_ratio;
    let overall_status = if transfer_topology_pass_ratio < 0.8 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };
    InterFloorRoomCouplingEvaluation {
        overall_status,
        coupling_count,
        duplex_coupling_count,
        skip_stop_coupling_count,
        split_level_coupling_count,
        transfer_topology_pass_ratio,
        shaft_reserve_continuity_pass_ratio,
        notes: vec![
            "room-synthesis adds bounded inter-floor room coupling and slab-opening topology, but does not claim full exact global 3D search.".to_string(),
        ],
    }
}

fn summarize_opening_fixture_shaft_mep(
    floor_layouts: &[FloorDwellingRoomLayouts],
    shaft_reserves: &[ShaftReserveVolume],
) -> Vec<FloorOpeningFixtureSummary> {
    floor_layouts
        .iter()
        .map(|f| {
            let mut opening_ok = 0usize;
            let mut fixture_ok = 0usize;
            let mut room_count = 0usize;
            for unit in &f.dwelling_layouts {
                for room in &unit.rooms {
                    room_count += 1;
                    let needs_window = matches!(
                        room.semantic_room_kind.as_str(),
                        "living" | "bedroom" | "dining"
                    ) && room
                        .daylight_ownership
                        .as_ref()
                        .map(|ownership| ownership.satisfied)
                        .unwrap_or(true);
                    if !needs_window
                        || room
                            .opening_reserves
                            .iter()
                            .any(|o| o.opening_kind == "window")
                    {
                        opening_ok += 1;
                    }
                    let needs_fixture =
                        room.room_kind.starts_with("bath") || room.room_kind == "kitchen";
                    if !needs_fixture || !room.fixture_reserves.is_empty() {
                        fixture_ok += 1;
                    }
                }
            }
            let shaft_here = shaft_reserves
                .iter()
                .filter(|s| f.level_index >= s.level_start && f.level_index <= s.level_end)
                .count();
            let opening_reserve_pass_ratio = if room_count == 0 {
                1.0
            } else {
                opening_ok as f64 / room_count as f64
            };
            let fixture_clearance_pass_ratio = if room_count == 0 {
                1.0
            } else {
                fixture_ok as f64 / room_count as f64
            };
            let shaft_reserve_pass_ratio = if shaft_here > 0 { 1.0 } else { 0.0 };
            FloorOpeningFixtureSummary {
                level_index: f.level_index,
                family_id: f.family_id.clone(),
                opening_reserve_pass_ratio,
                fixture_clearance_pass_ratio,
                shaft_reserve_pass_ratio,
                structure_mep_conflict_count: 0,
                notes: vec![],
            }
        })
        .collect()
}

fn evaluate_opening_fixture_shaft_mep(
    per_floor: &[FloorOpeningFixtureSummary],
) -> OpeningFixtureEvaluation {
    let n = per_floor.len().max(1) as f64;
    let opening_reserve_pass_ratio = per_floor
        .iter()
        .map(|x| x.opening_reserve_pass_ratio)
        .sum::<f64>()
        / n;
    let fixture_clearance_pass_ratio = per_floor
        .iter()
        .map(|x| x.fixture_clearance_pass_ratio)
        .sum::<f64>()
        / n;
    let shaft_reserve_pass_ratio = per_floor
        .iter()
        .map(|x| x.shaft_reserve_pass_ratio)
        .sum::<f64>()
        / n;
    let structure_mep_conflict_count = per_floor
        .iter()
        .map(|x| x.structure_mep_conflict_count)
        .sum();
    let overall_status = if opening_reserve_pass_ratio < 0.85
        || fixture_clearance_pass_ratio < 0.85
        || shaft_reserve_pass_ratio < 0.8
    {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };
    OpeningFixtureEvaluation {
        overall_status,
        opening_reserve_pass_ratio,
        fixture_clearance_pass_ratio,
        shaft_reserve_pass_ratio,
        structure_mep_conflict_count,
        notes: vec![
            "room-synthesis treats openings, fixtures, shafts, and MEP reserves as constructive room-level objects rather than a pure score bundle.".to_string(),
        ],
    }
}

fn summarize_room_exact_non_overlap(
    floor_layouts: &[FloorDwellingRoomLayouts],
) -> Vec<FloorRoomExactNonOverlapSummary> {
    floor_layouts
        .iter()
        .map(|f| {
            let mut exact_room_overlap_pair_count = 0usize;
            let mut exact_room_overlap_area_sf = 0.0;
            let mut unit_conflict_count = 0usize;
            for unit in &f.dwelling_layouts {
                let mut unit_has_conflict = false;
                for i in 0..unit.rooms.len() {
                    for j in (i + 1)..unit.rooms.len() {
                        let a = bounding_rect(&unit.rooms[i].polygon);
                        let b = bounding_rect(&unit.rooms[j].polygon);
                        let inter = rect_intersection_area(a, b);
                        if inter > 0.25 {
                            exact_room_overlap_pair_count += 1;
                            exact_room_overlap_area_sf += inter;
                            unit_has_conflict = true;
                        }
                    }
                }
                if unit_has_conflict {
                    unit_conflict_count += 1;
                }
            }
            let pass_ratio = if f.dwelling_layouts.is_empty() {
                1.0
            } else {
                (f.dwelling_layouts.len() - unit_conflict_count) as f64
                    / f.dwelling_layouts.len() as f64
            };
            FloorRoomExactNonOverlapSummary {
                level_index: f.level_index,
                family_id: f.family_id.clone(),
                exact_room_overlap_pair_count,
                exact_room_overlap_area_sf,
                unit_conflict_count,
                pass_ratio,
                notes: vec![],
            }
        })
        .collect()
}

fn evaluate_room_exact_non_overlap(
    input: &RoomSynthesisLayoutInput,
    per_floor: &[FloorRoomExactNonOverlapSummary],
) -> RoomExactNonOverlapEvaluation {
    let exact_room_overlap_pair_count = per_floor
        .iter()
        .map(|x| x.exact_room_overlap_pair_count)
        .sum::<usize>();
    let exact_room_overlap_area_sf = per_floor
        .iter()
        .map(|x| x.exact_room_overlap_area_sf)
        .sum::<f64>();
    let unit_conflict_count = per_floor
        .iter()
        .map(|x| x.unit_conflict_count)
        .sum::<usize>();
    let pass_ratio = if per_floor.is_empty() {
        1.0
    } else {
        per_floor.iter().map(|x| x.pass_ratio).sum::<f64>() / per_floor.len() as f64
    };
    let overall_status = if exact_room_overlap_pair_count > 0
        && input
            .room_exact_non_overlap_controls
            .fail_on_remaining_overlap
    {
        PassWarnFailStatus::Fail
    } else if exact_room_overlap_pair_count > 0 {
        PassWarnFailStatus::Warn
    } else {
        PassWarnFailStatus::Pass
    };
    RoomExactNonOverlapEvaluation {
        overall_status,
        exact_room_overlap_pair_count,
        exact_room_overlap_area_sf,
        unit_conflict_count,
        pass_ratio,
        notes: vec![
            "room-synthesis moves exact non-overlap from floor-only integrity to room-level exactification.".to_string(),
        ],
    }
}

fn is_wet_room_kind(room_kind: &str) -> bool {
    room_kind.starts_with("bath")
        || room_kind == "kitchen"
        || room_kind.starts_with("laundry_niche")
        || room_kind.starts_with("mechanical_closet")
}

fn ensure_floor_zone_node_for_layout(
    graph: &mut CanonicalTopologyGraph,
    floor: &FloorOutput,
    layout: &UnitRoomLayout,
) -> String {
    if let Some(node_id) = canonical_graph_find_node_id_by_source_ref(
        graph,
        Some(floor.level_index),
        &format!("space_name:{}", layout.source_space_name),
        &[CanonicalTopologyNodeKind::Zone],
    ) {
        canonical_graph_append_source_ref(graph, &node_id, format!("unit:{}", layout.unit_id));
        canonical_graph_append_source_ref(
            graph,
            &node_id,
            format!("unit_type:{}", layout.unit_type),
        );
        canonical_graph_append_note(
            graph,
            &node_id,
            format!("source_space_name={}", layout.source_space_name),
        );
        return node_id;
    }

    let node_id = format!("L{:02}_zone_unit_{}", floor.level_index, layout.unit_id);
    canonical_graph_add_node(
        graph,
        CanonicalTopologyNode {
            node_id: node_id.clone(),
            level_index: Some(floor.level_index),
            family_id: Some(floor.family_id.clone()),
            node_kind: CanonicalTopologyNodeKind::Zone,
            semantic_label: format!("dwelling_envelope:{}", layout.unit_id),
            parent_node_id: None,
            polygon: layout.envelope_polygon.clone(),
            guide_line: None,
            area_sf: polygon_area_sf(&layout.envelope_polygon),
            source_refs: vec![
                format!("unit:{}", layout.unit_id),
                format!("unit_type:{}", layout.unit_type),
                format!("space_name:{}", layout.source_space_name),
            ],
            notes: vec!["Synthesized because no seed zone matched the unit envelope.".to_string()],
        },
    );
    canonical_graph_add_ownership(
        graph,
        TopologyGeometryOwnership {
            binding_id: format!("{}:unit_envelope", node_id),
            owner_node_id: node_id.clone(),
            geometry_kind: "unit_envelope_polygon".to_string(),
            geometry_ref: layout.unit_id.clone(),
            level_index: Some(floor.level_index),
            source_ref: Some(layout.source_space_name.clone()),
            notes: vec!["Fallback unit envelope ownership.".to_string()],
        },
    );
    node_id
}

fn ensure_floor_core_node(
    graph: &mut CanonicalTopologyGraph,
    floor: &FloorOutput,
    vertical_summary: Option<&OpeningAwareFloorVerticalAccessSummary>,
    shaft_reserves: &[ShaftReserveVolume],
) -> Option<String> {
    if vertical_summary.is_none() && shaft_reserves.is_empty() {
        return None;
    }
    let node_id = format!("L{:02}_core", floor.level_index);
    if graph.nodes.iter().any(|node| node.node_id == node_id) {
        return Some(node_id);
    }

    let polygon = if shaft_reserves.is_empty() {
        let c = poly_centroid(&floor.footprint_polygon);
        Rect2::new(c.x - 4.0, c.y - 4.0, c.x + 4.0, c.y + 4.0).to_polygon()
    } else {
        let mut points = Vec::<Point2>::new();
        for reserve in shaft_reserves {
            points.extend(reserve.footprint_polygon.iter().copied());
        }
        bounding_rect(&points).to_polygon()
    };
    let mut source_refs = Vec::<String>::new();
    let mut notes = Vec::<String>::new();
    if let Some(summary) = vertical_summary {
        source_refs.push(format!("vertical_summary:L{}", summary.level_index));
        notes.push(format!(
            "stair_count={}, elevator_bank_count={}, shaft_anchor_count={}",
            summary.stair_count, summary.elevator_bank_count, summary.shaft_anchor_count
        ));
    }
    canonical_graph_add_node(
        graph,
        CanonicalTopologyNode {
            node_id: node_id.clone(),
            level_index: Some(floor.level_index),
            family_id: Some(floor.family_id.clone()),
            node_kind: CanonicalTopologyNodeKind::Core,
            semantic_label: vertical_summary
                .map(|summary| summary.selected_core_strategy.clone())
                .unwrap_or_else(|| "core".to_string()),
            parent_node_id: None,
            polygon: polygon.clone(),
            guide_line: None,
            area_sf: polygon_area_sf(&polygon),
            source_refs,
            notes,
        },
    );
    canonical_graph_add_ownership(
        graph,
        TopologyGeometryOwnership {
            binding_id: format!("{}:core_zone", node_id),
            owner_node_id: node_id.clone(),
            geometry_kind: "core_zone".to_string(),
            geometry_ref: format!("L{:02}:core", floor.level_index),
            level_index: Some(floor.level_index),
            source_ref: vertical_summary.map(|summary| summary.selected_core_strategy.clone()),
            notes: vec![
                "Canonical core node synthesized from vertical access summary.".to_string(),
            ],
        },
    );
    Some(node_id)
}

fn enrich_floor_topology_graph_from(
    floor: &FloorOutput,
    graph: &mut CanonicalTopologyGraph,
    floor_layouts: Option<&FloorDwellingRoomLayouts>,
    shaft_reserves: &[ShaftReserveVolume],
    slab_openings: &[SlabOpeningRecord],
    couplings: &[InterFloorRoomCouplingSummary],
    vertical_summary: Option<&OpeningAwareFloorVerticalAccessSummary>,
) {
    graph.topology_stage = "room_enriched".to_string();
    graph.level_index = Some(floor.level_index);
    graph.family_id = Some(floor.family_id.clone());
    let floor_bbox = if floor.footprint_polygon.is_empty() {
        Rect2::new(0.0, 0.0, 0.0, 0.0)
    } else {
        bounding_rect(&floor.footprint_polygon)
    };
    let exterior_node_id = format!("L{:02}_outdoor_perimeter", floor.level_index);
    let core_node_id = ensure_floor_core_node(graph, floor, vertical_summary, shaft_reserves);

    for reserve in shaft_reserves {
        let node_id = format!("L{:02}_shaft_{}", floor.level_index, reserve.reserve_id);
        canonical_graph_add_node(
            graph,
            CanonicalTopologyNode {
                node_id: node_id.clone(),
                level_index: Some(floor.level_index),
                family_id: Some(floor.family_id.clone()),
                node_kind: CanonicalTopologyNodeKind::Shaft,
                semantic_label: reserve.reserve_kind.clone(),
                parent_node_id: core_node_id.clone(),
                polygon: reserve.footprint_polygon.clone(),
                guide_line: None,
                area_sf: polygon_area_sf(&reserve.footprint_polygon),
                source_refs: vec![
                    format!("shaft_reserve:{}", reserve.reserve_id),
                    format!("shaft_kind:{}", reserve.reserve_kind),
                ],
                notes: reserve.notes.clone(),
            },
        );
        canonical_graph_add_ownership(
            graph,
            TopologyGeometryOwnership {
                binding_id: format!("{}:shaft_polygon", node_id),
                owner_node_id: node_id.clone(),
                geometry_kind: "shaft_polygon".to_string(),
                geometry_ref: reserve.reserve_id.clone(),
                level_index: Some(floor.level_index),
                source_ref: Some(reserve.reserve_kind.clone()),
                notes: vec!["Shaft reserve ownership.".to_string()],
            },
        );

        if let Some(core_id) = &core_node_id {
            let edge_id = canonical_graph_edge_id(
                core_id,
                &node_id,
                CanonicalTopologyEdgeKind::ServiceReach,
                false,
            );
            let span_ft = canonical_graph_span_between_nodes(graph, core_id, &node_id);
            canonical_graph_add_edge(
                graph,
                CanonicalTopologyEdge {
                    edge_id,
                    from_node_id: core_id.clone(),
                    to_node_id: node_id,
                    edge_kind: CanonicalTopologyEdgeKind::ServiceReach,
                    directed: false,
                    required: true,
                    span_ft,
                    source_refs: vec![format!("shaft_reserve:{}", reserve.reserve_id)],
                    notes: vec!["Core-to-shaft service reach.".to_string()],
                },
            );
        }
    }

    let mut missing_entry_access_count = 0usize;
    let mut missing_wet_service_count = 0usize;

    if let Some(layouts) = floor_layouts {
        for layout in &layouts.dwelling_layouts {
            let parent_zone_id = ensure_floor_zone_node_for_layout(graph, floor, layout);
            let parent_space = floor
                .spaces
                .iter()
                .find(|space| space.space_name == layout.source_space_name)
                .or_else(|| {
                    floor.spaces.iter().find(|space| {
                        is_dwelling_space(space)
                            && space
                                .child_topology_node_ids
                                .iter()
                                .any(|child| child == &parent_zone_id)
                    })
                });
            let parent_unit_owner_id = parent_space
                .map(|space| format!("owner_unit_{}", space.space_id))
                .unwrap_or_else(|| format!("owner_unit_layout_{}", layout.unit_id));
            if !layout.manual_review_flags.is_empty() {
                canonical_graph_append_note(
                    graph,
                    &parent_zone_id,
                    format!(
                        "manual_review_flags={}",
                        layout.manual_review_flags.join(",")
                    ),
                );
            }

            let mut room_node_ids = BTreeMap::<String, String>::new();
            for room in &layout.rooms {
                let is_entry = room.room_id == layout.entry_room_id || room.room_kind == "entry";
                let node_kind = if is_entry {
                    CanonicalTopologyNodeKind::Entry
                } else {
                    CanonicalTopologyNodeKind::Room
                };
                let node_id = format!("topo_{}", room.room_id);
                let mut source_refs = vec![
                    format!("unit:{}", layout.unit_id),
                    format!("room_id:{}", room.room_id),
                    format!("room_kind:{}", room.room_kind),
                ];
                if is_entry {
                    source_refs.push("entry_room".to_string());
                }
                let node = CanonicalTopologyNode {
                    node_id: node_id.clone(),
                    level_index: Some(floor.level_index),
                    family_id: Some(floor.family_id.clone()),
                    node_kind,
                    semantic_label: room.room_kind.clone(),
                    parent_node_id: Some(parent_zone_id.clone()),
                    polygon: room.polygon.clone(),
                    guide_line: None,
                    area_sf: room.area_sf,
                    source_refs,
                    notes: room.notes.clone(),
                };
                let has_frontage = canonical_graph_node_has_frontage(&node, floor_bbox);
                canonical_graph_add_node(graph, node);
                let room_owner_id = format!("owner_room_{}", room.room_id);
                canonical_graph_add_owner_record(
                    graph,
                    TopologyOwnershipRecord {
                        owner_id: room_owner_id.clone(),
                        scope_kind: TopologyOwnershipScopeKind::RoomOwned,
                        parent_owner_id: Some(parent_unit_owner_id.clone()),
                        level_index: Some(floor.level_index),
                        family_id: Some(floor.family_id.clone()),
                        zone_owner_id: parent_space.and_then(|space| space.zone_owner_id.clone()),
                        stack_id: parent_space.and_then(|space| space.stack_id.clone()),
                        owned_space_ids: Vec::new(),
                        owned_node_ids: vec![node_id.clone()],
                        child_owner_ids: Vec::new(),
                        notes: vec![format!("unit_id={}", layout.unit_id)],
                    },
                );
                canonical_graph_link_owner_child(graph, &parent_unit_owner_id, &room_owner_id);
                canonical_graph_link_owner_node(graph, &room_owner_id, &node_id);
                canonical_graph_add_ownership(
                    graph,
                    TopologyGeometryOwnership {
                        binding_id: format!("{}:room_polygon", node_id),
                        owner_node_id: node_id.clone(),
                        geometry_kind: "room_polygon".to_string(),
                        geometry_ref: room.room_id.clone(),
                        level_index: Some(floor.level_index),
                        source_ref: Some(layout.unit_id.clone()),
                        notes: vec![format!("room_kind={}", room.room_kind)],
                    },
                );
                for opening in &room.opening_reserves {
                    canonical_graph_add_ownership(
                        graph,
                        TopologyGeometryOwnership {
                            binding_id: format!("opening_reserve:{}", opening.opening_id),
                            owner_node_id: node_id.clone(),
                            geometry_kind: "opening_reserve".to_string(),
                            geometry_ref: opening.opening_id.clone(),
                            level_index: Some(floor.level_index),
                            source_ref: Some(opening.associated_room_id.clone()),
                            notes: vec![format!("kind={}", opening.opening_kind)],
                        },
                    );
                }
                for fixture in &room.fixture_reserves {
                    canonical_graph_add_ownership(
                        graph,
                        TopologyGeometryOwnership {
                            binding_id: format!("fixture_reserve:{}", fixture.fixture_id),
                            owner_node_id: node_id.clone(),
                            geometry_kind: "fixture_reserve".to_string(),
                            geometry_ref: fixture.fixture_id.clone(),
                            level_index: Some(floor.level_index),
                            source_ref: Some(fixture.associated_room_id.clone()),
                            notes: vec![format!("kind={}", fixture.fixture_kind)],
                        },
                    );
                }
                if has_frontage {
                    let edge_id = canonical_graph_edge_id(
                        &node_id,
                        &exterior_node_id,
                        CanonicalTopologyEdgeKind::FrontageReach,
                        false,
                    );
                    let span_ft =
                        canonical_graph_span_between_nodes(graph, &node_id, &exterior_node_id);
                    canonical_graph_add_edge(
                        graph,
                        CanonicalTopologyEdge {
                            edge_id,
                            from_node_id: node_id.clone(),
                            to_node_id: exterior_node_id.clone(),
                            edge_kind: CanonicalTopologyEdgeKind::FrontageReach,
                            directed: false,
                            required: false,
                            span_ft,
                            source_refs: vec!["room_frontage".to_string()],
                            notes: vec!["Room reaches the exterior boundary.".to_string()],
                        },
                    );
                }
                room_node_ids.insert(room.room_id.clone(), node_id);
            }

            for edge in &layout.room_graph_edges {
                match (
                    room_node_ids.get(&edge.from_room_id),
                    room_node_ids.get(&edge.to_room_id),
                ) {
                    (Some(from_node_id), Some(to_node_id)) => {
                        let edge_id = canonical_graph_edge_id(
                            from_node_id,
                            to_node_id,
                            CanonicalTopologyEdgeKind::Access,
                            false,
                        );
                        let span_ft = canonical_graph_span_between_nodes(
                            graph,
                            from_node_id,
                            to_node_id,
                        );
                        canonical_graph_add_edge(
                            graph,
                            CanonicalTopologyEdge {
                                edge_id,
                                from_node_id: from_node_id.clone(),
                                to_node_id: to_node_id.clone(),
                                edge_kind: CanonicalTopologyEdgeKind::Access,
                                directed: false,
                                required: edge.required,
                                span_ft,
                                source_refs: vec![format!("room_edge_kind:{}", edge.edge_kind)],
                                notes: vec!["Room graph edge promoted into canonical runtime graph.".to_string()],
                            },
                        );
                    }
                    _ => canonical_graph_add_validation(
                        graph,
                        ValidationIssue::warning(
                            "missing_room_node_for_room_graph_edge",
                            "A room graph edge could not be attached because one canonical room node was missing.",
                        ),
                    ),
                }
            }

            if let Some(entry_node_id) = room_node_ids.get(&layout.entry_room_id).cloned() {
                let entry_polygon = graph
                    .nodes
                    .iter()
                    .find(|node| node.node_id == entry_node_id)
                    .map(|node| node.polygon.clone())
                    .unwrap_or_default();
                if let Some(target_node_id) = canonical_graph_nearest_node_id(
                    graph,
                    floor.level_index,
                    &[
                        CanonicalTopologyNodeKind::CorridorSegment,
                        CanonicalTopologyNodeKind::Core,
                    ],
                    &entry_polygon,
                ) {
                    let edge_id = canonical_graph_edge_id(
                        &entry_node_id,
                        &target_node_id,
                        CanonicalTopologyEdgeKind::Access,
                        false,
                    );
                    let span_ft =
                        canonical_graph_span_between_nodes(graph, &entry_node_id, &target_node_id);
                    canonical_graph_add_edge(
                        graph,
                        CanonicalTopologyEdge {
                            edge_id,
                            from_node_id: entry_node_id.clone(),
                            to_node_id: target_node_id,
                            edge_kind: CanonicalTopologyEdgeKind::Access,
                            directed: false,
                            required: true,
                            span_ft,
                            source_refs: vec![format!("unit:{}", layout.unit_id)],
                            notes: vec![
                                "Entry-to-corridor/core access promoted into the canonical graph."
                                    .to_string(),
                            ],
                        },
                    );
                } else {
                    missing_entry_access_count += 1;
                }
            } else {
                missing_entry_access_count += 1;
            }

            for room in &layout.rooms {
                if is_wet_room_kind(&room.room_kind) {
                    if let Some(room_node_id) = room_node_ids.get(&room.room_id) {
                        if let Some(service_target_id) = canonical_graph_nearest_node_id(
                            graph,
                            floor.level_index,
                            &[
                                CanonicalTopologyNodeKind::Shaft,
                                CanonicalTopologyNodeKind::Core,
                            ],
                            &room.polygon,
                        ) {
                            let edge_id = canonical_graph_edge_id(
                                room_node_id,
                                &service_target_id,
                                CanonicalTopologyEdgeKind::ServiceReach,
                                false,
                            );
                            let span_ft = canonical_graph_span_between_nodes(
                                graph,
                                room_node_id,
                                &service_target_id,
                            );
                            canonical_graph_add_edge(
                                graph,
                                CanonicalTopologyEdge {
                                    edge_id,
                                    from_node_id: room_node_id.clone(),
                                    to_node_id: service_target_id,
                                    edge_kind: CanonicalTopologyEdgeKind::ServiceReach,
                                    directed: false,
                                    required: true,
                                    span_ft,
                                    source_refs: vec![format!("wet_room:{}", room.room_kind)],
                                    notes: vec![
                                        "Wet room receives service reach ownership.".to_string()
                                    ],
                                },
                            );
                        } else {
                            missing_wet_service_count += 1;
                        }
                    }
                }
            }
        }
    }

    for opening in slab_openings {
        if let Some(owner_node_id) = canonical_graph_find_node_id_by_source_ref(
            graph,
            Some(floor.level_index),
            &format!("shaft_reserve:{}", opening.source_ref),
            &[CanonicalTopologyNodeKind::Shaft],
        ) {
            canonical_graph_add_ownership(
                graph,
                TopologyGeometryOwnership {
                    binding_id: format!("slab_opening:{}", opening.opening_id),
                    owner_node_id,
                    geometry_kind: "slab_opening".to_string(),
                    geometry_ref: opening.opening_id.clone(),
                    level_index: Some(floor.level_index),
                    source_ref: Some(opening.source_ref.clone()),
                    notes: opening.notes.clone(),
                },
            );
            continue;
        }

        if let Some(coupling) = couplings
            .iter()
            .find(|coupling| coupling.coupling_id == opening.source_ref)
        {
            if let Some(owner_node_id) = canonical_graph_find_node_id_by_source_ref(
                graph,
                Some(floor.level_index),
                &format!("unit:{}", coupling.source_unit_id),
                &[
                    CanonicalTopologyNodeKind::Entry,
                    CanonicalTopologyNodeKind::Zone,
                ],
            ) {
                canonical_graph_add_ownership(
                    graph,
                    TopologyGeometryOwnership {
                        binding_id: format!("slab_opening:{}", opening.opening_id),
                        owner_node_id,
                        geometry_kind: "slab_opening".to_string(),
                        geometry_ref: opening.opening_id.clone(),
                        level_index: Some(floor.level_index),
                        source_ref: Some(opening.source_ref.clone()),
                        notes: opening.notes.clone(),
                    },
                );
            }
        }
    }

    if floor_layouts
        .map(|layouts| !layouts.dwelling_layouts.is_empty())
        .unwrap_or(false)
        && !graph.nodes.iter().any(|node| {
            node.level_index == Some(floor.level_index)
                && node.node_kind == CanonicalTopologyNodeKind::CorridorSegment
        })
    {
        canonical_graph_add_validation(
            graph,
            ValidationIssue::warning(
                "missing_corridor_node_for_room_graph",
                "Room-level topology was built, but no corridor segment node exists in the canonical floor graph.",
            ),
        );
    }
    if missing_entry_access_count > 0 {
        canonical_graph_add_validation(
            graph,
            ValidationIssue::warning(
                "entry_access_not_committed",
                "At least one unit entry could not be connected to a corridor/core node in the canonical graph.",
            ),
        );
    }
    if missing_wet_service_count > 0 {
        canonical_graph_add_validation(
            graph,
            ValidationIssue::warning(
                "wet_room_service_reach_missing",
                "At least one wet room could not reach a shaft/core node in the canonical graph.",
            ),
        );
    }

    graph.notes.push(format!(
        "Enriched with {} dwelling layouts, {} shaft reserves, and {} slab openings.",
        floor_layouts
            .map(|layouts| layouts.dwelling_layouts.len())
            .unwrap_or(0),
        shaft_reserves.len(),
        slab_openings.len()
    ));
}

fn sync_space_topology_children_from_graph(
    floor: &mut FloorOutput,
    floor_layouts: Option<&FloorDwellingRoomLayouts>,
) {
    let graph_snapshot = floor.canonical_topology_graph.clone();
    let level_index = floor.level_index;
    let mut graph_parent_map = BTreeMap::<String, Vec<String>>::new();
    for node in &graph_snapshot.nodes {
        if let Some(parent_id) = &node.parent_node_id {
            graph_parent_map
                .entry(parent_id.clone())
                .or_default()
                .push(node.node_id.clone());
        }
    }

    for space in &mut floor.spaces {
        let node_id = canonical_graph_find_node_id_by_source_ref(
            &graph_snapshot,
            Some(level_index),
            &format!("space_id:{}", space.space_id),
            &[],
        )
        .or_else(|| {
            canonical_graph_find_node_id_by_source_ref(
                &graph_snapshot,
                Some(level_index),
                &format!("space_name:{}", space.space_name),
                &[],
            )
        });

        if let Some(node_id) = node_id {
            if let Some(parent_node_id) = graph_snapshot
                .nodes
                .iter()
                .find(|node| node.node_id == node_id)
                .and_then(|node| node.parent_node_id.clone())
            {
                space.parent_topology_node_id = Some(parent_node_id);
            }
            if let Some(layouts) = floor_layouts {
                if let Some(layout) = layouts
                    .dwelling_layouts
                    .iter()
                    .find(|layout| layout.source_space_name == space.space_name)
                {
                    for room in &layout.rooms {
                        let room_node_id = format!("topo_{}", room.room_id);
                        if !space
                            .child_topology_node_ids
                            .iter()
                            .any(|id| id == &room_node_id)
                        {
                            space.child_topology_node_ids.push(room_node_id);
                        }
                    }
                }
            }
            if let Some(children) = graph_parent_map.get(&node_id) {
                for child in children {
                    if !space.child_topology_node_ids.iter().any(|id| id == child) {
                        space.child_topology_node_ids.push(child.clone());
                    }
                }
            }
        }

        dedup_vec_strings(&mut space.child_topology_node_ids);
        dedup_vec_strings(&mut space.adjacency_ids);
    }
}

