pub struct ProgressiveSolveLayoutEngine {
    pub inner: RoomSynthesisLayoutEngine,
}

fn shape_complexity(shape: BuildingShape) -> f64 {
    match shape {
        BuildingShape::Bar => 0.18,
        BuildingShape::LShape => 0.32,
        BuildingShape::UShape => 0.38,
        BuildingShape::OShape => 0.42,
        BuildingShape::Tower => 0.35,
        BuildingShape::HShape => 0.58,
        BuildingShape::XShape => 0.62,
        BuildingShape::Cluster => 0.68,
        BuildingShape::FreeForm => 0.74,
        BuildingShape::PerimeterPartial => 0.65,
    }
}

fn pass_rank_from_id(pass_id: &str) -> usize {
    match pass_id {
        "P0" => 0,
        "P1" => 1,
        "P2" => 2,
        "P3" => 3,
        "P4" => 4,
        "P5" => 5,
        "P6" => 6,
        "P7" => 7,
        "P8" => 8,
        "P9" => 9,
        "P10" => 10,
        _ => 0,
    }
}

fn pass_id_from_rank(rank: usize) -> String {
    match rank.min(10) {
        0 => "P0",
        1 => "P1",
        2 => "P2",
        3 => "P3",
        4 => "P4",
        5 => "P5",
        6 => "P6",
        7 => "P7",
        8 => "P8",
        9 => "P9",
        _ => "P10",
    }
    .to_string()
}

fn pass_name(rank: usize) -> &'static str {
    match rank {
        0 => "canonicalization",
        1 => "morphology_sensing",
        2 => "core_corridor_unit_skeleton",
        3 => "floor_topology_commit",
        4 => "unit_envelope_topology",
        5 => "rough_room_partition",
        6 => "exact_2d_hotspot_subset",
        7 => "constraint_refinement",
        8 => "repair_reconciliation",
        9 => "inter_floor_25d_coupling",
        _ => "hotspot_3d_refinement",
    }
}

fn pass_cost_weight(rank: usize) -> f64 {
    match rank {
        0 => 0.6,
        1 => 0.8,
        2 => 1.2,
        3 => 1.4,
        4 => 1.7,
        5 => 2.2,
        6 => 4.5,
        7 => 3.5,
        8 => 2.8,
        9 => 5.0,
        _ => 8.0,
    }
}

fn profile_target_rank(profile: &str) -> usize {
    match profile {
        "fast_preview" => 5,
        "balanced" => 7,
        "deep_validation" => 9,
        "research" => 10,
        _ => 7,
    }
}

fn maximum_rank_from_input(input: &ProgressiveSolveLayoutInput) -> usize {
    match input.progressive_solve_controls.maximum_pass.as_str() {
        "p5_room_proto" => 5,
        "p7_constraint_refined" => 7,
        "p9_stack_bounded" => 9,
        "p10_hotspot_3d" => 10,
        _ => 9,
    }
}

fn family_id_map(base: &RoomSynthesisLayoutOutput) -> BTreeMap<u32, String> {
    let mut out = BTreeMap::<u32, String>::new();
    for s in &base.per_floor_typical_equivalence_summaries {
        out.insert(s.level_index, s.family_id.clone());
    }
    for s in &base.per_floor_dwelling_unit_solver_summaries {
        out.insert(s.level_index, s.family_id.clone());
    }
    for s in &base.per_floor_allocation_completeness_summaries {
        out.entry(s.level_index)
            .or_insert_with(|| format!("{}_{}", s.floor_role, s.level_index));
    }
    out
}

